INSERT INTO public.hadiths (
  collection_id, book, hadith_number, text_ar, text_tr, text_en, narrator, grade, source, source_license, verified_at
) VALUES
  ('bukhari', 'Belief', 11, '"‏ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ ‏"', NULL, 'Narrated Abu Musa: Some people asked Allah''s Messenger (ﷺ), "Whose Islam is the best? i.e. (Who is a very good Muslim)?" He replied, "One who avoids harming the Muslims with his tongue and hands."', 'Narrated Abu Musa', NULL, 'https://sunnah.com/bukhari:11', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 12, '"‏ تُطْعِمُ الطَّعَامَ، وَتَقْرَأُ السَّلاَمَ عَلَى مَنْ عَرَفْتَ وَمَنْ لَمْ تَعْرِفْ ‏"', NULL, 'Narrated ''Abdullah bin ''Amr: A man asked the Prophet (ﷺ) , "What sort of deeds or (what qualities of) Islam are good?" The Prophet (ﷺ) replied, ''To feed (the poor) and greet those whom you know and those whom you do not Know (See Hadith No. 27).', 'Narrated ''Abdullah bin ''Amr', NULL, 'https://sunnah.com/bukhari:12', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 13, '"‏ لا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ ‏"', NULL, 'Narrated Anas: The Prophet (ﷺ) said, "None of you will have faith till he wishes for his (Muslim) brother what he likes for himself."', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:13', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 14, '"‏ فَوَالَّذِي نَفْسِي بِيَدِهِ لاَ يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَالِدِهِ وَوَلَدِهِ ‏"', NULL, 'Narrated Abu Huraira: "Allah''s Messenger (ﷺ) said, "By Him in Whose Hands my life is, none of you will have faith till he loves me more than his father and his children."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:14', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 15, '"‏ لاَ يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَالِدِهِ وَوَلَدِهِ وَالنَّاسِ أَجْمَعِينَ ‏"', NULL, 'Narrated Anas: The Prophet (ﷺ) said "None of you will have faith till he loves me more than his father, his children and all mankind."', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:15', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 16, '"‏ ثَلاَثٌ مَنْ كُنَّ فِيهِ وَجَدَ حَلاَوَةَ الإِيمَانِ أَنْ يَكُونَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا، وَأَنْ يُحِبَّ الْمَرْءَ لاَ يُحِبُّهُ إِلاَّ لِلَّهِ، وَأَنْ يَكْرَهَ أَنْ يَعُودَ فِي الْكُفْرِ كَمَا يَكْرَهُ أَنْ يُقْذَفَ فِي النَّارِ ‏"', NULL, 'Narrated Anas: The Prophet (ﷺ) said, "Whoever possesses the following three qualities will have the sweetness (delight) of faith: 1. The one to whom Allah and His Apostle becomes dearer than anything else. 2. Who loves a person and he loves him only for Allah''s sake. 3. Who hates to revert to Atheism (disbelief) as he hates to be thrown into the fire."', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:16', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 17, '"‏ آيَةُ الإِيمَانِ حُبُّ الأَنْصَارِ، وَآيَةُ النِّفَاقِ بُغْضُ الأَنْصَارِ ‏"', NULL, 'Narrated Anas: The Prophet (ﷺ) said, "Love for the Ansar is a sign of faith and hatred for the Ansar is a sign of hypocrisy."', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:17', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 18, '"‏ بَايِعُونِي عَلَى أَنْ لاَ تُشْرِكُوا بِاللَّهِ شَيْئًا، وَلاَ تَسْرِقُوا، وَلاَ تَزْنُوا، وَلاَ تَقْتُلُوا أَوْلاَدَكُمْ، وَلاَ تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ، وَلاَ تَعْصُوا فِي مَعْرُوفٍ، فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ، وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَعُوقِبَ فِي الدُّنْيَا فَهُوَ كَفَّارَةٌ لَهُ، وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا ثُمَّ سَتَرَهُ اللَّهُ، فَهُوَ إِلَى اللَّهِ إِنْ شَاءَ عَفَا عَنْهُ، وَإِنْ شَاءَ عَاقَبَهُ ‏"', NULL, 'Narrated ''Ubada bin As-Samit: who took part in the battle of Badr and was a Naqib (a person heading a group of six persons), on the night of Al-''Aqaba pledge: Allah''s Apostle said while a group of his companions were around him, "Swear allegiance to me for: 1. Not to join anything in worship along with Allah. 2. Not to steal. 3. Not to commit illegal sexual intercourse. 4. Not to kill your children. 5. Not to accuse an innocent person (to spread such an accusation among people). 6. Not to be disobedient (when ordered) to do good deed." The Prophet (ﷺ) added: "Whoever among you fulfills his pledge will be rewarded by Allah. And whoever indulges in any one of them (except the ascription of partners to Allah) and gets the punishment in this world, that punishment will be an expiation for that sin. And if one indulges in any of them, and Allah conceals his sin, it is up to Him to forgive or punish him (in the Hereafter)." ''Ubada bin As-Samit added: "So we swore allegiance for these." (points to Allah''s Apostle)', 'Narrated ''Ubada bin As-Samit', NULL, 'https://sunnah.com/bukhari:18', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 19, '"‏ يُوشِكُ أَنْ يَكُونَ خَيْرَ مَالِ الْمُسْلِمِ غَنَمٌ يَتْبَعُ بِهَا شَعَفَ الْجِبَالِ وَمَوَاقِعَ الْقَطْرِ، يَفِرُّ بِدِينِهِ مِنَ الْفِتَنِ ‏"', NULL, 'Narrated Abu Said Al-Khudri: Allah''s Messenger (ﷺ) said, "A time will soon come when the best property of a Muslim will be sheep which he will take on the top of mountains and the places of rainfall (valleys) so as to flee with his religion from afflictions."', 'Narrated Abu Said Al-Khudri', NULL, 'https://sunnah.com/bukhari:19', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 20, '"‏ إِنَّ أَتْقَاكُمْ وَأَعْلَمَكُمْ بِاللَّهِ أَنَا ‏"', NULL, 'Narrated ''Aisha: Whenever Allah''s Messenger (ﷺ) ordered the Muslims to do something, he used to order them deeds which were easy for them to do, (according to their strength and endurance). They said, "O Allah''s Messenger (ﷺ)! We are not like you. Allah has forgiven your past and future sins." So Allah''s Apostle became angry and it was apparent on his face. He said, "I am the most Allah fearing, and know Allah better than all of you do."', 'Narrated ''Aisha', NULL, 'https://sunnah.com/bukhari:20', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 21, '"‏ ثَلاَثٌ مَنْ كُنَّ فِيهِ وَجَدَ حَلاَوَةَ الإِيمَانِ مَنْ كَانَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا، وَمَنْ أَحَبَّ عَبْدًا لاَ يُحِبُّهُ إِلاَّ لِلَّهِ، وَمَنْ يَكْرَهُ أَنْ يَعُودَ فِي الْكُفْرِ بَعْدَ إِذْ أَنْقَذَهُ اللَّهُ، كَمَا يَكْرَهُ أَنْ يُلْقَى فِي النَّارِ ‏"', NULL, 'Narrated Anas: The Prophet (ﷺ) said, "Whoever possesses the following three qualities will taste the sweetness of faith: 1. The one to whom Allah and His Apostle become dearer than anything else. 2. Who loves a person and he loves him only for Allah''s sake. 3. Who hates to revert to disbelief (Atheism) after Allah has brought (saved) him out from it, as he hates to be thrown in fire."', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:21', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 22, 'حَدَّثَنَا إِسْمَاعِيلُ، قَالَ حَدَّثَنِي مَالِكٌ، عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ، عَنْ أَبِيهِ، عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ، رضى الله عنه ـ عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ يَدْخُلُ أَهْلُ الْجَنَّةِ الْجَنَّةَ، وَأَهْلُ النَّارِ النَّارَ، ثُمَّ يَقُولُ اللَّهُ تَعَالَى أَخْرِجُوا مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ خَرْدَلٍ مِنْ إِيمَانٍ‏.‏ فَيُخْرَجُونَ مِنْهَا قَدِ اسْوَدُّوا فَيُلْقَوْنَ فِي نَهَرِ الْحَيَا ـ أَوِ الْحَيَاةِ، شَكَّ مَالِكٌ ـ فَيَنْبُتُونَ كَمَا تَنْبُتُ الْحِبَّةُ فِي جَانِبِ السَّيْلِ، أَلَمْ تَرَ أَنَّهَا تَخْرُجُ صَفْرَاءَ مُلْتَوِيَةً ‏"‏‏.‏ قَالَ وُهَيْبٌ حَدَّثَنَا عَمْرٌو ‏"‏ الْحَيَاةِ ‏"‏‏.‏ وَقَالَ ‏"‏ خَرْدَلٍ مِنْ خَيْرٍ ‏"‏‏.‏', NULL, 'Narrated Abu Said Al-Khudri: The Prophet (ﷺ) said, "When the people of Paradise will enter Paradise and the people of Hell will go to Hell, Allah will order those who have had faith equal to the weight of a grain of mustard seed to be taken out from Hell. So they will be taken out but (by then) they will be blackened (charred). Then they will be put in the river of Haya'' (rain) or Hayat (life) (the Narrator is in doubt as to which is the right term), and they will revive like a grain that grows near the bank of a flood channel. Don''t you see that it comes out yellow and twisted"', 'Narrated Abu Said Al-Khudri', NULL, 'https://sunnah.com/bukhari:22', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 23, 'حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ، قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ، عَنْ صَالِحٍ، عَنِ ابْنِ شِهَابٍ، عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ، أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ، يَقُولُ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ بَيْنَا أَنَا نَائِمٌ رَأَيْتُ النَّاسَ يُعْرَضُونَ عَلَىَّ، وَعَلَيْهِمْ قُمُصٌ مِنْهَا مَا يَبْلُغُ الثُّدِيَّ، وَمِنْهَا مَا دُونَ ذَلِكَ، وَعُرِضَ عَلَىَّ عُمَرُ بْنُ الْخَطَّابِ وَعَلَيْهِ قَمِيصٌ يَجُرُّهُ ‏"‏‏.‏ قَالُوا فَمَا أَوَّلْتَ ذَلِكَ يَا رَسُولَ اللَّهِ قَالَ ‏"‏ الدِّينَ ‏"‏‏.‏', NULL, 'Narrated Abu Said Al-Khudri: Allah''s Messenger (ﷺ) said, "While I was sleeping I saw (in a dream) some people wearing shirts of which some were reaching up to the breasts only while others were even shorter than that. Umar bin Al-Khattab was shown wearing a shirt that he was dragging." The people asked, "How did you interpret it? (What is its interpretation) O Allah''s Messenger (ﷺ)?" He (the Prophet (ﷺ) ) replied, "It is the Religion."', 'Narrated Abu Said Al-Khudri', NULL, 'https://sunnah.com/bukhari:23', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 24, '"‏ دَعْهُ فَإِنَّ الْحَيَاءَ مِنَ الإِيمَانِ ‏"', NULL, 'Narrated ''Abdullah (bin ''Umar): Once Allah''s Messenger (ﷺ) passed by an Ansari (man) who was admonishing his brother regarding Haya''. On that Allah''s Messenger (ﷺ) said, "Leave him as Haya'' is a part of faith." (See Hadith 9)', 'Narrated ''Abdullah (bin ''Umar)', NULL, 'https://sunnah.com/bukhari:24', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 25, '"‏ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ، وَيُقِيمُوا الصَّلاَةَ، وَيُؤْتُوا الزَّكَاةَ، فَإِذَا فَعَلُوا ذَلِكَ عَصَمُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلاَّ بِحَقِّ الإِسْلاَمِ، وَحِسَابُهُمْ عَلَى اللَّهِ ‏"', NULL, 'Narrated Ibn ''Umar: Allah''s Messenger (ﷺ) said: "I have been ordered (by Allah) to fight against the people until they testify that none has the right to be worshipped but Allah and that Muhammad is Allah''s Messenger (ﷺ), and offer the prayers perfectly and give the obligatory charity, so if they perform that, then they save their lives and property from me except for Islamic laws and then their reckoning (accounts) will be done by Allah."', 'Narrated Ibn ''Umar', NULL, 'https://sunnah.com/bukhari:25', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 26, 'حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ، وَمُوسَى بْنُ إِسْمَاعِيلَ، قَالاَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ، قَالَ حَدَّثَنَا ابْنُ شِهَابٍ، عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ، عَنْ أَبِي هُرَيْرَةَ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم سُئِلَ أَىُّ الْعَمَلِ أَفْضَلُ فَقَالَ ‏"‏ إِيمَانٌ بِاللَّهِ وَرَسُولِهِ ‏"‏‏.‏ قِيلَ ثُمَّ مَاذَا قَالَ ‏"‏ الْجِهَادُ فِي سَبِيلِ اللَّهِ ‏"‏‏.‏ قِيلَ ثُمَّ مَاذَا قَالَ ‏"‏ حَجٌّ مَبْرُورٌ ‏"‏‏.‏', NULL, 'Narrated Abu Huraira: Allah''s Messenger (ﷺ) was asked, "What is the best deed?" He replied, "To believe in Allah and His Apostle (Muhammad). The questioner then asked, "What is the next (in goodness)? He replied, "To participate in Jihad (religious fighting) in Allah''s Cause." The questioner again asked, "What is the next (in goodness)?" He replied, "To perform Hajj (Pilgrim age to Mecca) ''Mubrur, (which is accepted by Allah and is performed with the intention of seeking Allah''s pleasure only and not to show off and without committing a sin and in accordance with the traditions of the Prophet)."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:26', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 27, 'حَدَّثَنَا أَبُو الْيَمَانِ، قَالَ أَخْبَرَنَا شُعَيْبٌ، عَنِ الزُّهْرِيِّ، قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدِ بْنِ أَبِي وَقَّاصٍ، عَنْ سَعْدٍ، رضى الله عنه أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم أَعْطَى رَهْطًا وَسَعْدٌ جَالِسٌ، فَتَرَكَ رَسُولُ اللَّهِ صلى الله عليه وسلم رَجُلاً هُوَ أَعْجَبُهُمْ إِلَىَّ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا لَكَ عَنْ فُلاَنٍ فَوَاللَّهِ إِنِّي لأَرَاهُ مُؤْمِنًا‏.‏ فَقَالَ ‏"‏ أَوْ مُسْلِمًا ‏"‏‏.‏ فَسَكَتُّ قَلِيلاً، ثُمَّ غَلَبَنِي مَا أَعْلَمُ مِنْهُ فَعُدْتُ لِمَقَالَتِي فَقُلْتُ مَا لَكَ عَنْ فُلاَنٍ فَوَاللَّهِ إِنِّي لأَرَاهُ مُؤْمِنًا فَقَالَ ‏"‏ أَوْ مُسْلِمًا ‏"‏‏.‏ ثُمَّ غَلَبَنِي مَا أَعْلَمُ مِنْهُ فَعُدْتُ لِمَقَالَتِي وَعَادَ رَسُولُ اللَّهِ صلى الله عليه وسلم ثُمَّ قَالَ ‏"‏ يَا سَعْدُ، إِنِّي لأُعْطِي الرَّجُلَ وَغَيْرُهُ أَحَبُّ إِلَىَّ مِنْهُ، خَشْيَةَ أَنْ يَكُبَّهُ اللَّهُ فِي النَّارِ ‏"‏‏.‏ وَرَوَاهُ يُونُسُ وَصَالِحٌ وَمَعْمَرٌ وَابْنُ أَخِي الزُّهْرِيِّ عَنِ الزُّهْرِيِّ‏.‏', NULL, 'Narrated Sa''d: Allah''s Messenger (ﷺ) distributed (Zakat) amongst (a group of) people while I was sitting there but Allah''s Messenger (ﷺ) left a man whom I thought the best of the lot. I asked, "O Allah''s Messenger (ﷺ)! Why have you left that person? By Allah I regard him as a faithful believer." The Prophet (ﷺ) commented: "Or merely a Muslim." I remained quiet for a while, but could not help repeating my question because of what I knew about him. And then asked Allah''s Messenger (ﷺ), "Why have you left so and so? By Allah! He is a faithful believer." The Prophet (ﷺ) again said, "Or merely a Muslim." And I could not help repeating my question because of what I knew about him. Then the Prophet (ﷺ) said, "O Sa''d! I give to a person while another is dearer to me, for fear that he might be thrown on his face in the Fire by Allah."', 'Narrated Sa''d', NULL, 'https://sunnah.com/bukhari:27', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 28, '"‏ تُطْعِمُ الطَّعَامَ، وَتَقْرَأُ السَّلاَمَ عَلَى مَنْ عَرَفْتَ وَمَنْ لَمْ تَعْرِفْ ‏"', NULL, 'Narrated ''Abdullah bin ''Amr: A person asked Allah''s Messenger (ﷺ) . "What (sort of) deeds in or (what qualities of) Islam are good?" He replied, "To feed (the poor) and greet those whom you know and those whom you don''t know."', 'Narrated ''Abdullah bin ''Amr', NULL, 'https://sunnah.com/bukhari:28', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 29, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ، عَنْ مَالِكٍ، عَنْ زَيْدِ بْنِ أَسْلَمَ، عَنْ عَطَاءِ بْنِ يَسَارٍ، عَنِ ابْنِ عَبَّاسٍ، قَالَ قَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ أُرِيتُ النَّارَ فَإِذَا أَكْثَرُ أَهْلِهَا النِّسَاءُ يَكْفُرْنَ ‏"‏‏.‏ قِيلَ أَيَكْفُرْنَ بِاللَّهِ قَالَ ‏"‏ يَكْفُرْنَ الْعَشِيرَ، وَيَكْفُرْنَ الإِحْسَانَ، لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّ ‏"‏‏.‏', NULL, 'Narrated Ibn ''Abbas: The Prophet (ﷺ) said: "I was shown the Hell-fire and that the majority of its dwellers were women who were ungrateful." It was asked, "Do they disbelieve in Allah?" (or are they ungrateful to Allah?) He replied, "They are ungrateful to their husbands and are ungrateful for the favors and the good (charitable deeds) done to them. If you have always been good (benevolent) to one of them and then she sees something in you (not of her liking), she will say, ''I have never received any good from you."', 'Narrated Ibn ''Abbas', NULL, 'https://sunnah.com/bukhari:29', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 30, '"‏ يَا أَبَا ذَرٍّ أَعَيَّرْتَهُ بِأُمِّهِ إِنَّكَ امْرُؤٌ فِيكَ جَاهِلِيَّةٌ، إِخْوَانُكُمْ خَوَلُكُمْ، جَعَلَهُمُ اللَّهُ تَحْتَ أَيْدِيكُمْ، فَمَنْ كَانَ أَخُوهُ تَحْتَ يَدِهِ فَلْيُطْعِمْهُ مِمَّا يَأْكُلُ، وَلْيُلْبِسْهُ مِمَّا يَلْبَسُ، وَلاَ تُكَلِّفُوهُمْ مَا يَغْلِبُهُمْ، فَإِنْ كَلَّفْتُمُوهُمْ فَأَعِينُوهُمْ ‏"', NULL, 'Narrated Al-Ma''rur: At Ar-Rabadha I met Abu Dhar who was wearing a cloak, and his slave, too, was wearing a similar one. I asked about the reason for it. He replied, "I abused a person by calling his mother with bad names." The Prophet said to me, ''O Abu Dhar! Did you abuse him by calling his mother with bad names You still have some characteristics of ignorance. Your slaves are your brothers and Allah has put them under your command. So whoever has a brother under his command should feed him of what he eats and dress him of what he wears. Do not ask them (slaves) to do things beyond their capacity (power) and if you do so, then help them.'' "', 'Narrated Al-Ma''rur', NULL, 'https://sunnah.com/bukhari:30', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 31, 'حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ، حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ، حَدَّثَنَا أَيُّوبُ، وَيُونُسُ، عَنِ الْحَسَنِ، عَنِ الأَحْنَفِ بْنِ قَيْسٍ، قَالَ ذَهَبْتُ لأَنْصُرَ هَذَا الرَّجُلَ، فَلَقِيَنِي أَبُو بَكْرَةَ فَقَالَ أَيْنَ تُرِيدُ قُلْتُ أَنْصُرُ هَذَا الرَّجُلَ‏.‏ قَالَ ارْجِعْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم يَقُولُ ‏"‏ إِذَا الْتَقَى الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ ‏"‏‏.‏ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ ‏"‏ إِنَّهُ كَانَ حَرِيصًا عَلَى قَتْلِ صَاحِبِهِ ‏"‏‏.‏', NULL, 'Narrated Al-Ahnaf bin Qais: While I was going to help this man (''Ali Ibn Abi Talib), Abu Bakra met me and asked, "Where are you going?" I replied, "I am going to help that person." He said, "Go back for I have heard Allah''s Messenger (ﷺ) saying, ''When two Muslims fight (meet) each other with their swords, both the murderer as well as the murdered will go to the Hell-fire.'' I said, ''O Allah''s Messenger (ﷺ)! It is all right for the murderer but what about the murdered one?'' Allah''s Messenger (ﷺ) replied, "He surely had the intention to kill his companion."', 'Narrated Al-Ahnaf bin Qais', NULL, 'https://sunnah.com/bukhari:31', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 32, 'حَدَّثَنَا أَبُو الْوَلِيدِ، قَالَ حَدَّثَنَا شُعْبَةُ، ح‏.‏ قَالَ وَحَدَّثَنِي بِشْرٌ، قَالَ حَدَّثَنَا مُحَمَّدٌ، عَنْ شُعْبَةَ، عَنْ سُلَيْمَانَ، عَنْ إِبْرَاهِيمَ، عَنْ عَلْقَمَةَ، عَنْ عَبْدِ اللَّهِ، قَالَ لَمَّا نَزَلَتِ ‏{‏الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ‏}‏ قَالَ أَصْحَابُ رَسُولِ اللَّهِ صلى الله عليه وسلم أَيُّنَا لَمْ يَظْلِمْ فَأَنْزَلَ اللَّهُ ‏{‏إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ‏}‏‏.‏', NULL, 'Narrated ''Abdullah: When the following Verse was revealed: "It is those who believe and confuse not their belief with wrong (worshipping others besides Allah.)" (6:83), the companions of Allah''s Messenger (ﷺ) asked, "Who is amongst us who had not done injustice (wrong)?" Allah revealed: "No doubt, joining others in worship with Allah is a great injustice (wrong) indeed." (31.13)', 'Narrated ''Abdullah', NULL, 'https://sunnah.com/bukhari:32', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 33, '"‏ آيَةُ الْمُنَافِقِ ثَلاَثٌ إِذَا حَدَّثَ كَذَبَ، وَإِذَا وَعَدَ أَخْلَفَ، وَإِذَا اؤْتُمِنَ خَانَ ‏"', NULL, 'Narrated Abu Huraira: The Prophet (ﷺ) said, "The signs of a hypocrite are three: 1. Whenever he speaks, he tells a lie. 2. Whenever he promises, he always breaks it (his promise ). 3. If you trust him, he proves to be dishonest. (If you keep something as a trust with him, he will not return it.)"', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:33', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 34, '"‏ أَرْبَعٌ مَنْ كُنَّ فِيهِ كَانَ مُنَافِقًا خَالِصًا، وَمَنْ كَانَتْ فِيهِ خَصْلَةٌ مِنْهُنَّ كَانَتْ فِيهِ خَصْلَةٌ مِنَ النِّفَاقِ حَتَّى يَدَعَهَا إِذَا اؤْتُمِنَ خَانَ وَإِذَا حَدَّثَ كَذَبَ وَإِذَا عَاهَدَ غَدَرَ، وَإِذَا خَاصَمَ فَجَرَ ‏"', NULL, 'Narrated ''Abdullah bin ''Amr: The Prophet (ﷺ) said, "Whoever has the following four (characteristics) will be a pure hypocrite and whoever has one of the following four characteristics will have one characteristic of hypocrisy unless and until he gives it up. 1. Whenever he is entrusted, he betrays. 2. Whenever he speaks, he tells a lie. 3. Whenever he makes a covenant, he proves treacherous. 4. Whenever he quarrels, he behaves in a very imprudent, evil and insulting manner."', 'Narrated ''Abdullah bin ''Amr', NULL, 'https://sunnah.com/bukhari:34', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 35, '"‏ مَنْ يَقُمْ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ ‏"', NULL, 'Narrated Abu Huraira: Allah''s Messenger (ﷺ) said, "Whoever establishes the prayers on the night of Qadr out of sincere faith and hoping to attain Allah''s rewards (not to show off) then all his past sins will be forgiven."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:35', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 36, '"‏ انْتَدَبَ اللَّهُ لِمَنْ خَرَجَ فِي سَبِيلِهِ لاَ يُخْرِجُهُ إِلاَّ إِيمَانٌ بِي وَتَصْدِيقٌ بِرُسُلِي أَنْ أُرْجِعَهُ بِمَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ، أَوْ أُدْخِلَهُ الْجَنَّةَ، وَلَوْلاَ أَنْ أَشُقَّ عَلَى أُمَّتِي مَا قَعَدْتُ خَلْفَ سَرِيَّةٍ، وَلَوَدِدْتُ أَنِّي أُقْتَلُ فِي سَبِيلِ اللَّهِ ثُمَّ أُحْيَا، ثُمَّ أُقْتَلُ ثُمَّ أُحْيَا، ثُمَّ أُقْتَلُ ‏"', NULL, 'Narrated Abu Huraira: The Prophet (ﷺ) said, "The person who participates in (Holy battles) in Allah''s cause and nothing compels him to do so except belief in Allah and His Apostles, will be recompensed by Allah either with a reward, or booty (if he survives) or will be admitted to Paradise (if he is killed in the battle as a martyr). Had I not found it difficult for my followers, then I would not remain behind any sariya going for Jihad and I would have loved to be martyred in Allah''s cause and then made alive, and then martyred and then made alive, and then again martyred in His cause."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:36', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 37, '"‏ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ ‏"', NULL, 'Narrated Abu Huraira: Allah''s Messenger (ﷺ) said: "Whoever establishes prayers during the nights of Ramadan faithfully out of sincere faith and hoping to attain Allah''s rewards (not for showing off), all his past sins will be forgiven."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:37', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 38, '"‏ مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ ‏"', NULL, 'Narrated Abu Huraira: Allah''s Messenger (ﷺ) said, "Whoever observes fasts during the month of Ramadan out of sincere faith, and hoping to attain Allah''s rewards, then all his past sins will be forgiven."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:38', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 39, '"‏ إِنَّ الدِّينَ يُسْرٌ، وَلَنْ يُشَادَّ الدِّينَ أَحَدٌ إِلاَّ غَلَبَهُ، فَسَدِّدُوا وَقَارِبُوا وَأَبْشِرُوا، وَاسْتَعِينُوا بِالْغَدْوَةِ وَالرَّوْحَةِ وَشَىْءٍ مِنَ الدُّلْجَةِ ‏"', NULL, 'Narrated Abu Huraira: The Prophet (ﷺ) said, "Religion is very easy and whoever overburdens himself in his religion will not be able to continue in that way. So you should not be extremists, but try to be near to perfection and receive the good tidings that you will be rewarded; and gain strength by worshipping in the mornings, the afternoons, and during the last hours of the nights." (See Fath-ul-Bari, Page 102, Vol 1).', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:39', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 40, 'حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ، قَالَ حَدَّثَنَا زُهَيْرٌ، قَالَ حَدَّثَنَا أَبُو إِسْحَاقَ، عَنِ الْبَرَاءِ، أَنَّ النَّبِيَّ صلى الله عليه وسلم كَانَ أَوَّلَ مَا قَدِمَ الْمَدِينَةَ نَزَلَ عَلَى أَجْدَادِهِ ـ أَوْ قَالَ أَخْوَالِهِ ـ مِنَ الأَنْصَارِ، وَأَنَّهُ صَلَّى قِبَلَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ شَهْرًا، أَوْ سَبْعَةَ عَشَرَ شَهْرًا، وَكَانَ يُعْجِبُهُ أَنْ تَكُونَ قِبْلَتُهُ قِبَلَ الْبَيْتِ، وَأَنَّهُ صَلَّى أَوَّلَ صَلاَةٍ صَلاَّهَا صَلاَةَ الْعَصْرِ، وَصَلَّى مَعَهُ قَوْمٌ، فَخَرَجَ رَجُلٌ مِمَّنْ صَلَّى مَعَهُ، فَمَرَّ عَلَى أَهْلِ مَسْجِدٍ، وَهُمْ رَاكِعُونَ فَقَالَ أَشْهَدُ بِاللَّهِ لَقَدْ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صلى الله عليه وسلم قِبَلَ مَكَّةَ، فَدَارُوا كَمَا هُمْ قِبَلَ الْبَيْتِ، وَكَانَتِ الْيَهُودُ قَدْ أَعْجَبَهُمْ إِذْ كَانَ يُصَلِّي قِبَلَ بَيْتِ الْمَقْدِسِ، وَأَهْلُ الْكِتَابِ، فَلَمَّا وَلَّى وَجْهَهُ قِبَلَ الْبَيْتِ أَنْكَرُوا ذَلِكَ‏.‏ قَالَ زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ عَنِ الْبَرَاءِ فِي حَدِيثِهِ هَذَا أَنَّهُ مَاتَ عَلَى الْقِبْلَةِ قَبْلَ أَنْ تُحَوَّلَ رِجَالٌ وَقُتِلُوا، فَلَمْ نَدْرِ مَا نَقُولُ فِيهِمْ، فَأَنْزَلَ اللَّهُ تَعَالَى ‏{‏وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ‏}‏', NULL, 'Narrated Al-Bara'' (bin ''Azib): When the Prophet (ﷺ) came to Medina, he stayed first with his grandfathers or maternal uncles from Ansar. He offered his prayers facing Baitul-Maqdis (Jerusalem) for sixteen or seventeen months, but he wished that he could pray facing the Ka''ba (at Mecca). The first prayer which he offered facing the Ka''ba was the ''Asr prayer in the company of some people. Then one of those who had offered that prayer with him came out and passed by some people in a mosque who were bowing during their prayers (facing Jerusalem). He said addressing them, "By Allah, I testify that I have prayed with Allah''s Messenger (ﷺ) facing Mecca (Ka''ba).'' Hearing that, those people changed their direction towards the Ka''ba immediately. Jews and the people of the scriptures used to be pleased to see the Prophet (ﷺ) facing Jerusalem in prayers but when he changed his direction towards the Ka''ba, during the prayers, they disapproved of it. Al-Bara'' added, "Before we changed our direction towards the Ka''ba (Mecca) in prayers, some Muslims had died or had been killed and we did not know what to say about them (regarding their prayers.) Allah then revealed: And Allah would never make your faith (prayers) to be lost (i.e. the prayers of those Muslims were valid).'' " (2:143).', 'Narrated Al-Bara'' (bin ''Azib)', NULL, 'https://sunnah.com/bukhari:40', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 41, '"‏ إِذَا أَسْلَمَ الْعَبْدُ فَحَسُنَ إِسْلاَمُهُ يُكَفِّرُ اللَّهُ عَنْهُ كُلَّ سَيِّئَةٍ كَانَ زَلَفَهَا، وَكَانَ بَعْدَ ذَلِكَ الْقِصَاصُ، الْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا إِلَى سَبْعِمِائَةِ ضِعْفٍ، وَالسَّيِّئَةُ بِمِثْلِهَا إِلاَّ أَنْ يَتَجَاوَزَ اللَّهُ عَنْهَا ‏"', NULL, 'Narrated Abu Sa''id Al Khudri:Allah''s Messenger (ﷺ) said, "If a person embraces Islam sincerely, then Allah shall forgive all his past sins, and after that starts the settlement of accounts, the reward of his good deeds will be ten times to seven hundred times for each good deed and one evil deed will be recorded as it is unless Allah forgives it."', 'Narrated Abu Sa''id Al Khudri', NULL, 'https://sunnah.com/bukhari:41', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 42, '"‏ إِذَا أَحْسَنَ أَحَدُكُمْ إِسْلاَمَهُ، فَكُلُّ حَسَنَةٍ يَعْمَلُهَا تُكْتَبُ لَهُ بِعَشْرِ أَمْثَالِهَا إِلَى سَبْعِمِائَةِ ضِعْفٍ، وَكُلُّ سَيِّئَةٍ يَعْمَلُهَا تُكْتَبُ لَهُ بِمِثْلِهَا ‏"', NULL, 'Narrated Abu Huraira: Allah''s Messenger (ﷺ) said, "If any one of you improve (follows strictly) his Islamic religion then his good deeds will be rewarded ten times to seven hundred times for each good deed and a bad deed will be recorded as it is."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:42', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 43, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، حَدَّثَنَا يَحْيَى، عَنْ هِشَامٍ، قَالَ أَخْبَرَنِي أَبِي، عَنْ عَائِشَةَ، أَنَّ النَّبِيَّ صلى الله عليه وسلم دَخَلَ عَلَيْهَا وَعِنْدَهَا امْرَأَةٌ قَالَ ‏"‏ مَنْ هَذِهِ ‏"‏‏.‏ قَالَتْ فُلاَنَةُ‏.‏ تَذْكُرُ مِنْ صَلاَتِهَا‏.‏ قَالَ ‏"‏ مَهْ، عَلَيْكُمْ بِمَا تُطِيقُونَ، فَوَاللَّهِ لاَ يَمَلُّ اللَّهُ حَتَّى تَمَلُّوا ‏"‏‏.‏ وَكَانَ أَحَبَّ الدِّينِ إِلَيْهِ مَا دَامَ عَلَيْهِ صَاحِبُهُ‏.‏', NULL, 'Narrated ''Aisha: Once the Prophet (ﷺ) came while a woman was sitting with me. He said, "Who is she?" I replied, "She is so and so," and told him about her (excessive) praying. He said disapprovingly, "Do (good) deeds which is within your capacity (without being overtaxed) as Allah does not get tired (of giving rewards) but (surely) you will get tired and the best deed (act of Worship) in the sight of Allah is that which is done regularly."', 'Narrated ''Aisha', NULL, 'https://sunnah.com/bukhari:43', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 44, 'حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ، قَالَ حَدَّثَنَا هِشَامٌ، قَالَ حَدَّثَنَا قَتَادَةُ، عَنْ أَنَسٍ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ يَخْرُجُ مِنَ النَّارِ مَنْ قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ، وَفِي قَلْبِهِ وَزْنُ شَعِيرَةٍ مِنْ خَيْرٍ، وَيَخْرُجُ مِنَ النَّارِ مَنْ قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ، وَفِي قَلْبِهِ وَزْنُ بُرَّةٍ مِنْ خَيْرٍ، وَيَخْرُجُ مِنَ النَّارِ مَنْ قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ، وَفِي قَلْبِهِ وَزْنُ ذَرَّةٍ مِنْ خَيْرٍ ‏"‏‏.‏ قَالَ أَبُو عَبْدِ اللَّهِ قَالَ أَبَانُ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسٌ عَنِ النَّبِيِّ صلى الله عليه وسلم ‏"‏ مِنْ إِيمَانٍ ‏"‏‏.‏ مَكَانَ ‏"‏ مِنْ خَيْرٍ ‏"‏‏.‏', NULL, 'Narrated Anas: The Prophet (ﷺ) said, "Whoever said "None has the right to be worshipped but Allah and has in his heart good (faith) equal to the weight of a barley grain will be taken out of Hell. And whoever said: "None has the right to be worshipped but Allah and has in his heart good (faith) equal to the weight of a wheat grain will be taken out of Hell. And whoever said, "None has the right to be worshipped but Allah and has in his heart good (faith) equal to the weight of an atom will be taken out of Hell."', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:44', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 45, 'حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ، سَمِعَ جَعْفَرَ بْنَ عَوْنٍ، حَدَّثَنَا أَبُو الْعُمَيْسِ، أَخْبَرَنَا قَيْسُ بْنُ مُسْلِمٍ، عَنْ طَارِقِ بْنِ شِهَابٍ، عَنْ عُمَرَ بْنِ الْخَطَّابِ، أَنَّ رَجُلاً، مِنَ الْيَهُودِ قَالَ لَهُ يَا أَمِيرَ الْمُؤْمِنِينَ، آيَةٌ فِي كِتَابِكُمْ تَقْرَءُونَهَا لَوْ عَلَيْنَا مَعْشَرَ الْيَهُودِ نَزَلَتْ لاَتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا‏.‏ قَالَ أَىُّ آيَةٍ قَالَ ‏{‏الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمُ الإِسْلاَمَ دِينًا‏}‏‏.‏ قَالَ عُمَرُ قَدْ عَرَفْنَا ذَلِكَ الْيَوْمَ وَالْمَكَانَ الَّذِي نَزَلَتْ فِيهِ عَلَى النَّبِيِّ صلى الله عليه وسلم وَهُوَ قَائِمٌ بِعَرَفَةَ يَوْمَ جُمُعَةٍ‏.‏', NULL, 'Narrated ''Umar bin Al-Khattab: Once a Jew said to me, "O the chief of believers! There is a verse in your Holy Book Which is read by all of you (Muslims), and had it been revealed to us, we would have taken that day (on which it was revealed as a day of celebration." ''Umar bin Al-Khattab asked, "Which is that verse?" The Jew replied, "This day I have perfected your religion For you, completed My favor upon you, And have chosen for you Islam as your religion." (5:3) ''Umar replied,"No doubt, we know when and where this verse was revealed to the Prophet. It was Friday and the Prophet (ﷺ) was standing at ''Arafat (i.e. the Day of Hajj)"', 'Narrated ''Umar bin Al-Khattab', NULL, 'https://sunnah.com/bukhari:45', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 46, 'حَدَّثَنَا إِسْمَاعِيلُ، قَالَ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ، عَنْ عَمِّهِ أَبِي سُهَيْلِ بْنِ مَالِكٍ، عَنْ أَبِيهِ، أَنَّهُ سَمِعَ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ، يَقُولُ جَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صلى الله عليه وسلم مِنْ أَهْلِ نَجْدٍ، ثَائِرُ الرَّأْسِ، يُسْمَعُ دَوِيُّ صَوْتِهِ، وَلاَ يُفْقَهُ مَا يَقُولُ حَتَّى دَنَا، فَإِذَا هُوَ يَسْأَلُ عَنِ الإِسْلاَمِ فَقَالَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ‏"‏ خَمْسُ صَلَوَاتٍ فِي الْيَوْمِ وَاللَّيْلَةِ ‏"‏‏.‏ فَقَالَ هَلْ عَلَىَّ غَيْرُهَا قَالَ ‏"‏ لاَ، إِلاَّ أَنْ تَطَوَّعَ ‏"‏‏.‏ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ وَصِيَامُ رَمَضَانَ ‏"‏‏.‏ قَالَ هَلْ عَلَىَّ غَيْرُهُ قَالَ ‏"‏ لاَ، إِلاَّ أَنْ تَطَوَّعَ ‏"‏‏.‏ قَالَ وَذَكَرَ لَهُ رَسُولُ اللَّهِ صلى الله عليه وسلم الزَّكَاةَ‏.‏ قَالَ هَلْ عَلَىَّ غَيْرُهَا قَالَ ‏"‏ لاَ، إِلاَّ أَنْ تَطَوَّعَ ‏"‏‏.‏ قَالَ فَأَدْبَرَ الرَّجُلُ وَهُوَ يَقُولُ وَاللَّهِ لاَ أَزِيدُ عَلَى هَذَا وَلاَ أَنْقُصُ‏.‏ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَفْلَحَ إِنْ صَدَقَ ‏"‏‏.‏', NULL, 'Narrated Talha bin ''Ubaidullah: A man from Najd with unkempt hair came to Allah''s Messenger (ﷺ) and we heard his loud voice but could not understand what he was saying, till he came near and then we came to know that he was asking about Islam. Allah''s Messenger (ﷺ) said, "You have to offer prayers perfectly five times in a day and night (24 hours)." The man asked, "Is there any more (praying)?" Allah''s Messenger (ﷺ) replied, "No, but if you want to offer the Nawafil prayers (you can)." Allah''s Messenger (ﷺ) further said to him: "You have to observe fasts during the month of Ramadan." The man asked, "Is there any more fasting?" Allah''s Messenger (ﷺ) replied, "No, but if you want to observe the Nawafil fasts (you can.)" Then Allah''s Messenger (ﷺ) further said to him, "You have to pay the Zakat (obligatory charity)." The man asked, "Is there any thing other than the Zakat for me to pay?" Allah''s Messenger (ﷺ) replied, "No, unless you want to give alms of your own." And then that man retreated saying, "By Allah! I will neither do less nor more than this." Allah''s Messenger (ﷺ) said, "If what he said is true, then he will be successful (i.e. he will be granted Paradise)."', 'Narrated Talha bin ''Ubaidullah', NULL, 'https://sunnah.com/bukhari:46', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 47, '"‏ مَنِ اتَّبَعَ جَنَازَةَ مُسْلِمٍ إِيمَانًا وَاحْتِسَابًا، وَكَانَ مَعَهُ حَتَّى يُصَلَّى عَلَيْهَا، وَيَفْرُغَ مِنْ دَفْنِهَا، فَإِنَّهُ يَرْجِعُ مِنَ الأَجْرِ بِقِيرَاطَيْنِ، كُلُّ قِيرَاطٍ مِثْلُ أُحُدٍ، وَمَنْ صَلَّى عَلَيْهَا ثُمَّ رَجَعَ قَبْلَ أَنْ تُدْفَنَ فَإِنَّهُ يَرْجِعُ بِقِيرَاطٍ ‏"', NULL, 'Narrated Abu Huraira: Allah''s Messenger (ﷺ) said, "(A believer) who accompanies the funeral procession of a Muslim out of sincere faith and hoping to attain Allah''s reward and remains with it till the funeral prayer is offered and the burial ceremonies are over, he will return with a reward of two Qirats. Each Qirat is like the size of the (Mount) Uhud. He who offers the funeral prayer only and returns before the burial, will return with the reward of one Qirat only."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:47', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 48, '"‏ سِبَابُ الْمُسْلِمِ فُسُوقٌ، وَقِتَالُهُ كُفْرٌ ‏"', NULL, 'Narrated ''Abdullah: The Prophet (ﷺ) said, "Abusing a Muslim is Fusuq (an evil doing) and killing him is Kufr (disbelief)."', 'Narrated ''Abdullah', NULL, 'https://sunnah.com/bukhari:48', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 49, '"‏ إِنِّي خَرَجْتُ لأُخْبِرَكُمْ بِلَيْلَةِ الْقَدْرِ، وَإِنَّهُ تَلاَحَى فُلاَنٌ وَفُلاَنٌ فَرُفِعَتْ وَعَسَى أَنْ يَكُونَ خَيْرًا لَكُمُ الْتَمِسُوهَا فِي السَّبْعِ وَالتِّسْعِ وَالْخَمْسِ ‏"', NULL, 'Narrated ''Ubada bin As-Samit:"Allah''s Messenger (ﷺ) went out to inform the people about the (date of the) night of decree (Al-Qadr) but there happened a quarrel between two Muslim men. The Prophet (ﷺ) said, "I came out to inform you about (the date of) the night of Al-Qadr, but as so and so and so and so quarrelled, its knowledge was taken away (I forgot it) and maybe it was better for you. Now look for it in the 7th, the 9th and the 5th (of the last 10 nights of the month of Ramadan)."', 'Narrated ''Ubada bin As-Samit', NULL, 'https://sunnah.com/bukhari:49', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 50, 'حَدَّثَنَا مُسَدَّدٌ، قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ، أَخْبَرَنَا أَبُو حَيَّانَ التَّيْمِيُّ، عَنْ أَبِي زُرْعَةَ، عَنْ أَبِي هُرَيْرَةَ، قَالَ كَانَ النَّبِيُّ صلى الله عليه وسلم بَارِزًا يَوْمًا لِلنَّاسِ، فَأَتَاهُ جِبْرِيلُ فَقَالَ مَا الإِيمَانُ قَالَ ‏"‏ الإِيمَانُ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلاَئِكَتِهِ وَبِلِقَائِهِ وَرُسُلِهِ، وَتُؤْمِنَ بِالْبَعْثِ ‏"‏‏.‏ قَالَ مَا الإِسْلاَمُ قَالَ ‏"‏ الإِسْلاَمُ أَنْ تَعْبُدَ اللَّهَ وَلاَ تُشْرِكَ بِهِ، وَتُقِيمَ الصَّلاَةَ، وَتُؤَدِّيَ الزَّكَاةَ الْمَفْرُوضَةَ، وَتَصُومَ رَمَضَانَ ‏"‏‏.‏ قَالَ مَا الإِحْسَانُ قَالَ ‏"‏ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ، فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ ‏"‏‏.‏ قَالَ مَتَى السَّاعَةُ قَالَ ‏"‏ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنَ السَّائِلِ، وَسَأُخْبِرُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتِ الأَمَةُ رَبَّهَا، وَإِذَا تَطَاوَلَ رُعَاةُ الإِبِلِ الْبُهْمُ فِي الْبُنْيَانِ، فِي خَمْسٍ لاَ يَعْلَمُهُنَّ إِلاَّ اللَّهُ ‏"‏‏.‏ ثُمَّ تَلاَ النَّبِيُّ صلى الله عليه وسلم ‏{‏إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ‏}‏ الآيَةَ‏.‏ ثُمَّ أَدْبَرَ فَقَالَ ‏"‏ رُدُّوهُ ‏"‏‏.‏ فَلَمْ يَرَوْا شَيْئًا‏.‏ فَقَالَ ‏"‏ هَذَا جِبْرِيلُ جَاءَ يُعَلِّمُ النَّاسَ دِينَهُمْ ‏"‏‏.‏ قَالَ أَبُو عَبْدِ اللَّهِ جَعَلَ ذَلِكَ كُلَّهُ مِنَ الإِيمَانِ‏.‏', NULL, 'Narrated Abu Huraira: One day while the Prophet (ﷺ) was sitting in the company of some people, (The angel) Gabriel came and asked, "What is faith?" Allah''s Messenger (ﷺ) replied, ''Faith is to believe in Allah, His angels, (the) meeting with Him, His Apostles, and to believe in Resurrection." Then he further asked, "What is Islam?" Allah''s Messenger (ﷺ) replied, "To worship Allah Alone and none else, to offer prayers perfectly to pay the compulsory charity (Zakat) and to observe fasts during the month of Ramadan." Then he further asked, "What is Ihsan (perfection)?" Allah''s Messenger (ﷺ) replied, "To worship Allah as if you see Him, and if you cannot achieve this state of devotion then you must consider that He is looking at you." Then he further asked, "When will the Hour be established?" Allah''s Messenger (ﷺ) replied, "The answerer has no better knowledge than the questioner. But I will inform you about its portents. 1. When a slave (lady) gives birth to her master. 2. When the shepherds of black camels start boasting and competing with others in the construction of higher buildings. And the Hour is one of five things which nobody knows except Allah. The Prophet (ﷺ) then recited: "Verily, with Allah (Alone) is the knowledge of the Hour--." (31. 34) Then that man (Gabriel) left and the Prophet (ﷺ) asked his companions to call him back, but they could not see him. Then the Prophet (ﷺ) said, "That was Gabriel who came to teach the people their religion." Abu ''Abdullah said: He (the Prophet) considered all that as a part of faith.', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:50', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 51, 'حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ، قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ، عَنْ صَالِحٍ، عَنِ ابْنِ شِهَابٍ، عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ، أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ، أَخْبَرَهُ قَالَ أَخْبَرَنِي أَبُو سُفْيَانَ، أَنَّ هِرَقْلَ، قَالَ لَهُ سَأَلْتُكَ هَلْ يَزِيدُونَ أَمْ يَنْقُصُونَ، فَزَعَمْتَ أَنَّهُمْ يَزِيدُونَ، وَكَذَلِكَ الإِيمَانُ حَتَّى يَتِمَّ‏.‏ وَسَأَلْتُكَ هَلْ يَرْتَدُّ أَحَدٌ سَخْطَةً لِدِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ، فَزَعَمْتَ أَنْ لاَ، وَكَذَلِكَ الإِيمَانُ حِينَ تُخَالِطُ بَشَاشَتُهُ الْقُلُوبَ، لاَ يَسْخَطُهُ أَحَدٌ‏.‏', NULL, 'Narrated ''Abdullah bin ''Abbas: I was informed by Abu Sufyan that Heraclius said to him, "I asked you whether they (followers of Muhammad) were increasing or decreasing. You replied that they were increasing. And in fact, this is the way of true Faith till it is complete in all respects. I further asked you whether there was anybody, who, after embracing his (the Prophets) religion (Islam) became displeased and discarded it. You replied in the negative, and in fact, this is (a sign of) true faith. When its delight enters the heart and mixes with them completely, nobody can be displeased with it."', 'Narrated ''Abdullah bin ''Abbas', NULL, 'https://sunnah.com/bukhari:51', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 52, '"‏ الْحَلاَلُ بَيِّنٌ وَالْحَرَامُ بَيِّنٌ، وَبَيْنَهُمَا مُشَبَّهَاتٌ لاَ يَعْلَمُهَا كَثِيرٌ مِنَ النَّاسِ، فَمَنِ اتَّقَى الْمُشَبَّهَاتِ اسْتَبْرَأَ لِدِيِنِهِ وَعِرْضِهِ، وَمَنْ وَقَعَ فِي الشُّبُهَاتِ كَرَاعٍ يَرْعَى حَوْلَ الْحِمَى، يُوشِكُ أَنْ يُوَاقِعَهُ‏.‏ أَلاَ وَإِنَّ لِكُلِّ مَلِكٍ حِمًى، أَلاَ إِنَّ حِمَى اللَّهِ فِي أَرْضِهِ مَحَارِمُهُ، أَلاَ وَإِنَّ فِي الْجَسَدِ مُضْغَةً إِذَا صَلَحَتْ صَلَحَ الْجَسَدُ كُلُّهُ، وَإِذَا فَسَدَتْ فَسَدَ الْجَسَدُ كُلُّهُ‏.‏ أَلاَ وَهِيَ الْقَلْبُ ‏"', NULL, 'Narrated An-Nu''man bin Bashir: I heard Allah''s Messenger (ﷺ) saying, ''Both legal and illegal things are evident but in between them there are doubtful (suspicious) things and most of the people have no knowledge about them. So whoever saves himself from these suspicious things saves his religion and his honor. And whoever indulges in these suspicious things is like a shepherd who grazes (his animals) near the Hima (private pasture) of someone else and at any moment he is liable to get in it. (O people!) Beware! Every king has a Hima and the Hima of Allah on the earth is His illegal (forbidden) things. Beware! There is a piece of flesh in the body if it becomes good (reformed) the whole body becomes good but if it gets spoilt the whole body gets spoilt and that is the heart.', 'Narrated An-Nu''man bin Bashir', NULL, 'https://sunnah.com/bukhari:52', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 53, 'حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ، قَالَ أَخْبَرَنَا شُعْبَةُ، عَنْ أَبِي جَمْرَةَ، قَالَ كُنْتُ أَقْعُدُ مَعَ ابْنِ عَبَّاسٍ، يُجْلِسُنِي عَلَى سَرِيرِهِ فَقَالَ أَقِمْ عِنْدِي حَتَّى أَجْعَلَ لَكَ سَهْمًا مِنْ مَالِي، فَأَقَمْتُ مَعَهُ شَهْرَيْنِ، ثُمَّ قَالَ إِنَّ وَفْدَ عَبْدِ الْقَيْسِ لَمَّا أَتَوُا النَّبِيَّ صلى الله عليه وسلم قَالَ ‏"‏ مَنِ الْقَوْمُ أَوْ مَنِ الْوَفْدُ ‏"‏‏.‏ قَالُوا رَبِيعَةُ‏.‏ قَالَ ‏"‏ مَرْحَبًا بِالْقَوْمِ ـ أَوْ بِالْوَفْدِ ـ غَيْرَ خَزَايَا وَلاَ نَدَامَى ‏"‏‏.‏ فَقَالُوا يَا رَسُولَ اللَّهِ، إِنَّا لاَ نَسْتَطِيعُ أَنْ نَأْتِيَكَ إِلاَّ فِي شَهْرِ الْحَرَامِ، وَبَيْنَنَا وَبَيْنَكَ هَذَا الْحَىُّ مِنْ كُفَّارِ مُضَرَ، فَمُرْنَا بِأَمْرٍ فَصْلٍ، نُخْبِرْ بِهِ مَنْ وَرَاءَنَا، وَنَدْخُلْ بِهِ الْجَنَّةَ‏.‏ وَسَأَلُوهُ عَنِ الأَشْرِبَةِ‏.‏ فَأَمَرَهُمْ بِأَرْبَعٍ، وَنَهَاهُمْ عَنْ أَرْبَعٍ، أَمَرَهُمْ بِالإِيمَانِ بِاللَّهِ وَحْدَهُ‏.‏ قَالَ ‏"‏ أَتَدْرُونَ مَا الإِيمَانُ بِاللَّهِ وَحْدَهُ ‏"‏‏.‏ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ‏.‏ قَالَ ‏"‏ شَهَادَةُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ، وَإِقَامُ الصَّلاَةِ، وَإِيتَاءُ الزَّكَاةِ، وَصِيَامُ رَمَضَانَ، وَأَنْ تُعْطُوا مِنَ الْمَغْنَمِ الْخُمُسَ ‏"‏‏.‏ وَنَهَاهُمْ عَنْ أَرْبَعٍ عَنِ الْحَنْتَمِ وَالدُّبَّاءِ وَالنَّقِيرِ وَالْمُزَفَّتِ‏.‏ وَرُبَّمَا قَالَ الْمُقَيَّرِ‏.‏ وَقَالَ ‏"‏ احْفَظُوهُنَّ وَأَخْبِرُوا بِهِنَّ مَنْ وَرَاءَكُمْ ‏"‏‏.‏', NULL, 'Narrated Abu Jamra: I used to sit with Ibn ''Abbas and he made me sit on his sitting place. He requested me to stay with him in order that he might give me a share from his property. So I stayed with him for two months. Once he told (me) that when the delegation of the tribe of ''Abdul Qais came to the Prophet, the Prophet (ﷺ) asked them, "Who are the people (i.e. you)? (Or) who are the delegate?" They replied, "We are from the tribe of Rabi''a." Then the Prophet (ﷺ) said to them, "Welcome! O people (or O delegation of ''Abdul Qais)! Neither will you have disgrace nor will you regret." They said, "O Allah''s Messenger (ﷺ)! We cannot come to you except in the sacred month and there is the infidel tribe of Mudar intervening between you and us. So please order us to do something good (religious deeds) so that we may inform our people whom we have left behind (at home), and that we may enter Paradise (by acting on them)." Then they asked about drinks (what is legal and what is illegal). The Prophet (ﷺ) ordered them to do four things and forbade them from four things. He ordered them to believe in Allah Alone and asked them, "Do you know what is meant by believing in Allah Alone?" They replied, "Allah and His Apostle know better." Thereupon the Prophet (ﷺ) said, "It means: 1. To testify that none has the right to be worshipped but Allah and Muhammad is Allah''s Messenger (ﷺ). 2. To offer prayers perfectly 3. To pay the Zakat (obligatory charity) 4. To observe fast during the month of Ramadan. 5. And to pay Al-Khumus (one fifth of the booty to be given in Allah''s Cause). Then he forbade them four things, namely, Hantam, Dubba,'' Naqir Ann Muzaffat or Muqaiyar; (These were the names of pots in which Alcoholic drinks were prepared) (The Prophet (ﷺ) mentioned the container of wine and he meant the wine itself). The Prophet (ﷺ) further said (to them): "Memorize them (these instructions) and convey them to the people whom you have left behind."', 'Narrated Abu Jamra', NULL, 'https://sunnah.com/bukhari:53', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 54, '"‏ الأَعْمَالُ بِالنِّيَّةِ، وَلِكُلِّ امْرِئٍ مَا نَوَى، فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ، فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ، وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا، أَوِ امْرَأَةٍ يَتَزَوَّجُهَا، فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ ‏"', NULL, 'Narrated ''Umar bin Al-Khattab: Allah''s Messenger (ﷺ) said, "The reward of deeds depends upon the intention and every person will get the reward according to what he has intended. So whoever emigrated for Allah and His Apostle, then his emigration was for Allah and His Apostle. And whoever emigrated for worldly benefits or for a woman to marry, his emigration was for what he emigrated for."', 'Narrated ''Umar bin Al-Khattab', NULL, 'https://sunnah.com/bukhari:54', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 55, '"‏ إِذَا أَنْفَقَ الرَّجُلُ عَلَى أَهْلِهِ يَحْتَسِبُهَا فَهُوَ لَهُ صَدَقَةٌ ‏"', NULL, 'Narrated Abu Mas''ud: The Prophet (ﷺ) said, "If a man spends on his family (with the intention of having a reward from Allah) sincerely for Allah''s sake then it is a (kind of) alms-giving in reward for him.', 'Narrated Abu Mas''ud', NULL, 'https://sunnah.com/bukhari:55', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 56, '"إِنَّكَ لَنْ تُنْفِقَ نَفَقَةً تَبْتَغِي بِهَا وَجْهَ اللَّهِ إِلَّا أُجِرْتَ عَلَيْهَا حَتَّى مَا تَجْعَلُ فِي فَمِ امْرَأَتِكَ"', NULL, 'Narrated Sa''d bin Abi Waqqas: Allah''s Messenger (ﷺ) said, "You will be rewarded for whatever you spend for Allah''s sake even if it were a morsel which you put in your wife''s mouth."', 'Narrated Sa''d bin Abi Waqqas', NULL, 'https://sunnah.com/bukhari:56', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 57, 'حَدَّثَنَا مُسَدَّدٌ، قَالَ حَدَّثَنَا يَحْيَى، عَنْ إِسْمَاعِيلَ، قَالَ حَدَّثَنِي قَيْسُ بْنُ أَبِي حَازِمٍ، عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ، قَالَ بَايَعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم عَلَى إِقَامِ الصَّلاَةِ، وَإِيتَاءِ الزَّكَاةِ، وَالنُّصْحِ لِكُلِّ مُسْلِمٍ‏.‏', NULL, 'Narrated Jarir bin Abdullah: I gave the pledge of allegiance to Allah''s Messenger (ﷺ) for the following: 1. offer prayers perfectly 2. pay the Zakat (obligatory charity) 3. and be sincere and true to every Muslim.', 'Narrated Jarir bin Abdullah', NULL, 'https://sunnah.com/bukhari:57', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Belief', 58, 'حَدَّثَنَا أَبُو النُّعْمَانِ، قَالَ حَدَّثَنَا أَبُو عَوَانَةَ، عَنْ زِيَادِ بْنِ عِلاَقَةَ، قَالَ سَمِعْتُ جَرِيرَ بْنَ عَبْدِ اللَّهِ، يَقُولُ يَوْمَ مَاتَ الْمُغِيرَةُ بْنُ شُعْبَةَ قَامَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ عَلَيْكُمْ بِاتِّقَاءِ اللَّهِ وَحْدَهُ لاَ شَرِيكَ لَهُ، وَالْوَقَارِ وَالسَّكِينَةِ حَتَّى يَأْتِيَكُمْ أَمِيرٌ، فَإِنَّمَا يَأْتِيكُمُ الآنَ، ثُمَّ قَالَ اسْتَعْفُوا لأَمِيرِكُمْ، فَإِنَّهُ كَانَ يُحِبُّ الْعَفْوَ‏.‏ ثُمَّ قَالَ أَمَّا بَعْدُ، فَإِنِّي أَتَيْتُ النَّبِيَّ صلى الله عليه وسلم قُلْتُ أُبَايِعُكَ عَلَى الإِسْلاَمِ‏.‏ فَشَرَطَ عَلَىَّ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ‏.‏ فَبَايَعْتُهُ عَلَى هَذَا، وَرَبِّ هَذَا الْمَسْجِدِ إِنِّي لَنَاصِحٌ لَكُمْ‏.‏ ثُمَّ اسْتَغْفَرَ وَنَزَلَ‏.‏', NULL, 'Narrated Ziyad bin''Ilaqa: I heard Jarir bin ''Abdullah (Praising Allah). On the day when Al-Mughira bin Shu''ba died, he (Jarir) got up (on the pulpit) and thanked and praised Allah and said, "Be afraid of Allah alone Who has none along with Him to be worshipped.(You should) be calm and quiet till the (new) chief comes to you and he will come to you soon. Ask Allah''s forgiveness for your (late) chief because he himself loved to forgive others." Jarir added, "Amma badu (now then), I went to the Prophet and said, ''I give my pledge of allegiance to you for Islam." The Prophet (ﷺ) conditioned (my pledge) for me to be sincere and true to every Muslim so I gave my pledge to him for this. By the Lord of this mosque! I am sincere and true to you (Muslims). Then Jarir asked for Allah''s forgiveness and came down (from the pulpit).', 'Narrated Ziyad bin''Ilaqa', NULL, 'https://sunnah.com/bukhari:58', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 59, 'حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ، قَالَ حَدَّثَنَا فُلَيْحٌ، ح وَحَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ، قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُلَيْحٍ، قَالَ حَدَّثَنِي أَبِي قَالَ، حَدَّثَنِي هِلاَلُ بْنُ عَلِيٍّ، عَنْ عَطَاءِ بْنِ يَسَارٍ، عَنْ أَبِي هُرَيْرَةَ، قَالَ بَيْنَمَا النَّبِيُّ صلى الله عليه وسلم فِي مَجْلِسٍ يُحَدِّثُ الْقَوْمَ جَاءَهُ أَعْرَابِيٌّ فَقَالَ مَتَى السَّاعَةُ فَمَضَى رَسُولُ اللَّهِ صلى الله عليه وسلم يُحَدِّثُ، فَقَالَ بَعْضُ الْقَوْمِ سَمِعَ مَا قَالَ، فَكَرِهَ مَا قَالَ، وَقَالَ بَعْضُهُمْ بَلْ لَمْ يَسْمَعْ، حَتَّى إِذَا قَضَى حَدِيثَهُ قَالَ ‏"‏ أَيْنَ ـ أُرَاهُ ـ السَّائِلُ عَنِ السَّاعَةِ ‏"‏‏.‏ قَالَ هَا أَنَا يَا رَسُولَ اللَّهِ‏.‏ قَالَ ‏"‏ فَإِذَا ضُيِّعَتِ الأَمَانَةُ فَانْتَظِرِ السَّاعَةَ ‏"‏‏.‏ قَالَ كَيْفَ إِضَاعَتُهَا قَالَ ‏"‏ إِذَا وُسِّدَ الأَمْرُ إِلَى غَيْرِ أَهْلِهِ فَانْتَظِرِ السَّاعَةَ ‏"‏‏.‏', NULL, 'Narrated Abu Huraira:While the Prophet (ﷺ) was saying something in a gathering, a Bedouin came and asked him, "When would the Hour (Doomsday) take place?" Allah''s Messenger (ﷺ) continued his talk, so some people said that Allah''s Messenger (ﷺ) had heard the question, but did not like what that Bedouin had asked. Some of them said that Allah''s Messenger (ﷺ) had not heard it. When the Prophet (ﷺ) finished his speech, he said, "Where is the questioner, who inquired about the Hour (Doomsday)?" The Bedouin said, "I am here, O Allah''s Apostle ." Then the Prophet (ﷺ) said, "When honesty is lost, then wait for the Hour (Doomsday)." The Bedouin said, "How will that be lost?" The Prophet (ﷺ) said, "When the power or authority comes in the hands of unfit persons, then wait for the Hour (Doomsday.)"', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:59', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 60, '"‏ وَيْلٌ لِلأَعْقَابِ مِنَ النَّارِ ‏"', NULL, 'Narrated `Abdullah bin `Amr:Once the Prophet (ﷺ) remained behind us in a journey. He joined us while we were performing ablution for the prayer which was over-due. We were just passing wet hands over our feet (and not washing them properly) so the Prophet (ﷺ) addressed us in a loud voice and said twice or thrice: "Save your heels from the fire."', 'Narrated `Abdullah bin `Amr', NULL, 'https://sunnah.com/bukhari:60', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 61, 'حَدَّثَنَا قُتَيْبَةُ، حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ، عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ، عَنِ ابْنِ عُمَرَ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ إِنَّ مِنَ الشَّجَرِ شَجَرَةً لاَ يَسْقُطُ وَرَقُهَا، وَإِنَّهَا مَثَلُ الْمُسْلِمِ، فَحَدِّثُونِي مَا هِيَ ‏"‏‏.‏ فَوَقَعَ النَّاسُ فِي شَجَرِ الْبَوَادِي‏.‏ قَالَ عَبْدُ اللَّهِ وَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ، فَاسْتَحْيَيْتُ ثُمَّ قَالُوا حَدِّثْنَا مَا هِيَ يَا رَسُولَ اللَّهِ قَالَ ‏"‏ هِيَ النَّخْلَةُ ‏"‏‏.‏', NULL, 'Narrated Ibn `Umar:Allah''s Messenger (ﷺ) said, "Amongst the trees, there is a tree, the leaves of which do not fall and is like a Muslim. Tell me the name of that tree." Everybody started thinking about the trees of the desert areas. And I thought of the date-palm tree but felt shy to answer the others then asked, "What is that tree, O Allah''s Messenger (ﷺ) ?" He replied, "It is the date-palm tree."', 'Narrated Ibn `Umar', NULL, 'https://sunnah.com/bukhari:61', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 62, 'حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ، حَدَّثَنَا سُلَيْمَانُ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ، عَنِ ابْنِ عُمَرَ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ إِنَّ مِنَ الشَّجَرِ شَجَرَةً لاَ يَسْقُطُ وَرَقُهَا، وَإِنَّهَا مَثَلُ الْمُسْلِمِ، حَدِّثُونِي مَا هِيَ ‏"‏‏.‏ قَالَ فَوَقَعَ النَّاسُ فِي شَجَرِ الْبَوَادِي‏.‏ قَالَ عَبْدُ اللَّهِ فَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ، ثُمَّ قَالُوا حَدِّثْنَا مَا هِيَ يَا رَسُولَ اللَّهِ قَالَ ‏"‏ هِيَ النَّخْلَةُ ‏"‏‏.‏', NULL, 'Narrated Ibn `Umar:The Prophet (ﷺ) said, "Amongst the trees, there is a tree, the leaves of which do not fall and is like a Muslim. Tell me the name of that tree." Everybody started thinking about the trees of the desert areas. And I thought of the date-palm tree. The others then asked, "Please inform us what is that tree, O Allah''s Messenger (ﷺ)?" He replied, "It is the date-palm tree."', 'Narrated Ibn `Umar', NULL, 'https://sunnah.com/bukhari:62', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 63, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ، قَالَ حَدَّثَنَا اللَّيْثُ، عَنْ سَعِيدٍ ـ هُوَ الْمَقْبُرِيُّ ـ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ، أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ، يَقُولُ بَيْنَمَا نَحْنُ جُلُوسٌ مَعَ النَّبِيِّ صلى الله عليه وسلم فِي الْمَسْجِدِ، دَخَلَ رَجُلٌ عَلَى جَمَلٍ فَأَنَاخَهُ فِي الْمَسْجِدِ، ثُمَّ عَقَلَهُ، ثُمَّ قَالَ لَهُمْ أَيُّكُمْ مُحَمَّدٌ وَالنَّبِيُّ صلى الله عليه وسلم مُتَّكِئٌ بَيْنَ ظَهْرَانَيْهِمْ‏.‏ فَقُلْنَا هَذَا الرَّجُلُ الأَبْيَضُ الْمُتَّكِئُ‏.‏ فَقَالَ لَهُ الرَّجُلُ ابْنَ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ النَّبِيُّ صلى الله عليه وسلم ‏"‏ قَدْ أَجَبْتُكَ ‏"‏‏.‏ فَقَالَ الرَّجُلُ لِلنَّبِيِّ صلى الله عليه وسلم إِنِّي سَائِلُكَ فَمُشَدِّدٌ عَلَيْكَ فِي الْمَسْأَلَةِ فَلاَ تَجِدْ عَلَىَّ فِي نَفْسِكَ‏.‏ فَقَالَ ‏"‏ سَلْ عَمَّا بَدَا لَكَ ‏"‏‏.‏ فَقَالَ أَسْأَلُكَ بِرَبِّكَ وَرَبِّ مَنْ قَبْلَكَ، آللَّهُ أَرْسَلَكَ إِلَى النَّاسِ كُلِّهِمْ فَقَالَ ‏"‏ اللَّهُمَّ نَعَمْ ‏"‏‏.‏ قَالَ أَنْشُدُكَ بِاللَّهِ، آللَّهُ أَمَرَكَ أَنْ نُصَلِّيَ الصَّلَوَاتِ الْخَمْسَ فِي الْيَوْمِ وَاللَّيْلَةِ قَالَ ‏"‏ اللَّهُمَّ نَعَمْ ‏"‏‏.‏ قَالَ أَنْشُدُكَ بِاللَّهِ، آللَّهُ أَمَرَكَ أَنْ نَصُومَ هَذَا الشَّهْرَ مِنَ السَّنَةِ قَالَ ‏"‏ اللَّهُمَّ نَعَمْ ‏"‏‏.‏ قَالَ أَنْشُدُكَ بِاللَّهِ، آللَّهُ أَمَرَكَ أَنْ تَأْخُذَ هَذِهِ الصَّدَقَةَ مِنْ أَغْنِيَائِنَا فَتَقْسِمَهَا عَلَى فُقَرَائِنَا فَقَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ اللَّهُمَّ نَعَمْ ‏"‏‏.‏ فَقَالَ الرَّجُلُ آمَنْتُ بِمَا جِئْتَ بِهِ، وَأَنَا رَسُولُ مَنْ وَرَائِي مِنْ قَوْمِي، وَأَنَا ضِمَامُ بْنُ ثَعْلَبَةَ أَخُو بَنِي سَعْدِ بْنِ بَكْرٍ‏.‏ رَوَاهُ مُوسَى وَعَلِيُّ بْنُ عَبْدِ الْحَمِيدِ عَنْ سُلَيْمَانَ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنِ النَّبِيِّ صلى الله عليه وسلم بِهَذَا‏.‏', NULL, 'Narrated Anas bin Malik:While we were sitting with the Prophet (ﷺ) in the mosque, a man came riding on a camel. He made his camel kneel down in the mosque, tied its foreleg and then said: "Who amongst you is Muhammad?" At that time the Prophet (ﷺ) was sitting amongst us (his companions) leaning on his arm. We replied, "This white man reclining on his arm." The man then addressed him, "O Son of `Abdul Muttalib." The Prophet (ﷺ) said, "I am here to answer your questions." The man said to the Prophet, "I want to ask you something and will be hard in questioning. So do not get angry." The Prophet (ﷺ) said, "Ask whatever you want." The man said, "I ask you by your Lord, and the Lord of those who were before you, has Allah sent you as an Apostle to all the mankind?" The Prophet (ﷺ) replied, "By Allah, yes." The man further said, "I ask you by Allah. Has Allah ordered you to offer five prayers in a day and night (24 hours).? He replied, "By Allah, Yes." The man further said, "I ask you by Allah! Has Allah ordered you to observe fasts during this month of the year (i.e. Ramadan)?" He replied, "By Allah, Yes." The man further said, "I ask you by Allah. Has Allah ordered you to take Zakat (obligatory charity) from our rich people and distribute it amongst our poor people?" The Prophet (ﷺ) replied, "By Allah, yes." Thereupon that man said, "I have believed in all that with which you have been sent, and I have been sent by my people as a messenger, and I am Dimam bin Tha`laba from the brothers of Bani Sa`d bin Bakr."', 'Narrated Anas bin Malik', NULL, 'https://sunnah.com/bukhari:63', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 64, 'حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ، قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ، عَنْ صَالِحٍ، عَنِ ابْنِ شِهَابٍ، عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ، أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ، أَخْبَرَهُ أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم بَعَثَ بِكِتَابِهِ رَجُلاً، وَأَمَرَهُ أَنْ يَدْفَعَهُ إِلَى عَظِيمِ الْبَحْرَيْنِ، فَدَفَعَهُ عَظِيمُ الْبَحْرَيْنِ إِلَى كِسْرَى، فَلَمَّا قَرَأَهُ مَزَّقَهُ‏.‏ فَحَسِبْتُ أَنَّ ابْنَ الْمُسَيَّبِ قَالَ فَدَعَا عَلَيْهِمْ رَسُولُ اللَّهِ صلى الله عليه وسلم أَنْ يُمَزَّقُوا كُلَّ مُمَزَّقٍ‏.‏', NULL, 'Narrated `Abdullah bin `Abbas:Once Allah''s Messenger (ﷺ) gave a letter to a person and ordered him to go and deliver it to the Governor of Bahrain. (He did so) and the Governor of Bahrain sent it to Chousroes, who read that letter and then tore it to pieces. (The sub-narrator (Ibn Shihab) thinks that Ibn Al-Musaiyab said that Allah''s Messenger (ﷺ) invoked Allah against them (saying), "May Allah tear them into pieces, and disperse them all totally.)"', 'Narrated `Abdullah bin `Abbas', NULL, 'https://sunnah.com/bukhari:64', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 65, 'حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ، أَخْبَرَنَا عَبْدُ اللَّهِ، قَالَ أَخْبَرَنَا شُعْبَةُ، عَنْ قَتَادَةَ، عَنْ أَنَسِ بْنِ مَالِكٍ، قَالَ كَتَبَ النَّبِيُّ صلى الله عليه وسلم كِتَابًا ـ أَوْ أَرَادَ أَنْ يَكْتُبَ ـ فَقِيلَ لَهُ إِنَّهُمْ لاَ يَقْرَءُونَ كِتَابًا إِلاَّ مَخْتُومًا‏.‏ فَاتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ نَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ‏.‏ كَأَنِّي أَنْظُرُ إِلَى بَيَاضِهِ فِي يَدِهِ‏.‏ فَقُلْتُ لِقَتَادَةَ مَنْ قَالَ نَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ قَالَ أَنَسٌ‏.‏', NULL, 'Narrated Anas bin Malik:Once the Prophet (ﷺ) wrote a letter or had an idea of writing a letter. The Prophet (ﷺ) was told that they (rulers) would not read letters unless they were sealed. So the Prophet (ﷺ) got a silver ring made with "Muhammad Allah''s Messenger (ﷺ)" engraved on it. As if I were just observing its white glitter in the hand of the Prophet.', 'Narrated Anas bin Malik', NULL, 'https://sunnah.com/bukhari:65', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 66, '"‏ أَلاَ أُخْبِرُكُمْ عَنِ النَّفَرِ الثَّلاَثَةِ أَمَّا أَحَدُهُمْ فَأَوَى إِلَى اللَّهِ، فَآوَاهُ اللَّهُ، وَأَمَّا الآخَرُ فَاسْتَحْيَا، فَاسْتَحْيَا اللَّهُ مِنْهُ، وَأَمَّا الآخَرُ فَأَعْرَضَ، فَأَعْرَضَ اللَّهُ عَنْهُ ‏"', NULL, 'Narrated Abu Waqid Al-Laithi:While Allah''s Messenger (ﷺ) was sitting in the mosque with some people, three men came. Two of them came in front of Allah''s Messenger (ﷺ) and the third one went away. The two persons kept on standing before Allah''s Messenger (ﷺ) for a while and then one of them found a place in the circle and sat there while the other sat behind the gathering, and the third one went away. When Allah''s Messenger (ﷺ) finished his preaching, he said, "Shall I tell you about these three persons? One of them betook himself to Allah, so Allah took him into His grace and mercy and accommodated him, the second felt shy from Allah, so Allah sheltered Him in His mercy (and did not punish him), while the third turned his face from Allah and went away, so Allah turned His face from him likewise. "', 'Narrated Abu Waqid Al-Laithi', NULL, 'https://sunnah.com/bukhari:66', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 67, 'حَدَّثَنَا مُسَدَّدٌ، قَالَ حَدَّثَنَا بِشْرٌ، قَالَ حَدَّثَنَا ابْنُ عَوْنٍ، عَنِ ابْنِ سِيرِينَ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ، عَنْ أَبِيهِ، ذَكَرَ النَّبِيَّ صلى الله عليه وسلم قَعَدَ عَلَى بَعِيرِهِ، وَأَمْسَكَ إِنْسَانٌ بِخِطَامِهِ ـ أَوْ بِزِمَامِهِ ـ قَالَ ‏"‏ أَىُّ يَوْمٍ هَذَا ‏"‏‏.‏ فَسَكَتْنَا حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ سِوَى اسْمِهِ‏.‏ قَالَ ‏"‏ أَلَيْسَ يَوْمَ النَّحْرِ ‏"‏‏.‏ قُلْنَا بَلَى‏.‏ قَالَ ‏"‏ فَأَىُّ شَهْرٍ هَذَا ‏"‏‏.‏ فَسَكَتْنَا حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ‏.‏ فَقَالَ ‏"‏ أَلَيْسَ بِذِي الْحِجَّةِ ‏"‏‏.‏ قُلْنَا بَلَى‏.‏ قَالَ ‏"‏ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ بَيْنَكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا، فِي شَهْرِكُمْ هَذَا، فِي بَلَدِكُمْ هَذَا‏.‏ لِيُبَلِّغِ الشَّاهِدُ الْغَائِبَ، فَإِنَّ الشَّاهِدَ عَسَى أَنْ يُبَلِّغَ مَنْ هُوَ أَوْعَى لَهُ مِنْهُ ‏"‏‏.‏', NULL, 'Narrated `Abdur-Rahman bin Abi Bakra''s father:Once the Prophet (ﷺ) was riding his camel and a man was holding its rein. The Prophet (ﷺ) asked, "What is the day today?" We kept quiet, thinking that he might give that day another name. He said, "Isn''t it the day of Nahr (slaughtering of the animals of sacrifice)" We replied, "Yes." He further asked, "Which month is this?" We again kept quiet, thinking that he might give it another name. Then he said, "Isn''t it the month of Dhul-Hijja?" We replied, "Yes." He said, "Verily! Your blood, property and honor are sacred to one another (i.e. Muslims) like the sanctity of this day of yours, in this month of yours and in this city of yours. It is incumbent upon those who are present to inform those who are absent because those who are absent might comprehend (what I have said) better than the present audience."', 'Narrated `Abdur-Rahman bin Abi Bakra''s father', NULL, 'https://sunnah.com/bukhari:67', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 68, 'حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ، قَالَ أَخْبَرَنَا سُفْيَانُ، عَنِ الأَعْمَشِ، عَنْ أَبِي وَائِلٍ، عَنِ ابْنِ مَسْعُودٍ، قَالَ كَانَ النَّبِيُّ صلى الله عليه وسلم يَتَخَوَّلُنَا بِالْمَوْعِظَةِ فِي الأَيَّامِ، كَرَاهَةَ السَّآمَةِ عَلَيْنَا‏.‏', NULL, 'Narrated Ibn Mas`ud:The Prophet (ﷺ) used to take care of us in preaching by selecting a suitable time, so that we might not get bored. (He abstained from pestering us with sermons and knowledge all the time).', 'Narrated Ibn Mas`ud', NULL, 'https://sunnah.com/bukhari:68', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 69, '"‏ يَسِّرُوا وَلاَ تُعَسِّرُوا، وَبَشِّرُوا وَلاَ تُنَفِّرُوا ‏"', NULL, 'Narrated Anas bin Malik:The Prophet (ﷺ) said, "Facilitate things to people (concerning religious matters), and do not make it hard for them and give them good tidings and do not make them run away (from Islam).', 'Narrated Anas bin Malik', NULL, 'https://sunnah.com/bukhari:69', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 70, 'حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ، قَالَ حَدَّثَنَا جَرِيرٌ، عَنْ مَنْصُورٍ، عَنْ أَبِي وَائِلٍ، قَالَ كَانَ عَبْدُ اللَّهِ يُذَكِّرُ النَّاسَ فِي كُلِّ خَمِيسٍ، فَقَالَ لَهُ رَجُلٌ يَا أَبَا عَبْدِ الرَّحْمَنِ لَوَدِدْتُ أَنَّكَ ذَكَّرْتَنَا كُلَّ يَوْمٍ‏.‏ قَالَ أَمَا إِنَّهُ يَمْنَعُنِي مِنْ ذَلِكَ أَنِّي أَكْرَهُ أَنْ أُمِلَّكُمْ، وَإِنِّي أَتَخَوَّلُكُمْ بِالْمَوْعِظَةِ كَمَا كَانَ النَّبِيُّ صلى الله عليه وسلم يَتَخَوَّلُنَا بِهَا، مَخَافَةَ السَّآمَةِ عَلَيْنَا‏.‏', NULL, 'Narrated Abu Wail:`Abdullah used to give a religious talk to the people on every Thursday. Once a man said, "O Aba `Abdur-Rahman! (By Allah) I wish if you could preach us daily." He replied, "The only thing which prevents me from doing so, is that I hate to bore you, and no doubt I take care of you in preaching by selecting a suitable time just as the Prophet (ﷺ) used to do with us, for fear of making us bored."', 'Narrated Abu Wail', NULL, 'https://sunnah.com/bukhari:70', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 71, '"‏ مَنْ يُرِدِ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ، وَإِنَّمَا أَنَا قَاسِمٌ وَاللَّهُ يُعْطِي، وَلَنْ تَزَالَ هَذِهِ الأُمَّةُ قَائِمَةً عَلَى أَمْرِ اللَّهِ لاَ يَضُرُّهُمْ مَنْ خَالَفَهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ ‏"', NULL, 'Narrated Muawiya:I heard Allah''s Messenger (ﷺ) saying, "If Allah wants to do good to a person, He makes him comprehend the religion. I am just a distributor, but the grant is from Allah. (And remember) that this nation (true Muslims) will keep on following Allah''s teachings strictly and they will not be harmed by any one going on a different path till Allah''s order (Day of Judgment) is established."', 'Narrated Muawiya', NULL, 'https://sunnah.com/bukhari:71', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 72, 'حَدَّثَنَا عَلِيٌّ، حَدَّثَنَا سُفْيَانُ، قَالَ قَالَ لِي ابْنُ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ، قَالَ صَحِبْتُ ابْنَ عُمَرَ إِلَى الْمَدِينَةِ فَلَمْ أَسْمَعْهُ يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صلى الله عليه وسلم إِلاَّ حَدِيثًا وَاحِدًا، قَالَ كُنَّا عِنْدَ النَّبِيِّ صلى الله عليه وسلم فَأُتِيَ بِجُمَّارٍ فَقَالَ ‏"‏ إِنَّ مِنَ الشَّجَرِ شَجَرَةً مَثَلُهَا كَمَثَلِ الْمُسْلِمِ ‏"‏‏.‏ فَأَرَدْتُ أَنْ أَقُولَ هِيَ النَّخْلَةُ، فَإِذَا أَنَا أَصْغَرُ الْقَوْمِ فَسَكَتُّ، قَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ هِيَ النَّخْلَةُ ‏"‏‏.‏', NULL, 'Narrated Ibn `Umar:We were with the Prophet (ﷺ) and fresh dates of a palm tree were brought to him. On that he said, "Amongst the trees, there is a tree which resembles a Muslim." I wanted to say that it was the datepalm tree but as I was the youngest of all (of them) I kept quiet. And then the Prophet (ﷺ) said, "It is the date-palm tree."', 'Narrated Ibn `Umar', NULL, 'https://sunnah.com/bukhari:72', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 73, '"‏ لاَ حَسَدَ إِلاَّ فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ مَالاً فَسُلِّطَ عَلَى هَلَكَتِهِ فِي الْحَقِّ، وَرَجُلٌ آتَاهُ اللَّهُ الْحِكْمَةَ، فَهْوَ يَقْضِي بِهَا وَيُعَلِّمُهَا ‏"', NULL, 'Narrated `Abdullah bin Mas`ud:The Prophet (ﷺ) said, "Do not wish to be like anyone except in two cases. (The first is) A person, whom Allah has given wealth and he spends it righteously; (the second is) the one whom Allah has given wisdom (the Holy Qur''an) and he acts according to it and teaches it to others." (Fath-al-Bari page 177 Vol. 1)', 'Narrated `Abdullah bin Mas`ud', NULL, 'https://sunnah.com/bukhari:73', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 74, '"‏ بَيْنَمَا مُوسَى فِي مَلإٍ مِنْ بَنِي إِسْرَائِيلَ، جَاءَهُ رَجُلٌ فَقَالَ هَلْ تَعْلَمُ أَحَدًا أَعْلَمَ مِنْكَ قَالَ مُوسَى لاَ‏.‏ فَأَوْحَى اللَّهُ إِلَى مُوسَى بَلَى، عَبْدُنَا خَضِرٌ، فَسَأَلَ مُوسَى السَّبِيلَ إِلَيْهِ، فَجَعَلَ اللَّهُ لَهُ الْحُوتَ آيَةً، وَقِيلَ لَهُ إِذَا فَقَدْتَ الْحُوتَ فَارْجِعْ، فَإِنَّكَ سَتَلْقَاهُ، وَكَانَ يَتَّبِعُ أَثَرَ الْحُوتِ فِي الْبَحْرِ، فَقَالَ لِمُوسَى فَتَاهُ أَرَأَيْتَ إِذْ أَوَيْنَا إِلَى الصَّخْرَةِ فَإِنِّي نَسِيتُ الْحُوتَ، وَمَا أَنْسَانِيهِ إِلاَّ الشَّيْطَانُ أَنْ أَذْكُرَهُ‏.‏ قَالَ ذَلِكَ مَا كُنَّا نَبْغِي، فَارْتَدَّا عَلَى آثَارِهِمَا قَصَصًا، فَوَجَدَا خَضِرًا‏.‏ فَكَانَ مِنْ شَأْنِهِمَا الَّذِي قَصَّ اللَّهُ ـ عَزَّ وَجَلَّ ـ فِي كِتَابِهِ ‏"', NULL, 'Narrated Ibn `Abbas:That he differed with Hur bin Qais bin Hisn Al-Fazari regarding the companion of (the Prophet) Moses. Ibn `Abbas said that he was Al Khadir. Meanwhile, Ubai bin Ka`b passed by them and Ibn `Abbas called him, saying "My friend (Hur) and I have differed regarding Moses'' companion, whom Moses asked the way to meet. Have you heard the Prophet (ﷺ) mentioning something about him? He said, "Yes. I heard Allah''s Messenger (ﷺ) saying, "While Moses was sitting in the company of some Israelites, a man came and asked him. "Do you know anyone who is more learned than you? Moses replied: "No." So Allah sent the Divine Inspiration to Moses: ''Yes, Our slave Khadir (is more learned than you.)'' Moses asked (Allah) how to meet him (Khadir). So Allah made the fish as a sign for him and he was told that when the fish was lost, he should return (to the place where he had lost it) and there he would meet him (Al-Khadir). So Moses went on looking for the sign of the fish in the sea. The servant-boy of Moses said to him: Do you remember when we betook ourselves to the rock, I indeed forgot the fish, none but Satan made me forget to remember it. On that Moses said: ''That is what we have been seeking? (18.64) So they went back retracing their footsteps, and found Khadir. (And) what happened further to them is narrated in the Holy Qur''an by Allah. (18.54 up to 18.82)', 'Narrated Ibn `Abbas', NULL, 'https://sunnah.com/bukhari:74', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 75, '"‏ اللَّهُمَّ عَلِّمْهُ الْكِتَابَ ‏"', NULL, 'Narrated Ibn `Abbas:Once the Prophet (ﷺ) embraced me and said, "O Allah! Bestow on him the knowledge of the Book (Qur''an).', 'Narrated Ibn `Abbas', NULL, 'https://sunnah.com/bukhari:75', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 76, 'حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ، قَالَ حَدَّثَنِي مَالِكٌ، عَنِ ابْنِ شِهَابٍ، عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ، عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ، قَالَ أَقْبَلْتُ رَاكِبًا عَلَى حِمَارٍ أَتَانٍ، وَأَنَا يَوْمَئِذٍ قَدْ نَاهَزْتُ الاِحْتِلاَمَ، وَرَسُولُ اللَّهِ صلى الله عليه وسلم يُصَلِّي بِمِنًى إِلَى غَيْرِ جِدَارٍ، فَمَرَرْتُ بَيْنَ يَدَىْ بَعْضِ الصَّفِّ وَأَرْسَلْتُ الأَتَانَ تَرْتَعُ، فَدَخَلْتُ فِي الصَّفِّ، فَلَمْ يُنْكَرْ ذَلِكَ عَلَىَّ‏.‏', NULL, 'Narrated Ibn `Abbas:Once I came riding a she-ass and had (just) attained the age of puberty. Allah''s Messenger (ﷺ) was offering the prayer at Mina. There was no wall in front of him and I passed in front of some of the row while they were offering their prayers. There I let the she-ass loose to graze and entered the row, and nobody objected to it.', 'Narrated Ibn `Abbas', NULL, 'https://sunnah.com/bukhari:76', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 77, 'حَدَّثَنِي مُحَمَّدُ بْنُ يُوسُفَ، قَالَ حَدَّثَنَا أَبُو مُسْهِرٍ، قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ حَرْبٍ، حَدَّثَنِي الزُّبَيْدِيُّ، عَنِ الزُّهْرِيِّ، عَنْ مَحْمُودِ بْنِ الرَّبِيعِ، قَالَ عَقَلْتُ مِنَ النَّبِيِّ صلى الله عليه وسلم مَجَّةً مَجَّهَا فِي وَجْهِي وَأَنَا ابْنُ خَمْسِ سِنِينَ مِنْ دَلْوٍ‏.‏', NULL, 'Narrated Mahmud bin Rabi`a:When I was a boy of five, I remember, the Prophet (ﷺ) took water from a bucket (used for getting water out of a well) with his mouth and threw it on my face.', 'Narrated Mahmud bin Rabi`a', NULL, 'https://sunnah.com/bukhari:77', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 78, '"‏ بَيْنَمَا مُوسَى فِي مَلإٍ مِنْ بَنِي إِسْرَائِيلَ، إِذْ جَاءَهُ رَجُلٌ فَقَالَ أَتَعْلَمُ أَحَدًا أَعْلَمَ مِنْكَ قَالَ مُوسَى لاَ‏.‏ فَأَوْحَى اللَّهُ عَزَّ وَجَلَّ إِلَى مُوسَى بَلَى، عَبْدُنَا خَضِرٌ، فَسَأَلَ السَّبِيلَ إِلَى لُقِيِّهِ، فَجَعَلَ اللَّهُ لَهُ الْحُوتَ آيَةً، وَقِيلَ لَهُ إِذَا فَقَدْتَ الْحُوتَ فَارْجِعْ، فَإِنَّكَ سَتَلْقَاهُ، فَكَانَ مُوسَى صلى الله عليه وسلم يَتَّبِعُ أَثَرَ الْحُوتِ فِي الْبَحْرِ‏.‏ فَقَالَ فَتَى مُوسَى لِمُوسَى أَرَأَيْتَ إِذْ أَوَيْنَا إِلَى الصَّخْرَةِ فَإِنِّي نَسِيتُ الْحُوتَ، وَمَا أَنْسَانِيهِ إِلاَّ الشَّيْطَانُ أَنْ أَذْكُرَهُ‏.‏ قَالَ مُوسَى ذَلِكَ مَا كُنَّا نَبْغِي‏.‏ فَارْتَدَّا عَلَى آثَارِهِمَا قَصَصًا، فَوَجَدَا خَضِرًا، فَكَانَ مِنْ شَأْنِهِمَا مَا قَصَّ اللَّهُ فِي كِتَابِهِ ‏"', NULL, 'Narrated Ibn `Abbas:that he differed with Hur bin Qais bin Hisn Al-Fazari regarding the companion of the Prophet (ﷺ) Moses. Meanwhile, Ubai bin Ka`b passed by them and Ibn `Abbas called him saying, "My friend (Hur) and I have differed regarding Moses'' companion whom Moses asked the way to meet. Have you heard Allah''s Messenger (ﷺ) mentioning something about him? Ubai bin Ka`b said: "Yes, I heard the Prophet (ﷺ) mentioning something about him (saying) while Moses was sitting in the company of some Israelites, a man came and asked him: "Do you know anyone who is more learned than you? Moses replied: "No." So Allah sent the Divine Inspiration to Moses: ''--Yes, Our slave Khadir is more learned than you. Moses asked Allah how to meet him (Al-Khadir). So Allah made the fish a sign for him and he was told when the fish was lost, he should return (to the place where he had lost it) and there he would meet him (Al-Khadir). So Moses went on looking for the sign of the fish in the sea. The servant-boy of Moses said: ''Do you remember when we betook ourselves to the rock, I indeed forgot the fish, none but Satan made me forget to remember it. On that Moses said, ''That is what we have been seeking.'' So they went back retracing their footsteps, and found Khadir. (and) what happened further about them is narrated in the Holy Qur''an by Allah." (18.54 up to 18.82)', 'Narrated Ibn `Abbas', NULL, 'https://sunnah.com/bukhari:78', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 79, '"‏ مَثَلُ مَا بَعَثَنِي اللَّهُ بِهِ مِنَ الْهُدَى وَالْعِلْمِ كَمَثَلِ الْغَيْثِ الْكَثِيرِ أَصَابَ أَرْضًا، فَكَانَ مِنْهَا نَقِيَّةٌ قَبِلَتِ الْمَاءَ، فَأَنْبَتَتِ الْكَلأَ وَالْعُشْبَ الْكَثِيرَ، وَكَانَتْ مِنْهَا أَجَادِبُ أَمْسَكَتِ الْمَاءَ، فَنَفَعَ اللَّهُ بِهَا النَّاسَ، فَشَرِبُوا وَسَقَوْا وَزَرَعُوا، وَأَصَابَتْ مِنْهَا طَائِفَةً أُخْرَى، إِنَّمَا هِيَ قِيعَانٌ لاَ تُمْسِكُ مَاءً، وَلاَ تُنْبِتُ كَلأً، فَذَلِكَ مَثَلُ مَنْ فَقِهَ فِي دِينِ اللَّهِ وَنَفَعَهُ مَا بَعَثَنِي اللَّهُ بِهِ، فَعَلِمَ وَعَلَّمَ، وَمَثَلُ مَنْ لَمْ يَرْفَعْ بِذَلِكَ رَأْسًا، وَلَمْ يَقْبَلْ هُدَى اللَّهِ الَّذِي أُرْسِلْتُ بِهِ ‏"', NULL, 'Narrated Abu Musa:The Prophet (ﷺ) said, "The example of guidance and knowledge with which Allah has sent me is like abundant rain falling on the earth, some of which was fertile soil that absorbed rain water and brought forth vegetation and grass in abundance. (And) another portion of it was hard and held the rain water and Allah benefited the people with it and they utilized it for drinking, making their animals drink from it and for irrigation of the land for cultivation. (And) a portion of it was barren which could neither hold the water nor bring forth vegetation (then that land gave no benefits). The first is the example of the person who comprehends Allah''s religion and gets benefit (from the knowledge) which Allah has revealed through me (the Prophets and learns and then teaches others. The last example is that of a person who does not care for it and does not take Allah''s guidance revealed through me (He is like that barren land.)"', 'Narrated Abu Musa', NULL, 'https://sunnah.com/bukhari:79', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 80, '"‏ إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يُرْفَعَ الْعِلْمُ، وَيَثْبُتَ الْجَهْلُ، وَيُشْرَبَ الْخَمْرُ، وَيَظْهَرَ الزِّنَا ‏"', NULL, 'Narrated Anas:Allah''s Messenger (ﷺ) said, "From among the portents of the Hour are (the following): -1. Religious knowledge will be taken away (by the death of Religious learned men). -2. (Religious) ignorance will prevail. -3. Drinking of Alcoholic drinks (will be very common). -4. There will be prevalence of open illegal sexual intercourse.', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:80', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 81, '"‏ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يَقِلَّ الْعِلْمُ، وَيَظْهَرَ الْجَهْلُ، وَيَظْهَرَ الزِّنَا، وَتَكْثُرَ النِّسَاءُ وَيَقِلَّ الرِّجَالُ، حَتَّى يَكُونَ لِخَمْسِينَ امْرَأَةً الْقَيِّمُ الْوَاحِدُ ‏"', NULL, 'Narrated Anas:I will narrate to you a Hadith and none other than I will tell you about after it. I heard Allah''s Messenger (ﷺ) saying: From among the portents of the Hour are (the following): -1. Religious knowledge will decrease [by the death of religious learned men]. -2. Religious ignorance will prevail. -3. There will be prevalence of open illegal sexual intercourse. -4. Women will increase in number and men will decrease in number so much so that fifty women will be looked after by one man.', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:81', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 82, 'حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ، قَالَ حَدَّثَنِي اللَّيْثُ، قَالَ حَدَّثَنِي عُقَيْلٌ، عَنِ ابْنِ شِهَابٍ، عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ، أَنَّ ابْنَ عُمَرَ، قَالَ سَمِعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ بَيْنَا أَنَا نَائِمٌ أُتِيتُ بِقَدَحِ لَبَنٍ، فَشَرِبْتُ حَتَّى إِنِّي لأَرَى الرِّيَّ يَخْرُجُ فِي أَظْفَارِي، ثُمَّ أَعْطَيْتُ فَضْلِي عُمَرَ بْنَ الْخَطَّابِ ‏"‏‏.‏ قَالُوا فَمَا أَوَّلْتَهُ يَا رَسُولَ اللَّهِ قَالَ ‏"‏ الْعِلْمَ ‏"‏‏.‏', NULL, 'Narrated Ibn `Umar:Allah''s Messenger (ﷺ) said, "While I was sleeping, I saw that a cup full of milk was brought to me and I drank my fill till I noticed (the milk) its wetness coming out of my nails. Then I gave the remaining milk to `Umar Ibn Al-Khattab" The companions of the Prophet (ﷺ) asked, "What have you interpreted (about this dream)? "O Allah''s Messenger (ﷺ) ,!" he replied, "(It is religious) knowledge."', 'Narrated Ibn `Umar', NULL, 'https://sunnah.com/bukhari:82', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 83, 'حَدَّثَنَا إِسْمَاعِيلُ، قَالَ حَدَّثَنِي مَالِكٌ، عَنِ ابْنِ شِهَابٍ، عَنْ عِيسَى بْنِ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ، عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم وَقَفَ فِي حَجَّةِ الْوَدَاعِ بِمِنًى لِلنَّاسِ يَسْأَلُونَهُ، فَجَاءَهُ رَجُلٌ فَقَالَ لَمْ أَشْعُرْ فَحَلَقْتُ قَبْلَ أَنْ أَذْبَحَ‏.‏ فَقَالَ ‏"‏ اذْبَحْ وَلاَ حَرَجَ ‏"‏‏.‏ فَجَاءَ آخَرُ فَقَالَ لَمْ أَشْعُرْ، فَنَحَرْتُ قَبْلَ أَنْ أَرْمِيَ‏.‏ قَالَ ‏"‏ ارْمِ وَلاَ حَرَجَ ‏"‏‏.‏ فَمَا سُئِلَ النَّبِيُّ صلى الله عليه وسلم عَنْ شَىْءٍ قُدِّمَ وَلاَ أُخِّرَ إِلاَّ قَالَ افْعَلْ وَلاَ حَرَجَ‏.‏', NULL, 'Narrated `Abdullah bin `Amr bin Al `Aas:Allah''s Messenger (ﷺ) stopped (for a while near the Jimar) at Mina during his last Hajj for the people and they were asking him questions. A man came and said, "I forgot and got my head shaved before slaughtering the Hadi (sacrificing animal)." The Prophet (ﷺ) said, "There is no harm, go and do the slaughtering now." Then another person came and said, "I forgot and slaughtered (the camel) before Rami (throwing of the pebbles) at the Jamra." The Prophet (ﷺ) said, "Do the Rami now and there is no harm." The narrator added: So on that day, when the Prophet (ﷺ) was asked about anything (as regards the ceremonies of Hajj) performed before or after its due time, his reply was: "Do it (now) and there is no harm."', 'Narrated `Abdullah bin `Amr bin Al `Aas', NULL, 'https://sunnah.com/bukhari:83', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 84, 'حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ، قَالَ حَدَّثَنَا وُهَيْبٌ، قَالَ حَدَّثَنَا أَيُّوبُ، عَنْ عِكْرِمَةَ، عَنِ ابْنِ عَبَّاسٍ، أَنَّ النَّبِيَّ صلى الله عليه وسلم سُئِلَ فِي حَجَّتِهِ فَقَالَ ذَبَحْتُ قَبْلَ أَنْ أَرْمِيَ، فَأَوْمَأَ بِيَدِهِ قَالَ وَلاَ حَرَجَ‏.‏ قَالَ حَلَقْتُ قَبْلَ أَنْ أَذْبَحَ‏.‏ فَأَوْمَأَ بِيَدِهِ وَلاَ حَرَجَ‏.‏', NULL, 'Narrated Ibn `Abbas:Somebody said to the Prophet (during his last Hajj), "I did the slaughtering before doing the Rami.'' The Prophet (ﷺ) beckoned with his hand and said, "There is no harm in that." Then another person said. "I got my head shaved before offering the sacrifice." The Prophet (ﷺ) beckoned with his hand saying, "There is no harm in that."', 'Narrated Ibn `Abbas', NULL, 'https://sunnah.com/bukhari:84', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 85, '"‏ يُقْبَضُ الْعِلْمُ، وَيَظْهَرُ الْجَهْلُ وَالْفِتَنُ، وَيَكْثُرُ الْهَرْجُ ‏"', NULL, 'Narrated Abu Huraira:The Prophet (ﷺ) said, "(Religious) knowledge will be taken away (by the death of religious scholars) ignorance (in religion) and afflictions will appear; and Harj will increase." It was asked, "What is Harj, O Allah''s Messenger (ﷺ)?" He replied by beckoning with his hand indicating "killing." (Fath-al-Bari Page 192, Vol. 1)', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:85', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 86, '"‏ مَا مِنْ شَىْءٍ لَمْ أَكُنْ أُرِيتُهُ إِلاَّ رَأَيْتُهُ فِي مَقَامِي حَتَّى الْجَنَّةَ وَالنَّارَ، فَأُوحِيَ إِلَىَّ أَنَّكُمْ تُفْتَنُونَ فِي قُبُورِكُمْ، مِثْلَ ـ أَوْ قَرِيبًا لاَ أَدْرِي أَىَّ ذَلِكَ قَالَتْ أَسْمَاءُ ـ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ، يُقَالُ مَا عِلْمُكَ بِهَذَا الرَّجُلِ فَأَمَّا الْمُؤْمِنُ ـ أَوِ الْمُوقِنُ لاَ أَدْرِي بِأَيِّهِمَا قَالَتْ أَسْمَاءُ ـ فَيَقُولُ هُوَ مُحَمَّدٌ رَسُولُ اللَّهِ جَاءَنَا بِالْبَيِّنَاتِ وَالْهُدَى، فَأَجَبْنَا وَاتَّبَعْنَا، هُوَ مُحَمَّدٌ‏.‏ ثَلاَثًا، فَيُقَالُ نَمْ صَالِحًا، قَدْ عَلِمْنَا إِنْ كُنْتَ لَمُوقِنًا بِهِ، وَأَمَّا الْمُنَافِقُ ـ أَوِ الْمُرْتَابُ لاَ أَدْرِي أَىَّ ذَلِكَ قَالَتْ أَسْمَاءُ ـ فَيَقُولُ لاَ أَدْرِي، سَمِعْتُ النَّاسَ يَقُولُونَ شَيْئًا فَقُلْتُهُ ‏"', NULL, 'Narrated Asma'':I came to `Aisha while she was praying, and said to her, "What has happened to the people?" She pointed out towards the sky. (I looked towards the mosque), and saw the people offering the prayer. Aisha said, "Subhan Allah." I said to her, "Is there a sign?" She nodded with her head meaning, "Yes." I, too, then stood (for the prayer of eclipse) till I became (nearly) unconscious and later on I poured water on my head. After the prayer, the Prophet (ﷺ) praised and glorified Allah and then said, "Just now at this place I have seen what I have never seen before, including Paradise and Hell. No doubt it has been inspired to me that you will be put to trials in your graves and these trials will be like the trials of Masih-ad-Dajjal or nearly like it (the sub narrator is not sure which expression Asma'' used). You will be asked, ''What do you know about this man (the Prophet (ﷺ) Muhammad)?'' Then the faithful believer (or Asma'' said a similar word) will reply, ''He is Muhammad Allah''s Messenger (ﷺ) who had come to us with clear evidences and guidance and so we accepted his teachings and followed him. And he is Muhammad.'' And he will repeat it thrice. Then the angels will say to him, ''Sleep in peace as we have come to know that you were a faithful believer.'' On the other hand, a hypocrite or a doubtful person will reply, ''I do not know, but I heard the people saying something and so I said it.'' (the same). "', 'Narrated Asma''', NULL, 'https://sunnah.com/bukhari:86', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 87, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، قَالَ حَدَّثَنَا غُنْدَرٌ، قَالَ حَدَّثَنَا شُعْبَةُ، عَنْ أَبِي جَمْرَةَ، قَالَ كُنْتُ أُتَرْجِمُ بَيْنَ ابْنِ عَبَّاسٍ وَبَيْنَ النَّاسِ فَقَالَ إِنَّ وَفْدَ عَبْدِ الْقَيْسِ أَتَوُا النَّبِيَّ صلى الله عليه وسلم فَقَالَ ‏"‏ مَنِ الْوَفْدُ ـ أَوْ مَنِ الْقَوْمُ ‏"‏‏.‏ قَالُوا رَبِيعَةُ‏.‏ فَقَالَ ‏"‏ مَرْحَبًا بِالْقَوْمِ ـ أَوْ بِالْوَفْدِ ـ غَيْرَ خَزَايَا وَلاَ نَدَامَى ‏"‏‏.‏ قَالُوا إِنَّا نَأْتِيكَ مِنْ شُقَّةٍ بَعِيدَةٍ، وَبَيْنَنَا وَبَيْنَكَ هَذَا الْحَىُّ مِنْ كُفَّارِ مُضَرَ، وَلاَ نَسْتَطِيعُ أَنْ نَأْتِيَكَ إِلاَّ فِي شَهْرٍ حَرَامٍ فَمُرْنَا بِأَمْرٍ نُخْبِرْ بِهِ مَنْ وَرَاءَنَا، نَدْخُلُ بِهِ الْجَنَّةَ‏.‏ فَأَمَرَهُمْ بِأَرْبَعٍ، وَنَهَاهُمْ عَنْ أَرْبَعٍ أَمَرَهُمْ بِالإِيمَانِ بِاللَّهِ عَزَّ وَجَلَّ وَحْدَهُ‏.‏ قَالَ ‏"‏ هَلْ تَدْرُونَ مَا الإِيمَانُ بِاللَّهِ وَحْدَهُ ‏"‏‏.‏ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ‏.‏ قَالَ ‏"‏ شَهَادَةُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ، وَإِقَامُ الصَّلاَةِ، وَإِيتَاءُ الزَّكَاةِ، وَصَوْمُ رَمَضَانَ، وَتُعْطُوا الْخُمُسَ مِنَ الْمَغْنَمِ ‏"‏‏.‏ وَنَهَاهُمْ عَنِ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ‏.‏ قَالَ شُعْبَةُ رُبَّمَا قَالَ النَّقِيرِ، وَرُبَّمَا قَالَ الْمُقَيَّرِ‏.‏ قَالَ ‏"‏ احْفَظُوهُ وَأَخْبِرُوهُ مَنْ وَرَاءَكُمْ ‏"‏‏.‏', NULL, 'Narrated Abu Jamra:I was an interpreter between the people and Ibn `Abbas. Once Ibn `Abbas said that a delegation of the tribe of `Abdul Qais came to the Prophet (ﷺ) who asked them, "Who are the people (i.e. you)? (Or) who are the delegates?" They replied, "We are from the tribe of Rabi`a." Then the Prophet (ﷺ) said to them, "Welcome, O people (or said, "O delegation (of `Abdul Qais).") Neither will you have disgrace nor will you regret." They said, "We have come to you from a distant place and there is the tribe of the infidels of Mudar intervening between you and us and we cannot come to you except in the sacred month. So please order us to do something good (religious deeds) and that we may also inform our people whom we have left behind (at home) and that we may enter Paradise (by acting on them.)" The Prophet ordered them to do four things, and forbade them from four things. He ordered them to believe in Allah Alone, the Honorable the Majestic and said to them, "Do you know what is meant by believing in Allah Alone?" They replied, "Allah and His Apostle know better." Thereupon the Prophet (ﷺ) said, "(That means to testify that none has the right to be worshipped but Allah and that Muhammad is His Apostle, to offer prayers perfectly, to pay Zakat, to observe fasts during the month of Ramadan, (and) to pay Al-Khumus (one fifth of the booty to be given in Allah''s cause)." Then he forbade them four things, namely Ad-Dubba.'' Hantam, Muzaffat (and) An-Naqir or Muqaiyar (These were the names of pots in which alcoholic drinks used to be prepared). The Prophet (ﷺ) further said, "Memorize them (these instructions) and tell them to the people whom you have left behind."', 'Narrated Abu Jamra', NULL, 'https://sunnah.com/bukhari:87', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 88, '"‏ كَيْفَ وَقَدْ قِيلَ ‏"', NULL, 'Narrated `Abdullah bin Abi Mulaika:`Uqba bin Al-Harith said that he had married the daughter of Abi Ihab bin `Aziz. Later on a woman came to him and said, "I have suckled (nursed) `Uqba and the woman whom he married (his wife) at my breast." `Uqba said to her, "Neither I knew that you have suckled (nursed) me nor did you tell me." Then he rode over to see Allah''s Messenger (ﷺ) at Medina, and asked him about it. Allah''s Messenger (ﷺ) said, "How can you keep her as a wife when it has been said (that she is your foster-sister)?" Then `Uqba divorced her, and she married another man.', 'Narrated `Abdullah bin Abi Mulaika', NULL, 'https://sunnah.com/bukhari:88', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 89, '"‏ لاَ ‏"', NULL, 'Narrated `Umar:My Ansari neighbor from Bani Umaiya bin Zaid who used to live at `Awali Al-Medina and used to visit the Prophet (ﷺ) by turns. He used to go one day and I another day. When I went I used to bring the news of that day regarding the Divine Inspiration and other things, and when he went, he used to do the same for me. Once my Ansari friend, in his turn (on returning from the Prophet), knocked violently at my door and asked if I was there." I became horrified and came out to him. He said, "Today a great thing has happened." I then went to Hafsa and saw her weeping. I asked her, "Did Allah''s Messenger (ﷺ) divorce you all?" She replied, "I do not know." Then, I entered upon the Prophet (ﷺ) and said while standing, "Have you divorced your wives?" The Prophet (ﷺ) replied in the negative. On that I said, "Allahu-Akbar (Allah is Greater)." (See Hadith No. 119, Vol. 3 for details)', 'Narrated `Umar', NULL, 'https://sunnah.com/bukhari:89', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 90, '"‏ أَيُّهَا النَّاسُ، إِنَّكُمْ مُنَفِّرُونَ، فَمَنْ صَلَّى بِالنَّاسِ فَلْيُخَفِّفْ، فَإِنَّ فِيهِمُ الْمَرِيضَ وَالضَّعِيفَ وَذَا الْحَاجَةِ ‏"', NULL, 'Narrated Abu Mas`ud Al-Ansari:Once a man said to Allah''s Messenger (ﷺ) "O Allah''s Messenger (ﷺ)! I may not attend the (compulsory congregational) prayer because so and so (the Imam) prolongs the prayer when he leads us for it. The narrator added: "I never saw the Prophet (ﷺ) more furious in giving advice than he was on that day. The Prophet said, "O people! Some of you make others dislike good deeds (the prayers). So whoever leads the people in prayer should shorten it because among them there are the sick the weak and the needy (having some jobs to do).', 'Narrated Abu Mas`ud Al-Ansari', NULL, 'https://sunnah.com/bukhari:90', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 91, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ، قَالَ حَدَّثَنَا أَبُو عَامِرٍ، قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلاَلٍ الْمَدِينِيُّ، عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ، عَنْ يَزِيدَ، مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ، أَنَّ النَّبِيَّ صلى الله عليه وسلم سَأَلَهُ رَجُلٌ عَنِ اللُّقَطَةِ فَقَالَ ‏"‏ اعْرِفْ وِكَاءَهَا ـ أَوْ قَالَ وِعَاءَهَا ـ وَعِفَاصَهَا، ثُمَّ عَرِّفْهَا سَنَةً، ثُمَّ اسْتَمْتِعْ بِهَا، فَإِنْ جَاءَ رَبُّهَا فَأَدِّهَا إِلَيْهِ ‏"‏‏.‏ قَالَ فَضَالَّةُ الإِبِلِ فَغَضِبَ حَتَّى احْمَرَّتْ وَجْنَتَاهُ ـ أَوْ قَالَ احْمَرَّ وَجْهُهُ ـ فَقَالَ ‏"‏ وَمَا لَكَ وَلَهَا مَعَهَا سِقَاؤُهَا وَحِذَاؤُهَا، تَرِدُ الْمَاءَ، وَتَرْعَى الشَّجَرَ، فَذَرْهَا حَتَّى يَلْقَاهَا رَبُّهَا ‏"‏‏.‏ قَالَ فَضَالَّةُ الْغَنَمِ قَالَ ‏"‏ لَكَ أَوْ لأَخِيكَ أَوْ لِلذِّئْبِ ‏"‏‏.‏', NULL, 'Narrated Zaid bin Khalid Al-Juhani:A man asked the Prophet (ﷺ) about the picking up of a "Luqata" (fallen lost thing). The Prophet (ﷺ) replied, "Recognize and remember its tying material and its container, and make public announcement (about it) for one year, then utilize it but give it to its owner if he comes." Then the person asked about the lost camel. On that, the Prophet (ﷺ) got angry and his cheeks or his Face became red and he said, "You have no concern with it as it has its water container, and its feet and it will reach water, and eat (the leaves) of trees till its owner finds it." The man then asked about the lost sheep. The Prophet (ﷺ) replied, "It is either for you, for your brother (another person) or for the wolf."', 'Narrated Zaid bin Khalid Al-Juhani', NULL, 'https://sunnah.com/bukhari:91', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 92, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلاَءِ، قَالَ حَدَّثَنَا أَبُو أُسَامَةَ، عَنْ بُرَيْدٍ، عَنْ أَبِي بُرْدَةَ، عَنْ أَبِي مُوسَى، قَالَ سُئِلَ النَّبِيُّ صلى الله عليه وسلم عَنْ أَشْيَاءَ كَرِهَهَا، فَلَمَّا أُكْثِرَ عَلَيْهِ غَضِبَ، ثُمَّ قَالَ لِلنَّاسِ ‏"‏ سَلُونِي عَمَّا شِئْتُمْ ‏"‏‏.‏ قَالَ رَجُلٌ مَنْ أَبِي قَالَ ‏"‏ أَبُوكَ حُذَافَةُ ‏"‏‏.‏ فَقَامَ آخَرُ فَقَالَ مَنْ أَبِي يَا رَسُولَ اللَّهِ فَقَالَ ‏"‏ أَبُوكَ سَالِمٌ مَوْلَى شَيْبَةَ ‏"‏‏.‏ فَلَمَّا رَأَى عُمَرُ مَا فِي وَجْهِهِ قَالَ يَا رَسُولَ اللَّهِ، إِنَّا نَتُوبُ إِلَى اللَّهِ عَزَّ وَجَلَّ‏.‏', NULL, 'Narrated Abu Musa:The Prophet (ﷺ) was asked about things which he did not like, but when the questioners insisted, the Prophet got angry. He then said to the people, "Ask me anything you like." A man asked, "Who is my father?" The Prophet (ﷺ) replied, "Your father is Hudhafa." Then another man got up and said, "Who is my father, O Allah''s Messenger (ﷺ) ?" He replied, "Your father is Salim, Maula (the freed slave) of Shaiba." So when `Umar saw that (the anger) on the face of the Prophet (ﷺ) he said, "O Allah''s Messenger (ﷺ)! We repent to Allah (Our offending you).', 'Narrated Abu Musa', NULL, 'https://sunnah.com/bukhari:92', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 93, 'حَدَّثَنَا أَبُو الْيَمَانِ، قَالَ أَخْبَرَنَا شُعَيْبٌ، عَنِ الزُّهْرِيِّ، قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم خَرَجَ، فَقَامَ عَبْدُ اللَّهِ بْنُ حُذَافَةَ فَقَالَ مَنْ أَبِي فَقَالَ ‏"‏ أَبُوكَ حُذَافَةُ ‏"‏‏.‏ ثُمَّ أَكْثَرَ أَنْ يَقُولَ ‏"‏ سَلُونِي ‏"‏‏.‏ فَبَرَكَ عُمَرُ عَلَى رُكْبَتَيْهِ فَقَالَ رَضِينَا بِاللَّهِ رَبًّا، وَبِالإِسْلاَمِ دِينًا، وَبِمُحَمَّدٍ صلى الله عليه وسلم نَبِيًّا، فَسَكَتَ‏.‏', NULL, 'Narrated Anas bin Malik:One day Allah''s Messenger (ﷺ) came out (before the people) and `Abdullah bin Hudhafa stood up and asked (him) "Who is my father?" The Prophet (ﷺ) replied, "Your father is Hudhafa." The Prophet (ﷺ) told them repeatedly (in anger) to ask him anything they liked. `Umar knelt down before the Prophet (ﷺ) and said thrice, "We accept Allah as (our) Lord and Islam as (our) religion and Muhammad as (our) Prophet." After that the Prophet (ﷺ) became silent.', 'Narrated Anas bin Malik', NULL, 'https://sunnah.com/bukhari:93', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 94, 'حَدَّثَنَا عَبْدَةُ، قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ، قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى، قَالَ حَدَّثَنَا ثُمَامَةُ بْنُ عَبْدِ اللَّهِ، عَنْ أَنَسٍ، عَنِ النَّبِيِّ صلى الله عليه وسلم أَنَّهُ كَانَ إِذَا سَلَّمَ سَلَّمَ ثَلاَثًا، وَإِذَا تَكَلَّمَ بِكَلِمَةٍ أَعَادَهَا ثَلاَثًا‏.‏', NULL, 'Narrated Anas:Whenever the Prophet (ﷺ) asked permission to enter, he knocked the door thrice with greeting and whenever he spoke a sentence (said a thing) he used to repeat it thrice. (See Hadith No. 261, Vol. 8).', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:94', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 95, 'حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ، حَدَّثَنَا عَبْدُ الصَّمَدِ، قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى، قَالَ حَدَّثَنَا ثُمَامَةُ بْنُ عَبْدِ اللَّهِ، عَنْ أَنَسٍ، عَنِ النَّبِيِّ صلى الله عليه وسلم أَنَّهُ كَانَ إِذَا تَكَلَّمَ بِكَلِمَةٍ أَعَادَهَا ثَلاَثًا حَتَّى تُفْهَمَ عَنْهُ، وَإِذَا أَتَى عَلَى قَوْمٍ فَسَلَّمَ عَلَيْهِمْ سَلَّمَ عَلَيْهِمْ ثَلاَثًا‏.‏', NULL, 'Narrated Anas:Whenever the Prophet (ﷺ) spoke a sentence (said a thing), he used to repeat it thrice so that the people could understand it properly from him and whenever he asked permission to enter, (he knocked the door) thrice with greeting.', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:95', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 96, '"‏ وَيْلٌ لِلأَعْقَابِ مِنَ النَّارِ ‏"', NULL, 'Narrated `Abdullah bin `Amr:Once Allah''s Messenger (ﷺ) remained behind us in a journey. He joined us while we were performing ablution for the `Asr prayer which was over-due. We were just passing wet hands over our feet (not washing them properly) so the Prophet (ﷺ) addressed us in a loud voice and said twice or thrice, "Save your heels from the fire."', 'Narrated `Abdullah bin `Amr', NULL, 'https://sunnah.com/bukhari:96', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 97, '"‏ ثَلاَثَةٌ لَهُمْ أَجْرَانِ رَجُلٌ مِنْ أَهْلِ الْكِتَابِ آمَنَ بِنَبِيِّهِ، وَآمَنَ بِمُحَمَّدٍ صلى الله عليه وسلم وَالْعَبْدُ الْمَمْلُوكُ إِذَا أَدَّى حَقَّ اللَّهِ وَحَقَّ مَوَالِيهِ، وَرَجُلٌ كَانَتْ عِنْدَهُ أَمَةٌ ‏{‏يَطَؤُهَا‏}‏ فَأَدَّبَهَا، فَأَحْسَنَ تَأْدِيبَهَا، وَعَلَّمَهَا فَأَحْسَنَ تَعْلِيمَهَا، ثُمَّ أَعْتَقَهَا فَتَزَوَّجَهَا، فَلَهُ أَجْرَانِ ‏"', NULL, 'Narrated Abu Burda''s father: Allah''s Messenger (ﷺ) said "Three persons will have a double reward: 1. A Person from the people of the scriptures who believed in his prophet (Jesus or Moses) and then believed in the Prophet (ﷺ) Muhammad (i .e. has embraced Islam). 2. A slave who discharges his duties to Allah and his master. 3. A master of a woman-slave who teaches her good manners and educates her in the best possible way (the religion) and manumits her and then marries her."', 'Narrated Abu Burda''s father', NULL, 'https://sunnah.com/bukhari:97', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 98, 'حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ، قَالَ حَدَّثَنَا شُعْبَةُ، عَنْ أَيُّوبَ، قَالَ سَمِعْتُ عَطَاءً، قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ، قَالَ أَشْهَدُ عَلَى النَّبِيِّ صلى الله عليه وسلم ـ أَوْ قَالَ عَطَاءٌ أَشْهَدُ عَلَى ابْنِ عَبَّاسٍ ـ أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم خَرَجَ وَمَعَهُ بِلاَلٌ، فَظَنَّ أَنَّهُ لَمْ يُسْمِعِ النِّسَاءَ فَوَعَظَهُنَّ، وَأَمَرَهُنَّ بِالصَّدَقَةِ، فَجَعَلَتِ الْمَرْأَةُ تُلْقِي الْقُرْطَ وَالْخَاتَمَ، وَبِلاَلٌ يَأْخُذُ فِي طَرَفِ ثَوْبِهِ‏.‏
وَقَالَ إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ عَطَاءٍ وَقَالَ عَنِ ابْنِ عَبَّاسٍ أَشْهَدُ عَلَى النَّبِيِّ صلى الله عليه وسلم‏.‏', NULL, 'Narrated Ibn ''Abbas: Once Allah''s Messenger (ﷺ) came out while Bilal was accompanying him. He went towards the women thinking that they had not heard him (i.e. his sermon). So he preached them and ordered them to pay alms. (Hearing that) the women started giving alms; some donated their ear-rings, some gave their rings and Bilal was collecting them in the corner of his garment.', 'Narrated Ibn ''Abbas', NULL, 'https://sunnah.com/bukhari:98', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 99, '"‏ لَقَدْ ظَنَنْتُ يَا أَبَا هُرَيْرَةَ أَنْ لاَ يَسْأَلَنِي عَنْ هَذَا الْحَدِيثِ أَحَدٌ أَوَّلُ مِنْكَ، لِمَا رَأَيْتُ مِنْ حِرْصِكَ عَلَى الْحَدِيثِ، أَسْعَدُ النَّاسِ بِشَفَاعَتِي يَوْمَ الْقِيَامَةِ مَنْ قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ، خَالِصًا مِنْ قَلْبِهِ أَوْ نَفْسِهِ ‏"', NULL, 'Narrated Abu Huraira:I said: "O Allah''s Messenger (ﷺ)! Who will be the luckiest person, who will gain your intercession on the Day of Resurrection?" Allah''s Messenger (ﷺ) said: O Abu Huraira! "I have thought that none will ask me about it before you as I know your longing for the (learning of) Hadiths. The luckiest person who will have my intercession on the Day of Resurrection will be the one who said sincerely from the bottom of his heart "None has the right to be worshipped but Allah."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:99', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 100, '"‏ إِنَّ اللَّهَ لاَ يَقْبِضُ الْعِلْمَ انْتِزَاعًا، يَنْتَزِعُهُ مِنَ الْعِبَادِ، وَلَكِنْ يَقْبِضُ الْعِلْمَ بِقَبْضِ الْعُلَمَاءِ، حَتَّى إِذَا لَمْ يُبْقِ عَالِمًا، اتَّخَذَ النَّاسُ رُءُوسًا جُهَّالاً فَسُئِلُوا، فَأَفْتَوْا بِغَيْرِ عِلْمٍ، فَضَلُّوا وَأَضَلُّوا ‏"', NULL, 'Narrated `Abdullah bin `Amr bin Al-`As:I heard Allah''s Messenger (ﷺ) saying, "Allah does not take away the knowledge, by taking it away from (the hearts of) the people, but takes it away by the death of the religious learned men till when none of the (religious learned men) remains, people will take as their leaders ignorant persons who when consulted will give their verdict without knowledge. So they will go astray and will lead the people astray."', 'Narrated `Abdullah bin `Amr bin Al-`As', NULL, 'https://sunnah.com/bukhari:100', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 101, 'حَدَّثَنَا آدَمُ، قَالَ حَدَّثَنَا شُعْبَةُ، قَالَ حَدَّثَنِي ابْنُ الأَصْبَهَانِيِّ، قَالَ سَمِعْتُ أَبَا صَالِحٍ، ذَكْوَانَ يُحَدِّثُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ،‏.‏ قَالَتِ النِّسَاءُ لِلنَّبِيِّ صلى الله عليه وسلم غَلَبَنَا عَلَيْكَ الرِّجَالُ، فَاجْعَلْ لَنَا يَوْمًا مِنْ نَفْسِكَ‏.‏ فَوَعَدَهُنَّ يَوْمًا لَقِيَهُنَّ فِيهِ، فَوَعَظَهُنَّ وَأَمَرَهُنَّ، فَكَانَ فِيمَا قَالَ لَهُنَّ ‏"‏ مَا مِنْكُنَّ امْرَأَةٌ تُقَدِّمُ ثَلاَثَةً مِنْ وَلَدِهَا إِلاَّ كَانَ لَهَا حِجَابًا مِنَ النَّارِ ‏"‏‏.‏ فَقَالَتِ امْرَأَةٌ وَاثْنَيْنِ فَقَالَ ‏"‏ وَاثْنَيْنِ ‏"‏‏.‏', NULL, 'Narrated Abu Sa`id Al-Khudri:Some women requested the Prophet (ﷺ) to fix a day for them as the men were taking all his time. On that he promised them one day for religious lessons and commandments. Once during such a lesson the Prophet said, "A woman whose three children die will be shielded by them from the Hell fire." On that a woman asked, "If only two die?" He replied, "Even two (will shield her from the Hell-fire).', 'Narrated Abu Sa`id Al-Khudri', NULL, 'https://sunnah.com/bukhari:101', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 102, '"‏ ثَلاَثَةً لَمْ يَبْلُغُوا الْحِنْثَ ‏"', NULL, 'Narrated Abu Sa`id Al-Khudri:as above (the sub narrators are different). Abu Huraira qualified the three children referred to in the above mentioned Hadith as not having reached the age of committing sins (i.e. age of puberty) .', 'Narrated Abu Sa`id Al-Khudri', NULL, 'https://sunnah.com/bukhari:102', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 103, 'حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ، قَالَ أَخْبَرَنَا نَافِعُ بْنُ عُمَرَ، قَالَ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ، أَنَّ عَائِشَةَ، زَوْجَ النَّبِيِّ صلى الله عليه وسلم كَانَتْ لاَ تَسْمَعُ شَيْئًا لاَ تَعْرِفُهُ إِلاَّ رَاجَعَتْ فِيهِ حَتَّى تَعْرِفَهُ، وَأَنَّ النَّبِيَّ صلى الله عليه وسلم قَالَ ‏"‏ مَنْ حُوسِبَ عُذِّبَ ‏"‏‏.‏ قَالَتْ عَائِشَةُ فَقُلْتُ أَوَ لَيْسَ يَقُولُ اللَّهُ تَعَالَى ‏{‏فَسَوْفَ يُحَاسَبُ حِسَابًا يَسِيرًا‏}‏ قَالَتْ فَقَالَ ‏"‏ إِنَّمَا ذَلِكَ الْعَرْضُ، وَلَكِنْ مَنْ نُوقِشَ الْحِسَابَ يَهْلِكْ ‏"‏‏.‏', NULL, 'Narrated Ibn Abu Mulaika:Whenever `Aisha (the wife of the Prophet) heard anything which she did not understand, she used to ask again till she understood it completely. Aisha said: "Once the Prophet (ﷺ) said, "Whoever will be called to account (about his deeds on the Day of Resurrection) will surely be punished." I said, "Doesn''t Allah say: "He surely will receive an easy reckoning." (84.8) The Prophet (ﷺ) replied, "This means only the presentation of the accounts but whoever will be argued about his account, will certainly be ruined."', 'Narrated Ibn Abu Mulaika', NULL, 'https://sunnah.com/bukhari:103', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 104, '"‏ إِنَّ مَكَّةَ حَرَّمَهَا اللَّهُ، وَلَمْ يُحَرِّمْهَا النَّاسُ، فَلاَ يَحِلُّ لاِمْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ أَنْ يَسْفِكَ بِهَا دَمًا، وَلاَ يَعْضِدَ بِهَا شَجَرَةً، فَإِنْ أَحَدٌ تَرَخَّصَ لِقِتَالِ رَسُولِ اللَّهِ صلى الله عليه وسلم فِيهَا فَقُولُوا إِنَّ اللَّهَ قَدْ أَذِنَ لِرَسُولِهِ، وَلَمْ يَأْذَنْ لَكُمْ‏.‏ وَإِنَّمَا أَذِنَ لِي فِيهَا سَاعَةً مِنْ نَهَارٍ، ثُمَّ عَادَتْ حُرْمَتُهَا الْيَوْمَ كَحُرْمَتِهَا بِالأَمْسِ، وَلْيُبَلِّغِ الشَّاهِدُ الْغَائِبَ ‏"', NULL, 'Narrated Sa`id:Abu Shuraih said, "When `Amr bin Sa`id was sending the troops to Mecca (to fight `Abdullah bin Az- Zubair) I said to him, ''O chief! Allow me to tell you what the Prophet (ﷺ) said on the day following the conquests of Mecca. My ears heard and my heart comprehended, and I saw him with my own eyes, when he said it. He glorified and praised Allah and then said, "Allah and not the people has made Mecca a sanctuary. So anybody who has belief in Allah and the Last Day (i.e. a Muslim) should neither shed blood in it nor cut down its trees. If anybody argues that fighting is allowed in Mecca as Allah''s Messenger (ﷺ) did fight (in Mecca), tell him that Allah gave permission to His Apostle, but He did not give it to you. The Prophet (ﷺ) added: Allah allowed me only for a few hours on that day (of the conquest) and today (now) its sanctity is the same (valid) as it was before. So it is incumbent upon those who are present to convey it (this information) to those who are absent." Abu- Shuraih was asked, "What did `Amr reply?" He said `Amr said, "O Abu Shuraih! I know better than you (in this respect). Mecca does not give protection to one who disobeys (Allah) or runs after committing murder, or theft (and takes refuge in Mecca).', 'Narrated Sa`id', NULL, 'https://sunnah.com/bukhari:104', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 105, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ، قَالَ حَدَّثَنَا حَمَّادٌ، عَنْ أَيُّوبَ، عَنْ مُحَمَّدٍ، عَنِ ابْنِ أَبِي بَكْرَةَ، عَنْ أَبِي بَكْرَةَ، ذُكِرَ النَّبِيُّ صلى الله عليه وسلم قَالَ ‏"‏ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ ـ قَالَ مُحَمَّدٌ وَأَحْسِبُهُ قَالَ وَأَعْرَاضَكُمْ ـ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا، أَلاَ لِيُبَلِّغِ الشَّاهِدُ مِنْكُمُ الْغَائِبَ ‏"‏‏.‏ وَكَانَ مُحَمَّدٌ يَقُولُ صَدَقَ رَسُولُ اللَّهِ صلى الله عليه وسلم كَانَ ذَلِكَ ‏"‏ أَلاَ هَلْ بَلَّغْتُ ‏"‏ مَرَّتَيْنِ‏.‏', NULL, 'Narrated Abu Bakra:The Prophet (ﷺ) said. No doubt your blood, property, the sub-narrator Muhammad thought that Abu Bakra had also mentioned and your honor (chastity), are sacred to one another as is the sanctity of this day of yours in this month of yours. It is incumbent on those who are present to inform those who are absent." (Muhammad the Sub-narrator used to say, "Allah''s Messenger (ﷺ) told the truth.") The Prophet (ﷺ) repeated twice: "No doubt! Haven''t I conveyed Allah''s message to you.', 'Narrated Abu Bakra', NULL, 'https://sunnah.com/bukhari:105', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 106, '"‏ لاَ تَكْذِبُوا عَلَىَّ، فَإِنَّهُ مَنْ كَذَبَ عَلَىَّ فَلْيَلِجِ النَّارَ ‏"', NULL, 'Narrated `Ali:The Prophet (ﷺ) said, "Do not tell a lie against me for whoever tells a lie against me (intentionally) then he will surely enter the Hell-fire."', 'Narrated `Ali', NULL, 'https://sunnah.com/bukhari:106', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 107, '"‏ مَنْ كَذَبَ عَلَىَّ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ ‏"', NULL, 'Narrated `Abdullah bin Az-Zubair:I said to my father, ''I do not hear from you any narration (Hadith) of Allah s Apostle as I hear (his narration) from so and so?" Az-Zubair replied. l was always with him (the Prophet) and I heard him saying "Whoever tells a lie against me (intentionally) then (surely) let him occupy, his seat in Hellfire.', 'Narrated `Abdullah bin Az-Zubair', NULL, 'https://sunnah.com/bukhari:107', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 108, '"‏ مَنْ تَعَمَّدَ عَلَىَّ كَذِبًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ ‏"', NULL, 'Narrated Anas:The fact which stops me from narrating a great number of Hadiths to you is that the Prophet (ﷺ) said: "Whoever tells a lie against me intentionally, then (surely) let him occupy his seat in Hell-fire."', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:108', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 109, '"‏ مَنْ يَقُلْ عَلَىَّ مَا لَمْ أَقُلْ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ ‏"', NULL, 'Narrated Salama:I heard the Prophet (ﷺ) saying, "Whoever (intentionally) ascribes to me what I have not said then (surely) let him occupy his seat in Hell-fire."', 'Narrated Salama', NULL, 'https://sunnah.com/bukhari:109', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 110, '"‏ تَسَمَّوْا بِاسْمِي وَلاَ تَكْتَنُوا بِكُنْيَتِي، وَمَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي، فَإِنَّ الشَّيْطَانَ لاَ يَتَمَثَّلُ فِي صُورَتِي، وَمَنْ كَذَبَ عَلَىَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ ‏"', NULL, 'Narrated Abu Huraira:The Prophet (ﷺ) said, "Name yourselves with my name (use my name) but do not name yourselves with my Kunya name (i.e. Abul Qasim). And whoever sees me in a dream then surely he has seen me for Satan cannot impersonate me. And whoever tells a lie against me (intentionally), then (surely) let him occupy his seat in Hell-fire."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:110', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 111, 'حَدَّثَنَا مُحَمَّدُ بْنُ سَلاَمٍ، قَالَ أَخْبَرَنَا وَكِيعٌ، عَنْ سُفْيَانَ، عَنْ مُطَرِّفٍ، عَنِ الشَّعْبِيِّ، عَنْ أَبِي جُحَيْفَةَ، قَالَ قُلْتُ لِعَلِيٍّ هَلْ عِنْدَكُمْ كِتَابٌ قَالَ لاَ، إِلاَّ كِتَابُ اللَّهِ، أَوْ فَهْمٌ أُعْطِيَهُ رَجُلٌ مُسْلِمٌ، أَوْ مَا فِي هَذِهِ الصَّحِيفَةِ‏.‏ قَالَ قُلْتُ فَمَا فِي هَذِهِ الصَّحِيفَةِ قَالَ الْعَقْلُ، وَفَكَاكُ الأَسِيرِ، وَلاَ يُقْتَلُ مُسْلِمٌ بِكَافِرٍ‏.‏', NULL, 'Narrated Ash-Shu`bi:Abu Juhaifa said, "I asked `Ali, ''Have you got any book (which has been revealed to the Prophet (ﷺ) apart from the Qur''an)?'' `Ali replied, ''No, except Allah''s Book or the power of understanding which has been bestowed (by Allah) upon a Muslim or what is (written) in this sheet of paper (with me).'' Abu Juhaifa said, "I asked, ''What is (written) in this sheet of paper?'' `Ali replied, it deals with The Diyya (compensation (blood money) paid by the killer to the relatives of the victim), the ransom for the releasing of the captives from the hands of the enemies, and the law that no Muslim should be killed in Qisas (equality in punishment) for the killing of (a disbeliever).', 'Narrated Ash-Shu`bi', NULL, 'https://sunnah.com/bukhari:111', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 112, 'حَدَّثَنَا أَبُو نُعَيْمٍ الْفَضْلُ بْنُ دُكَيْنٍ، قَالَ حَدَّثَنَا شَيْبَانُ، عَنْ يَحْيَى، عَنْ أَبِي سَلَمَةَ، عَنْ أَبِي هُرَيْرَةَ، أَنَّ خُزَاعَةَ، قَتَلُوا رَجُلاً مِنْ بَنِي لَيْثٍ عَامَ فَتْحِ مَكَّةَ بِقَتِيلٍ مِنْهُمْ قَتَلُوهُ، فَأُخْبِرَ بِذَلِكَ النَّبِيُّ صلى الله عليه وسلم فَرَكِبَ رَاحِلَتَهُ، فَخَطَبَ فَقَالَ ‏"‏ إِنَّ اللَّهَ حَبَسَ عَنْ مَكَّةَ الْقَتْلَ ـ أَوِ الْفِيلَ شَكَّ أَبُو عَبْدِ اللَّهِ ـ وَسَلَّطَ عَلَيْهِمْ رَسُولَ اللَّهِ صلى الله عليه وسلم وَالْمُؤْمِنِينَ، أَلاَ وَإِنَّهَا لَمْ تَحِلَّ لأَحَدٍ قَبْلِي، وَلاَ تَحِلُّ لأَحَدٍ بَعْدِي أَلاَ وَإِنَّهَا حَلَّتْ لِي سَاعَةً مِنْ نَهَارٍ، أَلاَ وَإِنَّهَا سَاعَتِي هَذِهِ حَرَامٌ، لاَ يُخْتَلَى شَوْكُهَا، وَلاَ يُعْضَدُ شَجَرُهَا، وَلاَ تُلْتَقَطُ سَاقِطَتُهَا إِلاَّ لِمُنْشِدٍ، فَمَنْ قُتِلَ فَهُوَ بِخَيْرِ النَّظَرَيْنِ إِمَّا أَنْ يُعْقَلَ، وَإِمَّا أَنْ يُقَادَ أَهْلُ الْقَتِيلِ ‏"‏‏.‏ فَجَاءَ رَجُلٌ مِنْ أَهْلِ الْيَمَنِ فَقَالَ اكْتُبْ لِي يَا رَسُولَ اللَّهِ‏.‏ فَقَالَ ‏"‏ اكْتُبُوا لأَبِي فُلاَنٍ ‏"‏‏.‏ فَقَالَ رَجُلٌ مِنْ قُرَيْشٍ إِلاَّ الإِذْخِرَ يَا رَسُولَ اللَّهِ، فَإِنَّا نَجْعَلُهُ فِي بُيُوتِنَا وَقُبُورِنَا‏.‏ فَقَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ إِلاَّ الإِذْخِرَ، إِلاَّ الإِذْخِرَ ‏"‏‏.‏ قَالَ أَبُو عَبْدِ اللَّهِ يُقَالُ يُقَادُ بِالْقَافِ‏.‏ فَقِيلَ لأَبِي عَبْدِ اللَّهِ أَىُّ شَىْءٍ كَتَبَ لَهُ قَالَ كَتَبَ لَهُ هَذِهِ الْخُطْبَةَ‏.‏', NULL, 'Narrated Abu Huraira:In the year of the Conquest of Mecca, the tribe of Khuza`a killed a man from the tribe of Bani Laith in revenge for a killed person, belonging to them. They informed the Prophet (ﷺ) about it. So he rode his Rahila (she-camel for riding) and addressed the people saying, "Allah held back the killing from Mecca. (The sub-narrator is in doubt whether the Prophet (ﷺ) said "elephant or killing," as the Arabic words standing for these words have great similarity in shape), but He (Allah) let His Apostle and the believers over power the infidels of Mecca. Beware! (Mecca is a sanctuary) Verily! Fighting in Mecca was not permitted for anyone before me nor will it be permitted for anyone after me. It (war) in it was made legal for me for few hours or so on that day. No doubt it is at this moment a sanctuary, it is not allowed to uproot its thorny shrubs or to uproot its trees or to pick up its Luqat (fallen things) except by a person who will look for its owner (announce it publicly). And if somebody is killed, then his closest relative has the right to choose one of the two-- the blood money (Diyya) or retaliation having the killer killed. In the meantime a man from Yemen came and said, "O Allah''s Messenger (ﷺ)! Get that written for me." The Prophet (ﷺ) ordered his companions to write that for him. Then a man from Quraish said, "Except Al-Idhkhir (a type of grass that has good smell) O Allah''s Messenger (ﷺ), as we use it in our houses and graves." The Prophet (ﷺ) said, "Except Al-Idhkhir i.e. Al-Idhkhir is allowed to be plucked."', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:112', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 113, 'حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ، قَالَ حَدَّثَنَا سُفْيَانُ، قَالَ حَدَّثَنَا عَمْرٌو، قَالَ أَخْبَرَنِي وَهْبُ بْنُ مُنَبِّهٍ، عَنْ أَخِيهِ، قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ، يَقُولُ مَا مِنْ أَصْحَابِ النَّبِيِّ صلى الله عليه وسلم أَحَدٌ أَكْثَرَ حَدِيثًا عَنْهُ مِنِّي، إِلاَّ مَا كَانَ مِنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو فَإِنَّهُ كَانَ يَكْتُبُ وَلاَ أَكْتُبُ‏.‏ تَابَعَهُ مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ‏.‏', NULL, 'Narrated Abu Huraira:There is none among the companions of the Prophet (ﷺ) who has narrated more Hadiths than I except `Abdullah bin `Amr (bin Al-`As) who used to write them and I never did the same.', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:113', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 114, 'حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ، قَالَ حَدَّثَنِي ابْنُ وَهْبٍ، قَالَ أَخْبَرَنِي يُونُسُ، عَنِ ابْنِ شِهَابٍ، عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ، عَنِ ابْنِ عَبَّاسٍ، قَالَ لَمَّا اشْتَدَّ بِالنَّبِيِّ صلى الله عليه وسلم وَجَعُهُ قَالَ ‏"‏ ائْتُونِي بِكِتَابٍ أَكْتُبُ لَكُمْ كِتَابًا لاَ تَضِلُّوا بَعْدَهُ ‏"‏‏.‏ قَالَ عُمَرُ إِنَّ النَّبِيَّ صلى الله عليه وسلم غَلَبَهُ الْوَجَعُ وَعِنْدَنَا كِتَابُ اللَّهِ حَسْبُنَا فَاخْتَلَفُوا وَكَثُرَ اللَّغَطُ‏.‏ قَالَ ‏"‏ قُومُوا عَنِّي، وَلاَ يَنْبَغِي عِنْدِي التَّنَازُعُ ‏"‏‏.‏ فَخَرَجَ ابْنُ عَبَّاسٍ يَقُولُ إِنَّ الرَّزِيَّةَ كُلَّ الرَّزِيَّةِ مَا حَالَ بَيْنَ رَسُولِ اللَّهِ صلى الله عليه وسلم وَبَيْنَ كِتَابِهِ‏.‏', NULL, 'Narrated ''Ubaidullah bin `Abdullah:Ibn `Abbas said, "When the ailment of the Prophet (ﷺ) became worse, he said, ''Bring for me (writing) paper and I will write for you a statement after which you will not go astray.'' But `Umar said, ''The Prophet is seriously ill, and we have got Allah''s Book with us and that is sufficient for us.'' But the companions of the Prophet (ﷺ) differed about this and there was a hue and cry. On that the Prophet (ﷺ) said to them, ''Go away (and leave me alone). It is not right that you should quarrel in front of me." Ibn `Abbas came out saying, "It was most unfortunate (a great disaster) that Allah''s Messenger (ﷺ) was prevented from writing that statement for them because of their disagreement and noise. (Note: It is apparent from this Hadith that Ibn `Abbas had witnessed the event and came out saying this statement. The truth is not so, for Ibn `Abbas used to say this statement on narrating the Hadith and he had not witnessed the event personally. See Fath Al-Bari Vol. 1, p.220 footnote.) (See Hadith No. 228, Vol. 4).', 'Narrated ''Ubaidullah bin `Abdullah', NULL, 'https://sunnah.com/bukhari:114', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 115, '"‏ سُبْحَانَ اللَّهِ مَاذَا أُنْزِلَ اللَّيْلَةَ مِنَ الْفِتَنِ وَمَاذَا فُتِحَ مِنَ الْخَزَائِنِ أَيْقِظُوا صَوَاحِبَاتِ الْحُجَرِ، فَرُبَّ كَاسِيَةٍ فِي الدُّنْيَا عَارِيَةٍ فِي الآخِرَةِ ‏"', NULL, 'Narrated Um Salama:One night Allah''s Messenger (ﷺ) got up and said, "Subhan Allah! How many afflictions have been descended tonight and how many treasures have been disclosed! Go and wake the sleeping lady occupants of these dwellings (his wives) up (for prayers). A well-dressed (soul) in this world may be naked in the Hereafter. "', 'Narrated Um Salama', NULL, 'https://sunnah.com/bukhari:115', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 116, '"‏ أَرَأَيْتَكُمْ لَيْلَتَكُمْ هَذِهِ، فَإِنَّ رَأْسَ مِائَةِ سَنَةٍ مِنْهَا لاَ يَبْقَى مِمَّنْ هُوَ عَلَى ظَهْرِ الأَرْضِ أَحَدٌ ‏"', NULL, 'Narrated `Abdullah bin `Umar:Once the Prophet (ﷺ) led us in the `Isha'' prayer during the last days of his life and after finishing it (the prayer) (with Taslim) he said: "Do you realize (the importance of) this night?" Nobody present on the surface of the earth tonight will be living after the completion of one hundred years from this night."', 'Narrated `Abdullah bin `Umar', NULL, 'https://sunnah.com/bukhari:116', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 117, '"‏ نَامَ الْغُلَيِّمُ ‏"', NULL, 'Narrated Ibn `Abbas:I stayed overnight in the house of my aunt Maimuna bint Al-Harith (the wife of the Prophet (ﷺ) ) while the Prophet (ﷺ) was there with her during her night turn. The Prophet (ﷺ) offered the `Isha'' prayer (in the mosque), returned home and after having prayed four rak`at, he slept. Later on he got up at night and then asked whether the boy (or he used a similar word) had slept? Then he got up for the prayer and I stood up by his left side but he made me stand to his right and offered five rak`at followed by two more rak`at. Then he slept and I heard him snoring and then (after a while) he left for the (Fajr) prayer.', 'Narrated Ibn `Abbas', NULL, 'https://sunnah.com/bukhari:117', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 118, 'حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ، قَالَ حَدَّثَنِي مَالِكٌ، عَنِ ابْنِ شِهَابٍ، عَنِ الأَعْرَجِ، عَنْ أَبِي هُرَيْرَةَ، قَالَ إِنَّ النَّاسَ يَقُولُونَ أَكْثَرَ أَبُو هُرَيْرَةَ، وَلَوْلاَ آيَتَانِ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُ حَدِيثًا، ثُمَّ يَتْلُو ‏{‏إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنَ الْبَيِّنَاتِ‏}‏ إِلَى قَوْلِهِ ‏{‏الرَّحِيمُ‏}‏ إِنَّ إِخْوَانَنَا مِنَ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمُ الصَّفْقُ بِالأَسْوَاقِ، وِإِنَّ إِخْوَانَنَا مِنَ الأَنْصَارِ كَانَ يَشْغَلُهُمُ الْعَمَلُ فِي أَمْوَالِهِمْ، وَإِنَّ أَبَا هُرَيْرَةَ كَانَ يَلْزَمُ رَسُولَ اللَّهِ صلى الله عليه وسلم بِشِبَعِ بَطْنِهِ وَيَحْضُرُ مَا لاَ يَحْضُرُونَ، وَيَحْفَظُ مَا لاَ يَحْفَظُونَ‏.‏', NULL, 'Narrated Abu Huraira:People say that I have narrated many Hadiths (The Prophet''s narration). Had it not been for two verses in the Qur''an, I would not have narrated a single Hadith, and the verses are: "Verily those who conceal the clear sign and the guidance which We have sent down . . . (up to) Most Merciful." (2:159-160). And no doubt our Muhajir (emigrant) brothers used to be busy in the market with their business (bargains) and our Ansari brothers used to be busy with their property (agriculture). But I (Abu Huraira) used to stick to Allah''s Messenger (ﷺ) contented with what will fill my stomach and I used to attend that which they used not to attend and I used to memorize that which they used not to memorize.', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:118', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 119, 'حَدَّثَنَا أَحْمَدُ بْنُ أَبِي بَكْرٍ أَبُو مُصْعَبٍ، قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ دِينَارٍ، عَنِ ابْنِ أَبِي ذِئْبٍ، عَنْ سَعِيدٍ الْمَقْبُرِيِّ، عَنْ أَبِي هُرَيْرَةَ، قَالَ قُلْتُ يَا رَسُولَ اللَّهِ، إِنِّي أَسْمَعُ مِنْكَ حَدِيثًا كَثِيرًا أَنْسَاهُ‏.‏ قَالَ ‏"‏ ابْسُطْ رِدَاءَكَ ‏"‏ فَبَسَطْتُهُ‏.‏ قَالَ فَغَرَفَ بِيَدَيْهِ ثُمَّ قَالَ ‏"‏ ضُمُّهُ ‏"‏ فَضَمَمْتُهُ فَمَا نَسِيتُ شَيْئًا بَعْدَهُ‏.
حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ بِهَذَا أَوْ قَالَ غَرَفَ بِيَدِهِ فِيهِ‏.‏', NULL, 'Narrated Abu Huraira:I said to Allah''s Messenger (ﷺ) "I hear many narrations (Hadiths) from you but I forget them." Allah''s Apostle said, "Spread your Rida'' (garment)." I did accordingly and then he moved his hands as if filling them with something (and emptied them in my Rida'') and then said, "Take and wrap this sheet over your body." I did it and after that I never forgot any thing. Narrated Ibrahim bin Al-Mundhir: Ibn Abi Fudaik narrated the same as above (Hadith...119) but added that the Prophet (ﷺ) had moved his hands as if filling them with something and then he emptied them in the Rida'' of Abu Huraira.', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:119', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 120, 'حَدَّثَنَا إِسْمَاعِيلُ، قَالَ حَدَّثَنِي أَخِي، عَنِ ابْنِ أَبِي ذِئْبٍ، عَنْ سَعِيدٍ الْمَقْبُرِيِّ، عَنْ أَبِي هُرَيْرَةَ، قَالَ حَفِظْتُ مِنْ رَسُولِ اللَّهِ صلى الله عليه وسلم وِعَاءَيْنِ، فَأَمَّا أَحَدُهُمَا فَبَثَثْتُهُ، وَأَمَّا الآخَرُ فَلَوْ بَثَثْتُهُ قُطِعَ هَذَا الْبُلْعُومُ‏.‏', NULL, 'Narrated Abu Huraira:I have memorized two kinds of knowledge from Allah''s Messenger (ﷺ) . I have propagated one of them to you and if I propagated the second, then my pharynx (throat) would be cut (i.e. killed).', 'Narrated Abu Huraira', NULL, 'https://sunnah.com/bukhari:120', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 121, 'حَدَّثَنَا حَجَّاجٌ، قَالَ حَدَّثَنَا شُعْبَةُ، قَالَ أَخْبَرَنِي عَلِيُّ بْنُ مُدْرِكٍ، عَنْ أَبِي زُرْعَةَ، عَنْ جَرِيرٍ، أَنَّ النَّبِيَّ صلى الله عليه وسلم قَالَ لَهُ فِي حَجَّةِ الْوَدَاعِ ‏"‏ اسْتَنْصِتِ النَّاسَ ‏"‏ فَقَالَ ‏"‏ لاَ تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ ‏"‏‏.‏', NULL, 'Narrated Jarir:The Prophet (ﷺ) said to me during Hajjat-al-Wida`: Let the people keep quiet and listen. Then he said (addressing the people), "Do not (become infidels) revert to disbelief after me by striking the necks (cutting the throats) of one another (killing each other).', 'Narrated Jarir', NULL, 'https://sunnah.com/bukhari:121', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 122, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ، قَالَ حَدَّثَنَا سُفْيَانُ، قَالَ حَدَّثَنَا عَمْرٌو، قَالَ أَخْبَرَنِي سَعِيدُ بْنُ جُبَيْرٍ، قَالَ قُلْتُ لاِبْنِ عَبَّاسٍ إِنَّ نَوْفًا الْبِكَالِيَّ يَزْعُمُ أَنَّ مُوسَى لَيْسَ بِمُوسَى بَنِي إِسْرَائِيلَ، إِنَّمَا هُوَ مُوسَى آخَرُ‏.‏ فَقَالَ كَذَبَ عَدُوُّ اللَّهِ، حَدَّثَنَا أُبَىُّ بْنُ كَعْبٍ عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ قَامَ مُوسَى النَّبِيُّ خَطِيبًا فِي بَنِي إِسْرَائِيلَ، فَسُئِلَ أَىُّ النَّاسِ أَعْلَمُ فَقَالَ أَنَا أَعْلَمُ‏.‏ فَعَتَبَ اللَّهُ عَلَيْهِ، إِذْ لَمْ يَرُدَّ الْعِلْمَ إِلَيْهِ، فَأَوْحَى اللَّهُ إِلَيْهِ أَنَّ عَبْدًا مِنْ عِبَادِي بِمَجْمَعِ الْبَحْرَيْنِ هُوَ أَعْلَمُ مِنْكَ‏.‏ قَالَ يَا رَبِّ وَكَيْفَ بِهِ فَقِيلَ لَهُ احْمِلْ حُوتًا فِي مِكْتَلٍ فَإِذَا فَقَدْتَهُ فَهْوَ ثَمَّ، فَانْطَلَقَ وَانْطَلَقَ بِفَتَاهُ يُوشَعَ بْنِ نُونٍ، وَحَمَلاَ حُوتًا فِي مِكْتَلٍ، حَتَّى كَانَا عِنْدَ الصَّخْرَةِ وَضَعَا رُءُوسَهُمَا وَنَامَا فَانْسَلَّ الْحُوتُ مِنَ الْمِكْتَلِ فَاتَّخَذَ سَبِيلَهُ فِي الْبَحْرِ سَرَبًا، وَكَانَ لِمُوسَى وَفَتَاهُ عَجَبًا، فَانْطَلَقَا بَقِيَّةَ لَيْلَتِهِمَا وَيَوْمِهِمَا فَلَمَّا أَصْبَحَ قَالَ مُوسَى لِفَتَاهُ آتِنَا غَدَاءَنَا، لَقَدْ لَقِينَا مِنْ سَفَرِنَا هَذَا نَصَبًا، وَلَمْ يَجِدْ مُوسَى مَسًّا مِنَ النَّصَبِ حَتَّى جَاوَزَ الْمَكَانَ الَّذِي أُمِرَ بِهِ‏.‏ فَقَالَ لَهُ فَتَاهُ أَرَأَيْتَ إِذْ أَوَيْنَا إِلَى الصَّخْرَةِ فَإِنِّي نَسِيتُ الْحُوتَ، قَالَ مُوسَى ذَلِكَ مَا كُنَّا نَبْغِي، فَارْتَدَّا عَلَى آثَارِهِمَا قَصَصًا، فَلَمَّا انْتَهَيَا إِلَى الصَّخْرَةِ إِذَا رَجُلٌ مُسَجًّى بِثَوْبٍ ـ أَوْ قَالَ تَسَجَّى بِثَوْبِهِ ـ فَسَلَّمَ مُوسَى‏.‏ فَقَالَ الْخَضِرُ وَأَنَّى بِأَرْضِكَ السَّلاَمُ فَقَالَ أَنَا مُوسَى‏.‏ فَقَالَ مُوسَى بَنِي إِسْرَائِيلَ قَالَ نَعَمْ‏.‏ قَالَ هَلْ أَتَّبِعُكَ عَلَى أَنْ تُعَلِّمَنِي مِمَّا عُلِّمْتَ رَشَدًا قَالَ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِيَ صَبْرًا، يَا مُوسَى إِنِّي عَلَى عِلْمٍ مِنْ عِلْمِ اللَّهِ عَلَّمَنِيهِ لاَ تَعْلَمُهُ أَنْتَ، وَأَنْتَ عَلَى عِلْمٍ عَلَّمَكَهُ لاَ أَعْلَمُهُ‏.‏ قَالَ سَتَجِدُنِي إِنْ شَاءَ اللَّهُ صَابِرًا، وَلاَ أَعْصِي لَكَ أَمْرًا، فَانْطَلَقَا يَمْشِيَانِ عَلَى سَاحِلِ الْبَحْرِ لَيْسَ لَهُمَا سَفِينَةٌ، فَمَرَّتْ بِهِمَا سَفِينَةٌ، فَكَلَّمُوهُمْ أَنْ يَحْمِلُوهُمَا، فَعُرِفَ الْخَضِرُ، فَحَمَلُوهُمَا بِغَيْرِ نَوْلٍ، فَجَاءَ عُصْفُورٌ فَوَقَعَ عَلَى حَرْفِ السَّفِينَةِ، فَنَقَرَ نَقْرَةً أَوْ نَقْرَتَيْنِ فِي الْبَحْرِ‏.‏ فَقَالَ الْخَضِرُ يَا مُوسَى، مَا نَقَصَ عِلْمِي وَعِلْمُكَ مِنْ عِلْمِ اللَّهِ إِلاَّ كَنَقْرَةِ هَذَا الْعُصْفُورِ فِي الْبَحْرِ‏.‏ فَعَمَدَ الْخَضِرُ إِلَى لَوْحٍ مِنْ أَلْوَاحِ السَّفِينَةِ فَنَزَعَهُ‏.‏ فَقَالَ مُوسَى قَوْمٌ حَمَلُونَا بِغَيْرِ نَوْلٍ، عَمَدْتَ إِلَى سَفِينَتِهِمْ فَخَرَقْتَهَا لِتُغْرِقَ أَهْلَهَا قَالَ أَلَمْ أَقُلْ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِيَ صَبْرًا قَالَ لاَ تُؤَاخِذْنِي بِمَا نَسِيتُ‏.‏ فَكَانَتِ الأُولَى مِنْ مُوسَى نِسْيَانًا‏.‏ فَانْطَلَقَا فَإِذَا غُلاَمٌ يَلْعَبُ مَعَ الْغِلْمَانِ، فَأَخَذَ الْخَضِرُ بِرَأْسِهِ مِنْ أَعْلاَهُ فَاقْتَلَعَ رَأْسَهُ بِيَدِهِ‏.‏ فَقَالَ مُوسَى أَقَتَلْتَ نَفْسًا زَكِيَّةً بِغَيْرِ نَفْسٍ قَالَ أَلَمْ أَقُلْ لَكَ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِيَ صَبْرًا ـ قَالَ ابْنُ عُيَيْنَةَ وَهَذَا أَوْكَدُ ـ فَانْطَلَقَا حَتَّى إِذَا أَتَيَا أَهْلَ قَرْيَةٍ اسْتَطْعَمَا أَهْلَهَا، فَأَبَوْا أَنْ يُضَيِّفُوهُمَا، فَوَجَدَا فِيهَا جِدَارًا يُرِيدُ أَنْ يَنْقَضَّ فَأَقَامَهُ‏.‏ قَالَ الْخَضِرُ بِيَدِهِ فَأَقَامَهُ‏.‏ فَقَالَ لَهُ مُوسَى لَوْ شِئْتَ لاَتَّخَذْتَ عَلَيْهِ أَجْرًا‏.‏ قَالَ هَذَا فِرَاقُ بَيْنِي وَبَيْنِكَ ‏"‏‏.‏ قَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ يَرْحَمُ اللَّهُ مُوسَى، لَوَدِدْنَا لَوْ صَبَرَ حَتَّى يُقَصَّ عَلَيْنَا مِنْ أَمْرِهِمَا ‏"‏‏.‏', NULL, 'Narrated Sa`id bin Jubair:I said to Ibn `Abbas, "Nauf-Al-Bakali claims that Moses (the companion of Khadir) was not the Moses of Bani Israel but he was another Moses." Ibn `Abbas remarked that the enemy of Allah (Nauf) was a liar. Narrated Ubai bin Ka`b: The Prophet (ﷺ) said, "Once the Prophet (ﷺ) Moses stood up and addressed Bani Israel. He was asked, "Who is the most learned man amongst the people. He said, "I am the most learned." Allah admonished Moses as he did not attribute absolute knowledge to Him (Allah). So Allah inspired to him "At the junction of the two seas there is a slave amongst my slaves who is more learned than you." Moses said, "O my Lord! How can I meet him?" Allah said: Take a fish in a large basket (and proceed) and you will find him at the place where you will lose the fish. So Moses set out along with his (servant) boy, Yusha` bin Noon and carried a fish in a large basket till they reached a rock, where they laid their heads (i.e. lay down) and slept. The fish came out of the basket and it took its way into the sea as in a tunnel. So it was an amazing thing for both Moses and his (servant) boy. They proceeded for the rest of that night and the following day. When the day broke, Moses said to his (servant) boy: "Bring us our early meal. No doubt, we have suffered much fatigue in this journey." Moses did not get tired till he passed the place about which he was told. There the (servant) boy told Moses, "Do you remember when we betook ourselves to the rock, I indeed forgot the fish." Moses remarked, "That is what we have been seeking. So they went back retracing their footsteps, till they reached the rock. There they saw a man covered with a garment (or covering himself with his own garment). Moses greeted him. Al-Khadir replied saying, "How do people greet each other in your land?" Moses said, "I am Moses." He asked, "The Moses of Bani Israel?" Moses replied in the affirmative and added, "May I follow you so that you teach me of that knowledge which you have been taught." Al-Khadir replied, "Verily! You will not be able to remain patient with me, O Moses! I have some of the knowledge of Allah which He has taught me and which you do not know, while you have some knowledge which Allah has taught you which I do not know." Moses said, "Allah willing, you will find me patient and I will disobey no order of yours. So both of them set out walking along the seashore, as they did not have a boat. In the meantime a boat passed by them and they requested the crew of the boat to take them on board. The crew recognized Al-Khadir and took them on board without fare. Then a sparrow came and stood on the edge of the boat and dipped its beak once or twice in the sea. Al-Khadir said: "O Moses! My knowledge and your knowledge have not decreased Allah''s knowledge except as much as this sparrow has decreased the water of the sea with its beak." Al- Khadir went to one of the planks of the boat and plucked it out. Moses said, "These people gave us a free lift but you have broken their boat and scuttled it so as to drown its people." Al-Khadir replied, "Didn''t I tell you that you will not be able to remain patient with me." Moses said, "Call me not to account for what I forgot." The first (excuse) of Moses was that he had forgotten. Then they proceeded further and found a boy playing with other boys. Al-Khadir took hold of the boy''s head from the top and plucked it out with his hands (i.e. killed him). Moses said, "Have you killed an innocent soul who has killed none." Al-Khadir replied, "Did I not tell you that you cannot remain patient with me?" Then they both proceeded till when they came to the people of a town, they asked them for food, but they refused to entertain them. Then they found there a wall on the point of collapsing. Al-Khadir repaired it with his own hands. Moses said, "If you had wished, surely you could have taken wages for it." Al-Khadir replied, "This is the parting between you and me." The Prophet added, "May Allah be Merciful to Moses! Would that he could have been more patient to learn more about his story with Al-Khadir. "', 'Narrated Sa`id bin Jubair', NULL, 'https://sunnah.com/bukhari:122', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 123, '"‏ مَنْ قَاتَلَ لِتَكُونَ كَلِمَةُ اللَّهِ هِيَ الْعُلْيَا فَهُوَ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ ‏"', NULL, 'Narrated Abu Musa:A man came to the Prophet (ﷺ) and asked, "O Allah''s Messenger (ﷺ)! What kind of fighting is in Allah''s cause? (I ask this), for some of us fight because of being enraged and angry and some for the sake of his pride and haughtiness." The Prophet (ﷺ) raised his head (as the questioner was standing) and said, "He who fights so that Allah''s Word (Islam) should be superior, then he fights in Allah''s cause."', 'Narrated Abu Musa', NULL, 'https://sunnah.com/bukhari:123', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 124, 'حَدَّثَنَا أَبُو نُعَيْمٍ، قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ، عَنِ الزُّهْرِيِّ، عَنْ عِيسَى بْنِ طَلْحَةَ، عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو، قَالَ رَأَيْتُ النَّبِيَّ صلى الله عليه وسلم عِنْدَ الْجَمْرَةِ وَهُوَ يُسْأَلُ، فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ نَحَرْتُ قَبْلَ أَنْ أَرْمِيَ‏.‏ قَالَ ‏"‏ ارْمِ وَلاَ حَرَجَ ‏"‏‏.‏ قَالَ آخَرُ يَا رَسُولَ اللَّهِ حَلَقْتُ قَبْلَ أَنْ أَنْحَرَ‏.‏ قَالَ ‏"‏ انْحَرْ وَلاَ حَرَجَ ‏"‏‏.‏ فَمَا سُئِلَ عَنْ شَىْءٍ قُدِّمَ وَلاَ أُخِّرَ إِلاَّ قَالَ افْعَلْ وَلاَ حَرَجَ‏.‏', NULL, 'Narrated `Abdullah bin `Ammar:I saw the Prophet (ﷺ) near the Jamra and the people were asking him questions (about religious problems). A man asked, "O Allah''s Messenger (ﷺ)! I have slaughtered the Hadi (animal) before doing the Rami." The Prophet (ﷺ) replied, "Do the Rami (now) and there is no harm." Another person asked, "O Allah''s Messenger (ﷺ)! I got my head shaved before slaughtering the animal." The Prophet (ﷺ) replied, "Do the slaughtering (now) and there is no harm." So on that day, when the Prophet (ﷺ) was asked about anything as regards the ceremonies of Hajj performed before or after its due time his reply was, "Do it (now) and there is no harm."', 'Narrated `Abdullah bin `Ammar', NULL, 'https://sunnah.com/bukhari:124', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 125, 'حَدَّثَنَا قَيْسُ بْنُ حَفْصٍ، قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ، قَالَ حَدَّثَنَا الأَعْمَشُ، سُلَيْمَانُ عَنْ إِبْرَاهِيمَ، عَنْ عَلْقَمَةَ، عَنْ عَبْدِ اللَّهِ، قَالَ بَيْنَا أَنَا أَمْشِي، مَعَ النَّبِيِّ صلى الله عليه وسلم فِي خَرِبِ الْمَدِينَةِ، وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ مَعَهُ، فَمَرَّ بِنَفَرٍ مِنَ الْيَهُودِ، فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنِ الرُّوحِ‏.‏ وَقَالَ بَعْضُهُمْ لاَ تَسْأَلُوهُ لاَ يَجِيءُ فِيهِ بِشَىْءٍ تَكْرَهُونَهُ‏.‏ فَقَالَ بَعْضُهُمْ لَنَسْأَلَنَّهُ‏.‏ فَقَامَ رَجُلٌ مِنْهُمْ فَقَالَ يَا أَبَا الْقَاسِمِ، مَا الرُّوحُ فَسَكَتَ‏.‏ فَقُلْتُ إِنَّهُ يُوحَى إِلَيْهِ‏.‏ فَقُمْتُ، فَلَمَّا انْجَلَى عَنْهُ، قَالَ ‏{‏وَيَسْأَلُونَكَ عَنِ الرُّوحِ قُلِ الرُّوحُ مِنْ أَمْرِ رَبِّي وَمَا أُوتُيتُمْ مِنَ الْعِلْمِ إِلاَّ قَلِيلاً‏}‏‏.‏ قَالَ الأَعْمَشُ هَكَذَا فِي قِرَاءَتِنَا‏.‏', NULL, 'Narrated `Abdullah:While I was going with the Prophet (ﷺ) through the ruins of Medina and he was reclining on a date-palm leaf stalk, some Jews passed by. Some of them said to the others: Ask him (the Prophet) about the spirit. Some of them said that they should not ask him that question as he might give a reply which would displease them. But some of them insisted on asking, and so one of them stood up and asked, "O Abul-Qasim ! What is the spirit?" The Prophet (ﷺ) remained quiet. I thought he was being inspired Divinely. So I stayed till that state of the Prophet (while being inspired) was over. The Prophet (ﷺ) then said, "And they ask you (O Muhammad) concerning the spirit --Say: The spirit -- its knowledge is with my Lord. And of knowledge you (mankind) have been given only a little)." (17.85)', 'Narrated `Abdullah', NULL, 'https://sunnah.com/bukhari:125', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 126, '"‏ يَا عَائِشَةُ، لَوْلاَ قَوْمُكِ حَدِيثٌ عَهْدُهُمْ ـ قَالَ ابْنُ الزُّبَيْرِ بِكُفْرٍ ـ لَنَقَضْتُ الْكَعْبَةَ فَجَعَلْتُ لَهَا بَابَيْنِ باب يَدْخُلُ النَّاسُ، وَبَابٌ يَخْرُجُونَ ‏"', NULL, 'Narrated Aswad:Ibn Az-Zubair said to me, "Aisha used to tell you secretly a number of things. What did she tell you about the Ka`ba?" I replied, "She told me that once the Prophet (ﷺ) said, ''O `Aisha! Had not your people been still close to the pre-Islamic period of ignorance (infidelity)! I would have dismantled the Ka`ba and would have made two doors in it; one for entrance and the other for exit." Later on Ibn Az-Zubair did the same.', 'Narrated Aswad', NULL, 'https://sunnah.com/bukhari:126', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 127, 'حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ مَعْرُوفِ بْنِ خَرَّبُوذٍ عَنْ أَبِي الطُّفَيْلِ عَنْ عَلِيٍّ بِذَلِكَ‏.‏', NULL, 'Narrated Abu at-Tufail:The above mentioned Statement of `Ali.', 'Narrated Abu at-Tufail', NULL, 'https://sunnah.com/bukhari:127', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 128, 'حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ، قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ، قَالَ حَدَّثَنِي أَبِي، عَنْ قَتَادَةَ، قَالَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ، أَنَّ النَّبِيَّ صلى الله عليه وسلم وَمُعَاذٌ رَدِيفُهُ عَلَى الرَّحْلِ قَالَ ‏"‏ يَا مُعَاذُ بْنَ جَبَلٍ ‏"‏‏.‏ قَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ وَسَعْدَيْكَ‏.‏ قَالَ ‏"‏ يَا مُعَاذُ ‏"‏‏.‏ قَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ وَسَعْدَيْكَ‏.‏ ثَلاَثًا‏.‏ قَالَ ‏"‏ مَا مِنْ أَحَدٍ يَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ صِدْقًا مِنْ قَلْبِهِ إِلاَّ حَرَّمَهُ اللَّهُ عَلَى النَّارِ ‏"‏‏.‏ قَالَ يَا رَسُولَ اللَّهِ، أَفَلاَ أُخْبِرُ بِهِ النَّاسَ فَيَسْتَبْشِرُوا قَالَ ‏"‏ إِذًا يَتَّكِلُوا ‏"‏‏.‏ وَأَخْبَرَ بِهَا مُعَاذٌ عِنْدَ مَوْتِهِ تَأَثُّمًا ‏.‏', NULL, 'Narrated Anas bin Malik:"Once Mu`adh was along with Allah''s Messenger (ﷺ) as a companion rider. Allah''s Messenger (ﷺ) said, "O Mu`adh bin Jabal." Mu`adh replied, "Labbaik and Sa`daik. O Allah''s Messenger (ﷺ)!" Again the Prophet (ﷺ) said, "O Mu`adh!" Mu`adh said thrice, "Labbaik and Sa`daik, O Allah''s Messenger (ﷺ)!" Allah''s Messenger (ﷺ) said, "There is none who testifies sincerely that none has the right to be worshipped but Allah and Muhammad is his Apostle, except that Allah, will save him from the Hell-fire." Mu`adh said, "O Allah''s Messenger (ﷺ) ! Should I not inform the people about it so that they may have glad tidings?" He replied, "When the people hear about it, they will solely depend on it." Then Mu`adh narrated the above-mentioned Hadith just before his death, being afraid of committing sin (by not telling the knowledge).', 'Narrated Anas bin Malik', NULL, 'https://sunnah.com/bukhari:128', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 129, 'حَدَّثَنَا مُسَدَّدٌ، قَالَ حَدَّثَنَا مُعْتَمِرٌ، قَالَ سَمِعْتُ أَبِي قَالَ، سَمِعْتُ أَنَسًا، قَالَ ذُكِرَ لِي أَنَّ النَّبِيَّ صلى الله عليه وسلم قَالَ لِمُعَاذٍ ‏"‏ مَنْ لَقِيَ اللَّهَ لاَ يُشْرِكُ بِهِ شَيْئًا دَخَلَ الْجَنَّةَ ‏"‏‏.‏ قَالَ أَلاَ أُبَشِّرُ النَّاسَ قَالَ ‏"‏ لاَ، إِنِّي أَخَافُ أَنْ يَتَّكِلُوا ‏"‏‏.‏', NULL, 'Narrated Anas:I was informed that the Prophet (ﷺ) had said to Mu`adh, "Whosoever will meet Allah without associating anything in worship with Him will go to Paradise." Mu`adh asked the Prophet, "Should I not inform the people of this good news?" The Prophet (ﷺ) replied, "No, I am afraid, lest they should depend upon it (absolutely).', 'Narrated Anas', NULL, 'https://sunnah.com/bukhari:129', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 130, 'حَدَّثَنَا مُحَمَّدُ بْنُ سَلاَمٍ، قَالَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ، قَالَ حَدَّثَنَا هِشَامٌ، عَنْ أَبِيهِ، عَنْ زَيْنَبَ ابْنَةِ أُمِّ سَلَمَةَ، عَنْ أُمِّ سَلَمَةَ، قَالَتْ جَاءَتْ أُمُّ سُلَيْمٍ إِلَى رَسُولِ اللَّهِ صلى الله عليه وسلم فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ لاَ يَسْتَحْيِي مِنَ الْحَقِّ، فَهَلْ عَلَى الْمَرْأَةِ مِنْ غُسْلٍ إِذَا احْتَلَمَتْ قَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ إِذَا رَأَتِ الْمَاءَ ‏"‏‏.‏ فَغَطَّتْ أُمُّ سَلَمَةَ ـ تَعْنِي وَجْهَهَا ـ وَقَالَتْ يَا رَسُولَ اللَّهِ وَتَحْتَلِمُ الْمَرْأَةُ قَالَ ‏"‏ نَعَمْ تَرِبَتْ يَمِينُكِ فَبِمَ يُشْبِهُهَا وَلَدُهَا ‏"‏‏.‏', NULL, 'Narrated Um Salama:Um-Sulaim came to Allah''s Messenger (ﷺ) and said, "Verily, Allah is not shy of (telling you) the truth. Is it necessary for a woman to take a bath after she has a wet dream (nocturnal sexual discharge?) The Prophet replied, "Yes, if she notices a discharge." Um Salama, then covered her face and asked, "O Allah''s Messenger (ﷺ)! Does a woman get a discharge?" He replied, "Yes, let your right hand be in dust (An Arabic expression you say to a person when you contradict his statement meaning "you will not achieve goodness"), and that is why the son resembles his mother."', 'Narrated Um Salama', NULL, 'https://sunnah.com/bukhari:130', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 131, 'حَدَّثَنَا إِسْمَاعِيلُ، قَالَ حَدَّثَنِي مَالِكٌ، عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ، عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ إِنَّ مِنَ الشَّجَرِ شَجَرَةً لاَ يَسْقُطُ وَرَقُهَا، وَهِيَ مَثَلُ الْمُسْلِمِ، حَدِّثُونِي مَا هِيَ ‏"‏‏.‏ فَوَقَعَ النَّاسُ فِي شَجَرِ الْبَادِيَةِ، وَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ‏.‏ قَالَ عَبْدُ اللَّهِ فَاسْتَحْيَيْتُ‏.‏ فَقَالُوا يَا رَسُولَ اللَّهِ، أَخْبِرْنَا بِهَا‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ هِيَ النَّخْلَةُ ‏"‏‏.‏ قَالَ عَبْدُ اللَّهِ فَحَدَّثْتُ أَبِي بِمَا وَقَعَ فِي نَفْسِي فَقَالَ لأَنْ تَكُونَ قُلْتَهَا أَحَبُّ إِلَىَّ مِنْ أَنْ يَكُونَ لِي كَذَا وَكَذَا‏.‏', NULL, 'Narrated `Abdullah bin `Umar:Once Allah''s Messenger (ﷺ) said, "Amongst the trees there is a tree, the leaves of which do not fall and is like a Muslim, tell me the name of that tree." Everybody started thinking about the trees of the desert areas and I thought of the date-palm tree but felt shy (to answer). The others asked, "O Allah''s Apostle! inform us of it." He replied, "it is the date-palm tree." I told my father what had come to my mind and on that he said, "Had you said it I would have preferred it to such and such a thing that I might possess."', 'Narrated `Abdullah bin `Umar', NULL, 'https://sunnah.com/bukhari:131', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 132, '"‏ فِيهِ الْوُضُوءُ ‏"', NULL, 'Narrated `Ali:I used to get the emotional urethral discharge frequently so I requested Al-Miqdad to ask the Prophet (ﷺ) about it. Al-Miqdad asked him and he replied, "One has to perform ablution (after it)." (See Hadith No. 269).', 'Narrated `Ali', NULL, 'https://sunnah.com/bukhari:132', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 133, 'حَدَّثَنِي قُتَيْبَةُ بْنُ سَعِيدٍ، قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ، قَالَ حَدَّثَنَا نَافِعٌ، مَوْلَى عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ،‏.‏ أَنَّ رَجُلاً، قَامَ فِي الْمَسْجِدِ فَقَالَ يَا رَسُولَ اللَّهِ، مِنْ أَيْنَ تَأْمُرُنَا أَنْ نُهِلَّ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ يُهِلُّ أَهْلُ الْمَدِينَةِ مِنْ ذِي الْحُلَيْفَةِ، وَيُهِلُّ أَهْلُ الشَّأْمِ مِنَ الْجُحْفَةِ، وَيُهِلُّ أَهْلُ نَجْدٍ مِنْ قَرْنٍ ‏"‏‏.‏ وَقَالَ ابْنُ عُمَرَ وَيَزْعُمُونَ أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ وَيُهِلُّ أَهْلُ الْيَمَنِ مِنْ يَلَمْلَمَ ‏"‏‏.‏ وَكَانَ ابْنُ عُمَرَ يَقُولُ لَمْ أَفْقَهْ هَذِهِ مِنْ رَسُولِ اللَّهِ صلى الله عليه وسلم‏.‏', NULL, 'Narrated Nafi`:`Abdullah bin `Umar said: "A man got up in the mosque and said: O Allah''s Messenger (ﷺ) ''At which place you order us that we should assume the Ihram?'' Allah''s Messenger (ﷺ) replied, ''The residents of Medina should assure the Ihram from Dhil-Hulaifa, the people of Syria from Al-Juhfa and the people of Najd from Qarn." Ibn `Umar further said, "The people consider that Allah''s Messenger (ﷺ) had also said, ''The residents of Yemen should assume Ihram from Yalamlam.'' " Ibn `Umar used to say, "I do not: remember whether Allah''s Messenger (ﷺ) had said the last statement or not?"', 'Narrated Nafi`', NULL, 'https://sunnah.com/bukhari:133', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('bukhari', 'Knowledge', 134, '"‏ لاَ يَلْبَسِ الْقَمِيصَ وَلاَ الْعِمَامَةَ وَلاَ السَّرَاوِيلَ وَلاَ الْبُرْنُسَ وَلاَ ثَوْبًا مَسَّهُ الْوَرْسُ أَوِ الزَّعْفَرَانُ، فَإِنْ لَمْ يَجِدِ النَّعْلَيْنِ فَلْيَلْبَسِ الْخُفَّيْنِ وَلْيَقْطَعْهُمَا حَتَّى يَكُونَا تَحْتَ الْكَعْبَيْنِ ‏"', NULL, 'Narrated Ibn `Umar:A man asked the Prophet (ﷺ) : "What (kinds of clothes) should a Muhrim (a Muslim intending to perform `Umra or Hajj) wear? He replied, "He should not wear a shirt, a turban, trousers, a head cloak or garment scented with saffron or Wars (kinds of perfumes). And if he has no slippers, then he can use Khuffs (socks made from thick fabric or leather) but the socks should be cut short so as to make the ankles bare." (See Hadith No. 615, Vol. 2).', 'Narrated Ibn `Umar', NULL, 'https://sunnah.com/bukhari:134', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 267, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ، عَنْ أَبِي رَيْحَانَةَ، عَنْ سَفِينَةَ، قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَتَوَضَّأُ بِالْمُدِّ وَيَغْتَسِلُ بِالصَّاعِ ‏.‏', NULL, 'It was narrated that Safinah said:"The Messenger of Allah used to perform ablution with a Mudd (of water) and bath with a Sa''."', 'It was narrated that Safinah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:267', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 268, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ، عَنْ هَمَّامٍ، عَنْ قَتَادَةَ، عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ، عَنْ عَائِشَةَ، قَالَتْ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَتَوَضَّأُ بِالْمُدِّ وَيَغْتَسِلُ بِالصَّاعِ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah used to perform ablution with a Mudd (of water) and bath with a Sa''."', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:268', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 269, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا الرَّبِيعُ بْنُ بَدْرٍ، حَدَّثَنَا أَبُو الزُّبَيْرِ، عَنْ جَابِرٍ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ كَانَ يَتَوَضَّأُ بِالْمُدِّ وَيَغْتَسِلُ بِالصَّاعِ ‏.‏', NULL, 'It was narrated from Jabir that:The Messenger of Allah used to perform ablution with a Mudd (of water) and bath with a Sa''.', 'It was narrated from Jabir that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:269', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 270, '"‏ يُجْزِئُ مِنَ الْوُضُوءِ مُدٌّ وَمِنَ الْغُسْلِ صَاعٌ ‏"', NULL, '''Abdullah bin Muhammed bin ''Aqil bin Abu Talib narrated from his father that his grandfather said:"The Messenger of Allah said: ''A Mudd is sufficient for the ablution and a Sa'' is sufficient for the bath.'' A man said: ''It is not sufficient for us.''" He (the narrator) said: "It was sufficient for one who is better than you and had more hair" meaning the Prophet.', NULL, 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:270', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 271, '"‏ لاَ يَقْبَلُ اللَّهُ صَلاَةً إِلاَّ بِطُهُورٍ وَلاَ يَقْبَلُ صَدَقَةً مِنْ غُلُولٍ ‏"', NULL, 'It was narrated that Usamah bin ''Umair Al-Hudhali said:"The Messenger of Allah said: ''Allah does not accept any prayer without purification and He does not accept any charity from Ghulul.''" (Sahih) Another chain with similar wording.', 'It was narrated that Usamah bin ''Umair Al-Hudhali said', NULL, 'https://sunnah.com/ibnmajah:271', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 272, '"‏ لاَ يَقْبَلُ اللَّهُ صَلاَةً إِلاَّ بِطُهُورٍ وَلاَ صَدَقَةً مِنْ غُلُولٍ ‏"', NULL, 'It was narrated that Ibn ''Umar said:"The Messenger of Allah said: ''Allah does not accept any prayer without purification, and He does not accept any charity from ghulul.''"', 'It was narrated that Ibn ''Umar said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:272', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 273, '"‏ لاَ يَقْبَلُ اللَّهُ صَلاَةً بِغَيْرِ طُهُورٍ وَلاَ يَقْبَلُ صَدَقَةً مِنْ غُلُولٍ ‏"', NULL, 'It was narrated that Anas bin Malik said:"I heard the Messenger of Allah say: ''Allah does not accept any prayer without purification, and He does not accept any charity from Ghulul.''"', 'It was narrated that Anas bin Malik said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:273', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 274, '"‏ لاَ يَقْبَلُ اللَّهُ صَلاَةً بِغَيْرِ طُهُورٍ وَلاَ صَدَقَةً مِنْ غُلُولٍ ‏"', NULL, 'It was narrated that Abu Bakrah said:"The Messenger of Allah said: ''Allah does not accept any Salat (prayer) without purification, and He does not accept any charity from Ghulul.''"', 'It was narrated that Abu Bakrah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:274', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 275, '"‏ مِفْتَاحُ الصَّلاَةِ الطُّهُورُ وَتَحْرِيمُهَا التَّكْبِيرُ وَتَحْلِيلُهَا التَّسْلِيمُ ‏"', NULL, 'It was narrated from Muhammed bin Al-Hanafiyyah that his father said:"The Messenger of Allah said: ''The key to prayer is purification, its opening is to say ''Allahu Akbar'' and its closing is to say As-salamu ''alaikum.''"', 'It was narrated from Muhammed bin Al-Hanafiyyah that his father said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:275', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 276, '"‏ مِفْتَاحُ الصَّلاَةِ الطُّهُورُ وَتَحْرِيمُهَا التَّكْبِيرُ وَتَحْلِيلُهَا التَّسْلِيمُ ‏"', NULL, 'It was narrated from Abu Sa''eed Al-Khudri that:The Messenger of Allah said: "The key to prayer is purification, its opening is to say Allahu Akbar and its closing is to say As-salamu ''alaikum."', 'It was narrated from Abu Sa''eed Al-Khudri that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:276', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 277, '"‏ اسْتَقِيمُوا وَلَنْ تُحْصُوا وَاعْلَمُوا أَنَّ خَيْرَ أَعْمَالِكُمُ الصَّلاَةُ وَلاَ يُحَافِظُ عَلَى الْوُضُوءِ إِلاَّ مُؤْمِنٌ ‏"', NULL, 'It was narrated that Thawban said:"The Messenger of Allah said: ''Adhere to righteousness even though you will not be able to do all acts of virtue. Know that the best of your deeds is Salat (prayer) and that no one maintains his ablution except a believer.''"', 'It was narrated that Thawban said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:277', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 278, '"‏ اسْتَقِيمُوا وَلَنْ تُحْصُوا وَاعْلَمُوا أَنَّ مِنْ أَفْضَلِ أَعْمَالِكُمُ الصَّلاَةَ وَلاَ يُحَافِظُ عَلَى الْوُضُوءِ إِلاَّ مُؤْمِنٌ ‏"', NULL, 'It was narrated that ''Abdullah bin ''Amr said:"The Messenger of Allah said: ''Adhere to righteousness even though you will not be able to do all acts of virtue. Know that among the best of your deeds is prayer and that no one maintains his ablution except a believer.''"', 'It was narrated that ''Abdullah bin ''Amr said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:278', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 279, '"‏ اسْتَقِيمُوا وَنِعِمَّا أَنْ تَسْتَقِيمُوا وَخَيْرُ أَعْمَالِكُمُ الصَّلاَةُ وَلاَ يُحَافِظُ عَلَى الْوُضُوءِ إِلاَّ مُؤْمِنٌ ‏"', NULL, 'It was narrated that Abu Umamah said, in a marfu'' Hadith:"Adhere to righteousness and it is a blessing if you are able to do so. Know that the best of your deeds is prayer and that no one maintains his ablution except a believer."', 'It was narrated that Abu Umamah said, in a marfu'' Hadith', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:279', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 280, '"‏ إِسْبَاغُ الْوُضُوءِ شَطْرُ الإِيمَانِ وَالْحَمْدُ لِلَّهِ تَمْلأُ الْمِيزَانَ وَالتَّسْبِيحُ وَالتَّكْبِيرُ مِلْءُ السَّمَوَاتِ وَالأَرْضِ وَالصَّلاَةُ نُورٌ وَالزَّكَاةُ بُرْهَانٌ وَالصَّبْرُ ضِيَاءٌ وَالْقُرْآنُ حُجَّةٌ لَكَ أَوْ عَلَيْكَ كُلُّ النَّاسِ يَغْدُو فَبَائِعٌ نَفْسَهُ فَمُعْتِقُهَا أَوْ مُوبِقُهَا ‏"', NULL, 'It was narrated from Abu Malik Ash''ari that:The Messenger of Allah said: "Performing ablution properly is half of faith, saying Al-Hamdu Lillah fills the Scale (of good deeds), saying Subhan-Allah and Allahu Akbar fills the heavens and the earth, prayer is light, Zakat is proof, patience is brightness and the Qur''an is proof for you or against you. Every person goes out in the morning to sell his soul, so he either frees it or destroys it.''"', 'It was narrated from Abu Malik Ash''ari that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:280', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 281, '"‏ إِنَّ أَحَدَكُمْ إِذَا تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ أَتَى الْمَسْجِدَ لاَ يَنْهَزُهُ إِلاَّ الصَّلاَةُ لَمْ يَخْطُ خَطْوَةً إِلاَّ رَفَعَهُ اللَّهُ عَزَّ وَجَلَّ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةً حَتَّى يَدْخُلَ الْمَسْجِدَ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''When anyone of you performs ablution and does it well, then he comes to the mosque for no other purpose than prayer, he does not take one step but Allah will raise him one degree (in status) thereby, and remove one sin from him thereby, until he enters the mosque.''"', 'It was narrated that Abu Hurairah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:281', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 282, '"‏ مَنْ تَوَضَّأَ فَمَضْمَضَ وَاسْتَنْشَقَ خَرَجَتْ خَطَايَاهُ مِنْ فَمِهِ وَأَنْفِهِ فَإِذَا غَسَلَ وَجْهَهُ خَرَجَتْ خَطَايَاهُ مِنْ وَجْهِهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَشْفَارِ عَيْنَيْهِ فَإِذَا غَسَلَ يَدَيْهِ خَرَجَتْ خَطَايَاهُ مِنْ يَدَيْهِ فَإِذَا مَسَحَ رَأْسَهُ خَرَجَتْ خَطَايَاهُ مِنْ رَأْسِهِ حَتَّى تَخْرُجَ مِنْ أُذُنَيْهِ فَإِذَا غَسَلَ رِجْلَيْهِ خَرَجَتْ خَطَايَاهُ مِنْ رِجْلَيْهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَظْفَارِ رِجْلَيْهِ وَكَانَتْ صَلاَتُهُ وَمَشْيُهُ إِلَى الْمَسْجِدِ نَافِلَةً ‏"', NULL, 'It was narrated from ''Abdullah As-Sunabihi that:The Messenger of Allah said: "Whoever performs ablution and rinses his mouth and nose, his sins will exit through his mouth and nose. When he washes his face, his sins will exit from his face, even from beneath his eyelids. When he washes his hands, his sins will exit from his hands. When he wipes his head, his sins will exit from his head, and even from his ears. When he washes his feet, his sins will exit from his feet, even from beneath his toenails. Then his prayer and walking towards the mosque will earn extra merit for him."', 'It was narrated from ''Abdullah As-Sunabihi that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:282', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 283, '"‏ إِنَّ الْعَبْدَ إِذَا تَوَضَّأَ فَغَسَلَ يَدَيْهِ خَرَّتْ خَطَايَاهُ مِنْ يَدَيْهِ فَإِذَا غَسَلَ وَجْهَهُ خَرَّتْ خَطَايَاهُ مِنْ وَجْهِهِ فَإِذَا غَسَلَ ذِرَاعَيْهِ وَمَسَحَ بِرَأْسِهِ خَرَّتْ خَطَايَاهُ مِنْ ذِرَاعَيْهِ وَرَأْسِهِ فَإِذَا غَسَلَ رِجْلَيْهِ خَرَّتْ خَطَايَاهُ مِنْ رِجْلَيْهِ ‏"', NULL, 'It was narrated that ''Amr bin ''Abasah said:"The Messenger of Allah said: ''When a person performs ablution and washes his hands, his sins exit through his hands. When he washes his face, his sins exit through his face. When he washes his forearms and wipes his head, his sins exit though his forearms and head. When he washes his feet, his sins exit through his feet.''"', 'It was narrated that ''Amr bin ''Abasah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:283', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 284, '"‏ غُرٌّ مُحَجَّلُونَ بُلْقٌ مِنْ آثَارِ الطُّهُورِ ‏"', NULL, '''Abdullah bin Mas''ud said:"It was said: ''O Messenger of Allah, how will you recognize those whom you have not seen of your Ummah?'' He said: ''From the blazes of their foreheads and feet, like horses with black and white traces (which make them distinct from others) which are the traces of ablution.''" (Hasan) Another chain with similar wording.', '''Abdullah bin Mas''ud said', NULL, 'https://sunnah.com/ibnmajah:284', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 285, 'حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ، حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ، حَدَّثَنَا الأَوْزَاعِيُّ، حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ، حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ، حَدَّثَنِي شَقِيقُ بْنُ سَلَمَةَ، حَدَّثَنِي حُمْرَانُ، مَوْلَى عُثْمَانَ بْنِ عَفَّانَ قَالَ رَأَيْتُ عُثْمَانَ بْنَ عَفَّانَ قَاعِدًا فِي الْمَقَاعِدِ فَدَعَا بِوَضُوءٍ فَتَوَضَّأَ ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ فِي مَقْعَدِي هَذَا تَوَضَّأَ مِثْلَ وُضُوئِي هَذَا ثُمَّ قَالَ ‏"‏ مَنْ تَوَضَّأَ مِثْلَ وُضُوئِي هَذَا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ ‏"‏ ‏.‏ وَقَالَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ ‏"‏ وَلاَ تَغْتَرُّوا ‏"‏ ‏.‏

حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبٍ، حَدَّثَنَا الأَوْزَاعِيُّ، حَدَّثَنِي يَحْيَى، حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ، حَدَّثَنِي عِيسَى بْنُ طَلْحَةَ، حَدَّثَنِي حُمْرَانُ، عَنْ عُثْمَانَ، عَنِ النَّبِيِّ ـ صلى الله عليه وسلم ـ نَحْوَهُ ‏.‏', NULL, 'Humran the freed slave of ''Uthman bin ''Affan said:"I saw ''Uthman bin ''Affan sitting in Maqa''id. He called for water and he performed ablution, the he said: ''I saw the Messenger of Allah sitting in this place where I am sitting, performing ablution as I have done. Then he said: "Whoever performs ablution as I have done, his previous sins will be forgiven." And the Messenger of Allah said: "And do not be conceited (due to this great virtue)." (Sahih) Another chain with similar wording.', 'Humran the freed slave of ''Uthman bin ''Affan said', NULL, 'https://sunnah.com/ibnmajah:285', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 286, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ، حَدَّثَنَا أَبُو مُعَاوِيَةَ، وَأَبِي، عَنِ الأَعْمَشِ، ح وَحَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، عَنْ سُفْيَانَ، عَنْ مَنْصُورٍ، وَحُصَيْنٍ، عَنْ أَبِي وَائِلٍ، عَنْ حُذَيْفَةَ، قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ إِذَا قَامَ مِنَ اللَّيْلِ يَتَهَجَّدُ يَشُوصُ فَاهُ بِالسِّوَاكِ ‏.‏', NULL, 'It was narrated that Hudhaifah said:"Whenever the Messenger of Allah got up for prayer at night to pray Tahajjud (night optional prayer), he would clean his mouth with the tooth stick."', 'It was narrated that Hudhaifah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:286', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 287, '"‏ لَوْلاَ أَنْ أَشُقَّ عَلَى أُمَّتِي لأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلاَةٍ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''Were it not that it would be too difficult for my Ummah (nation), I would have commanded them to use the tooth stick at every time of prayer.''"', 'It was narrated that Abu Hurairah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:287', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 288, 'حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ، حَدَّثَنَا عَثَّامُ بْنُ عَلِيٍّ، عَنِ الأَعْمَشِ، عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ، عَنْ سَعِيدِ بْنِ جُبَيْرٍ، عَنِ ابْنِ عَبَّاسٍ، قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يُصَلِّي بِاللَّيْلِ رَكْعَتَيْنِ رَكْعَتَيْنِ ثُمَّ يَنْصَرِفُ فَيَسْتَاكُ ‏.‏', NULL, 'It was narrated that Ibn ''Abbas said:"The Messenger of Allah used to pray in the night (Qiyamul-Lail) two Rak''ah by two, then when he finished he would use the tooth stick."', 'It was narrated that Ibn ''Abbas said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:288', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 289, '"‏ تَسَوَّكُوا فَإِنَّ السِّوَاكَ مَطْهَرَةٌ لِلْفَمِ مَرْضَاةٌ لِلرَّبِّ وَمَا جَاءَنِي جِبْرِيلُ إِلاَّ أَوْصَانِي بِالسِّوَاكِ حَتَّى لَقَدْ خَشِيتُ أَنْ يُفْرَضَ عَلَىَّ وَعَلَى أُمَّتِي وَلَوْلاَ أَنِّي أَخَافُ أَنْ أَشُقَّ عَلَى أُمَّتِي لَفَرَضْتُهُ لَهُمْ وَإِنِّي لأَسْتَاكُ حَتَّى لَقَدْ خَشِيتُ أَنْ أُحْفِيَ مَقَادِمَ فَمِي ‏"', NULL, 'It was narrated from Abu Umamah that:The Messenger of Allah said: "Use the tooth stick, for the tooth stick purifies the mouth and is pleasing to the Lord. Jibril never came to me but he advised me to use the tooth stick, until I feared that it would be made obligatory for me and my Ummah. Were it not that I fear that it would be too difficult for my Ummah, I would have enjoined it upon them. And I use the tooth stick until I fear that I may make the front of my mouth sore.'' (i.e. my gums) (or cause my teeth to fall out due to brushing them so often)."', 'It was narrated from Abu Umamah that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:289', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 290, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا شَرِيكٌ، عَنِ الْمِقْدَامِ بْنِ شُرَيْحِ بْنِ هَانِئٍ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ، قَالَ قُلْتُ أَخْبِرِينِي بِأَىِّ، شَىْءٍ كَانَ النَّبِيُّ ـ صلى الله عليه وسلم ـ يَبْدَأُ إِذَا دَخَلَ عَلَيْكِ قَالَتْ كَانَ إِذَا دَخَلَ يَبْدَأُ بِالسِّوَاكِ ‏.‏', NULL, 'It was narrated from Miqdam bin Shuraih bin Hani'' that his father said:"I said to ''Aishah: ''Tell me, what was the first thing that the Messenger of Allah did when he entered upon you?'' She said: ''The first thing he would do would be to use the tooth stick.''"', 'It was narrated from Miqdam bin Shuraih bin Hani'' that his father said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:290', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 291, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ، حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ، حَدَّثَنَا بَحْرُ بْنُ كَنِيزٍ، عَنْ عُثْمَانَ بْنِ سَاجٍ، عَنْ سَعِيدِ بْنِ جُبَيْرٍ، عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ، قَالَ إِنَّ أَفْوَاهَكُمْ طُرُقٌ لِلْقُرْآنِ فَطَيِّبُوهَا بِالسِّوَاكِ ‏.‏', NULL, 'It was narrated that ''Ali bin Abu Talib said:"Your mouths are the paths of the Qur''an, so perfume them with the tooth stick."', 'It was narrated that ''Ali bin Abu Talib said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:291', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 292, '"‏ الْفِطْرَةُ خَمْسٌ - أَوْ خَمْسٌ مِنَ الْفِطْرَةِ - الْخِتَانُ وَالاِسْتِحْدَادُ وَتَقْلِيمُ الأَظْفَارِ وَنَتْفُ الإِبِطِ وَقَصُّ الشَّارِبِ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''The deeds connected to the Fitrah are five (or five things are connected to the Fitrah): circumcision, shaving the pubic hairs, clipping the nails, plucking the armpit hairs and trimming the mustache.''"', 'It was narrated that Abu Hurairah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:292', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 293, '"‏ عَشْرٌ مِنَ الْفِطْرَةِ قَصُّ الشَّارِبِ وَإِعْفَاءُ اللِّحْيَةِ وَالسِّوَاكُ وَالاِسْتِنْشَاقُ بِالْمَاءِ وَقَصُّ الأَظْفَارِ وَغَسْلُ الْبَرَاجِمِ وَنَتْفُ الإِبِطِ وَحَلْقُ الْعَانَةِ وَانْتِقَاصُ الْمَاءِ ‏"', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah said: ''Ten things are connected to the Fitrah: trimming the mustache, letting the beard grow, using the tooth stick, rinsing out the nostrils with water, clipping the nails, washing the joints, plucking the armpit hairs, shaving the pubic hairs, washing the private parts with water.''"(One of the narrators) Zakariyya said: "Mus''ab said: ''I have forgotten the tenth thing, but it may have been rinsing out the mouth.''"', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:293', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 294, '"‏ مِنَ الْفِطْرَةِ الْمَضْمَضَةُ وَالاِسْتِنْشَاقُ وَالسِّوَاكُ وَقَصُّ الشَّارِبِ وَتَقْلِيمُ الأَظْفَارِ وَنَتْفُ الإِبِطِ وَالاِسْتِحْدَادُ وَغَسْلُ الْبَرَاجِمِ وَالاِنْتِضَاحُ وَالاِخْتِتَانُ ‏"', NULL, 'It was narrated from ''Ammar bin Yasir that:The Messenger of Allah said: "Part of the Fitrah is rinsing out the mouth, rinsing out the nostrils, using the tooth stick, trimming the mustache, clipping the nails, plucking the armpit hairs, shaving the pubic hairs, washing the joints, washing the private parts and circumcision.''" (Da''if) Another chain with similar wording.', 'It was narrated from ''Ammar bin Yasir that', NULL, 'https://sunnah.com/ibnmajah:294', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 295, 'حَدَّثَنَا بِشْرُ بْنُ هِلاَلٍ الصَّوَّافُ، حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ، عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ، عَنْ أَنَسِ بْنِ مَالِكٍ، قَالَ وُقِّتَ لَنَا فِي قَصِّ الشَّارِبِ وَحَلْقِ الْعَانَةِ وَنَتْفِ الإِبْطِ وَتَقْلِيمِ الأَظْفَارِ أَنْ لاَ نَتْرُكَ أَكْثَرَ مِنْ أَرْبَعِينَ لَيْلَةً ‏.‏', NULL, 'It was narrated that Anas bin Malik said:"We were given a time limit with regard to trimming the mustache, shaving the pubic hairs, plucking the armpit hairs and clipping the nails. We were not to leave that for more than forty days."', 'It was narrated that Anas bin Malik said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:295', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 296, '"‏ إِنَّ هَذِهِ الْحُشُوشَ مُحْتَضَرَةٌ فَإِذَا دَخَلَ أَحَدُكُمْ فَلْيَقُلِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْخُبُثِ وَالْخَبَائِثِ ‏"', NULL, 'It was narrated that Zaid bin Arqam said:"The Messenger of Allah said: ''These Hushush (waste areas) are visited (by devils), so when anyone of you enters, let him say: ''Allahumma inni a`udhu bika minal-khubthi wal-khaba''ith (O Allah, I seek refuge with You from male and female devils).''" (Sahih) Other chains with similar wording.', 'It was narrated that Zaid bin Arqam said', NULL, 'https://sunnah.com/ibnmajah:296', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 297, '"‏ سِتْرُ مَا بَيْنَ الْجِنِّ وَعَوْرَاتِ بَنِي آدَمَ إِذَا دَخَلَ الْكَنِيفَ أَنْ يَقُولَ بِسْمِ اللَّهِ ‏"', NULL, 'It was narrated that ''Ali said:"The Messenger of Allah said: ''The screen between the Jinn and the nakedness of the sons of Adam is that when a person enters the Kanif, he should say: Bismillah (in the name of Allah).''"', 'It was narrated that ''Ali said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:297', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 298, '"‏ أَعُوذُ بِاللَّهِ مِنَ الْخُبُثِ وَالْخَبَائِثِ ‏"', NULL, 'It was narrated that Anas bin Malik said:"Whenever the Messenger of Allah entered the toilet, he would say: ''A''udhu Billahi minal-khubthi wa''l-khaba''ith (I seek refuge with Allah from male and female devils).''"', 'It was narrated that Anas bin Malik said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:298', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 299, '"‏ لاَ يَعْجِزْ أَحَدُكُمْ إِذَا دَخَلَ مِرْفَقَهُ أَنْ يَقُولَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الرِّجْسِ النَّجَسِ الْخَبِيثِ الْمُخْبِثِ الشَّيْطَانِ الرَّجِيمِ ‏"', NULL, 'It was narrated from Abu Umamah that:The Messenger of Allah said: "None of you should fail to say, when he enters his toilet: ''Allahumma inni a`udhu bika minar-rijsin-najis, al-khabithil-mukhbith, ash-Shaitanir-rajim (O Allah, I seek refuge with You from the filthy and impure, the evil one with evil companions, the accursed Shaitan).''" (Da''if) Another chain with a slightly different wording from Ibn Abi Maryam who mentioned similar, but he did not say in his narration: "Minar-rijsin-najis (From the filthy and the impure)" he only said: "Minal-khabithil-mukhbith, ash-Shaitanir-rajim (From the evil one with evil companions, the accursed Shaitan)."', 'It was narrated from Abu Umamah that', NULL, 'https://sunnah.com/ibnmajah:299', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 300, '"‏ غُفْرَانَكَ ‏"', NULL, 'Yusuf bin Abi Burdah narrated:"I heard my father say: ''I entered upon ''Aishah, and I heard her say: "When the Messenger of Allah exited the toilet, he would say: Ghufranaka (I seek Your forgiveness).''" (Sahih) Another chain with similar wording.', 'Yusuf bin Abi Burdah narrated', NULL, 'https://sunnah.com/ibnmajah:300', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 301, '"‏ الْحَمْدُ لِلَّهِ الَّذِي أَذْهَبَ عَنِّي الأَذَى وَعَافَانِي ‏"', NULL, 'It was narrated that Anas bin Malik said:"Whenever the Prophet exited the toilet, he would say: ''Al-hamdu lillahilladhi adhhaba ''annial-adha wa ''afani (Praise is to Allah Who has relieved me of impurity and given me good health).''"', 'It was narrated that Anas bin Malik said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:301', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 302, 'حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ، حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ، عَنْ أَبِيهِ، عَنْ خَالِدِ بْنِ سَلَمَةَ، عَنْ عَبْدِ اللَّهِ الْبَهِيِّ، عَنْ عُرْوَةَ، عَنْ عَائِشَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ كَانَ يَذْكُرُ اللَّهَ عَلَى كُلِّ أَحْيَانِهِ ‏.‏', NULL, '''Urwah narrated from ''Aishah that:The Messenger of Allah used to remember Allah in all circumstances.', '''Urwah narrated from ''Aishah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:302', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 303, 'حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ، حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ، حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى، عَنِ ابْنِ جُرَيْجٍ، عَنِ الزُّهْرِيِّ، عَنْ أَنَسِ بْنِ مَالِكٍ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ كَانَ إِذَا دَخَلَ الْخَلاَءَ وَضَعَ خَاتَمَهُ ‏.‏', NULL, 'It was narrated from Anas bin Malik that:When the Prophet entered the toilet, he would take off his ring.', 'It was narrated from Anas bin Malik that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:303', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 304, '"‏ لاَ يَبُولَنَّ أَحَدُكُمْ فِي مُسْتَحَمِّهِ فَإِنَّ عَامَّةَ الْوَسْوَاسِ مِنْهُ ‏"', NULL, 'It was narrated that ''Abdullah bin Mughaffal said:"The Messenger of Allah said: ''None of you should urinate in his wash area for most of the insinuating thoughts come from that.''" (Da''if) Abu ''Abdullah bin Majah said: ("Abul-Hasan said: ''I heard Muhammed bin Yazid saying:) ''''Ali bin Muhammed At-Tanafisi said: ''This (prohibition) applies to cases where the ground (in the place used for washing) was soft. But nowadays this does not apply, because the baths you use now are built of plaster, Saruj and tar; so if a person urinates there then pours water over it, that clears it away, and that is fine.''"', 'It was narrated that ''Abdullah bin Mughaffal said', NULL, 'https://sunnah.com/ibnmajah:304', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 305, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا شَرِيكٌ، وَهُشَيْمٌ، وَوَكِيعٌ، عَنِ الأَعْمَشِ، عَنْ أَبِي وَائِلٍ، عَنْ حُذَيْفَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ أَتَى سُبَاطَةَ قَوْمٍ فَبَالَ عَلَيْهَا قَائِمًا ‏.‏', NULL, 'It was narrated from Hudhaifah that:The Messenger of Allah came to the garbage dump of some people and he urinated on it standing up.', 'It was narrated from Hudhaifah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:305', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 306, 'حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ، حَدَّثَنَا أَبُو دَاوُدَ، حَدَّثَنَا شُعْبَةُ، عَنْ عَاصِمٍ، عَنْ أَبِي وَائِلٍ، عَنِ الْمُغِيرَةِ بْنِ شُعْبَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ أَتَى سُبَاطَةَ قَوْمٍ فَبَالَ قَائِمًا ‏.‏
قَالَ شُعْبَةُ قَالَ عَاصِمٌ يَوْمَئِذٍ وَهَذَا الأَعْمَشُ يَرْوِيهِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ وَمَا حَفِظَهُ ‏.‏ فَسَأَلْتُ عَنْهُ مَنْصُورًا فَحَدَّثَنِيهِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ أَتَى سُبَاطَةَ قَوْمٍ فَبَالَ قَائِمًا ‏.‏', NULL, 'Shu''bah narrated from ''Asim from Abu Wa''il from Mughirah bin Shu''bah that:The Messenger of Allah came to the garbage dump of some people and urinated while standing up. (Hasan) Shu''bah said: "That day, ''Asim said: ''Amash reported this from Abu Wa''il, from Hudhaifah, but he did not remember it (correctly). So I asked Mansur about it, and he narrated it to me from Abu Wa''il, from Hudhaifah, that the Prophet came to a dump of some people and urinated while standing.''"', 'Shu''bah narrated from ''Asim from Abu Wa''il from Mughirah bin Shu''bah that', NULL, 'https://sunnah.com/ibnmajah:306', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 307, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَسُوَيْدُ بْنُ سَعِيدٍ، وَإِسْمَاعِيلُ بْنُ مُوسَى السُّدِّيُّ، قَالُوا حَدَّثَنَا شَرِيكٌ، عَنِ الْمِقْدَامِ بْنِ شُرَيْحِ بْنِ هَانِئٍ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ، قَالَتْ مَنْ حَدَّثَكَ أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ بَالَ قَائِمًا فَلاَ تُصَدِّقْهُ أَنَا رَأَيْتُهُ يَبُولُ قَاعِدًا ‏.‏', NULL, 'It was narrated that ''Aishah said:"If anyone tells you that the Messenger of Allah urinated while standing, do not believe him, for I (always) saw him urinating while sitting down."', 'It was narrated that ''Aishah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:307', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 308, '"‏ يَا عُمَرُ لاَ تَبُلْ قَائِمًا ‏"', NULL, 'It was narrated that ''Umar said:"The Messenger of Allah saw me urinating while standing, and he said: ''O ''Umar, do not urinate standing up.'' So I never urinated whilst standing after that."', 'It was narrated that ''Umar said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:308', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 309, 'حَدَّثَنَا يَحْيَى بْنُ الْفَضْلِ، حَدَّثَنَا أَبُو عَامِرٍ، حَدَّثَنَا عَدِيُّ بْنُ الْفَضْلِ، عَنْ عَلِيِّ بْنِ الْحَكَمِ، عَنْ أَبِي نَضْرَةَ، عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ، قَالَ نَهَى رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ أَنْ يَبُولَ قَائِمًا ‏.‏
سَمِعْتُ مُحَمَّدَ بْنَ يَزِيدَ أَبَا عَبْدِ اللَّهِ يَقُولُ سَمِعْتُ أَحْمَدَ بْنَ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيَّ يَقُولُ قَالَ سُفْيَانُ الثَّوْرِيُّ - فِي حَدِيثِ عَائِشَةَ أَنَا رَأَيْتُهُ يَبُولُ قَاعِدًا - قَالَ الرَّجُلُ أَعْلَمُ بِهَذَا مِنْهَا ‏.‏
قَالَ أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ كَانَ مِنْ شَأْنِ الْعَرَبِ الْبَوْلُ قَائِمًا أَلاَ تَرَاهُ فِي حَدِيثِ عَبْدِ الرَّحْمَنِ ابْنِ حَسَنَةَ يَقُولُ قَعَدَ يَبُولُ كَمَا تَبُولُ الْمَرْأَةُ ‏.‏', NULL, 'It was narrated that Jabir bin ''Abdullah said:"The Messenger of Allah forbade us to urinate while standing." (Da''if) I heard Muhammed bin Yazid, Abu ''Abdullah, say: "I heard Ahmad bin ''Abdur-Rahman Al-Makhzumi say: ''Sufyan Ath-Thawri said concerning the Hadith of ''Aisha- ''I (always) saw him urinating whilst sitting down'' - a man knows more about that (about such matters) than she.'' Ahmad bin ''Abdur-Rahman said: ''It was the custom of the Arabs to urinate standing up. Do you not see that in the Hadith of ''Abdur-Rahman bin Hasanah it was said: ''He sits down to urinate as a woman does.''"', 'It was narrated that Jabir bin ''Abdullah said', NULL, 'https://sunnah.com/ibnmajah:309', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 310, '"‏ إِذَا بَالَ أَحَدُكُمْ فَلاَ يَمَسَّ ذَكَرَهُ بِيَمِينِهِ وَلاَ يَسْتَنْجِ بِيَمِينِهِ ‏"', NULL, '''Abdullah bin Abu Qatadah said:"My father told me that he heard the Messenger of Allah say: ''When anyone of you urinates, let him not touch his penis with his right hand nor clean himself with his right hand.''" Another chain with similar wording.', '''Abdullah bin Abu Qatadah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:310', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 311, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، حَدَّثَنَا الصَّلْتُ بْنُ دِينَارٍ، عَنْ عُقْبَةَ بْنِ صُهْبَانَ، قَالَ سَمِعْتُ عُثْمَانَ بْنَ عَفَّانَ، يَقُولُ مَا تَغَنَّيْتُ وَلاَ تَمَنَّيْتُ وَلاَ مَسِسْتُ ذَكَرِي بِيَمِينِي مُنْذُ بَايَعْتُ بِهَا رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ ‏.‏', NULL, 'It was narrated that ''Uqbah bin Suhban said:"I heard ''Uthman bin ''Affan say: ''I never sang a song or told a lie or touched my penis with my right hand after I swore on oath of allegiance to the Messenger of Allah to that effect.''"', 'It was narrated that ''Uqbah bin Suhban said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:311', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 312, '"‏ إِذَا اسْتَطَابَ أَحَدُكُمْ فَلاَ يَسْتَطِبْ بِيَمِينِهِ لِيَسْتَنْجِ بِشِمَالِهِ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''When anyone of you cleans himself, he should not clean himself with his right hand. Let him clean himself with his left hand.''"', 'It was narrated that Abu Hurairah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:312', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 313, '"‏ إِنَّمَا أَنَا لَكُمْ مِثْلُ الْوَالِدِ لِوَلَدِهِ أُعَلِّمُكُمْ إِذَا أَتَيْتُمُ الْغَائِطَ فَلاَ تَسْتَقْبِلُوا الْقِبْلَةَ وَلاَ تَسْتَدْبِرُوهَا ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''I am to you like a father to his son, and I teach you. So when you go to relieve yourselves, do not face the Qiblah or turn your backs towards it.'' He ordered us to use three pebbles, and he forbade us to use dung and bones, and he forbade cleaning oneself with the right hand."', 'It was narrated that Abu Hurairah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:313', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 314, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلاَّدٍ الْبَاهِلِيُّ، حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ، عَنْ زُهَيْرٍ، عَنْ أَبِي إِسْحَاقَ، - قَالَ لَيْسَ أَبُو عُبَيْدَةَ ذَكَرَهُ وَلَكِنْ عَبْدُ الرَّحْمَنِ بْنُ الأَسْوَدِ - عَنِ الأَسْوَدِ، عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ أَتَى الْخَلاَءَ فَقَالَ ‏"‏ ائْتِنِي بِثَلاَثَةِ أَحْجَارٍ ‏"‏ ‏.‏ فَأَتَيْتُهُ بِحَجَرَيْنِ وَرَوْثَةٍ فَأَخَذَ الْحَجَرَيْنِ وَأَلْقَى الرَّوْثَةَ وَقَالَ ‏"‏ هِيَ رِجْسٌ ‏"‏ ‏.‏', NULL, 'It was narrated from ''Abdullah bin Mas''ud:"The Messenger of Allah went to the toilet and said: ''Bring me three stones.'' So I brought him two stones and a piece of dung. He took the two stones and threw the dung away, saying: ''It is impure.''"', 'It was narrated from ''Abdullah bin Mas''ud', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:314', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 315, '"‏ فِي الاِسْتِنْجَاءِ ثَلاَثَةُ أَحْجَارٍ لَيْسَ فِيهَا رَجِيعٌ ‏"', NULL, 'It was narrated that Khuzaimah bin Thabit said:"The Messenger of Allah said: ''For cleaning yourself you need three stones, no one of them being dung.''"', 'It was narrated that Khuzaimah bin Thabit said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:315', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 316, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، عَنِ الأَعْمَشِ، ح وَحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا عَبْدُ الرَّحْمَنِ، حَدَّثَنَا سُفْيَانُ، عَنْ مَنْصُورٍ، وَالأَعْمَشِ، عَنْ إِبْرَاهِيمَ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ، عَنْ سَلْمَانَ، قَالَ قَالَ لَهُ بَعْضُ الْمُشْرِكِينَ وَهُمْ يَسْتَهْزِئُونَ بِهِ إِنِّي أَرَى صَاحِبَكُمْ يُعَلِّمُكُمْ كُلَّ شَىْءٍ حَتَّى الْخِرَاءَةِ ‏.‏ قَالَ أَجَلْ أَمَرَنَا أَنْ لاَ نَسْتَقْبِلَ الْقِبْلَةَ وَأَنْ لاَ نَسْتَنْجِيَ بِأَيْمَانِنَا وَلاَ نَكْتَفِيَ بِدُونِ ثَلاَثَةِ أَحْجَارٍ لَيْسَ فِيهَا رَجِيعٌ وَلاَ عَظْمٌ ‏.‏', NULL, 'Salman said that one of the idolaters said to him, while they were making fun of him:"I see that your companion (the Prophet) is teaching you everything, even how to relieve yourselves?" He said: "Yes indeed. He has ordered us not to face the Qiblah (prayer direction) nor to clean ourselves with our right hands, and not to be content with anything less than three stones, which are not to include any excrement or bones."', NULL, 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:316', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 317, '"‏ لاَ يَبُولَنَّ أَحَدُكُمْ مُسْتَقْبِلَ الْقِبْلَةِ ‏"', NULL, '''Abdullah bin Harith bin Jaz'' Az-Zubaidi said:"I am the first one who heard the Prophet say: ''No one among you should urinate facing towards the Qiblah,'' and I am the first one who told the people of that."', '''Abdullah bin Harith bin Jaz'' Az-Zubaidi said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:317', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 318, '"‏ شَرِّقُوا أَوْ غَرِّبُوا ‏"', NULL, 'It was narrated that Abu Ayyub Ansari said:"The Messenger of Allah forbade the person who went to the Gha''it to face the Qiblah. He said: ''face towards the east or the west.''"', 'It was narrated that Abu Ayyub Ansari said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:318', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 319, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ، عَنْ سُلَيْمَانَ بْنِ بِلاَلٍ، حَدَّثَنِي عَمْرُو بْنُ يَحْيَى الْمَازِنِيُّ، عَنْ أَبِي زَيْدٍ، مَوْلَى الثَّعْلَبِيِّينَ عَنْ مَعْقِلِ بْنِ أَبِي مَعْقِلٍ الأَسَدِيِّ، وَقَدْ صَحِبَ النَّبِيَّ ـ صلى الله عليه وسلم ـ قَالَ نَهَى رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ أَنْ نَسْتَقْبِلَ الْقِبْلَتَيْنِ بِغَائِطٍ أَوْ بِبَوْلٍ ‏.‏', NULL, 'It was narrated that Ma''qil bin Abu Ma''qil Al-Asadi, who was a Companion of the Prophet, said:"The Messenger of Allah forbade us from facing either of the two Qiblah when defecating or urinating."', NULL, 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:319', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 320, 'حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ، حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ، حَدَّثَنَا ابْنُ لَهِيعَةَ، عَنْ أَبِي الزُّبَيْرِ، عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ، حَدَّثَنِي أَبُو سَعِيدٍ الْخُدْرِيُّ، أَنَّهُ شَهِدَ عَلَى رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ أَنَّهُ نَهَى أَنْ نَسْتَقْبِلَ الْقِبْلَةَ بِغَائِطٍ أَوْ بِبَوْلٍ ‏.‏', NULL, 'It was narrated from Jabir bin ''Abdullah:"Abu Sa''eed Al-Khudri narrated to me, that he bears witness that the Messenger of Allah forbade facing the Qiblah when defecating or urinating.''"', 'It was narrated from Jabir bin ''Abdullah', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:320', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 321, 'قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ وَحَدَّثَنَاهُ أَبُو سَعْدٍ، عُمَيْرُ بْنُ مِرْدَاسٍ الدَّوْنَقِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ أَبُو يَحْيَى الْبَصْرِيُّ، حَدَّثَنَا ابْنُ لَهِيعَةَ، عَنْ أَبِي الزُّبَيْرِ، عَنْ جَابِرٍ، أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ، يَقُولُ إِنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ نَهَانِي أَنْ أَشْرَبَ قَائِمًا وَأَنْ أَبُولَ مُسْتَقْبِلَ الْقِبْلَةِ ‏.‏', NULL, 'It was narrated that Jabir heard Abu Sa''eed Al-Khudri say:"The Messenger of Allah forbade me from drinking while standing and from urinating while facing the Qiblah."', 'It was narrated that Jabir heard Abu Sa''eed Al-Khudri say', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:321', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 322, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبٍ، حَدَّثَنَا الأَوْزَاعِيُّ، حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ الأَنْصَارِيُّ، ح وَحَدَّثَنَا أَبُو بَكْرِ بْنُ خَلاَّدٍ، وَمُحَمَّدُ بْنُ يَحْيَى، قَالاَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ، أَنْبَأَنَا يَحْيَى بْنُ سَعِيدٍ، أَنَّ مُحَمَّدَ بْنَ يَحْيَى بْنِ حَبَّانَ، أَخْبَرَهُ أَنَّ عَمَّهُ وَاسِعَ بْنَ حَبَّانَ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ يَقُولُ أُنَاسٌ إِذَا قَعَدْتَ لِلْغَائِطِ فَلاَ تَسْتَقْبِلِ الْقِبْلَةَ وَلَقَدْ ظَهَرْتُ ذَاتَ يَوْمٍ مِنَ الأَيَّامِ عَلَى ظَهْرِ بَيْتِنَا فَرَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ قَاعِدًا عَلَى لَبِنَتَيْنِ مُسْتَقْبِلَ بَيْتِ الْمَقْدِسِ ‏.‏ هَذَا حَدِيثُ يَزِيدَ بْنِ هَارُونَ ‏.‏', NULL, '''Abdullah bin ''Umar said:"People say: ''When you sit to relieve yourself, do not face the Qiblah.'' But one day I climbed up onto the roof of our house, and I saw the Messenger of Allah sitting on two bricks (to relieve himself), facing the direction of Baitul-Maqdis (Jerusalem)." This is a Hadith narrated by Yazid bin Harun.', '''Abdullah bin ''Umar said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:322', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 323, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى، عَنْ عِيسَى الْحَنَّاطِ، عَنْ نَافِعٍ، عَنِ ابْنِ عُمَرَ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ فِي كَنِيفِهِ مُسْتَقْبِلَ الْقِبْلَةِ ‏.
‏ قَالَ عِيسَى فَقُلْتُ ذَلِكَ لِلشَّعْبِيِّ فَقَالَ صَدَقَ ابْنُ عُمَرَ وَصَدَقَ أَبُو هُرَيْرَةَ أَمَّا قَوْلُ أَبِي هُرَيْرَةَ فَقَالَ فِي الصَّحْرَاءِ لاَ يَسْتَقْبِلِ الْقِبْلَةَ وَلاَ يَسْتَدْبِرْهَا وَأَمَّا قَوْلُ ابْنِ عُمَرَ فَإِنَّ الْكَنِيفَ لَيْسَ فِيهِ قِبْلَةٌ اسْتَقْبِلْ فِيهِ حَيْثُ شِئْتَ ‏.‏

قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ وَحَدَّثَنَا أَبُو حَاتِمٍ، حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى، فَذَكَرَ نَحْوَهُ ‏.‏', NULL, 'It was narrated that Ibn ''Umar said:"I saw the Messenger of Allah in his (constructed) toilet, facing towards the Qiblah." (Da''if) (One of the narrators) ''Eisa said: "I told that to Sha''bi, and he said: ''Ibn ''Umar spoke the truth. As for the words of Abu Hurairah, he said: "In the desert do not face the Qiblah nor turn one''s back towards it." As for the words of Ibn ''Umar, he said: "In the (constructed) toilet there is no Qiblah so turn in whatever direction you want." Another chain with similar wording.', 'It was narrated that Ibn ''Umar said', NULL, 'https://sunnah.com/ibnmajah:323', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 324, '"‏ أُرَاهُمْ قَدْ فَعَلُوهَا اسْتَقْبِلُوا بِمَقْعَدَتِي الْقِبْلَةَ ‏"', NULL, 'It was narrated that ''Aishah said:"Mention was made in the presence of the Messenger of Allah of some people who did not like to face towards the Qiblah with their private parts. He said: ''I think that they do that. Turn my seat (in the toilet) to face the Qiblah.''" (Da''if) Another chain with similar wording.', 'It was narrated that ''Aishah said', NULL, 'https://sunnah.com/ibnmajah:324', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 325, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ، حَدَّثَنَا أَبِي قَالَ، سَمِعْتُ مُحَمَّدَ بْنَ إِسْحَاقَ، عَنْ أَبَانَ بْنِ صَالِحٍ، عَنْ مُجَاهِدٍ، عَنْ جَابِرٍ، قَالَ نَهَى رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ أَنْ نَسْتَقْبِلَ الْقِبْلَةَ بِبَوْلٍ فَرَأَيْتُهُ قَبْلَ أَنْ يُقْبَضَ بِعَامٍ يَسْتَقْبِلُهَا ‏.‏', NULL, 'It was narrated that Jabir said:"The Messenger of Allah forbade facing the Qiblah when urinating. But I saw him, one year before he died, facing the Qiblah (while urinating)."', 'It was narrated that Jabir said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:325', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 326, '"‏ إِذَا بَالَ أَحَدُكُمْ فَلْيَنْتُرْ ذَكَرَهُ ثَلاَثَ مَرَّاتٍ ‏"', NULL, 'It was narrated from ''Eisa bin Yazdad Al-Yamani that his father said:"The Messenger of Allah said: ''When anyone of you urinates, let him squeeze his penis three times (to remove the remaining urine drops)." (Da''if) Another chain with similar wording.', 'It was narrated from ''Eisa bin Yazdad Al-Yamani that his father said', NULL, 'https://sunnah.com/ibnmajah:326', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 327, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو أُسَامَةَ، عَنْ عَبْدِ اللَّهِ بْنِ يَحْيَى التَّوْأَمِ، عَنِ ابْنِ أَبِي مُلَيْكَةَ، عَنْ أُمِّهِ، عَنْ عَائِشَةَ، قَالَتِ انْطَلَقَ النَّبِيُّ ـ صلى الله عليه وسلم ـ يَبُولُ فَاتَّبَعَهُ عُمَرُ بِمَاءٍ فَقَالَ ‏"‏ مَا هَذَا يَا عُمَرُ ‏"‏ ‏.‏ قَالَ مَاءٌ ‏.‏ قَالَ ‏"‏ مَا أُمِرْتُ كُلَّمَا بُلْتُ أَنْ أَتَوَضَّأَ وَلَوْ فَعَلْتُ لَكَانَتْ سُنَّةً ‏"‏ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Prophet went out to urinate, and ''Umar followed him with water. He said: ''What is this, O ''Umar?'' He said: ''Water.'' He said: ''I have not been commanded to perform ablution every time I urinate. If I did that it would have become a Sunnah.''"', 'It was narrated that ''Aishah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:327', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 328, '"‏ اتَّقُوا الْمَلاَعِنَ الثَّلاَثَ الْبَرَازَ فِي الْمَوَارِدِ وَالظِّلِّ وَقَارِعَةِ الطَّرِيقِ ‏"', NULL, 'Abu Sa''eed Al-Himyari narrated that :Mu''adh bin Jabal used to narrate something that the Companions of the Messenger of Allah had not heard, and he used to keep quiet about what they had heard. News of this report reached ''Abdullah bin ''Amr, and he said: "By Allah, I never heard the Messenger of Allah say this, and Mu''adh will put you into difficulty with regard to relieving yourself." News of that reached Mu''adh, so he met with him (''Abdullah). Mu''adh said: "O ''Abdullah! Denying a Hadith from the Messenger of Allah is hypocrisy, and its sn is upon the one who said it (if it is not true). I did indeed hear the Messenger of Allah say: ''Beware of the three things which provoke curses: Relieving oneself in watering places, in places of shade and in the middle of the street.''"', 'Abu Sa''eed Al-Himyari narrated that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:328', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 329, '"‏ إِيَّاكُمْ وَالتَّعْرِيسَ عَلَى جَوَادِّ الطَّرِيقِ وَالصَّلاَةَ عَلَيْهَا فَإِنَّهَا مَأْوَى الْحَيَّاتِ وَالسِّبَاعِ وَقَضَاءَ الْحَاجَةِ عَلَيْهَا فَإِنَّهَا مِنَ الْمَلاَعِنِ ‏"', NULL, 'It was narrated that Jabir bin ''Abdullah said:"The Messenger of Allah said: ''Beware of stopping to rest and praying in the middle of the road, for it is the refuge of snakes and carnivorous animals, and beware of relieving yourselves in the middle of the road, for this is an act that provokes curses.''"', 'It was narrated that Jabir bin ''Abdullah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:329', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 330, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ، حَدَّثَنَا ابْنُ لَهِيعَةَ، عَنْ قُرَّةَ، عَنِ ابْنِ شِهَابٍ، عَنْ سَالِمٍ، عَنْ أَبِيهِ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ نَهَى أَنْ يُصَلَّى عَلَى قَارِعَةِ الطَّرِيقِ أَوْ يُضْرَبَ الْخَلاَءُ عَلَيْهَا أَوْ يُبَالَ فِيهَا ‏.‏', NULL, 'Salim narrated from his father that:The Prophet forbade praying in the middle of the road, or defecating there, or urinating.', 'Salim narrated from his father that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:330', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 331, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا إِسْمَاعِيلُ ابْنُ عُلَيَّةَ، عَنْ مُحَمَّدِ بْنِ عَمْرٍو، عَنْ أَبِي سَلَمَةَ، عَنِ الْمُغِيرَةِ بْنِ شُعْبَةَ، قَالَ كَانَ النَّبِيُّ ـ صلى الله عليه وسلم ـ إِذَا ذَهَبَ الْمَذْهَبَ أَبْعَدَ ‏.‏', NULL, 'It was narrated that Mugirah bin Shu''bah said:"Whenever the Prophet went to relieve himself, he would go far away."', 'It was narrated that Mugirah bin Shu''bah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:331', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 332, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ، حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ، عَنْ عُمَرَ بْنِ الْمُثَنَّى، عَنْ عَطَاءٍ الْخُرَاسَانِيِّ، عَنْ أَنَسٍ، قَالَ كُنْتُ مَعَ النَّبِيِّ ـ صلى الله عليه وسلم ـ فِي سَفَرٍ فَتَنَحَّى لِحَاجَتِهِ ثُمَّ جَاءَ فَدَعَا بِوَضُوءٍ فَتَوَضَّأَ ‏.‏', NULL, 'It was narrated that Anas said:"I was with the Prophet on a journey. He went away to relieve himself, then he came and called for water and performed ablution."', 'It was narrated that Anas said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:332', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 333, 'حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ، حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ، عَنِ ابْنِ خُثَيْمٍ، عَنْ يُونُسَ بْنِ خَبَّابٍ، عَنْ يَعْلَى بْنِ مُرَّةَ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ كَانَ إِذَا ذَهَبَ إِلَى الْغَائِطِ أَبْعَدَ ‏.‏', NULL, 'It was narrated from Ya''la bin Murrah that:When the Prophet went to relieve himself, he would go far away.', 'It was narrated from Ya''la bin Murrah that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:333', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 334, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَمُحَمَّدُ بْنُ بَشَّارٍ، قَالاَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ، عَنْ أَبِي جَعْفَرٍ الْخَطْمِيِّ، - قَالَ أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَاسْمُهُ عُمَيْرُ بْنُ يَزِيدَ - عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ، وَالْحَارِثِ بْنِ فُضَيْلٍ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي قُرَادٍ، قَالَ حَجَجْتُ مَعَ النَّبِيِّ ـ صلى الله عليه وسلم ـ فَذَهَبَ لِحَاجَتِهِ فَأَبْعَدَ ‏.‏', NULL, 'It was narrated that ''Abdur-Rahman bin Abu Qurad said:"I went for Hajj with the Prophet and he went far away to relieve himself."', 'It was narrated that ''Abdur-Rahman bin Abu Qurad said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:334', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 335, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى، أَنْبَأَنَا إِسْمَاعِيلُ بْنُ عَبْدِ الْمَلِكِ، عَنْ أَبِي الزُّبَيْرِ، عَنْ جَابِرٍ، قَالَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ فِي سَفَرٍ وَكَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ لاَ يَأْتِي الْبَرَازَ حَتَّى يَتَغَيَّبَ فَلاَ يُرَى ‏.‏', NULL, 'It was narrated that Jabir said:"We went out on a journey with the Messenger of Allah, and the Messenger of Allah would not relieve himself until he had disappeared and could not be seen by anyone."', 'It was narrated that Jabir said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:335', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 336, 'حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ كَثِيرِ بْنِ جَعْفَرٍ، حَدَّثَنَا كَثِيرُ بْنُ عَبْدِ اللَّهِ الْمُزَنِيُّ، عَنْ أَبِيهِ، عَنْ جَدِّهِ، عَنْ بِلاَلِ بْنِ الْحَارِثِ الْمُزَنِيِّ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ كَانَ إِذَا أَرَادَ الْحَاجَةَ أَبْعَدَ ‏.‏', NULL, 'It was narrated from Bilal bin Al-Harith Al-Muzani that:When the Messenger of Allah wanted to relieve himself, he would go far away.', 'It was narrated from Bilal bin Al-Harith Al-Muzani that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:336', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 337, '"‏ مَنِ اسْتَجْمَرَ فَلْيُوتِرْ مَنْ فَعَلَ ذَلِكَ فَقَدْ أَحْسَنَ وَمَنْ لاَ فَلاَ حَرَجَ وَمَنْ تَخَلَّلَ فَلْيَلْفِظْ وَمَنْ لاَكَ فَلْيَبْتَلِعْ مَنْ فَعَلَ ذَلِكَ فَقَدْ أَحْسَنَ وَمَنْ لاَ فَلاَ حَرَجَ وَمَنْ أَتَى الْخَلاَءَ فَلْيَسْتَتِرْ فَإِنْ لَمْ يَجِدْ إِلاَّ كَثِيبًا مِنْ رَمْلٍ فَلْيَمْدُدْهُ عَلَيْهِ فَإِنَّ الشَّيْطَانَ يَلْعَبُ بِمَقَاعِدِ ابْنِ آدَمَ مَنْ فَعَلَ فَقَدْ أَحْسَنَ وَمَنْ لاَ فَلاَ حَرَجَ ‏"', NULL, 'It was narrated from Abu Hurairah that:The Prophet said: "Whoever uses stones to clean himself, let him use an odd number of stones. Whoever does that has done well, and whoever does not, there is no harm in it. Whoever uses a tooth stick should spit out (whatever he removes) and whoever removes (the particle of food) by dislodging it with his tongue should swallow it. Whoever does that has done well, and whoever does not, tere is no harm in it. Whoever goes to the toilet should conceal himself, and if he cannot find anything except a pile of sand (behind which to conceal himself), then he should use that, for the Shaitan plays with the backside of the son of Adam. Whoever does that has done well, and whoever does not, there is no harm in it."', 'It was narrated from Abu Hurairah that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:337', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 338, '"‏ وَمَنِ اكْتَحَلَ فَلْيُوتِرْ مَنْ فَعَلَ فَقَدْ أَحْسَنَ وَمَنْ لاَ فَلاَ حَرَجَ وَمَنْ لاَكَ فَلْيَبْتَلِعْ ‏"', NULL, 'A similar report was narrated by ''Abdul-Malik bin As-Sabbah with a similar chain, with the additional words:"Whoever applies kohl to his eyes, let him add it an odd number of times. Whoever does that has done well, and whoever does not, there is no harm in it. And whoever dislodges (a particle of food from between the teeth) by dislodging it with his tongue, let him swallow it."', NULL, 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:338', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 339, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، عَنِ الأَعْمَشِ، عَنِ الْمِنْهَالِ بْنِ عَمْرٍو، عَنْ يَعْلَى بْنِ مُرَّةَ، عَنْ أَبِيهِ، قَالَ كُنْتُ مَعَ النَّبِيِّ ـ صلى الله عليه وسلم ـ فِي سَفَرٍ فَأَرَادَ أَنْ يَقْضِيَ حَاجَتَهُ فَقَالَ لِي ‏"‏ ائْتِ تِلْكَ الأَشَاءَتَيْنِ ‏"‏ ‏.‏ - قَالَ وَكِيعٌ يَعْنِي النَّخْلَ الصِّغَارَ ‏.‏ قَالَ أَبُو بَكْرٍ الْقِصَارَ - ‏"‏ فَقُلْ لَهُمَا إِنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ يَأْمُرُكُمَا أَنْ تَجْتَمِعَا ‏"‏ ‏.‏ فَاجْتَمَعَتَا فَاسْتَتَرَ بِهِمَا فَقَضَى حَاجَتَهُ ثُمَّ قَالَ لِي ‏"‏ ائْتِهِمَا فَقُلْ لَهُمَا لِتَرْجِعْ كُلُّ وَاحِدَةٍ مِنْكُمَا إِلَى مَكَانِهَا ‏"‏ ‏.‏ فَقُلْتُ لَهُمَا فَرَجَعَتَا ‏.‏', NULL, 'It was narrated from Ya''la bin Murrah that his father said:"I was with the Prophet on a journey, and he wanted to relieve himself. He said to me: ''Go to those two small date-palm trees and tell them: "The Messenger of Allah orders you to come together.''" So they came together and he concealed himself behind them, and relieved himself. Then he said to me: ''Go to them and tell them: "Go back, each one of you, to your places.''" So I said that to them and they went back."', 'It was narrated from Ya''la bin Murrah that his father said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:339', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 340, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا أَبُو النُّعْمَانِ، حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ، حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ، عَنِ الْحَسَنِ بْنِ سَعْدٍ، عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ، قَالَ كَانَ أَحَبَّ مَا اسْتَتَرَ بِهِ النَّبِيُّ ـ صلى الله عليه وسلم ـ لِحَاجَتِهِ هَدَفٌ أَوْ حَائِشُ نَخْلٍ ‏.‏', NULL, 'It was narrated that ''Abdullah bin Ja''far said:"The thing that the Prophet most liked to conceal himself behind when relieving himself was a hillock or a stand of date-palm trees."', 'It was narrated that ''Abdullah bin Ja''far said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:340', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 341, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَقِيلِ بْنِ خُوَيْلِدٍ، حَدَّثَنِي حَفْصُ بْنُ عَبْدِ اللَّهِ، حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ، عَنْ مُحَمَّدِ بْنِ ذَكْوَانَ، عَنْ يَعْلَى بْنِ حَكِيمٍ، عَنْ سَعِيدِ بْنِ جُبَيْرٍ، عَنِ ابْنِ عَبَّاسٍ، قَالَ عَدَلَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ إِلَى الشِّعْبِ فَبَالَ حَتَّى أَنِّي آوِي لَهُ مِنْ فَكِّ وَرِكَيْهِ حِينَ بَالَ ‏.‏', NULL, 'It was narrated that Ibn ''Abbas said:"The Messenger of Allah turned towards a mountain pass and urinated, until I took pity on him because of the way he parted his legs when he urinated."', 'It was narrated that Ibn ''Abbas said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:341', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 342, '"‏ لاَ يَتَنَاجَى اثْنَانِ عَلَى غَائِطِهِمَا يَنْظُرُ كُلُّ وَاحِدٍ مِنْهُمَا إِلَى عَوْرَةِ صَاحِبِهِ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ يَمْقُتُ عَلَى ذَلِكَ ‏"', NULL, 'It was narrated from Abu Sa`eed al-Khudri that:The Messenger of Allah said: "No two people should converse while relieving themselves, each of them looking at the private parts of the other, for Allah, the Mighty and Sublime, hates that." (Da''if) Other chains with similar wording.', 'It was narrated from Abu Sa`eed al-Khudri that', NULL, 'https://sunnah.com/ibnmajah:342', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 343, 'حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ، أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ، عَنْ أَبِي الزُّبَيْرِ، عَنْ جَابِرٍ، عَنْ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ أَنَّهُ نَهَى عَنْ أَنْ يُبَالَ فِي الْمَاءِ الرَّاكِدِ ‏.‏', NULL, 'It was narrated from Jabir that:The Messenger of Allah forbade urinating into standing water.', 'It was narrated from Jabir that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:343', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 344, '"‏ لاَ يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ الرَّاكِدِ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''No one among you should urinate into standing water.''"', 'It was narrated that Abu Hurairah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:344', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 345, '"‏ لاَ يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ النَّاقِعِ ‏"', NULL, 'It was narrated that Ibn ''Umar said:"The Messenger of Allah said: ''No one among you should urinate into standing water.''"', 'It was narrated that Ibn ''Umar said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:345', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 346, '"‏ وَيْحَكَ أَمَا عَلِمْتَ مَا أَصَابَ صَاحِبَ بَنِي إِسْرَائِيلَ كَانُوا إِذَا أَصَابَهُمُ الْبَوْلُ قَرَضُوهُ بِالْمَقَارِيضِ فَنَهَاهُمْ عَنْ ذَلِكَ فَعُذِّبَ فِي قَبْرِهِ ‏"', NULL, 'It was narrated that `Abdur-Rahman bin Hasanah said:"The Messenger of Allah came out to us holding a small shield in his hand. He put it down, then he sat down and urinated towards it. Some of the people said: ''Look at him, he urinates like a woman!'' The Prophet heard that and said: ''Woe to you! Do you not know what happened to one of the children of Israel? If any urine touched any part of their clothes, they would cut that out with scissors. He told them not to do that, so he was tormented in his grave.''" (Da''if) Another chain with similar wording.', 'It was narrated that `Abdur-Rahman bin Hasanah said', NULL, 'https://sunnah.com/ibnmajah:346', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 347, '"‏ إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا أَحَدُهُمَا فَكَانَ لاَ يَسْتَنْزِهُ مِنْ بَوْلِهِ وَأَمَّا الآخَرُ فَكَانَ يَمْشِي بِالنَّمِيمَةِ ‏"', NULL, 'It was narrated that Ibn ''Abbas said:"The Messenger of Allah passed by two new graves, and he said: ''They are being punished, but they are not being punished for anything major. One of them was heedless about preventing urine from getting on his clothes, and the other used to walk about spreading malicious gossip.''"', 'It was narrated that Ibn ''Abbas said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:347', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 348, '"‏ أَكْثَرُ عَذَابِ الْقَبْرِ مِنَ الْبَوْلِ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''Most of the torment of the grave is because of urine.''"', 'It was narrated that Abu Hurairah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:348', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 349, '"‏ إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا أَحَدُهُمَا فَيُعَذَّبُ فِي الْبَوْلِ وَأَمَّا الآخَرُ فَيُعَذَّبُ فِي الْغِيبَةِ ‏"', NULL, 'Bahr bin Marrar narrated that his grandfather Abu Bakrah said:"The Messenger of Allah passed by two graves, and he said: ''They are being punished but they are not being punished for anything major. One of them is being punished because of urine, and the other is being punished because of backbiting.''"', 'Bahr bin Marrar narrated that his grandfather Abu Bakrah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:349', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 350, '"‏ إِنَّهُ لَمْ يَمْنَعْنِي مِنْ أَنْ أَرُدَّ عَلَيْكَ إِلاَّ أَنِّي كُنْتُ عَلَى غَيْرِ وُضُوءٍ ‏"', NULL, 'It was narrated that Muhajir bin Qunfudh bin (Umair) bin Jud''an said:"I came to the Prophet when he was performing ablution and greeted him with the Salam, but he did not return (the greeting). When he had finished his ablution he said: ''Nothing prevented me from returning your greeting but the fact that I need to have ablution.''" (Da''if) Another chain with similar wording.', 'It was narrated that Muhajir bin Qunfudh bin (Umair) bin Jud''an said', NULL, 'https://sunnah.com/ibnmajah:350', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 351, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا مَسْلَمَةُ بْنُ عُلَىٍّ، حَدَّثَنَا الأَوْزَاعِيُّ، عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ، عَنْ أَبِي سَلَمَةَ، عَنْ أَبِي هُرَيْرَةَ، قَالَ مَرَّ رَجُلٌ عَلَى النَّبِيِّ ـ صلى الله عليه وسلم ـ وَهُوَ يَبُولُ فَسَلَّمَ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْهِ فَلَمَّا فَرَغَ ضَرَبَ بِكَفَّيْهِ الأَرْضَ فَتَيَمَّمَ ثُمَّ رَدَّ عَلَيْهِ السَّلاَمَ ‏.‏', NULL, 'It was narrated that Abu Hurairah said:"A man passed by the Prophet while he was urinating, and greeted him with the Salam, but he did not return the greeting. While he finished, he struck the ground with his palms and did dry ablution (Tayammum), then he returned the greeting."', 'It was narrated that Abu Hurairah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:351', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 352, '"‏ إِذَا رَأَيْتَنِي عَلَى مِثْلِ هَذِهِ الْحَالَةِ فَلاَ تُسَلِّمْ عَلَىَّ فَإِنَّكَ إِنْ فَعَلْتَ ذَلِكَ لَمْ أَرُدَّ عَلَيْكَ ‏"', NULL, 'It was narrated from Jabir bin `Abdullah that:"A man passed by the Prophet while he was urinating, and greeted him by the Salam. The Messenger of Allah said to him: "If you see me in this situation, do not greet me with the Salam, for if you do that I will not respond to you.''"', 'It was narrated from Jabir bin `Abdullah that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:352', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 353, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ، وَالْحُسَيْنُ بْنُ أَبِي السَّرِيِّ الْعَسْقَلاَنِيُّ، قَالاَ حَدَّثَنَا أَبُو دَاوُدَ، عَنْ سُفْيَانَ، عَنِ الضَّحَّاكِ بْنِ عُثْمَانَ، عَنْ نَافِعٍ، عَنِ ابْنِ عُمَرَ، قَالَ مَرَّ رَجُلٌ عَلَى النَّبِيِّ ـ صلى الله عليه وسلم ـ وَهُوَ يَبُولُ فَسَلَّمَ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْهِ ‏.‏', NULL, 'It was narrated that Ibn ''Umar said:"A man passed by the Prophet while he was urinating and greeted him with the Salam, and he did not return the greeting."', 'It was narrated that Ibn ''Umar said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:353', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 354, 'حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ، حَدَّثَنَا أَبُو الأَحْوَصِ، عَنْ مَنْصُورٍ، عَنْ إِبْرَاهِيمَ، عَنِ الأَسْوَدِ، عَنْ عَائِشَةَ، قَالَتْ مَا رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ خَرَجَ مِنْ غَائِطٍ قَطُّ إِلاَّ مَسَّ مَاءً ‏.‏', NULL, 'It was narrated that ''Aishah said:"I never saw the Messenger of Allah come out of the toilet without first (cleansing himself) with water."', 'It was narrated that ''Aishah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:354', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 355, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ، حَدَّثَنَا عُتْبَةُ بْنُ أَبِي حَكِيمٍ، حَدَّثَنِي طَلْحَةُ بْنُ نَافِعٍ أَبُو سُفْيَانَ، قَالَ حَدَّثَنِي أَبُو أَيُّوبَ الأَنْصَارِيُّ، وَجَابِرُ بْنُ عَبْدِ اللَّهِ، وَأَنَسُ بْنُ مَالِكٍ، أَنَّ هَذِهِ الآيَةَ، نَزَلَتْ ‏{فِيهِ رِجَالٌ يُحِبُّونَ أَنْ يَتَطَهَّرُوا وَاللَّهُ يُحِبُّ الْمُطَّهِّرِينَ}‏ قَالَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ ‏"‏ يَا مَعْشَرَ الأَنْصَارِ إِنَّ اللَّهَ قَدْ أَثْنَى عَلَيْكُمْ فِي الطُّهُورِ فَمَا طُهُورُكُمْ ‏"‏ ‏.‏ قَالُوا نَتَوَضَّأُ لِلصَّلاَةِ وَنَغْتَسِلُ مِنَ الْجَنَابَةِ وَنَسْتَنْجِي بِالْمَاءِ ‏.‏ قَالَ ‏"‏ هُوَ ذَلِكَ فَعَلَيْكُمُوهُ ‏"‏ ‏.‏', NULL, 'Abu Sufyan said:"Abu Ayyub Al-Ansari, Jabir bin ''Abdullah, and Anas bin Malik told me that when this Verse: "In it (the mosque) are men who love to clean and to purify themselves. And Allah loves those who make themselves clean and pure." was revealed, the Messenger of Allah said: ''O Ansar! Allah has praised you for your cleanliness. What is the nature of your cleanliness?'' They said: ''We perform ablution for prayer and we take bath to cleanse ourselves of impurity due to sexual activity, and we clean ourselves with water (after urinating). He said: ''This is what it is. So adhere to it.''"', 'Abu Sufyan said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:355', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 356, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، عَنْ شَرِيكٍ، عَنْ جَابِرٍ، عَنْ زَيْدٍ الْعَمِّيِّ، عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ، عَنْ عَائِشَةَ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ كَانَ يَغْسِلُ مَقْعَدَتَهُ ثَلاَثًا ‏.‏ قَالَ ابْنُ عُمَرَ فَعَلْنَاهُ فَوَجَدْنَاهُ دَوَاءً وَطُهُورًا ‏.‏
قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ، وَإِبْرَاهِيمُ بْنُ سُلَيْمَانَ الْوَاسِطِيُّ، قَالاَ حَدَّثَنَا أَبُو نُعَيْمٍ، حَدَّثَنَا شَرِيكٌ، نَحْوَهُ ‏.‏', NULL, 'It was narrated from ''Aishah that:The Prophet used to wash his private parts three times. Ibn ''Umar said: "We did that and we found it to be healing and a means of purification."', 'It was narrated from ''Aishah that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:356', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 357, 'حَدَّثَنَا أَبُو كُرَيْبٍ، حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ، عَنْ يُونُسَ بْنِ الْحَارِثِ، عَنْ إِبْرَاهِيمَ بْنِ أَبِي مَيْمُونَةَ، عَنْ أَبِي صَالِحٍ، عَنْ أَبِي هُرَيْرَةَ، قَالَ قَالَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ ‏"‏ نَزَلَتْ فِي أَهْلِ قُبَاءٍ ‏{فِيهِ رِجَالٌ يُحِبُّونَ أَنْ يَتَطَهَّرُوا وَاللَّهُ يُحِبُّ الْمُطَّهِّرِينَ}‏ قَالَ كَانُوا يَسْتَنْجُونَ بِالْمَاءِ فَنَزَلَتْ فِيهِمْ هَذِهِ الآيَةُ ‏"‏ ‏.‏', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''The (following) was revealed about the people of Quba'': ''In it (the mosque) are men who love to clean and purify themselves. And Allah loves those who make themselves clean and pure.''" He said: ''They used to clean themselves with water (after urinating), and this Verse was revealed concerning them.''"', 'It was narrated that Abu Hurairah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:357', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 358, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنْ شَرِيكٍ، عَنْ إِبْرَاهِيمَ بْنِ جَرِيرٍ، عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ، عَنْ أَبِي هُرَيْرَةَ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ قَضَى حَاجَتَهُ ثُمَّ اسْتَنْجَى مِنْ تَوْرٍ ثُمَّ دَلَكَ يَدَهُ بِالأَرْضِ ‏.‏
قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ، حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ الْوَاسِطِيُّ، عَنْ شَرِيكٍ، نَحْوَهُ ‏.‏', NULL, 'It was narrated from Abu Hurairah that:The Prophet relieved himself, then he cleaned himself (with water) from a pot made of brass, then he wiped his hand on the ground. Another chain with similar wording.', 'It was narrated from Abu Hurairah that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:358', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 359, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا أَبُو نُعَيْمٍ، حَدَّثَنَا أَبَانُ بْنُ عَبْدِ اللَّهِ، حَدَّثَنِي إِبْرَاهِيمُ بْنُ جَرِيرٍ، عَنْ أَبِيهِ، أَنَّ نَبِيَّ اللَّهِ ـ صلى الله عليه وسلم ـ دَخَلَ الْغَيْضَةَ فَقَضَى حَاجَتَهُ فَأَتَاهُ جَرِيرٌ بِإِدَاوَةٍ مِنْ مَاءٍ فَاسْتَنْجَى مِنْهَا وَمَسَحَ يَدَهُ بِالتُّرَابِ ‏.‏', NULL, 'Ibrahim bin Jarir narrated from his father that :The Prophet of Allah entered a thicket and relieved himself, then Jarir brought him a small water skin from which he cleansed himself, then he wiped his hand in the dirt.', 'Ibrahim bin Jarir narrated from his father that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:359', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 360, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ، حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ، عَنْ أَبِي الزُّبَيْرِ، عَنْ جَابِرٍ، قَالَ أَمَرَنَا النَّبِيُّ ـ صلى الله عليه وسلم ـ أَنْ نُوكِيَ أَسْقِيَتَنَا وَنُغَطِّيَ آنِيَتَنَا ‏.‏', NULL, 'It was narrated that Jabir said:"The Prophet commanded (us) to tie up our water skins and cover our vessels."', 'It was narrated that Jabir said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:360', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 361, 'حَدَّثَنَا عِصْمَةُ بْنُ الْفَضْلِ، وَيَحْيَى بْنُ حَكِيمٍ، قَالاَ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ بْنِ أَبِي حَفْصَةَ، حَدَّثَنَا حَرِيشُ بْنُ الْخِرِّيتِ، أَنْبَأَنَا ابْنُ أَبِي مُلَيْكَةَ، عَنْ عَائِشَةَ، قَالَتْ كُنْتُ أَضَعُ لِرَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ ثَلاَثَةَ آنِيَةٍ مِنَ اللَّيْلِ مُخَمَّرَةً إِنَاءً لِطَهُورِهِ وَإِنَاءً لِسِوَاكِهِ وَإِنَاءً لِشَرَابِهِ ‏.‏', NULL, 'It was narrated that ''Aishah said:"I used to cover three vessels for the Messenger of Allah at night: A vessel (of water) for his ablution, a vessel for his tooth stick and a vessel for his drink."', 'It was narrated that ''Aishah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:361', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 362, 'حَدَّثَنَا أَبُو بَدْرٍ، عَبَّادُ بْنُ الْوَلِيدِ حَدَّثَنَا مُطَهَّرُ بْنُ الْهَيْثَمِ، حَدَّثَنَا عَلْقَمَةُ بْنُ أَبِي جَمْرَةَ الضُّبَعِيُّ، عَنْ أَبِيهِ أَبِي جَمْرَةَ الضُّبَعِيِّ، عَنِ ابْنِ عَبَّاسٍ، قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ لاَ يَكِلُ طُهُورَهُ إِلَى أَحَدٍ وَلاَ صَدَقَتَهُ الَّتِي يَتَصَدَّقُ بِهَا يَكُونُ هُوَ الَّذِي يَتَوَلاَّهَا بِنَفْسِهِ ‏.‏', NULL, 'It was narrated that Ibn ''Abbas said:"The Messenger of Allah never entrusted his purification to anyone nor his charity that he had given to anyone; he would be the one to take care of these matters himself."', 'It was narrated that Ibn ''Abbas said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:362', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 363, '"‏ إِذَا وَلَغَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍ ‏"', NULL, 'It was narrated that Abu Razin said:''I saw Abu Hurairah hitting his forehead with his hand and saying: "O people of Iraq! Do you claim that I would tell a lie against the Messenger of Allah so that it may be more convenient for you and a sin upon me?'' I bear witness that I heard the Messenger of Allah say: ''If a dog licks the vessel of anyone of you, let him wash it seven times.''"', 'It was narrated that Abu Razin said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:363', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 364, '"‏ إِذَا شَرِبَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍ ‏"', NULL, 'It was narrated from Abu Hurairah that:The Messenger of Allah said: "If a dog licks the vessel of anyome of you, let him wash it seven times."', 'It was narrated from Abu Hurairah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:364', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 365, '"‏ إِذَا وَلَغَ الْكَلْبُ فِي الإِنَاءِ فَاغْسِلُوهُ سَبْعَ مَرَّاتٍ وَعَفِّرُوهُ الثَّامِنَةَ بِالتُّرَابِ ‏"', NULL, 'It was narrated from ''Abdullah bin Mughaffal that:The Messenger of Allah said: ''If a dog licks a vessel, wash it seven times and rub it with dust the eight times."', 'It was narrated from ''Abdullah bin Mughaffal that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:365', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 366, '"‏ إِذَا وَلَغَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍ ‏"', NULL, 'It was narrated that Ibn ''Umar said:"The Messenger of Allah said: ''If a dog licks the vessel of anyone of you, let him wash it seven times.''"', 'It was narrated that Ibn ''Umar said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:366', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 367, '"‏ إِنَّهَا لَيْسَتْ بِنَجَسٍ هِيَ مِنَ الطَّوَّافِينَ أَوِ الطَّوَّافَاتِ ‏"', NULL, 'It was narrated from Kabshah bint Ka''b, who was married to one of the sons of Ab Qatadah, that:She poured water for Abu Qatadah to perform ablution. A cat came and drank the water, and he tilted the vessel for it. She started looking at it (in surprise) and he said: "O daughter of my brother, do you find it strange? The Messenger of Allah said: ''They (cats) are not impure, they are of those who go around among you.''"', NULL, 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:367', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 368, 'حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ، وَإِسْمَاعِيلُ بْنُ تَوْبَةَ، قَالاَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ، عَنْ حَارِثَةَ، عَنْ عَمْرَةَ، عَنْ عَائِشَةَ، قَالَتْ كُنْتُ أَتَوَضَّأُ أَنَا وَرَسُولُ اللَّهِ، ـ صلى الله عليه وسلم ـ مِنْ إِنَاءٍ وَاحِدٍ قَدْ أَصَابَتْ مِنْهُ الْهِرَّةُ قَبْلَ ذَلِكَ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah and I used to perform ablution from a single vessel, when the cat had drunk from it beforehand."', 'It was narrated that ''Aishah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:368', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 369, '"‏ الْهِرَّةُ لاَ تَقْطَعُ الصَّلاَةَ لأَنَّهَا مِنْ مَتَاعِ الْبَيْتِ ‏"', NULL, 'It was narrated from Abu Hurairah that:The Messenger of Allah said: "Cats do not invalidate the prayer, because they are one of the things that are useful in the house."', 'It was narrated from Abu Hurairah that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:369', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 370, '"‏ الْمَاءُ لاَ يُجْنِبُ ‏"', NULL, 'It was narrated that Ibn ''Abbas said:"One of the wives of the Prophet took a bath from a large vessel, then the Prophet came and had a bath or ablution, and she said: ''O Messenger of Allah, I was sexually impure.'' He said: ''Water does not become impure.''"', 'It was narrated that Ibn ''Abbas said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:370', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 371, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، عَنْ سُفْيَانَ، عَنْ سِمَاكِ بْنِ حَرْبٍ، عَنْ عِكْرِمَةَ، عَنِ ابْنِ عَبَّاسٍ، أَنَّ امْرَأَةً، مِنْ أَزْوَاجِ النَّبِيِّ ـ صلى الله عليه وسلم ـ اغْتَسَلَتْ مِنْ جَنَابَةٍ فَتَوَضَّأَ أَوِ اغْتَسَلَ النَّبِيُّ ـ صلى الله عليه وسلم ـ مِنْ فَضْلِ وَضُوئِهَا ‏.‏', NULL, 'It was narrated from Ibn ''Abbas that:One of the wives of the Prophet took a bath to cleanse herself from sexual impurity, then the Prophet performed ablution and had a bath with the water left over from her ablution."', 'It was narrated from Ibn ''Abbas that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:371', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 372, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، وَمُحَمَّدُ بْنُ يَحْيَى، وَإِسْحَاقُ بْنُ مَنْصُورٍ، قَالُوا حَدَّثَنَا أَبُو دَاوُدَ، حَدَّثَنَا شَرِيكٌ، عَنْ سِمَاكٍ، عَنْ عِكْرِمَةَ، عَنِ ابْنِ عَبَّاسٍ، عَنْ مَيْمُونَةَ، زَوْجِ النَّبِيِّ ـ صلى الله عليه وسلم ـ أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ تَوَضَّأَ بِفَضْلِ غُسْلِهَا مِنَ الْجَنَابَةِ ‏.‏', NULL, 'It was narrated from Ibn ''Abbas, from Maimunah the wife of the Prophet, that :the Prophet performed ablution with the water left over after she had taken a bath to cleanse herself from sexual impurity.', 'It was narrated from Ibn ''Abbas, from Maimunah the wife of the Prophet, that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:372', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 373, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا أَبُو دَاوُدَ، حَدَّثَنَا شُعْبَةُ، عَنْ عَاصِمٍ الأَحْوَلِ، عَنْ أَبِي حَاجِبٍ، عَنِ الْحَكَمِ بْنِ عَمْرٍو، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ نَهَى أَنْ يَتَوَضَّأَ الرَّجُلُ بِفَضْلِ وَضُوءِ الْمَرْأَةِ ‏.‏', NULL, 'It was narrated from Hakam bin ''Amr that:The Messenger of Allah forbade men to perform ablution with the left over water by a woman.', 'It was narrated from Hakam bin ''Amr that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:373', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 374, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ، حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ، حَدَّثَنَا عَاصِمٌ الأَحْوَلُ، عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ، قَالَ نَهَى رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ أَنْ يَغْتَسِلَ الرَّجُلُ بِفَضْلِ وَضُوءِ الْمَرْأَةِ وَالْمَرْأَةُ بِفَضْلِ الرَّجُلِ وَلَكِنْ يَشْرَعَانِ جَمِيعًا ‏.
‏ قَالَ أَبُو عَبْدِ اللَّهِ بْنُ مَاجَهْ الصَّحِيحُ هُوَ الأَوَّلُ وَالثَّانِي وَهَمٌ ‏.‏

قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو حَاتِمٍ، وَأَبُو عُثْمَانَ الْبُخَارِيُّ قَالاَ حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ، نَحْوَهُ ‏.‏', NULL, 'It was narrated that `Abdullah bin Sarjis said:"The Messenger of Allah forbade men to perform ablution with the water left over by a woman, and women to perform ablution with water left over by a man, however both (spouses) may start to perform their ablutions at the same time." Abu `Abdullah Ibn Majah said: "The first (narration) is correct, and the second (narration) is Wahm (an error)." Another chain with similar wording.', 'It was narrated that `Abdullah bin Sarjis said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:374', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 375, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا عُبَيْدُ اللَّهِ، عَنْ إِسْرَائِيلَ، عَنْ أَبِي إِسْحَاقَ، عَنِ الْحَارِثِ، عَنْ عَلِيٍّ، قَالَ كَانَ النَّبِيُّ ـ صلى الله عليه وسلم ـ وَأَهْلُهُ يَغْتَسِلُونَ مِنْ إِنَاءٍ وَاحِدٍ وَلاَ يَغْتَسِلُ أَحَدُهُمَا بِفَضْلِ صَاحِبِهِ ‏.‏', NULL, 'It was narrated that ''Ali said:"The Prophet and his wife would take a bath from one vessel, but neither of them would have a bath with the leftover water of the other." (Daif)', 'It was narrated that ''Ali said', NULL, 'https://sunnah.com/ibnmajah:375', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 376, 'حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ، أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ، عَنِ ابْنِ شِهَابٍ، ح وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ، عَنِ الزُّهْرِيِّ، عَنْ عُرْوَةَ، عَنْ عَائِشَةَ، قَالَتْ كُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ، ـ صلى الله عليه وسلم ـ مِنْ إِنَاءٍ وَاحِدٍ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah and I would take a bath from a single vessel."', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:376', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 377, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ، عَنْ عَمْرِو بْنِ دِينَارٍ، عَنْ جَابِرِ بْنِ زَيْدٍ، عَنِ ابْنِ عَبَّاسٍ، عَنْ خَالَتِهِ، مَيْمُونَةَ قَالَتْ كُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ، ـ صلى الله عليه وسلم ـ مِنْ إِنَاءٍ وَاحِدٍ ‏.‏', NULL, 'It was narrated from Ibn ''Abbas that his maternal aunt Maimunah said:"The Messager of Allah and I used to take bath from a single vessel."', 'It was narrated from Ibn ''Abbas that his maternal aunt Maimunah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:377', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 378, 'حَدَّثَنَا أَبُو عَامِرٍ الأَشْعَرِيُّ عَبْدُ اللَّهِ بْنُ عَامِرٍ، حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ، حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ، عَنِ ابْنِ أَبِي نَجِيحٍ، عَنْ مُجَاهِدٍ، عَنْ أُمِّ هَانِئٍ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ اغْتَسَلَ وَمَيْمُونَةُ مِنْ إِنَاءٍ وَاحِدٍ فِي قَصْعَةٍ فِيهَا أَثَرُ الْعَجِينِ ‏.‏', NULL, 'It was narrated from Umm Hani that :The Prophet and Maimunah took a bath from a single vessel, a large bowl in which they were some traces of dough.', 'It was narrated from Umm Hani that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:378', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 379, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا مُحَمَّدُ بْنُ الْحَسَنِ الأَسَدِيُّ، حَدَّثَنَا شَرِيكٌ، عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ، عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ، قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ وَأَزْوَاجُهُ يَغْتَسِلُونَ مِنْ إِنَاءٍ وَاحِدٍ ‏.‏', NULL, 'It was narrated that Jabir bin ''Abdullah said:"The Messenger of Allah and his wives used to take a bath from a single vessel."', 'It was narrated that Jabir bin ''Abdullah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:379', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 380, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا إِسْمَاعِيلُ ابْنُ عُلَيَّةَ، عَنْ هِشَامٍ الدَّسْتَوَائِيِّ، عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ، عَنْ أَبِي سَلَمَةَ، عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ، عَنْ أُمِّ سَلَمَةَ، أَنَّهَا كَانَتْ وَرَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَغْتَسِلاَنِ مِنْ إِنَاءٍ وَاحِدٍ ‏.‏', NULL, 'Zainab the daughter of Umm Salamah narrated from Umm Salamah that:She and the Messenger of Allah used to take a bath from a single vessel.', 'Zainab the daughter of Umm Salamah narrated from Umm Salamah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:380', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 381, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ، حَدَّثَنِي نَافِعٌ، عَنِ ابْنِ عُمَرَ، قَالَ كَانَ الرِّجَالُ وَالنِّسَاءُ يَتَوَضَّئُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ مِنْ إِنَاءٍ وَاحِدٍ ‏.‏', NULL, 'It was narrated that Ibn ''Umar said:"Men and women used to perform ablution from a single vessel during the time of the Messenger of Allah."', 'It was narrated that Ibn ''Umar said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:381', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 382, 'حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ، حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ، حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ، عَنْ سَالِمٍ أَبِي النُّعْمَانِ، - وَهُوَ ابْنُ سَرْجٍ - عَنْ أُمِّ صُبَيَّةَ الْجُهَنِيَّةِ، قَالَتْ رُبَّمَا اخْتَلَفَتْ يَدِي وَيَدُ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ فِي الْوُضُوءِ مِنْ إِنَاءٍ وَاحِدٍ ‏.
‏ قَالَ أَبُو عَبْدِ اللَّهِ ابْنُ مَاجَهْ سَمِعْتُ مُحَمَّدًا يَقُولُ أُمُّ صُبَيَّةَ هِيَ خَوْلَةُ بِنْتُ قَيْسٍ ‏.‏ فَذَكَرْتُ لأَبِي زُرْعَةَ فَقَالَ صَدَقَ ‏.‏', NULL, 'It was narrated that Umm Subyah Al-Juhaniyyah said:"Often my hand would touch the hand of the Messenger of Allah while performing ablution from a single vessel." (Hasan) Abu `Abdullah bin Majah said: "I heard Muhammad say: ''Umm Subyah was Khawlah bint Qais. I mentioned that to Abu Zur`ah and he said: "It is true."', 'It was narrated that Umm Subyah Al-Juhaniyyah said', NULL, 'https://sunnah.com/ibnmajah:382', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 383, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا دَاوُدُ بْنُ شَبِيبٍ، حَدَّثَنَا حَبِيبُ بْنُ أَبِي حَبِيبٍ، عَنْ عَمْرِو بْنِ هَرَمٍ، عَنْ عِكْرِمَةَ، عَنْ عَائِشَةَ، عَنِ النَّبِيِّ ـ صلى الله عليه وسلم ـ أَنَّهُمَا كَانَا يَتَوَضَّآنِ جَمِيعًا لِلصَّلاَةِ ‏.‏', NULL, 'It was narrated from ''Aishah that:The Prophet and she used to perform ablution together for prayer.', 'It was narrated from ''Aishah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:383', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 384, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنْ أَبِيهِ، ح وَحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، عَنْ سُفْيَانَ، عَنْ أَبِي فَزَارَةَ الْعَبْسِيِّ، عَنْ أَبِي زَيْدٍ، مَوْلَى عَمْرِو بْنِ حُرَيْثٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ قَالَ لَهُ لَيْلَةَ الْجِنِّ ‏"‏ عِنْدَكَ طَهُورٌ ‏"‏ ‏.‏ قَالَ لاَ إِلاَّ شَىْءٌ مِنْ نَبِيذٍ فِي إِدَاوَةٍ ‏.‏ قَالَ ‏"‏ تَمْرَةٌ طَيِّبَةٌ وَمَاءٌ طَهُورٌ ‏"‏ ‏.‏ فَتَوَضَّأَ ‏.‏ هَذَا حَدِيثُ وَكِيعٍ ‏.‏', NULL, 'It was narrated from ''Abdullah bin Mas''ud that :On the night of the jinn, the Messenger of Allah said to him: "Do you have water for ablution?" He said: "No, I have nothing, but some Nabidh in a vessel." He said: "Good dates and pure water (i.e. there is no harm from the mixing of the two)." So he performed ablution with it. This is the narration of Waki''.', 'It was narrated from ''Abdullah bin Mas''ud that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:384', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 385, 'حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ، حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ، حَدَّثَنَا ابْنُ لَهِيعَةَ، حَدَّثَنَا قَيْسُ بْنُ الْحَجَّاجِ، عَنْ حَنَشٍ الصَّنْعَانِيِّ، عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ قَالَ لاِبْنِ مَسْعُودٍ لَيْلَةَ الْجِنِّ ‏"‏ مَعَكَ مَاءٌ ‏"‏ ‏.‏ قَالَ لاَ إِلاَّ نَبِيذًا فِي سَطِيحَةٍ ‏.‏ فَقَالَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ ‏"‏ تَمْرَةٌ طَيِّبَةٌ وَمَاءٌ طَهُورٌ صُبَّ عَلَىَّ ‏"‏ ‏.‏ قَالَ فَصَبَبْتُ عَلَيْهِ فَتَوَضَّأَ بِهِ ‏.‏', NULL, 'It was narrated from ''Abdullah bin ''Abbas that :On the night of the Jinn the Messenger of Allah said to Ibn Mas''ud: "Do you have water?" He said: "No, only some Nabidh in a large water skin." The Messenger of Allah said: "Good dates and pure water." (i.e. there is no harm from the mixing of the two.) Pour it for me." He said: "So I performed ablution with it."', 'It was narrated from ''Abdullah bin ''Abbas that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:385', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 386, '"‏ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُ ‏"', NULL, 'It was narrated that Mughirah bin Abu Burdah, who was from the tribe of Banu ''Abdud-Dar, said that:He heard Abu Hurairah say: "A man came to the Messenger of Allah and said: "O Messenger of Allah, we travel by sea and carry a small amount of water with us. If we use it for ablution, we will become thirsty. Can we perform ablution with seawater?'' The Messenger of Allah said: ''Its water is a means of purification, ad its dead meat is permissible. (i.e. the fish found dead in the sea).''"', NULL, 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:386', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 387, '"‏ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُ ‏"', NULL, 'It was narrated that Ibn Firasi said:"I was fishing and I had a vessel with me in which I kept water, and I used seawater for ablution. I mentioned that to the Messenger of Allah and he said: ''Its water is a means of purification, and its dead meat is permissible.''"', 'It was narrated that Ibn Firasi said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:387', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 388, '"‏ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُ ‏"', NULL, 'It was narrated from Jabir that:The Prophet was asked about seawater, and he said: "Its water is a means of purification, and its dead meat is permissible." (Hasan) Another chain with similar wording.', 'It was narrated from Jabir that', NULL, 'https://sunnah.com/ibnmajah:388', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 389, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا عِيسَى بْنُ يُونُسَ، حَدَّثَنَا الأَعْمَشُ، عَنْ مُسْلِمِ بْنِ صُبَيْحٍ، عَنْ مَسْرُوقٍ، عَنِ الْمُغِيرَةِ بْنِ شُعْبَةَ، قَالَ خَرَجَ النَّبِيُّ ـ صلى الله عليه وسلم ـ لِبَعْضِ حَاجَتِهِ فَلَمَّا رَجَعَ تَلَقَّيْتُهُ بِالإِدَاوَةِ فَصَبَبْتُ عَلَيْهِ فَغَسَلَ يَدَيْهِ ثُمَّ غَسَلَ وَجْهَهُ ثُمَّ ذَهَبَ يَغْسِلُ ذِرَاعَيْهِ فَضَاقَتِ الْجُبَّةُ فَأَخْرَجَهُمَا مِنْ تَحْتِ الْجُبَّةِ فَغَسَلَهُمَا وَمَسَحَ عَلَى خُفَّيْهِ ثُمَّ صَلَّى بِنَا ‏.‏', NULL, 'It was narrated that Mughirah bin Shu''bah said:"The Prophet went out to relieve himself and when he came back, I met him with a water skin and poured water for him. He washed his hands and his face, then he went to wash his forearms but his garment was too tight, so he brought his arms out from underneath his garment and washed them, then he wiped over his leather socks, then he led us in prayer."', 'It was narrated that Mughirah bin Shu''bah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:389', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 390, '"‏ اسْكُبِي ‏"', NULL, 'It was narrated that Rubai'' bint Mu''awwidh said:"I brought a basin of water to the Prophet and he said: ''Pour it,'' so I poured it and he washed his face and forearms, then he took fresh water and wiped his head, front and back, and then he washed his feet. He washed each part three times."', 'It was narrated that Rubai'' bint Mu''awwidh said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:390', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 391, 'حَدَّثَنَا بِشْرُ بْنُ آدَمَ، حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ، حَدَّثَنِي الْوَلِيدُ بْنُ عُقْبَةَ، حَدَّثَنِي حُذَيْفَةُ بْنُ أَبِي حُذَيْفَةَ الأَزْدِيُّ، عَنْ صَفْوَانَ بْنِ عَسَّالٍ، قَالَ صَبَبْتُ عَلَى النَّبِيِّ ـ صلى الله عليه وسلم ـ الْمَاءَ فِي السَّفَرِ وَالْحَضَرِ فِي الْوُضُوءِ ‏.‏', NULL, 'It was narrated that Safwan bin ''Assal said:"I poured water for the Prophet on journeys and as a resident, when he performed ablution."', 'It was narrated that Safwan bin ''Assal said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:391', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 392, 'حَدَّثَنَا كُرْدُوسُ بْنُ أَبِي عَبْدِ اللَّهِ الْوَاسِطِيُّ، حَدَّثَنَا عَبْدُ الْكَرِيمِ بْنُ رَوْحٍ، حَدَّثَنَا أَبِي رَوْحُ بْنُ عَنْبَسَةَ بْنِ سَعِيدِ بْنِ أَبِي عَيَّاشٍ، مَوْلَى عُثْمَانَ بْنِ عَفَّانَ عَنْ أَبِيهِ، عَنْبَسَةَ بْنِ سَعِيدٍ عَنْ جَدَّتِهِ أُمِّ أَبِيهِ أُمِّ عَيَّاشٍ، وَكَانَتْ، أَمَةً لِرُقَيَّةَ بِنْتِ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ قَالَتْ كُنْتُ أُوَضِّئُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ أَنَا قَائِمَةٌ وَهُوَ قَاعِدٌ ‏.‏', NULL, 'Umm ''Ayyash, the slave woman of Ruqayyah, the daughter of the Messenger of Allah, said:"I used to help the Messenger of Allah perform ablution, when I was standing and he was sitting."', NULL, 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:392', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 393, '"‏ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنَ اللَّيْلِ فَلاَ يُدْخِلْ يَدَهُ فِي الإِنَاءِ حَتَّى يُفْرِغَ عَلَيْهَا مَرَّتَيْنِ أَوْ ثَلاَثًا فَإِنَّ أَحَدَكُمْ لاَ يَدْرِي فِيمَ بَاتَتْ يَدُهُ ‏"', NULL, 'Sa''eed bin Musayyab and Abu Salamah bin ''Abdur-Rahman narrated that :Abu Hurairah used to say: "The Messenger of Allah said: ''When anyone of you wakes up from sleep, he should not put his hand into the vessel until he has poured water on it two or three times, for none of you knows where his hand spent the night,''"', 'Sa''eed bin Musayyab and Abu Salamah bin ''Abdur-Rahman narrated that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:393', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 394, '"‏ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ نَوْمِهِ فَلاَ يُدْخِلْ يَدَهُ فِي الإِنَاءِ حَتَّى يَغْسِلَهَا ‏"', NULL, 'It was narrated from Salim from his father that:The Messenger of Allah said: "When anyone of you wakes up from sleep, he should not put his hand into the vessel until he has washed it."', 'It was narrated from Salim from his father that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:394', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 395, '"‏ إِذَا قَامَ أَحَدُكُمْ مِنَ النَّوْمِ فَأَرَادَ أَنْ يَتَوَضَّأَ فَلاَ يُدْخِلْ يَدَهُ فِي وَضُوئِهِ حَتَّى يَغْسِلَهَا فَإِنَّهُ لاَ يَدْرِي أَيْنَ بَاتَتْ يَدُهُ وَلاَ عَلَى مَا وَضَعَهَا ‏"', NULL, 'It was narrated that Jabir said:"The Messenger of Allah said: ''When anyone of oyu gets up from sleep and wants to perform ablution, he should not put his hand into the vessel he used for ablution until he has washed it, because he does not know where his hand spent the night or where he put it.''" [(One of the narrators) Abu Ishaq said: "What is correct is that it is narrated from Jabir, from Abu Hurairah."]', 'It was narrated that Jabir said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:395', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 396, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ، عَنْ أَبِي إِسْحَاقَ، عَنِ الْحَارِثِ، قَالَ دَعَا عَلِيٌّ بِمَاءٍ فَغَسَلَ يَدَيْهِ قَبْلَ أَنْ يُدْخِلَهُمَا الإِنَاءَ ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ صَنَعَ ‏.‏', NULL, 'It was narrated that Harith said:"''Ali called for water, and he washed his hands before putting them in the vessel, then he said: ''This is what I saw the Messenger of Allah doing.''"', 'It was narrated that Harith said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:396', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 397, '"‏ لاَ وُضُوءَ لِمَنْ لَمْ يَذْكُرِ اسْمَ اللَّهِ عَلَيْهِ ‏"', NULL, 'It was narrated from Abu Sa''eed that:The Messenger of Allah said: "There is no ablution for one who does not mention the Name of Allah (before doing it)."', 'It was narrated from Abu Sa''eed that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:397', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 398, '"‏ لاَ صَلاَةَ لِمَنْ لاَ وُضُوءَ لَهُ وَلاَ وُضُوءَ لِمَنْ لَمْ يَذْكُرِ اسْمَ اللَّهِ عَلَيْهِ ‏"', NULL, 'It was narrated that Abu Sa''eed bin Zaid said:"The Messenger of Allah said: ''There is no prayer for one who does not have ablution, and there is no ablution for one who does not mention the Name of Allah (before it).''"', 'It was narrated that Abu Sa''eed bin Zaid said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:398', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 399, '"‏ لاَ صَلاَةَ لِمَنْ لاَ وُضُوءَ لَهُ وَلاَ وُضُوءَ لِمَنْ لَمْ يَذْكُرِ اسْمَ اللَّهِ عَلَيْهِ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''There is no prayer for one who does not have ablution, and there is no ablution for one who does not mention the Name of Allah (before it).''"', 'It was narrated that Abu Hurairah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:399', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 400, '"‏ لاَ صَلاَةَ لِمَنْ لاَ وُضُوءَ لَهُ وَلاَ وُضُوءَ لِمَنْ لَمْ يَذْكُرِ اسْمَ اللَّهِ عَلَيْهِ وَلاَ صَلاَةَ لِمَنْ لاَ يُصَلِّي عَلَى النَّبِيِّ ـ صلى الله عليه وسلم ـ وَلاَ صَلاَةَ لِمَنْ لاَ يُحِبُّ الأَنْصَارَ ‏"', NULL, 'It was narrated by ''Abdul-Muhaimin bin ''Abbas bin Sahl bin Sa''d As-Sa''idi, from his father, from his grandfather, that:The Prophet said: "There is no prayer for one who does not have ablution, and there is no ablution for one who does not mention the Name of Allah (before it). There is no prayer for one who does not send blessing, (Salat) upon the Prophet, and there is no prayer for one who does not love the Ansar." (Da''if) Another chain with similar wording.', NULL, NULL, 'https://sunnah.com/ibnmajah:400', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 401, 'حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ، حَدَّثَنَا أَبُو الأَحْوَصِ، عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ، ح وَحَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ، حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ، عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ، عَنْ أَبِيهِ، عَنْ مَسْرُوقٍ، عَنْ عَائِشَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ كَانَ يُحِبُّ التَّيَمُّنَ فِي الطُّهُورِ إِذَا تَطَهَّرَ وَفِي تَرَجُّلِهِ إِذَا تَرَجَّلَ وَفِي انْتِعَالِهِ إِذَا انْتَعَلَ ‏.‏', NULL, 'It was narrated from ''Aishah that:The Messenger of Allah liked to start on the right when purifying himself, when combing his hair and when putting on his footwear.', 'It was narrated from ''Aishah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:401', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 402, '"‏ إِذَا تَوَضَّأْتُمْ فَابْدَءُوا بِمَيَامِنِكُمْ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''When you perform ablution, start on the right.''" (Da''if) Another chain with similar wording.', 'It was narrated that Abu Hurairah said', NULL, 'https://sunnah.com/ibnmajah:402', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 403, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ، وَأَبُو بَكْرِ بْنُ خَلاَّدٍ الْبَاهِلِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ، عَنْ زَيْدِ بْنِ أَسْلَمَ، عَنْ عَطَاءِ بْنِ يَسَارٍ، عَنِ ابْنِ عَبَّاسٍ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ مَضْمَضَ وَاسْتَنْشَقَ مِنْ غَرْفَةٍ وَاحِدَةٍ ‏.‏', NULL, 'It was narrated from Ibn ''Abbas that:The Messenger of Allah rinsed his mouth and sniffed water up into his nostrils from one scoop of water.', 'It was narrated from Ibn ''Abbas that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:403', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 404, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا شَرِيكٌ، عَنْ خَالِدِ بْنِ عَلْقَمَةَ، عَنْ عَبْدِ خَيْرٍ، عَنْ عَلِيٍّ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ فَمَضْمَضَ ثَلاَثًا وَاسْتَنْشَقَ ثَلاَثًا مِنْ كَفٍّ وَاحِدٍ ‏.‏', NULL, 'It was narrated from ''Ali that:The Messenger of Allah performed ablution and he rinsed his mouth three times, and sniffed water up into his nose three times from one handful.', 'It was narrated from ''Ali that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:404', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 405, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا أَبُو الْحُسَيْنِ الْعُكْلِيُّ، عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ، عَنْ عَمْرِو بْنِ يَحْيَى، عَنْ أَبِيهِ، عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ الأَنْصَارِيِّ، قَالَ أَتَانَا رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ فَسَأَلَنَا وَضُوءًا فَأَتَيْتُهُ بِمَاءٍ فَمَضْمَضَ وَاسْتَنْشَقَ مِنْ كَفٍّ وَاحِدٍ ‏.‏', NULL, 'It was narrated that ''Abdullah bin Zaid Al-Ansari said:"The Messenger of Allah came to us and asked us for water for ablution. I brought water to him and he rinsed his mouth and sniffed water up into his nostrils from one handful."', 'It was narrated that ''Abdullah bin Zaid Al-Ansari said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:405', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 406, '"‏ إِذَا تَوَضَّأْتَ فَانْثُرْ وَإِذَا اسْتَجْمَرْتَ فَأَوْتِرْ ‏"', NULL, 'It was narrated that Salamah bin Qais said to me:The Messenger of Allah said to me: ''When you perform ablution, clean your nose, and when you use pebbles to clean yourself after defecating, use an odd number.''"', 'It was narrated that Salamah bin Qais said to me', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:406', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 407, '"‏ أَسْبِغِ الْوُضُوءَ وَبَالِغْ فِي الاِسْتِنْشَاقِ إِلاَّ أَنْ تَكُونَ صَائِمًا ‏"', NULL, 'It was narrated from ''Asim bin Laqit bin Sabrah that his father said:"I said: ''O Messenger of Allah! Tell me about ablution.'' He said: ''Perform ablution properly and sniff water up into your nostrils, thoroughly, unless you are fasting.''"', 'It was narrated from ''Asim bin Laqit bin Sabrah that his father said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:407', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 408, '"‏ اسْتَنْثِرُوا مَرَّتَيْنِ بَالِغَتَيْنِ أَوْ ثَلاَثًا ‏"', NULL, 'It was narrated that Ibn ''Abbas said:''Sniff up water into the nostrils thoroughly, two or three times.''"', 'It was narrated that Ibn ''Abbas said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:408', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 409, '"‏ مَنْ تَوَضَّأَ فَلْيَسْتَنْثِرْ وَمَنِ اسْتَجْمَرَ فَلْيُوتِرْ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''Whoever performs ablution, let him clean his nose, and whoever uses pebbles to clean himself after defecating, let him use an odd number.''"', 'It was narrated that Abu Hurairah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:409', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 410, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ، حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ النَّخَعِيُّ، عَنْ ثَابِتِ بْنِ أَبِي صَفِيَّةَ الثُّمَالِيِّ، قَالَ سَأَلْتُ أَبَا جَعْفَرٍ قُلْتُ لَهُ حُدِّثْتَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ تَوَضَّأَ مَرَّةً مَرَّةً قَالَ نَعَمْ ‏.‏ قُلْتُ وَمَرَّتَيْنِ مَرَّتَيْنِ وَثَلاَثًا ثَلاَثًا قَالَ نَعَمْ ‏.‏', NULL, 'It was narrated that Thabit bin Abi Safiyyah Ath-Thumali said:"I asked Abu Ja''far: Was it narrated to you from Jabir bin ''Abdullah that the Prophet performed ablution washing each part once?'' He said: ''Yes.'' I said: ''And each part twice, and each part thrice?'' He said: ''Yes.''"', 'It was narrated that Thabit bin Abi Safiyyah Ath-Thumali said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:410', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 411, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلاَّدٍ الْبَاهِلِيُّ، حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ، عَنْ سُفْيَانَ، عَنْ زَيْدِ بْنِ أَسْلَمَ، عَنْ عَطَاءِ بْنِ يَسَارٍ، عَنِ ابْنِ عَبَّاسٍ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ غُرْفَةً غُرْفَةً ‏.‏', NULL, 'It was narrated that Ibn ''Abbas said:"I saw the Messenger of Allah performing ablution, taking one handful (of water) at a time.''"', 'It was narrated that Ibn ''Abbas said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:411', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 412, 'حَدَّثَنَا أَبُو كُرَيْبٍ، حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ، أَنْبَأَنَا الضَّحَّاكُ بْنُ شُرَحْبِيلَ، عَنْ زَيْدِ بْنِ أَسْلَمَ، عَنْ أَبِيهِ، عَنْ عُمَرَ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ فِي غَزْوَةِ تَبُوكَ تَوَضَّأَ وَاحِدَةً وَاحِدَةً ‏.‏', NULL, 'It was narrated that ''Umar said:"I saw the Messenger of Allah during the campaign of Tabuk performing ablution, washing each part once."', 'It was narrated that ''Umar said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:412', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 413, 'حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ الدِّمَشْقِيُّ، حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ الدِّمَشْقِيُّ، عَنِ ابْنِ ثَوْبَانَ، عَنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ، عَنْ شَقِيقِ بْنِ سَلَمَةَ، قَالَ رَأَيْتُ عُثْمَانَ وَعَلِيًّا يَتَوَضَّآنِ ثَلاَثًا ثَلاَثًا وَيَقُولاَنِ هَكَذَا كَانَ وُضُوءُ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ ‏.‏
قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ حَدَّثَنَاهُ أَبُو حَاتِمٍ، حَدَّثَنَا أَبُو نُعَيْمٍ، حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ ثَابِتِ بْنِ ثَوْبَانَ، فَذَكَرَ نَحْوَهُ ‏.‏', NULL, 'It was narrated that Shaqiq bin Salamah said:"I saw `Uthman and `Ali performing ablution, washing each part three times, and they said: ''This is how the Messenger of Allah used to perform ablution.''" (Hasan) Another chain with similar wording.', 'It was narrated that Shaqiq bin Salamah said', NULL, 'https://sunnah.com/ibnmajah:413', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 414, 'حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ، حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ، حَدَّثَنَا الأَوْزَاعِيُّ، عَنِ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ، عَنِ ابْنِ عُمَرَ، أَنَّهُ تَوَضَّأَ ثَلاَثًا ثَلاَثًا وَرَفَعَ ذَلِكَ إِلَى النَّبِيِّ ـ صلى الله عليه وسلم ـ ‏.‏', NULL, 'It was narrated that Ibn ''Umar:Performed ablution washing each part three times, and he attributed that to the Prophet.', 'It was narrated that Ibn ''Umar', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:414', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 415, 'حَدَّثَنَا أَبُو كُرَيْبٍ، حَدَّثَنَا خَالِدُ بْنُ حَيَّانَ، عَنْ سَالِمٍ أَبِي الْمُهَاجِرِ، عَنْ مَيْمُونِ بْنِ مِهْرَانَ، عَنْ عَائِشَةَ، وَأَبِي، هُرَيْرَةَ أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ تَوَضَّأَ ثَلاَثًا ثَلاَثًا ‏.‏', NULL, 'It was narrated from ''Aishah and Abu Hurairah that:The Prophet did ablution washing each part three times.', 'It was narrated from ''Aishah and Abu Hurairah that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:415', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 416, 'حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ، حَدَّثَنَا عِيسَى بْنُ يُونُسَ، عَنْ فَائِدٍ أَبِي الْوَرْقَاءِ بْنِ عَبْدِ الرَّحْمَنِ، عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ ثَلاَثًا ثَلاَثًا وَمَسَحَ رَأْسَهُ مَرَّةً ‏.‏', NULL, 'It was narrated that ''Abdullah bin Awfa said:"I saw the Messenger of Allah performing ablution, washing each part three times, and wiping his head once."', 'It was narrated that ''Abdullah bin Awfa said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:416', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 417, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ، عَنْ سُفْيَانَ، عَنْ لَيْثٍ، عَنْ شَهْرِ بْنِ حَوْشَبٍ، عَنْ أَبِي مَالِكٍ الأَشْعَرِيِّ، قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَتَوَضَّأُ ثَلاَثًا ثَلاَثًا ‏.‏', NULL, 'It was narrated that Abu Malik Ash''ari said:"The Messenger of Allah used to perform ablution washing each part three times."', 'It was narrated that Abu Malik Ash''ari said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:417', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 418, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنْ سُفْيَانَ، عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ، عَنِ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ بْنِ عَفْرَاءَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ ثَلاَثًا ثَلاَثًا ‏.‏', NULL, 'It was narrated from Rabi'' bint Mu''awwidh bin ''Afra'' that:The Messenger of Allah performed ablution washing each part three times.', 'It was narrated from Rabi'' bint Mu''awwidh bin ''Afra'' that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:418', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 419, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلاَّدٍ الْبَاهِلِيُّ، حَدَّثَنِي مَرْحُومُ بْنُ عَبْدِ الْعَزِيزِ الْعَطَّارُ، حَدَّثَنِي عَبْدُ الرَّحِيمِ بْنُ زَيْدٍ الْعَمِّيُّ، عَنْ أَبِيهِ، عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ، عَنِ ابْنِ عُمَرَ، قَالَ تَوَضَّأَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ وَاحِدَةً وَاحِدَةً فَقَالَ ‏"‏ هَذَا وُضُوءُ مَنْ لاَ يَقْبَلُ اللَّهُ مِنْهُ صَلاَةً إِلاَّ بِهِ ‏"‏ ‏.‏ ثُمَّ تَوَضَّأَ ثِنْتَيْنِ ثِنْتَيْنِ فَقَالَ ‏"‏ هَذَا وُضُوءُ الْقَدْرِ مِنَ الْوُضُوءِ ‏"‏ ‏.‏ وَتَوَضَّأَ ثَلاَثًا ثَلاَثًا وَقَالَ ‏"‏ هَذَا أَسْبَغُ الْوُضُوءِ وَهُوَ وُضُوئِي وَوُضُوءُ خَلِيلِ اللَّهِ إِبْرَاهِيمَ وَمَنْ تَوَضَّأَ هَكَذَا ثُمَّ قَالَ عِنْدَ فَرَاغِهِ أَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ فُتِحَ لَهُ ثَمَانِيَةُ أَبْوَابِ الْجَنَّةِ يَدْخُلُ مِنْ أَيِّهَا شَاءَ ‏"‏ ‏.‏', NULL, 'It was narrated that Ibn ''Umar said:"The Messenger of Allah performed ablution washing each part once. He said: ''This is the ablution of the person from whom Allah will not accept his prayer without it.'' Then he performed ablution washing each part twice, and he said: ''This is the ablution that Allah appreciates.'' Then he performed ablution washing each part three times, and said: ''This is how ablution is performed properly, and this is my ablution and the ablution of the Close Friend of Allah, Ibrahim. Whoever performs ablution like this, then on completing it says: ''Ashhadu an la ilaha illallah, wa ashhadu anna Muhammadan ''abduhu wa rasuluhu'' (I bear witness that none has the right to be worshipped but Allah, and I bear witness that Muhammed is His servant and His Messenger), eight gates of Paradise will be opened to him and he may enter through whichever one he wants.''"', 'It was narrated that Ibn ''Umar said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:419', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 420, 'حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ، حَدَّثَنَا إِسْمَاعِيلُ بْنُ قَعْنَبٍ أَبُو بِشْرٍ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَرَادَةَ الشَّيْبَانِيُّ، عَنْ زَيْدِ بْنِ الْحَوَارِيِّ، عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ، عَنْ عُبَيْدِ بْنِ عُمَيْرٍ، عَنْ أُبَىِّ بْنِ كَعْبٍ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ دَعَا بِمَاءٍ فَتَوَضَّأَ مَرَّةً مَرَّةً فَقَالَ ‏"‏ هَذَا وَظِيفَةُ الْوُضُوءِ ‏"‏ ‏.‏ أَوْ قَالَ ‏"‏ وُضُوءٌ مَنْ لَمْ يَتَوَضَّأْهُ لَمْ يَقْبَلِ اللَّهُ لَهُ صَلاَةً ‏"‏ ‏.‏ ثُمَّ تَوَضَّأَ مَرَّتَيْنِ مَرَّتَيْنِ ثُمَّ قَالَ ‏"‏ هَذَا وُضُوءٌ مَنْ تَوَضَّأَهُ أَعْطَاهُ اللَّهُ كِفْلَيْنِ مِنَ الأَجْرِ ‏"‏ ‏.‏ ثُمَّ تَوَضَّأَ ثَلاَثًا ثَلاَثًا فَقَالَ ‏"‏ هَذَا وُضُوئِي وَوُضُوءُ الْمُرْسَلِينَ مِنْ قَبْلِي ‏"‏ ‏.‏', NULL, 'It was narrated from Ubayy bin Ka''b that:The Messenger of Allah called for water and performed ablution once. He said: "This is the minimum requirement of ablution'' or he said: ''The ablution of one who, if he does not perform this ablution, Allah will not accept his prayer." Then he performed ablution washing each part twice, and he said: ''This is the ablution of one who, if he performs it, Allah will give him two shares of reward." Then he performed ablution washing each part three times, and said: ''This is my ablution and the ablution of the Messengers who were sent before me."', 'It was narrated from Ubayy bin Ka''b that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:420', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 421, '"‏ إِنَّ لِلْوُضُوءِ شَيْطَانًا يُقَالُ لَهُ وَلَهَانُ فَاتَّقُوا وَسْوَاسَ الْمَاءِ ‏"', NULL, 'It was narrated that Ubayy bin Ka''b said:"The Messenger of Allah said: ''There is a devil for ablution who is called Walahan, so be on guard against the insinuating thoughts (Waswas) about water.''"', 'It was narrated that Ubayy bin Ka''b said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:421', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 422, '"‏ هَذَا الْوُضُوءُ فَمَنْ زَادَ عَلَى هَذَا فَقَدْ أَسَاءَ وَتَعَدَّى أَوْ ظَلَمَ ‏"', NULL, 'It was narrated from ''Amr bin Shu''aib from his father, from his grandfather, that:A Bedouin came to the Prophet and asked him about ablution. He showed him how to perform it washing each part of the body three times. Then he said: ''This is the ablution, and whoever does more than this, has done evil, transgressed the limits and wronged himself.''"', NULL, 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:422', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 423, 'حَدَّثَنَا أَبُو إِسْحَاقَ الشَّافِعِيُّ، إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ الْعَبَّاسِ حَدَّثَنَا سُفْيَانُ، عَنْ عَمْرٍو، سَمِعَ كُرَيْبًا، يَقُولُ سَمِعْتُ ابْنَ عَبَّاسٍ، يَقُولُ بِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ فَقَامَ النَّبِيُّ ـ صلى الله عليه وسلم ـ فَتَوَضَّأَ مِنْ شَنَّةٍ وُضُوءًا يُقَلِّلُهُ فَقُمْتُ فَصَنَعْتُ كَمَا صَنَعَ ‏.‏', NULL, 'It was narrated that ''Amr heard Kuraib saying:"I heard Ibn ''Abbas say: ''I stayed overnight with my maternal aunt Maimunah, and the Prophet got up and performed ablution from an old water skin, and he did a brief ablution. Then I got up and did the same as he had done."', 'It was narrated that ''Amr heard Kuraib saying', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:423', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 424, '"‏ لاَ تُسْرِفْ لاَ تُسْرِفْ ‏"', NULL, 'It is narrated that Ibn ''Umar said:"The Messenger of Allah saw a man performing ablution, and he said: ''Do not be extravagant, do not be extravagant (in using water).''" (Maudu'')', 'It is narrated that Ibn ''Umar said', NULL, 'https://sunnah.com/ibnmajah:424', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 425, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا قُتَيْبَةُ، حَدَّثَنَا ابْنُ لَهِيعَةَ، عَنْ حُيَىِّ بْنِ عَبْدِ اللَّهِ الْمَعَافِرِيِّ، عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ، عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ مَرَّ بِسَعْدٍ وَهُوَ يَتَوَضَّأُ فَقَالَ ‏"‏ مَا هَذَا السَّرَفُ ‏"‏ ‏.‏ فَقَالَ أَفِي الْوُضُوءِ إِسْرَافٌ قَالَ ‏"‏ نَعَمْ وَإِنْ كُنْتَ عَلَى نَهَرٍ جَارٍ ‏"‏ ‏.‏', NULL, 'It was narrated from ''Abdullah bin ''Amr that:The Messenger of Allah passed by Sa''d when he was performing ablution, and he said: ''What is this extravagance?'' He said: ''Can there be any extravagance in ablution?'' He said: ''Yes, even if you are on the bank of a flowing river.''"', 'It was narrated from ''Abdullah bin ''Amr that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:425', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 426, 'حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ، حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ، حَدَّثَنَا مُوسَى بْنُ سَالِمٍ أَبُو جَهْضَمٍ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ، عَنِ ابْنِ عَبَّاسٍ، قَالَ أَمَرَنَا رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ بِإِسْبَاغِ الْوُضُوءِ ‏.‏', NULL, 'It was narrated that Ibn ''Abbas said:"The Messenger of Allah commanded us to perform ablution properly."', 'It was narrated that Ibn ''Abbas said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:426', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 427, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ، حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ، عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ، عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ، عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ، أَنَّهُ سَمِعَ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ قَالَ ‏"‏ أَلاَ أَدُلُّكُمْ عَلَى مَا يُكَفِّرُ اللَّهُ بِهِ الْخَطَايَا وَيَزِيدُ بِهِ فِي الْحَسَنَاتِ ‏"‏ ‏.‏ قَالُوا بَلَى يَا رَسُولَ اللَّهِ ‏.‏ قَالَ ‏"‏ إِسْبَاغُ الْوُضُوءِ عَلَى الْمَكَارِهِ وَكَثْرَةُ الْخُطَا إِلَى الْمَسَاجِدِ وَانْتِظَارُ الصَّلاَةِ بَعْدَ الصَّلاَةِ ‏"‏ ‏.‏', NULL, 'It was narrated from Abu Sa''eed Khudri that he heard :The Messenger of Allah say: "Shall I not tell you of something by means of which Allah expiates for sins and increases good deeds?" They said: "Yes, O Messenger of Allah." He said: "Perform ablution properly despite difficulties, increasing the number of steps one takes towards the mosque and waiting for the next prayer after prayer.''"', 'It was narrated from Abu Sa''eed Khudri that he heard', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:427', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 428, '"‏ كَفَّارَاتُ الْخَطَايَا إِسْبَاغُ الْوُضُوءِ عَلَى الْمَكَارِهِ وَإِعْمَالُ الأَقْدَامِ إِلَى الْمَسَاجِدِ وَانْتِظَارُ الصَّلاَةِ بَعْدَ الصَّلاَةِ ‏"', NULL, 'It was narrated from Abu Hurairah that:The Prophet said: "Sins are expiated by well-performed ablution despite difficulties, increasing the number of steps one takes towards the mosque, (and waiting for the next prayer after prayer)."', 'It was narrated from Abu Hurairah that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:428', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 429, 'حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ، حَدَّثَنَا سُفْيَانُ، عَنْ عَبْدِ الْكَرِيمِ أَبِي أُمَيَّةَ، عَنْ حَسَّانِ بْنِ بِلاَلٍ، عَنْ عَمَّارِ بْنِ يَاسِرٍ، ح وَحَدَّثَنَا ابْنُ أَبِي عُمَرَ، قَالَ حَدَّثَنَا سُفْيَانُ، عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ، عَنْ قَتَادَةَ، عَنْ حَسَّانِ بْنِ بِلاَلٍ، عَنْ عَمَّارِ بْنِ يَاسِرٍ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ يُخَلِّلُ لِحْيَتَهُ ‏.‏', NULL, 'It was narrated that ''Ammar bin Yasir said:"I saw the Messenger of Allah running his fingers through his beard."', 'It was narrated that ''Ammar bin Yasir said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:429', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 430, 'حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي خَالِدٍ الْقَزْوِينِيُّ، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، عَنْ إِسْرَائِيلَ، عَنْ عَامِرِ بْنِ شَقِيقٍ الأَسَدِيِّ، عَنْ أَبِي وَائِلٍ، عَنْ عُثْمَانَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ فَخَلَّلَ لِحْيَتَهُ ‏.‏', NULL, 'It was narrated from ''Uthman that:The Messenger of Allah performed ablution and ran his fingers through his beard.', 'It was narrated from ''Uthman that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:430', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 431, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَفْصِ بْنِ هِشَامِ بْنِ زَيْدِ بْنِ أَنَسِ بْنِ مَالِكٍ، حَدَّثَنَا يَحْيَى بْنُ كَثِيرٍ أَبُو النَّضْرِ، صَاحِبُ الْبَصْرِيِّ عَنْ يَزِيدَ الرَّقَاشِيِّ، عَنْ أَنَسِ بْنِ مَالِكٍ، قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ إِذَا تَوَضَّأَ خَلَّلَ لِحْيَتَهُ وَفَرَّجَ أَصَابِعَهُ مَرَّتَيْنِ ‏.‏', NULL, 'It was narrated that Anas bin Malik said:"When the Messenger of Allah performed ablution, he ran his fingers through his beard and separated his fingers (to let water run through them) twice."', 'It was narrated that Anas bin Malik said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:431', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 432, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبٍ، حَدَّثَنَا الأَوْزَاعِيُّ، حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ قَيْسٍ، حَدَّثَنِي نَافِعٌ، عَنِ ابْنِ عُمَرَ، قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ إِذَا تَوَضَّأَ عَرَكَ عَارِضَيْهِ بَعْضَ الْعَرْكِ ثُمَّ شَبَكَ لِحْيَتَهُ بِأَصَابِعِهِ مِنْ تَحْتِهَا ‏.‏', NULL, 'It was narrated that Ibn ''Umar said:"Whenever the Messenger of Allah performed ablution, he rubbed the sides of his face then run his fingers through his beard from beneath."', 'It was narrated that Ibn ''Umar said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:432', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 433, 'حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ الرَّقِّيُّ، حَدَّثَنَا مُحَمَّدُ بْنُ رَبِيعَةَ الْكِلاَبِيُّ، حَدَّثَنَا وَاصِلُ بْنُ السَّائِبِ الرَّقَاشِيُّ، عَنْ أَبِي سَوْرَةَ، عَنْ أَبِي أَيُّوبَ الأَنْصَارِيِّ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ فَخَلَّلَ لِحْيَتَهُ ‏.‏', NULL, 'It was narrated that Abu Ayyub Al-Ansari said:"I saw the Messenger of Allah performing ablution and he ran his fingers through his beard."', 'It was narrated that Abu Ayyub Al-Ansari said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:433', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 434, 'حَدَّثَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ، وَحَرْمَلَةُ بْنُ يَحْيَى، قَالاَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِدْرِيسَ الشَّافِعِيُّ، قَالَ أَنْبَأَنَا مَالِكُ بْنُ أَنَسٍ، عَنْ عَمْرِو بْنِ يَحْيَى، عَنْ أَبِيهِ، أَنَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ زَيْدٍ - وَهُوَ جَدُّ عَمْرِو بْنِ يَحْيَى - هَلْ تَسْتَطِيعُ أَنْ تُرِيَنِي، كَيْفَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَتَوَضَّأُ فَقَالَ عَبْدُ اللَّهِ بْنُ زَيْدٍ نَعَمْ ‏.‏ فَدَعَا بِوَضُوءٍ فَأَفْرَغَ عَلَى يَدَيْهِ فَغَسَلَ يَدَيْهِ مَرَّتَيْنِ ثُمَّ تَمَضْمَضَ وَاسْتَنْثَرَ ثَلاَثًا ثُمَّ غَسَلَ وَجْهَهُ ثَلاَثًا ثُمَّ غَسَلَ يَدَيْهِ مَرَّتَيْنِ مَرَّتَيْنِ إِلَى الْمِرْفَقَيْنِ ثُمَّ مَسَحَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ بَدَأَ بِمُقَدَّمِ رَأْسِهِ ثُمَّ ذَهَبَ بِهِمَا إِلَى قَفَاهُ ثُمَّ رَدَّهُمَا حَتَّى رَجَعَ إِلَى الْمَكَانِ الَّذِي بَدَأَ مِنْهُ ثُمَّ غَسَلَ رِجْلَيْهِ ‏.‏', NULL, '''Amr bin Yahya narrated that his father said to ''Abdullah bin Zaid who was the grandfather of ''Amr bin Yahya:"Can you show me how the Messenger of Allah used to perform ablution?" ''Abdullah bin Zaid said: "Yes," So he called for water, poured it over his hands and washed his hands twice. Then he raised his mouth and sniffed water up into his nostrils three times. Then he washed his face three times and his arms up to his elbows twice. Then he wiped his head with his hands, from front to back. He started at the front of his head, then went with them to the nape of his neck, then he brought them back, returning them to the place he started, then he washed his feet."', NULL, 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:434', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 435, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ، عَنْ حَجَّاجٍ، عَنْ عَطَاءٍ، عَنْ عُثْمَانَ بْنِ عَفَّانَ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ فَمَسَحَ رَأْسَهُ مَرَّةً ‏.‏', NULL, 'It was narrated that ''Uthman bin ''Affan said:"I saw the Messenger of Allah performing ablution and he wiped his head once."', 'It was narrated that ''Uthman bin ''Affan said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:435', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 436, 'حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ، حَدَّثَنَا أَبُو الأَحْوَصِ، عَنْ أَبِي إِسْحَاقَ، عَنْ أَبِي حَيَّةَ، عَنْ عَلِيٍّ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ مَسَحَ رَأْسَهُ مَرَّةً ‏.‏', NULL, 'It was narrated from ''Ali that:The Messenger of Allah wiped his head once.', 'It was narrated from ''Ali that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:436', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 437, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْحَارِثِ الْمِصْرِيُّ، حَدَّثَنَا يَحْيَى بْنُ رَاشِدٍ الْبَصْرِيُّ، عَنْ يَزِيدَ، مَوْلَى سَلَمَةَ عَنْ سَلَمَةَ بْنِ الأَكْوَعِ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ فَمَسَحَ رَأْسَهُ مَرَّةً ‏.‏', NULL, 'It was narrated that Salamah bin Akwa'' said:"I saw the Messenger of Allah performing ablution, and he wiped his head once."', 'It was narrated that Salamah bin Akwa'' said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:437', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 438, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنْ سُفْيَانَ، عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ، عَنِ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَ، قَالَتْ تَوَضَّأَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ فَمَسَحَ رَأْسَهُ مَرَّتَيْنِ ‏.‏', NULL, 'It was narrated that Ar-Rubai'' bint Mu''awwidh bin ''Afra'' said:"The Messenger of Allah performed ablution and wiped his head twice."', 'It was narrated that Ar-Rubai'' bint Mu''awwidh bin ''Afra'' said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:438', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 439, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ، عَنِ ابْنِ عَجْلاَنَ، عَنْ زَيْدِ بْنِ أَسْلَمَ، عَنْ عَطَاءِ بْنِ يَسَارٍ، عَنِ ابْنِ عَبَّاسٍ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ مَسَحَ أُذُنَيْهِ دَاخِلَهُمَا بِالسَّبَّابَتَيْنِ وَخَالَفَ إِبْهَامَيْهِ إِلَى ظَاهِرِ أُذُنَيْهِ فَمَسَحَ ظَاهِرَهُمَا وَبَاطِنَهُمَا ‏.‏', NULL, 'It was narrated from Ibn ''Abbas that:The Messenger of Allah wiped his ears, putting his forefingers in his ears and wiping the back of them with his thumbs, so he wiped them inside and out.', 'It was narrated from Ibn ''Abbas that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:439', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 440, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا شَرِيكٌ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَقِيلٍ، عَنِ الرُّبَيِّعِ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ تَوَضَّأَ فَمَسَحَ ظَاهِرَ أُذُنَيْهِ وَبَاطِنَهُمَا ‏.‏', NULL, 'It was narrated from Rubai'' that:The prophet performed ablution and wiped his ears inside and out.', 'It was narrated from Rubai'' that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:440', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 441, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنِ الْحَسَنِ بْنِ صَالِحٍ، عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ، عَنِ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَ، قَالَتْ تَوَضَّأَ النَّبِيُّ ـ صلى الله عليه وسلم ـ فَأَدْخَلَ إِصْبَعَيْهِ فِي جُحْرَىْ أُذُنَيْهِ ‏.‏', NULL, 'It was narrated that Rubai'' bint Mu''awwidh bin ''Afra'' said:"The Prophet performed ablution, and he put his fingers in the (holes) inside of his ears."', 'It was narrated that Rubai'' bint Mu''awwidh bin ''Afra'' said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:441', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 442, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا الْوَلِيدُ، حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَيْسَرَةَ، عَنِ الْمِقْدَامِ بْنِ مَعْدِيكَرِبَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ فَمَسَحَ بِرَأْسِهِ وَأُذُنَيْهِ ظَاهِرَهُمَا وَبَاطِنَهُمَا ‏.‏', NULL, 'It was narrated from Miqdam bin Ma''dikarib that:The Messenger of Allah performed ablution and he wiped his head and his ears, inside and out.', 'It was narrated from Miqdam bin Ma''dikarib that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:442', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 443, '"‏ الأُذُنَانِ مِنَ الرَّأْسِ ‏"', NULL, 'It was narrated that ''Abdullah bin Zaid said:"The Messenger of Allah said: ''The ears are part of the head.''"', 'It was narrated that ''Abdullah bin Zaid said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:443', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 444, '"‏ الأُذُنَانِ مِنَ الرَّأْسِ ‏"', NULL, 'It was narrated from Abu Umamah that:The Messenger of Allah said: "The ears are part of the head." He used to wipe his head once, and he used to wipe over the inner corners of the eyes (that are close to the nose).', 'It was narrated from Abu Umamah that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:444', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 445, '"‏ الأُذُنَانِ مِنَ الرَّأْسِ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''The ears are part of the head.''"', 'It was narrated that Abu Hurairah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:445', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 446, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ، حَدَّثَنَا مُحَمَّدُ بْنُ حِمْيَرَ، عَنِ ابْنِ لَهِيعَةَ، حَدَّثَنِي يَزِيدُ بْنُ عَمْرٍو الْمَعَافِرِيُّ، عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ، عَنِ الْمُسْتَوْرِدِ بْنِ شَدَّادٍ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ فَخَلَّلَ أَصَابِعَ رِجْلَيْهِ بِخِنْصِرِهِ ‏.‏
