INSERT INTO public.hadiths (
  collection_id, book, hadith_number, text_ar, text_tr, text_en, narrator, grade, source, source_license, verified_at
) VALUES
  ('ibnmajah', 'The Book of Purification and its Sunnah', 543, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، عَنِ الأَعْمَشِ، عَنْ إِبْرَاهِيمَ، عَنْ هَمَّامِ بْنِ الْحَارِثِ، قَالَ بَالَ جَرِيرُ بْنُ عَبْدِ اللَّهِ ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقِيلَ لَهُ أَتَفْعَلُ هَذَا قَالَ وَمَا يَمْنَعُنِي وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ يَفْعَلُهُ ‏.‏ قَالَ إِبْرَاهِيمُ كَانَ يُعْجِبُهُمْ حَدِيثُ جَرِيرٍ لأَنَّ إِسْلاَمَهُ كَانَ بَعْدَ نُزُولِ الْمَائِدَةِ ‏.‏', NULL, 'It was narrated that Hammam bin Harith said:"Jarir bin ''Abdullah urinated, then he performed ablution and wiped over his leather socks. Someone asked him: ''Do you do this?'' He said: ''Why shouldn''t I? I saw the Messenger of Allah doing this.''" Ibrahim (who narrated it from Hammam) said: "They were pleased by the Hadith of Jarir because he accepted Islam after the revelation of Ma''idah."', 'It was narrated that Hammam bin Harith said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:543', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 544, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، ح وَحَدَّثَنَا أَبُو هَمَّامٍ الْوَلِيدُ بْنُ شُجَاعِ بْنِ الْوَلِيدِ، حَدَّثَنَا أَبِي وَابْنُ، عُيَيْنَةَ وَابْنُ أَبِي زَائِدَةَ جَمِيعًا عَنِ الأَعْمَشِ، عَنْ أَبِي وَائِلٍ، عَنْ حُذَيْفَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ ‏.‏', NULL, 'It was narrated from Hudhaifah that:The Messenger of Allah performed ablution and wiped over his leather socks.', 'It was narrated from Hudhaifah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:544', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 545, 'حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ، أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ، عَنْ يَحْيَى بْنِ سَعِيدٍ، عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ، عَنْ نَافِعِ بْنِ جُبَيْرٍ، عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ، عَنْ أَبِيهِ الْمُغِيرَةِ بْنِ شُعْبَةَ، عَنْ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ أَنَّهُ خَرَجَ لِحَاجَتِهِ فَاتَّبَعَهُ الْمُغِيرَةُ بِإِدَاوَةٍ فِيهَا مَاءٌ حَتَّى فَرَغَ مِنْ حَاجَتِهِ فَتَوَضَّأَ وَمَسَحَ عَلَى الْخُفَّيْنِ ‏.‏', NULL, 'It was narrated from ''Urwah bin Mughirah bin Shu''bah from his father Mughirah bin Shu''bah, that:The Messenger of Allah went out to relieve himself, and Mughirah followed him with a vessel of water. When he finished relieving himself, he performed ablution and wiped over his leather socks.', NULL, 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:545', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 546, 'حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى اللَّيْثِيُّ، حَدَّثَنَا مُحَمَّدُ بْنُ سَوَاءٍ، حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ، عَنْ أَيُّوبَ، عَنْ نَافِعٍ، عَنِ ابْنِ عُمَرَ، أَنَّهُ رَأَى سَعْدَ بْنَ مَالِكٍ وَهُوَ يَمْسَحُ عَلَى الْخُفَّيْنِ فَقَالَ إِنَّكُمْ لَتَفْعَلُونَ ذَلِكَ فَاجْتَمَعْنَا عِنْدَ عُمَرَ فَقَالَ سَعْدٌ لِعُمَرَ أَفْتِ ابْنَ أَخِي فِي الْمَسْحِ عَلَى الْخُفَّيْنِ ‏.‏ فَقَالَ عُمَرُ كُنَّا وَنَحْنُ مَعَ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ نَمْسَحُ عَلَى خِفَافِنَا لَمْ نَرَ بِذَلِكَ بَأْسًا ‏.‏ فَقَالَ ابْنُ عُمَرَ وَإِنْ جَاءَ مِنَ الْغَائِطِ قَالَ نَعَمْ ‏.‏', NULL, 'It was narrated from Ibn ''Umar that:He saw Sa''d bin Malik wiping over his leather socks and said: "Is it you doing this?" They both went to ''Umar and Sa''d said to ''Umar: "Give my brother''s son a verdict regarding wiping over leather socks." ''Umar said: "We used to wipe over our leather socks when we were with the Messenger of Allah and we do not see anything wrong with that." Ibn ''Umar said: "Even if that is after one has defecated?" He said: "Yes."', 'It was narrated from Ibn ''Umar that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:546', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 547, 'حَدَّثَنَا أَبُو مُصْعَبٍ الْمَدَنِيُّ، حَدَّثَنَا عَبْدُ الْمُهَيْمِنِ بْنُ الْعَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيُّ، عَنْ أَبِيهِ، عَنْ جَدِّهِ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ مَسَحَ عَلَى الْخُفَّيْنِ وَأَمَرَنَا بِالْمَسْحِ عَلَى الْخُفَّيْنِ ‏.‏', NULL, '''Abdul-Muhaimin bin ''Abbas bin Sahl As-Sa''idi narrated from his father, from his grandfather:"The Messenger of Allah wiped over his leather socks and he ordered us to wipe over the leather socks."', NULL, 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:547', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 548, '"‏ هَلْ مِنْ مَاءٍ ‏"', NULL, 'It was narrated that Anas bin Malik said:"I was with the Messenger of Allah on a journey, and he said: ''Is there any water?'' He performed ablution and wiped over his leather socks, then he joined the army and led them (in prayer)."', 'It was narrated that Anas bin Malik said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:548', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 549, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، حَدَّثَنَا دَلْهَمُ بْنُ صَالِحٍ الْكِنْدِيُّ، عَنْ حُجَيْرِ بْنِ عَبْدِ اللَّهِ الْكِنْدِيِّ، عَنِ ابْنِ بُرَيْدَةَ، عَنْ أَبِيهِ، أَنَّ النَّجَاشِيَّ، أَهْدَى لِلنَّبِيِّ ـ صلى الله عليه وسلم ـ خُفَّيْنِ أَسْوَدَيْنِ سَاذَجَيْنِ فَلَبِسَهُمَا ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَيْهِمَا ‏.‏', NULL, 'It was narrated from Abu Buraidah from his father that:An-Najashi gave the Prophet a gift of a pair of plain black leather socks. He put them on, then he (performed ablution and) wiped over them.', 'It was narrated from Abu Buraidah from his father that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:549', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 550, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ، حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ، عَنْ رَجَاءِ بْنِ حَيْوَةَ، عَنْ وَرَّادٍ، كَاتِبِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنِ الْمُغِيرَةِ بْنِ شُعْبَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ مَسَحَ أَعْلَى الْخُفِّ وَأَسْفَلَهُ ‏.‏', NULL, 'It was narrated from Mughirah bin Shu''bah that:The Messenger of Allah wiped over the top and the bottom of the leather socks.', 'It was narrated from Mughirah bin Shu''bah that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:550', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 551, '"‏ إِنَّمَا أُمِرْتَ بِالْمَسْحِ ‏"', NULL, 'It was narrated that Jabir said:"The Messenger of Allah passed by a man who was performing ablution and washing his leather socks. He gestures with his hand, (and said): ''Rather I have been commanded to wipe them.'' The Messenger of Allah gestured with his hand like this, from the tips of the toes to the base of the shin, tracing lines with his fingers."', 'It was narrated that Jabir said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:551', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 552, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، عَنِ الْحَكَمِ، قَالَ سَمِعْتُ الْقَاسِمَ بْنَ مُخَيْمِرَةَ، عَنْ شُرَيْحِ بْنِ هَانِئٍ، قَالَ سَأَلْتُ عَائِشَةَ عَنِ الْمَسْحِ، عَلَى الْخُفَّيْنِ فَقَالَتِ ائْتِ عَلِيًّا فَسَلْهُ فَإِنَّهُ أَعْلَمُ بِذَلِكَ مِنِّي ‏.‏ فَأَتَيْتُ عَلِيًّا فَسَأَلْتُهُ عَنِ الْمَسْحِ فَقَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَأْمُرُنَا أَنْ نَمْسَحَ لِلْمُقِيمِ يَوْمًا وَلَيْلَةً وَلِلْمُسَافِرِ ثَلاَثَةَ أَيَّامٍ ‏.‏', NULL, 'It was narrated that Shuraih bin Hani'' said:"I asked ''Aishah about wiping over the leather socks and she said: ''Go to ''Ali and ask him, for he knows more about that than I do.'' So I went to ''Ali and asked him about wiping. He said: ''The Messenger of Allah used to tell us that the resident could wipe for one day and one night, and the traveler could do so for three days.''"', 'It was narrated that Shuraih bin Hani'' said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:552', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 553, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، حَدَّثَنَا سُفْيَانُ، عَنْ أَبِيهِ، عَنْ إِبْرَاهِيمَ التَّيْمِيِّ، عَنْ عَمْرِو بْنِ مَيْمُونٍ، عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ، قَالَ جَعَلَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ لِلْمُسَافِرِ ثَلاَثًا وَلَوْ مَضَى السَّائِلُ عَلَى مَسْأَلَتِهِ لَجَعَلَهَا خَمْسًا ‏.‏', NULL, 'It was narrated that Khuzaimah bin Thabit said:"The Messenger of Allah set a time limit for the traveler of three days, and if the questioner had persisted in asking, he would have made it five (days)."', 'It was narrated that Khuzaimah bin Thabit said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:553', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 554, '"‏ ثَلاَثَةُ أَيَّامٍ - أَحْسِبُهُ قَالَ - وَلَيَالِيهِنَّ لِلْمُسَافِرِ فِي الْمَسْحِ عَلَى الْخُفَّيْنِ ‏"', NULL, 'It was narrated from Khuzaimah bin Thabit that:The Prophet said: "Three days." I think he said, "And three nights during which the traveler may wipe over his leather socks."', 'It was narrated from Khuzaimah bin Thabit that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:554', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 555, '"‏ لِلْمُسَافِرِ ثَلاَثَةُ أَيَّامٍ وَلَيَالِيهِنَّ وَلِلْمُقِيمِ يَوْمٌ وَلَيْلَةٌ ‏"', NULL, 'It was narrated that Abu Hurairah said:"They said: ''O Messenger of Allah! What about the purification of the leather socks?'' He said: ''For the traveler it is three days and nights, and for the resident it is one day and one night.''"', 'It was narrated that Abu Hurairah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:555', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 556, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، وَبِشْرُ بْنُ هِلاَلٍ الصَّوَّافُ، قَالاَ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ، قَالَ حَدَّثَنَا الْمُهَاجِرُ أَبُو مَخْلَدٍ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ، عَنْ أَبِيهِ، عَنِ النَّبِيِّ ـ صلى الله عليه وسلم ـ أَنَّهُ رَخَّصَ لِلْمُسَافِرِ إِذَا تَوَضَّأَ وَلَبِسَ خُفَّيْهِ ثُمَّ أَحْدَثَ وُضُوءًا أَنْ يَمْسَحَ ثَلاَثَةَ أَيَّامٍ وَلَيَالِيَهُنَّ وَلِلْمُقِيمِ يَوْمًا وَلَيْلَةً ‏"‏ ‏.‏', NULL, 'It was narrated from ''Abdur-Rahman bin Abu Bakrah, from his father, that:The Prophet granted a concession to travelers: "If a traveler performed ablution and put on leather socks, then he performed a fresh ablution, he could wipe over the leather socks for three days and nights; the resident could do so for one day and one night."', 'It was narrated from ''Abdur-Rahman bin Abu Bakrah, from his father, that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:556', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 557, 'حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى، وَعَمْرُو بْنُ سَوَّادٍ الْمِصْرِيَّانِ، قَالاَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ، أَنْبَأَنَا يَحْيَى بْنُ أَيُّوبَ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ رَزِينٍ، عَنْ مُحَمَّدِ بْنِ يَزِيدَ بْنِ أَبِي زِيَادٍ، عَنْ أَيُّوبَ بْنِ قَطَنٍ، عَنْ عُبَادَةَ بْنِ نُسَىٍّ، عَنْ أُبَىِّ بْنِ عِمَارَةَ، - وَكَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ قَدْ صَلَّى فِي بَيْتِهِ الْقِبْلَتَيْنِ كِلْتَيْهِمَا - أَنَّهُ قَالَ لِرَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ أَمْسَحُ عَلَى الْخُفَّيْنِ قَالَ ‏"‏ نَعَمْ ‏"‏ ‏.‏ قَالَ يَوْمًا قَالَ ‏"‏ وَيَوْمَيْنِ ‏"‏ ‏.‏ قَالَ وَثَلاَثًا حَتَّى بَلَغَ سَبْعًا قَالَ لَهُ ‏"‏ وَمَا بَدَا لَكَ ‏"‏ ‏.‏', NULL, 'It was narrated from Ubayy bin ''Imarah, in whose house the Messenger of Allah performed prayer facing both prayer direction, that :He said to the Messenger of Allah: "Can I wipe over my leather socks?" He said: "Yes." He said: "For one day?" He said: "For two days?" He said: "For three?" And so on, until the number reached seven. He (the Prophet) said: "For as long as you see fit."', NULL, 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:557', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 558, 'حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ، حَدَّثَنَا أَبُو عَاصِمٍ، حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ، عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ، عَنِ الْحَكَمِ بْنِ عَبْدِ اللَّهِ الْبَلَوِيِّ، عَنْ عَلِيِّ بْنِ رَبَاحٍ اللَّخْمِيِّ، عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ، أَنَّهُ قَدِمَ عَلَى عُمَرَ بْنِ الْخَطَّابِ مِنْ مِصْرَ فَقَالَ مُنْذُ كَمْ لَمْ تَنْزِعْ خُفَّيْكَ قَالَ مِنَ الْجُمُعَةِ إِلَى الْجُمُعَةِ ‏.‏ قَالَ أَصَبْتَ السُّنَّةَ ‏.‏', NULL, 'It was narrated from ''Uqbah bin ''Amir Al-Juhani that:He came to ''Umar bin Khattab from Egypt. ''Umar said: "How long has it been since you have taken off your leather socks?" He said: "From one Friday to the next." He said: "You have acted in accordance with the Sunnah."', 'It was narrated from ''Uqbah bin ''Amir Al-Juhani that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:558', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 559, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، حَدَّثَنَا سُفْيَانُ، عَنْ أَبِي قَيْسٍ الأَوْدِيِّ، عَنِ الْهُزَيْلِ بْنِ شُرَحْبِيلَ، عَنِ الْمُغِيرَةِ بْنِ شُعْبَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ وَمَسَحَ عَلَى الْجَوْرَبَيْنِ وَالنَّعْلَيْنِ ‏.‏', NULL, 'It was narrated from Mughirah bin Shu''bah that:The Messenger of Allah performed ablution and wiped over his socks and his sandals.', 'It was narrated from Mughirah bin Shu''bah that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:559', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 560, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا مُعَلَّى بْنُ مَنْصُورٍ، وَبِشْرُ بْنُ آدَمَ، قَالاَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ، عَنْ عِيسَى بْنِ سِنَانٍ، عَنِ الضَّحَّاكِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَرْزَبٍ، عَنْ أَبِي مُوسَى الأَشْعَرِيِّ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ وَمَسَحَ عَلَى الْجَوْرَبَيْنِ وَالنَّعْلَيْنِ ‏.‏ قَالَ الْمُعَلَّى فِي حَدِيثِهِ لاَ أَعْلَمُهُ إِلاَّ قَالَ وَالنَّعْلَيْنِ ‏.‏', NULL, 'It was narrated from Abu Musa Al-Ash''ari that:The Messenger of Allah performed ablution and wiped over his socks and his sandals.', 'It was narrated from Abu Musa Al-Ash''ari that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:560', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 561, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا عِيسَى بْنُ يُونُسَ، عَنِ الأَعْمَشِ، عَنِ الْحَكَمِ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى، عَنْ كَعْبِ بْنِ عُجْرَةَ، عَنْ بِلاَلٍ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ مَسَحَ عَلَى الْخُفَّيْنِ وَالْخِمَارِ ‏.‏', NULL, 'It was narrated from Bilal that:The Messenger of Allah wiped over his leather socks and his head cover (i.e., over the Imamah).', 'It was narrated from Bilal that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:561', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 562, 'حَدَّثَنَا دُحَيْمٌ، حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ، حَدَّثَنَا الأَوْزَاعِيُّ، ح وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ، حَدَّثَنَا الأَوْزَاعِيُّ، حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ، حَدَّثَنَا أَبُو سَلَمَةَ، عَنْ جَعْفَرِ بْنِ عَمْرٍو، عَنْ أَبِيهِ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ يَمْسَحُ عَلَى الْخُفَّيْنِ وَالْعِمَامَةِ ‏.‏', NULL, 'It was narrated from Ja''far bin ''Amr that his father said:"I saw the Messenger of Allah wiping over his leather socks and turban."', 'It was narrated from Ja''far bin ''Amr that his father said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:562', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 563, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ، عَنْ دَاوُدَ بْنِ أَبِي الْفُرَاتِ، عَنْ مُحَمَّدِ بْنِ زَيْدٍ، عَنْ أَبِي شُرَيْحٍ، عَنْ أَبِي مُسْلِمٍ، مَوْلَى زَيْدِ بْنِ صُوحَانَ قَالَ كُنْتُ مَعَ سَلْمَانَ فَرَأَى رَجُلاً يَنْزِعُ خُفَّيْهِ لِلْوُضُوءِ فَقَالَ لَهُ سَلْمَانُ امْسَحْ عَلَى خُفَّيْكَ وَعَلَى خِمَارِكَ وَبِنَاصِيَتِكَ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ يَمْسَحُ عَلَى الْخُفَّيْنِ وَالْخِمَارِ ‏.‏', NULL, 'It was narrated that Abu Muslim, the freed slave of Zaid bin Suhan, said:"I was with Salman, and he saw a man removing his leather socks for ablution. Salman said to him" ''Wipe over your leather socks and your head cover, and your forehead, for I saw the Messenger of Allah wiping over his leather socks and head cover.''"', 'It was narrated that Abu Muslim, the freed slave of Zaid bin Suhan, said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:563', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 564, 'حَدَّثَنَا أَبُو طَاهِرٍ، أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ، حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ، عَنْ عَبْدِ الْعَزِيزِ بْنِ مُسْلِمٍ، عَنْ أَبِي مَعْقِلٍ، عَنْ أَنَسِ بْنِ مَالِكٍ، قَالَ رَأَيْتُ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ تَوَضَّأَ وَعَلَيْهِ عِمَامَةٌ قِطْرِيَّةٌ فَأَدْخَلَ يَدَهُ مِنْ تَحْتِ الْعِمَامَةِ فَمَسَحَ مُقَدَّمَ رَأْسِهِ وَلَمْ يَنْقُضِ الْعِمَامَةَ ‏.‏', NULL, 'It was narrated that Anas bin Malik said:"I saw the Messenger of Allah performing ablution, wearing a Qatari turban. He put his hand beneath the turban and wiped the front part of his head, and he did not take the turban off."', 'It was narrated that Anas bin Malik said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:564', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 565, 'حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ، حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ، عَنِ ابْنِ شِهَابٍ، عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ، عَنْ عَمَّارِ بْنِ يَاسِرٍ، أَنَّهُ قَالَ سَقَطَ عِقْدُ عَائِشَةَ فَتَخَلَّفَتْ لاِلْتِمَاسِهِ فَانْطَلَقَ أَبُو بَكْرٍ إِلَى عَائِشَةَ فَتَغَيَّظَ عَلَيْهَا فِي حَبْسِهَا النَّاسَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ الرُّخْصَةَ فِي التَّيَمُّمِ ‏.‏ قَالَ فَمَسَحْنَا يَوْمَئِذٍ إِلَى الْمَنَاكِبِ ‏.‏ قَالَ فَانْطَلَقَ أَبُو بَكْرٍ إِلَى عَائِشَةَ فَقَالَ مَا عَلِمْتُ إِنَّكِ لَمُبَارَكَةٌ ‏.‏', NULL, 'It was narrated that ''Ammar bin Yasir said:"Aishah dropped a necklace and stayed behind to look for it. Abu Bakr went to ''Aishah and got angry with her for keeping the people waiting. Then Allah revealed the concession allowing dry ablution, so we wiped our arms up to the shoulders. Abu Bakr went to ''Aishah and said: ''I did not know that you are blessed.''"', 'It was narrated that ''Ammar bin Yasir said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:565', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 566, 'حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ، حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ، عَنْ عَمْرٍو، عَنِ الزُّهْرِيِّ، عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ، عَنْ أَبِيهِ، عَنْ عَمَّارِ بْنِ يَاسِرٍ، قَالَ تَيَمَّمْنَا مَعَ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ إِلَى الْمَنَاكِبِ ‏.‏', NULL, 'It was narrated that ''Ammar [bin Yasir] said:"We did dry ablution with the Messenger of Allah, (wiping our arms) up to our shoulders."', 'It was narrated that ''Ammar [bin Yasir] said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:566', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 567, '"‏ جُعِلَتْ لِيَ الأَرْضُ مَسْجِدًا وَطَهُورًا ‏"', NULL, 'It was narrated from Abu Hurairah that:The Messenger of Allah said: "the earth has been made for me a place of worship and a means of purification."', 'It was narrated from Abu Hurairah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:567', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 568, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو أُسَامَةَ، عَنْ هِشَامِ بْنِ عُرْوَةَ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ، أَنَّهَا اسْتَعَارَتْ مِنْ أَسْمَاءَ قِلاَدَةً فَهَلَكَتْ فَأَرْسَلَ النَّبِيُّ ـ صلى الله عليه وسلم ـ أُنَاسًا فِي طَلَبِهَا فَأَدْرَكَتْهُمُ الصَّلاَةُ فَصَلَّوْا بِغَيْرِ وُضُوءٍ فَلَمَّا أَتَوُا النَّبِيَّ ـ صلى الله عليه وسلم ـ شَكَوْا ذَلِكَ إِلَيْهِ فَنَزَلَتْ آيَةُ التَّيَمُّمِ فَقَالَ أُسَيْدُ بْنُ حُضَيْرٍ جَزَاكِ اللَّهُ خَيْرًا فَوَاللَّهِ مَا نَزَلَ بِكِ أَمْرٌ قَطُّ إِلاَّ جَعَلَ اللَّهُ لَكِ مِنْهُ مَخْرَجًا وَجَعَلَ لِلْمُسْلِمِينَ فِيهِ بَرَكَةً ‏.‏', NULL, 'It was narrated from ''Aishah that:She borrowed a necklace from Asma'', and she lost it. The Prophet sent some people to look for it, and the time for prayer came so they prayed without ablution. When they came to the Prophet they complained to him about that, then the Verse of dry ablution was revealed. Usaid bin Hudair said: "May Allah reward you with good, for by Allah, nothing ever happens to you but Allah grants you a way out and blesses the Muslims thereby."', 'It was narrated from ''Aishah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:568', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 569, '"‏ إِنَّمَا كَانَ يَكْفِيكَ ‏"', NULL, 'It was narrated from Sa''eed bin ''Abdur-Rahman bin Abza from his father, that:A man came to ''Umar bin khattab and said: "I became impure following sexual emission and cannot find any water." ''Umar said to him: "Do not pray." But ''Ammar bin Yasir said: "Do you not remember, O Commander of the Believers, when you and I were on a military expedition and we became sexually impure and could not find water? As for you, you did not pray, but I rolled in the dust and then prayed. When I came to the Prophet and told him what had happened, he said: ''It would have been enough for you (to do this).'' (Then demonstrating) the Prophet struck the ground with his hands, then blew on hem, and wiped his face and palms with them."', 'It was narrated from Sa''eed bin ''Abdur-Rahman bin Abza from his father, that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:569', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 570, 'حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ، عَنِ ابْنِ أَبِي لَيْلَى، عَنِ الْحَكَمِ، وَسَلَمَةَ بْنِ كُهَيْلٍ، أَنَّهُمَا سَأَلاَ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى عَنِ التَّيَمُّمِ، فَقَالَ أَمَرَ النَّبِيُّ ـ صلى الله عليه وسلم ـ عَمَّارًا أَنْ يَفْعَلَ هَكَذَا وَضَرَبَ بِيَدَيْهِ إِلَى الأَرْضِ ثُمَّ نَفَضَهُمَا وَمَسَحَ عَلَى وَجْهِهِ ‏.‏ قَالَ الْحَكَمُ وَيَدَيْهِ ‏.‏ وَقَالَ سَلَمَةُ وَمِرْفَقَيْهِ ‏.‏', NULL, 'It was narrated from Hakam and Salamah in Kuhail that:They asked ''Abdullah bin Abi Awfa about dry ablution. He said: "The Prophet commanded ''Ammar to do like this;'' and he struck the ground with his palms, shook the dust off and wiped his face. (Da''if)Hakam said, "and his hands," Salamah said, "and his elbows."', 'It was narrated from Hakam and Salamah in Kuhail that', NULL, 'https://sunnah.com/ibnmajah:570', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 571, 'حَدَّثَنَا أَبُو الطَّاهِرِ، أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ، أَنْبَأَنَا يُونُسُ بْنُ يَزِيدَ، عَنِ ابْنِ شِهَابٍ، عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ، عَنْ عَمَّارِ بْنِ يَاسِرٍ، حِينَ تَيَمَّمُوا مَعَ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ فَأَمَرَ الْمُسْلِمِينَ فَضَرَبُوا بِأَكُفِّهِمُ التُّرَابَ وَلَمْ يَقْبِضُوا مِنَ التُّرَابِ شَيْئًا فَمَسَحُوا بِوُجُوهِهِمْ مَسْحَةً وَاحِدَةً ثُمَّ عَادُوا فَضَرَبُوا بِأَكُفِّهِمُ الصَّعِيدَ مَرَّةً أُخْرَى فَمَسَحُوا بِأَيْدِيهِمْ ‏.‏', NULL, 'It was narrated from ''Ammar bin Yasir that:When they did dry ablution with the Messenger of Allah, he commanded the Muslims to strike the dust with the palms of their hands, and they did not pick up any dust. Then they wiped their faces once, then they struck the dust with their palms once again and wiped their hands.', 'It was narrated from ''Ammar bin Yasir that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:571', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 572, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبِ بْنِ أَبِي الْعِشْرِينَ، حَدَّثَنَا الأَوْزَاعِيُّ، عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ، قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ، يُخْبِرُ أَنَّ رَجُلاً، أَصَابَهُ جُرْحٌ فِي رَأْسِهِ عَلَى عَهْدِ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ ثُمَّ أَصَابَهُ احْتِلاَمٌ فَأُمِرَ بِالاِغْتِسَالِ فَاغْتَسَلَ فَكُزَّ فَمَاتَ فَبَلَغَ ذَلِكَ النَّبِيَّ ـ صلى الله عليه وسلم ـ فَقَالَ ‏"‏ قَتَلُوهُ قَتَلَهُمُ اللَّهُ أَفَلَمْ يَكُنْ شِفَاءَ الْعِيِّ السُّؤَالُ ‏"‏ ‏.‏ قَالَ عَطَاءٌ وَبَلَغَنَا أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ قَالَ ‏"‏ لَوْ غَسَلَ جَسَدَهُ وَتَرَكَ رَأْسَهُ حَيْثُ أَصَابَهُ الْجِرَاحُ ‏"‏ ‏.‏', NULL, 'It was narrated that ''Ata'' bin Abu Rabah said:"I heard Ibn ''Abbas saying that a man was injured in the head at the time of the Messenger of Allah, then he had a wet dream. He was told to have a bath, so he took the bath, became rigid and stiff, and died. News of that reached the Messenger of Allah and he said: ''They have killed him, may Allah kill them! Is not the cure for a lack of knowledge to ask questions?''"''Ata'' said: "We heard that the Messenger of Allah said: ''If only he had washed his body and left his head alone where the wound was.''"', 'It was narrated that ''Ata'' bin Abu Rabah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:572', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 573, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنِ الأَعْمَشِ، عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ، عَنْ كُرَيْبٍ، مَوْلَى ابْنِ عَبَّاسٍ حَدَّثَنَا ابْنُ عَبَّاسٍ، عَنْ خَالَتِهِ، مَيْمُونَةَ قَالَتْ وَضَعْتُ لِلنَّبِيِّ ـ صلى الله عليه وسلم ـ غُسْلاً فَاغْتَسَلَ مِنَ الْجَنَابَةِ فَأَكْفَأَ الإِنَاءَ بِشِمَالِهِ عَلَى يَمِينِهِ فَغَسَلَ كَفَّيْهِ ثَلاَثًا ثُمَّ أَفَاضَ عَلَى فَرْجِهِ ثُمَّ دَلَكَ يَدَهُ فِي الأَرْضِ ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ ثَلاَثًا وَذِرَاعَيْهِ ثَلاَثًا ثُمَّ أَفَاضَ الْمَاءَ عَلَى سَائِرِ جَسَدِهِ ثُمَّ تَنَحَّى فَغَسَلَ رِجْلَيْهِ ‏.‏', NULL, 'Ibn ''Abbas narrated that his maternal aunt Maimunah said:"I put out some water for the Prophet to take a bath, and he bathe to cleanse himself from impurity following sexual activity. He tilted the vessel with his left hand, pouring water into his right, and washed his hands three times. Then he pourd water over his private parts, then he rubbed his hands on the ground. Then he rinsed his mouth and nose, and washed his face three times, and his forearms three times. Then he poured water over the rest of his body, then he moved aside and washed his feet."', 'Ibn ''Abbas narrated that his maternal aunt Maimunah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:573', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 574, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ، حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ، حَدَّثَنَا صَدَقَةُ بْنُ سَعِيدٍ الْحَنَفِيُّ، حَدَّثَنَا جُمَيْعُ بْنُ عُمَيْرٍ التَّيْمِيُّ، قَالَ انْطَلَقْتُ مَعَ عَمَّتِي وَخَالَتِي فَدَخَلْنَا عَلَى عَائِشَةَ فَسَأَلْنَاهَا كَيْفَ كَانَ يَصْنَعُ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ عِنْدَ غُسْلِهِ مِنَ الْجَنَابَةِ قَالَتْ كَانَ يُفِيضُ عَلَى كَفَّيْهِ ثَلاَثَ مَرَّاتٍ ثُمَّ يُدْخِلُهَا فِي الإِنَاءِ ثُمَّ يَغْسِلُ رَأْسَهُ ثَلاَثَ مَرَّاتٍ ثُمَّ يُفِيضُ عَلَى جَسَدِهِ ثُمَّ يَقُومُ إِلَى الصَّلاَةِ وَأَمَّا نَحْنُ فَإِنَّا نَغْسِلُ رُءُوسَنَا خَمْسَ مِرَارٍ مِنْ أَجْلِ الضَّفْرِ ‏.‏', NULL, 'Jumai'' bin ''Umair At-Taimi said:"I went out with my paternal aunt and maternal aunt and we entered upon ''Aishah. We asked her: ''What did the Messenger of Allah do when he had the bath to cleanse himself from sexual impurity?'' She said: ''He used to pour water on his hand three times, then he would put them in the vessel and wash his face three times, then he would pour water over his body, then he would get up and perform prayer. As for us, we would wash our heads five times because of our braided hair.''"', 'Jumai'' bin ''Umair At-Taimi said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:574', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 575, '"‏ أَمَّا أَنَا فَأُفِيضُ عَلَى رَأْسِي ثَلاَثَ أَكُفٍّ ‏"', NULL, 'It was narrated that Jubair bin Mut''im said:"(The Companions) disputed in the presence of the Messenger of Allah about having a bath to cleanse oneself from sexual impurity. The Messenger of Allah said: ''As for me, I pour three handfuls of water on my head.''"', 'It was narrated that Jubair bin Mut''im said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:575', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 576, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، ح وَحَدَّثَنَا أَبُو كُرَيْبٍ، حَدَّثَنَا ابْنُ فُضَيْلٍ، جَمِيعًا عَنْ فُضَيْلِ بْنِ مَرْزُوقٍ، عَنْ عَطِيَّةَ، عَنْ أَبِي سَعِيدٍ، أَنَّ رَجُلاً، سَأَلَهُ عَنِ الْغُسْلِ، مِنَ الْجَنَابَةِ فَقَالَ ثَلاَثًا ‏.‏ فَقَالَ الرَّجُلُ إِنَّ شَعْرِي كَثِيرٌ ‏.‏ فَقَالَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ كَانَ أَكْثَرَ شَعْرًا مِنْكَ وَأَطْيَبَ ‏.‏', NULL, 'It was narrated from Abu Sa''eed that:A man asked him about having a bath to cleanse oneself from sexual impurity. He said to pour water three times. The man said: "But I have a lot of hair." He said: "The Messenger of Allah had more hair than you and he was cleaner."', 'It was narrated from Abu Sa''eed that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:576', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 577, '"‏ أَمَّا أَنَا فَأَحْثُو عَلَى رَأْسِي ثَلاَثًا ‏"', NULL, 'It was narrated that Jabir said:"I said: ''O Messenger of Allah! I live in a cold land, so how should I have a bath to cleanse myself from sexual impurity?'' He said: ''As for me, I pour three handfuls of water over my head.''"', 'It was narrated that Jabir said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:577', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 578, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو خَالِدٍ الأَحْمَرُ، عَنِ ابْنِ عَجْلاَنَ، عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ، عَنْ أَبِي هُرَيْرَةَ، سَأَلَهُ رَجُلٌ كَمْ أُفِيضُ عَلَى رَأْسِي وَأَنَا جُنُبٌ قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَحْثُو عَلَى رَأْسِهِ ثَلاَثَ حَثَيَاتٍ ‏.‏ قَالَ الرَّجُلُ إِنَّ شَعْرِي طَوِيلٌ ‏.‏ قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ أَكْثَرَ شَعَرًا مِنْكَ وَأَطْيَبَ ‏.‏', NULL, 'It was narrated from Abu Hurairah that :A man asked him: "How much water should I pour over my head when I m sexually impure?" He said: "the messenger of Allah used to pour three handfuls of water over his head." The man said: "My hair is long." He said: "The Messenger of Allah had more hair than you and he was cleaner."', 'It was narrated from Abu Hurairah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:578', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 579, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ، وَإِسْمَاعِيلُ بْنُ مُوسَى السُّدِّيُّ، قَالُوا حَدَّثَنَا شَرِيكٌ، عَنْ أَبِي إِسْحَاقَ، عَنِ الأَسْوَدِ، عَنْ عَائِشَةَ، قَالَتْ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ لاَ يَتَوَضَّأُ بَعْدَ الْغُسْلِ مِنَ الْجَنَابَةِ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah would not perform ablution after the bath to cleanse himself from sexual impurity."', 'It was narrated that ''Aishah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:579', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 580, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا شَرِيكٌ، عَنْ حُرَيْثٍ، عَنِ الشَّعْبِيِّ، عَنْ مَسْرُوقٍ، عَنْ عَائِشَةَ، قَالَتْ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَغْتَسِلُ مِنَ الْجَنَابَةِ ثُمَّ يَسْتَدْفِئُ بِي قَبْلَ أَنْ أَغْتَسِلَ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah used to have a bath to cleanse himself from sexual impurity, then he would warm himself with me before I had the bath."', 'It was narrated that ''Aishah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:580', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 581, 'حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ، حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ، عَنِ الأَعْمَشِ، عَنْ أَبِي إِسْحَاقَ، عَنِ الأَسْوَدِ، عَنْ عَائِشَةَ، قَالَتْ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يُجْنِبُ ثُمَّ يَنَامُ وَلاَ يَمَسُّ مَاءً حَتَّى يَقُومَ بَعْدَ ذَلِكَ فَيَغْتَسِلَ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah would become sexually impure and then sleep without water until he got up later on and taken a bath."', 'It was narrated that ''Aishah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:581', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 582, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو الأَحْوَصِ، عَنْ أَبِي إِسْحَاقَ، عَنِ الأَسْوَدِ، عَنْ عَائِشَةَ، قَالَتْ إِنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ إِنْ كَانَتْ لَهُ إِلَى أَهْلِهِ حَاجَةٌ قَضَاهَا ثُمَّ يَنَامُ كَهَيْئَتِهِ لاَ يَمَسُّ مَاءً ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah, if he needed any of his wives, would satisfy his needs then he would sleep as he was, without touching water."', 'It was narrated that ''Aishah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:582', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 583, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، حَدَّثَنَا سُفْيَانُ، عَنْ أَبِي إِسْحَاقَ، عَنِ الأَسْوَدِ، عَنْ عَائِشَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ كَانَ يُجْنِبُ ثُمَّ يَنَامُ كَهَيْئَتِهِ لاَ يَمَسُّ مَاءً ‏.‏ قَالَ سُفْيَانُ فَذَكَرْتُ الْحَدِيثَ يَوْمًا فَقَالَ لِي إِسْمَاعِيلُ يَا فَتًى يُشَدُّ هَذَا الْحَدِيثُ بِشَىْءٍ ‏.‏', NULL, 'It was narrated from ''Aishah that:The Messenger of Allah would become sexually impure then sleep as he was, without touching water. (Da''if)Sufyan said: "I mentioned this Hadith one day, and Isma''il said to me: ''O young man, you should support this Hadith with something else.''"', 'It was narrated from ''Aishah that', NULL, 'https://sunnah.com/ibnmajah:583', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 584, 'حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ، أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ، عَنِ الزُّهْرِيِّ، عَنْ أَبِي سَلَمَةَ، عَنْ عَائِشَةَ، قَالَتْ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ إِذَا أَرَادَ أَنْ يَنَامَ وَهُوَ جُنُبٌ تَوَضَّأَ وُضُوءَهُ لِلصَّلاَةِ ‏.‏', NULL, 'It was narrated that ''Aishah said:"When the Messenger of Allah wanted to sleep and he was sexually impure, he would perform ablution as for prayer."', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:584', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 585, '"‏ نَعَمْ إِذَا تَوَضَّأَ ‏"', NULL, 'It was narrated from Ibn ''Umar that :''Umar bin Khattab said to the Messenger of Allah: "can anyone of us sleep if he is sexually impure?" He said: "Yes, if he performs ablution."', 'It was narrated from Ibn ''Umar that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:585', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 586, 'حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ، مُحَمَّدُ بْنُ عُثْمَانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ، عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ، عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ، عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ، أَنَّهُ كَانَ تُصِيبُهُ الْجَنَابَةُ بِاللَّيْلِ فَيُرِيدُ أَنْ يَنَامَ فَأَمَرَهُ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ أَنْ يَتَوَضَّأَ ثُمَّ يَنَامَ ‏.‏', NULL, 'It was narrated from Abu Sa''eed Khudri that:He used to become sexually impure at night, then he would want to sleep. The Messenger of Allah told him to perform ablution and then go to sleep.', 'It was narrated from Abu Sa''eed Khudri that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:586', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 587, '"‏ إِذَا أَتَى أَحَدُكُمْ أَهْلَهُ ثُمَّ أَرَادَ أَنْ يَعُودَ فَلْيَتَوَضَّأْ ‏"', NULL, 'It was narrated that Abu Sa''eed said:"The Messenger of Allah said: ''If anyone of you has intercourse with his wife, then he wants to do it again, let him perform ablution.''"', 'It was narrated that Abu Sa''eed said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:587', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 588, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى أَبُو مُوسَى، حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ، وَأَبُو أَحْمَدَ عَنْ سُفْيَانَ، عَنْ مَعْمَرٍ، عَنْ قَتَادَةَ، عَنْ أَنَسٍ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ كَانَ يَطُوفُ عَلَى نِسَائِهِ فِي غُسْلٍ وَاحِدٍ ‏.‏', NULL, 'It was narrated from Anas that:The Prophet used to go round to all his wives with one bath.', 'It was narrated from Anas that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:588', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 589, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، عَنْ صَالِحِ بْنِ أَبِي الأَخْضَرِ، عَنِ الزُّهْرِيِّ، عَنْ أَنَسٍ، قَالَ وَضَعْتُ لِرَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ غُسْلاً فَاغْتَسَلَ مِنْ جَمِيعِ نِسَائِهِ فِي لَيْلَةٍ ‏.‏', NULL, 'It was narrated that Anas said:"I put out water for the Messenger of Allah for a bath, and he had a bath after going to all of his wives in one night."', 'It was narrated that Anas said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:589', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 590, '"‏ هُوَ أَزْكَى وَأَطْيَبُ وَأَطْهَرُ ‏"', NULL, 'It was narrated from Abu Rafi'' that:The Prophet went around to all of his wives in one night, and he had a bath after each one of them. It was said to him: "O Messenger of Allah, why not make it one bath?" He said: "This is purer, better and cleaner."', 'It was narrated from Abu Rafi'' that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:590', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 591, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا ابْنُ عُلَيَّةَ، وَغُنْدَرٌ، وَوَكِيعٌ، عَنْ شُعْبَةَ، عَنِ الْحَكَمِ، عَنْ إِبْرَاهِيمَ، عَنِ الأَسْوَدِ، عَنْ عَائِشَةَ، قَالَتْ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ إِذَا أَرَادَ أَنْ يَأْكُلَ وَهُوَ جُنُبٌ تَوَضَّأَ ‏.‏', NULL, 'It was narrated that ''Aishah said:"If the Messenger of Allah wanted to eat when he was sexually impure, he would perform ablution."', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:591', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 592, '"‏ نَعَمْ إِذَا تَوَضَّأَ وُضُوءَهُ لِلصَّلاَةِ ‏"', NULL, 'It was narrated that Jabir bin ''Abdullah said:"The Prophet was asked about whether a person who is sexually impure can sleep, or eat, or drink. He said: ''yes, if he does ablution as for the prayer.''"', 'It was narrated that Jabir bin ''Abdullah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:592', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 593, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ، عَنْ يُونُسَ، عَنِ الزُّهْرِيِّ، عَنْ أَبِي سَلَمَةَ، عَنْ عَائِشَةَ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ كَانَ إِذَا أَرَادَ أَنْ يَأْكُلَ وَهُوَ جُنُبٌ غَسَلَ يَدَيْهِ ‏.‏', NULL, 'It was narrated from ''Aishah that:If the Prophet wanted to eat when he was sexually impure, he would wash his hands.', 'It was narrated from ''Aishah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:593', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 594, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، عَنْ عَمْرِو بْنِ مُرَّةَ، عَنْ عَبْدِ اللَّهِ بْنِ سَلِمَةَ، قَالَ دَخَلْتُ عَلَى عَلِيِّ بْنِ أَبِي طَالِبٍ فَقَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَأْتِي الْخَلاَءَ فَيَقْضِي الْحَاجَةَ ثُمَّ يَخْرُجُ فَيَأْكُلُ مَعَنَا الْخُبْزَ وَاللَّحْمَ وَيَقْرَأُ الْقُرْآنَ وَلاَ يَحْجُبُهُ - وَرُبَّمَا قَالَ وَلاَ يَحْجُزُهُ - عَنِ الْقُرْآنِ شَىْءٌ إِلاَّ الْجَنَابَةُ ‏.‏', NULL, 'It was narrated that ''Abdullah bin Salamah said:"I entered upon ''Ali bin Abu Talib and he said: ''The Messenger of Allah used to go to the lavatory and relieve himself, then come out, and he would eat bread and meat with us and recite Qur''an, nothing stopped him'' or perhaps he said: ''prevented him from doing so except sexual impurity.''"', 'It was narrated that ''Abdullah bin Salamah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:594', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 595, '"‏ لاَ يَقْرَأُ الْقُرْآنَ الْجُنُبُ وَلاَ الْحَائِضُ ‏"', NULL, 'It was narrated that Ibn ''Umar said:"The Messenger of Allah said: ''No one who is sexually impure and no woman who is menstruating should recite Qur''an.''"', 'It was narrated that Ibn ''Umar said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:595', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 596, '"‏ لاَ يَقْرَأُ الْجُنُبُ وَالْحَائِضُ شَيْئًا مِنَ الْقُرْآنِ ‏"', NULL, 'It was narrated that Ibn ''Umar said:"The Messenger of Allah said: ''No one who is sexually impure and no woman who is menstruating should recite anything of the Qur''an.''"', 'It was narrated that Ibn ''Umar said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:596', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 597, '"‏ إِنَّ تَحْتَ كُلِّ شَعَرَةٍ جَنَابَةً فَاغْسِلُوا الشَّعَرَ وَأَنْقُوا الْبَشَرَةَ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''Under every hair there is the state of sexual impurity, so wash the hair and cleanse the skin.''"', 'It was narrated that Abu Hurairah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:597', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 598, 'حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ، حَدَّثَنِي عُتْبَةُ بْنُ أَبِي حَكِيمٍ، حَدَّثَنِي طَلْحَةُ بْنُ نَافِعٍ، حَدَّثَنِي أَبُو أَيُّوبَ الأَنْصَارِيُّ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ قَالَ ‏"‏ الصَّلَوَاتُ الْخَمْسُ وَالْجُمُعَةُ إِلَى الْجُمُعَةِ وَأَدَاءُ الأَمَانَةِ كَفَّارَةٌ لِمَا بَيْنَهَا ‏"‏ ‏.‏ قُلْتُ وَمَا أَدَاءُ الأَمَانَةِ قَالَ ‏"‏ غُسْلُ الْجَنَابَةِ فَإِنَّ تَحْتَ كُلِّ شَعَرَةٍ جَنَابَةً ‏"‏ ‏.‏', NULL, 'Abu Ayyub Al-Ansari narrated that:The Prophet said: "The five daily prayers, from one Friday to the next, and fulfilling the trust are all expiation for whatever (sins) come between them." I said: "What is fulfilling the trust?" He said: Having a bath to cleanse oneself from sexual impurity, for under every hair there is the state of sexual impurity."', 'Abu Ayyub Al-Ansari narrated that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:598', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 599, '"‏ مَنْ تَرَكَ مَوْضِعَ شَعَرَةٍ مِنْ جَسَدِهِ مِنْ جَنَابَةٍ لَمْ يَغْسِلْهَا فُعِلَ بِهِ كَذَا وَكَذَا مِنَ النَّارِ ‏"', NULL, 'It was narrated from ''Ali bin Abu Talib that:The Prophet said: "Whoever leaves an area the size of a hair on his body and does not cleanse it from sexual impurity, such and such will be done to him in the Fire." ''Ali said: "Because of that I am hostile towards my hair," and he used to shave his head.', 'It was narrated from ''Ali bin Abu Talib that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:599', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 600, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنْ هِشَامِ بْنِ عُرْوَةَ، عَنْ أَبِيهِ، عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ، عَنْ أُمِّهَا أُمِّ سَلَمَةَ، قَالَتْ جَاءَتْ أُمُّ سُلَيْمٍ إِلَى النَّبِيِّ ـ صلى الله عليه وسلم ـ فَسَأَلَتْهُ عَنِ الْمَرْأَةِ تَرَى فِي مَنَامِهَا مَا يَرَى الرَّجُلُ قَالَ ‏"‏ نَعَمْ إِذَا رَأَتِ الْمَاءَ فَلْتَغْتَسِلْ ‏"‏ ‏.‏ فَقُلْتُ فَضَحْتِ النِّسَاءَ وَهَلْ تَحْتَلِمُ الْمَرْأَةُ قَالَ النَّبِيُّ ـ صلى الله عليه وسلم ـ ‏"‏ تَرِبَتْ يَمِينُكِ فَبِمَ يُشْبِهُهَا وَلَدُهَا إِذًا ‏"‏ ‏.‏', NULL, 'It was narrated from Zainab, the daughter of Umm Salamah, that :Her mother Umm Salamah said: "Umm Sulaim came to the Prophet and asked him about a woman who sees in her dream something like a man sees. He said: ''Yes, if she sees water (discharge), let her take a bath.'' I said: ''You have embarrassed the women. Do women experience wet dreams?'' The Prophet said: ''May your hands be rubbed with dust, how else does her child resemble her?''"', 'It was narrated from Zainab, the daughter of Umm Salamah, that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:600', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 601, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ، وَعَبْدُ الأَعْلَى، عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ، عَنْ قَتَادَةَ، عَنْ أَنَسٍ، أَنَّ أُمَّ سُلَيْمٍ، سَأَلَتْ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ عَنِ الْمَرْأَةِ تَرَى فِي مَنَامِهَا مَا يَرَى الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ ‏"‏ إِذَا رَأَتْ ذَلِكَ فَأَنْزَلَتْ فَعَلَيْهَا الْغُسْلُ ‏"‏ ‏.‏ فَقَالَتْ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ أَيَكُونُ هَذَا قَالَ ‏"‏ نَعَمْ مَاءُ الرَّجُلِ غَلِيظٌ أَبْيَضُ وَمَاءُ الْمَرْأَةِ رَقِيقٌ أَصْفَرُ فَأَيُّهُمَا سَبَقَ أَوْ عَلاَ أَشْبَهَهُ الْوَلَدُ ‏"‏ ‏.‏', NULL, 'It was narrated from Anas that:Umm Sulaim asked the Messenger of Allah about a woman who sees in her dream something like that which a man sees. The Messenger of Allah said: "If she sees that and has a discharge, then let her perform a bath." Umm Salamah said: "O Messenger of Allah, does that really happen?" He said: "Yes, the water of the man is thick and white and the water of a woman is thin and yellow. Whichever of them comes first or predominates, the child will resemble (that parent)."', 'It was narrated from Anas that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:601', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 602, '"‏ لَيْسَ عَلَيْهَا غُسْلٌ حَتَّى تُنْزِلَ كَمَا أَنَّهُ لَيْسَ عَلَى الرَّجُلِ غُسْلٌ حَتَّى يُنْزِلَ ‏"', NULL, 'It was narrated from Khawlah bint Hakim that:She asked the Messenger of Allah about a woman who sees in her dream that which a man sees. He said: "She does not have to take a bath unless she has an orgasm, just as man does not have to take a bath unless he has an orgasm."', 'It was narrated from Khawlah bint Hakim that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:602', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 603, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ، عَنْ أَيُّوبَ بْنِ مُوسَى، عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ، عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ، عَنْ أُمِّ سَلَمَةَ، قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أَشُدُّ ضَفْرَ رَأْسِي أَفَأَنْقُضُهُ لِغُسْلِ الْجَنَابَةِ فَقَالَ ‏"‏ إِنَّمَا يَكْفِيكِ أَنْ تَحْثِي عَلَيْهِ ثَلاَثَ حَثَيَاتٍ مِنْ مَاءٍ ثُمَّ تُفِيضِي عَلَيْكِ مِنَ الْمَاءِ فَتَطْهُرِينَ ‏"‏ ‏.‏ أَوْ قَالَ ‏"‏ فَإِذَا أَنْتِ قَدْ طَهُرْتِ ‏"‏ ‏.‏', NULL, 'It was narrated that Umm Salamah said:"I said, O Messenger of Allah! I am a woman with tight braids. Should I undo them when I take a bath to cleanse myself from the state of sexual impurity?" He said: "Rather it is sufficient for you to pour three handfuls of water over yourself, and you will be purified," or he said: "In that case you would have become purified."', 'It was narrated that Umm Salamah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:603', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 604, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا إِسْمَاعِيلُ ابْنُ عُلَيَّةَ، عَنْ أَيُّوبَ، عَنْ أَبِي الزُّبَيْرِ، عَنْ عُبَيْدِ بْنِ عُمَيْرٍ، قَالَ بَلَغَ عَائِشَةَ أَنَّ عَبْدَ، اللَّهِ بْنَ عَمْرٍو يَأْمُرُ نِسَاءَهُ إِذَا اغْتَسَلْنَ أَنْ يَنْقُضْنَ رُءُوسَهُنَّ فَقَالَتْ يَا عَجَبًا لاِبْنِ عَمْرٍو هَذَا أَفَلاَ يَأْمُرُهُنَّ أَنَّ يَحْلِقْنَ رُءُوسَهُنَّ لَقَدْ كُنْتُ أَنَا وَرَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ نَغْتَسِلُ مِنْ إِنَاءٍ وَاحِدٍ فَلاَ أَزِيدُ عَلَى أَنْ أُفْرِغَ عَلَى رَأْسِي ثَلاَثَ إِفْرَاغَاتٍ ‏.‏', NULL, 'It was narrated that ''Ubaid bin ''Umair said:"Aishah heard that ''Abdullah bin ''Amr was telling his wives to undo their braids (when they bathed). She said: ''How odd that Ibn ''Amr would do that! Why does he not tell them to shave their heads? The Messenger of Allah and I used to bathe from a single vessel, and I never did more than pour three handfuls of water over my head.''"', 'It was narrated that ''Ubaid bin ''Umair said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:604', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 605, '"‏ لاَ يَغْتَسِلْ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ وَهُوَ جُنُبٌ ‏"', NULL, 'It was narrated from Bukair bin ''Abdullah bin Ashajj that:Abu Sa''ib, the freed slave of Hisham bin Zuhrah, told him that he heard Abu Hurairah say: "The Messenger of Allah said: ''No one of you should bathe in standing water when he is sexually impure.''" He (Abu Sa''ib) said: "What should he do, O Abu Hurairah?" He said: "Let him take some out (and pour it over himself)."', 'It was narrated from Bukair bin ''Abdullah bin Ashajj that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:605', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 606, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَمُحَمَّدُ بْنُ بَشَّارٍ، قَالاَ حَدَّثَنَا غُنْدَرٌ، مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ، عَنِ الْحَكَمِ، عَنْ ذَكْوَانَ، عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ مَرَّ عَلَى رَجُلٍ مِنَ الأَنْصَارِ فَأَرْسَلَ إِلَيْهِ فَخَرَجَ رَأْسُهُ يَقْطُرُ فَقَالَ ‏"‏ لَعَلَّنَا أَعْجَلْنَاكَ ‏"‏ ‏.‏ قَالَ نَعَمْ يَا رَسُولَ اللَّهِ ‏.‏ قَالَ ‏"‏ إِذَا أُعْجِلْتَ أَوْ أُقْحِطْتَ فَلاَ غُسْلَ عَلَيْكَ وَعَلَيْكَ الْوُضُوءُ ‏"‏ ‏.‏', NULL, 'It was narrated from Abu Sa''eed Al-Khudri that:The Messenger of Allah passed by (the house of) one of the Ansar and sent word for him to come out. He came out with his head dripping and (the Prophet) said: "Perhaps we made you hurry?"He said: "O Messenger of Allah." He said, "If you are hurried (by someone) or obstructed (from orgasm) and do not ejaculate, then you do not have to take a bath, but you should perform ablution."', 'It was narrated from Abu Sa''eed Al-Khudri that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:606', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 607, '"‏ الْمَاءُ مِنَ الْمَاءِ ‏"', NULL, 'It was narrated that Abu Ayyub said:"The Messenger of Allah said: ''Water (of bath) is for water (of seminal discharge).''"', 'It was narrated that Abu Ayyub said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:607', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 608, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ الطَّنَافِسِيُّ، وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ، قَالاَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ، حَدَّثَنَا الأَوْزَاعِيُّ، أَنْبَأَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ، أَخْبَرَنَا الْقَاسِمُ بْنُ مُحَمَّدٍ، عَنْ عَائِشَةَ، زَوْجِ النَّبِيِّ ـ صلى الله عليه وسلم ـ قَالَتْ إِذَا الْتَقَى الْخِتَانَانِ فَقَدْ وَجَبَ الْغُسْلُ فَعَلْتُهُ أَنَا وَرَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ فَاغْتَسَلْنَا ‏.‏', NULL, 'It was narrated that ''Aishah the wife of the Prophet said:"When the two circumcised parts meet, then bath is obligatory. The Messenger of Allah and I did that, and we bathed."', 'It was narrated that ''Aishah the wife of the Prophet said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:608', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 609, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ، أَنْبَأَنَا يُونُسُ، عَنِ الزُّهْرِيِّ، قَالَ قَالَ سَهْلُ بْنُ سَعْدٍ السَّاعِدِيُّ أَنْبَأَنَا أُبَىُّ بْنُ كَعْبٍ، قَالَ إِنَّمَا كَانَتْ رُخْصَةً فِي أَوَّلِ الإِسْلاَمِ ثُمَّ أُمِرْنَا بِالْغُسْلِ بَعْدُ ‏.‏', NULL, 'Ubayy bin Ka''b said:"That was a concession that was granted in the early days of Islam, then we were commanded to have a bathe after that."', 'Ubayy bin Ka''b said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:609', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 610, '"‏ إِذَا جَلَسَ الرَّجُلُ بَيْنَ شُعَبِهَا الأَرْبَعِ ثُمَّ جَهَدَهَا فَقَدْ وَجَبَ الْغُسْلُ ‏"', NULL, 'It was narrated from Abu Hurairah that:The Messenger of Allah said: "When a man sits between the four parts (arms and legs of his wife) and has intercourse, then bath is obligatory."', 'It was narrated from Abu Hurairah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:610', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 611, '"‏ إِذَا الْتَقَى الْخِتَانَانِ وَتَوَارَتِ الْحَشَفَةُ فَقَدْ وَجَبَ الْغُسْلُ ‏"', NULL, 'It was narrated from ''Amr bin Shu''aib from his father, that his grandfather said:"The Messenger of Allah said: ''When the two circumcised parts meet, and (the tip of the penis) disappears, then bath is obligatory.''"', 'It was narrated from ''Amr bin Shu''aib from his father, that his grandfather said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:611', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 612, '"‏ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ نَوْمِهِ فَرَأَى بَلَلاً وَلَمْ يَرَ أَنَّهُ احْتَلَمَ اغْتَسَلَ وَإِذَا رَأَى أَنَّهُ قَدِ احْتَلَمَ وَلَمْ يَرَ بَلَلاً فَلاَ غُسْلَ عَلَيْهِ ‏"', NULL, 'It was narrated from ''Aishah that:The Prophet said: "If anyone of wakes up and sees some wetness, but he does not think that he had an erotic dream, let him have a bath. But if he thinks that he had an erotic dream but he does not see any wetness, then he does not have to take a bath."', 'It was narrated from ''Aishah that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:612', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 613, '"‏ وَلِّنِي ‏"', NULL, 'Abu Samh said:"I used to serve the Prophet, and when he wanted to take a bath he would say: ''Turn your back to me.'' So I would turn my back and hung up a cloth, and concealed him with it."', 'Abu Samh said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:613', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 614, 'حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ، أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ، عَنِ ابْنِ شِهَابٍ، عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ نَوْفَلٍ، أَنَّهُ قَالَ سَأَلْتُ فَلَمْ أَجِدْ أَحَدًا يُخْبِرُنِي أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ سَبَّحَ فِي سَفَرٍ حَتَّى أَخْبَرَتْنِي أُمُّ هَانِئٍ بِنْتُ أَبِي طَالِبٍ أَنَّهُ قَدِمَ عَامَ الْفَتْحِ فَأَمَرَ بِسِتْرٍ فَسُتِرَ عَلَيْهِ فَاغْتَسَلَ ثُمَّ سَبَّحَ ثَمَانِيَ رَكَعَاتٍ ‏.‏', NULL, 'It was narrated that ''Abdullah bin Harith bin Nawfal said:"I asked whether the Messenger of Allah prayed voluntary prayer when traveling, but I could not find anyone to tell me until Umm Hani'' bint Abu Talib told me that he had come during the year of the Conquest (of Makkah). He ordered that a screen be held up, and that was done, and he took a bath; then he prayed eight Rak''ah (units) of voluntary prayer."', 'It was narrated that ''Abdullah bin Harith bin Nawfal said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:614', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 615, '"‏ لاَ يَغْتَسِلَنَّ أَحَدُكُمْ بِأَرْضِ فَلاَةٍ وَلاَ فَوْقَ سَطْحٍ لاَ يُوَارِيهِ فَإِنْ لَمْ يَكُنْ يَرَى فَإِنَّهُ يُرَى ‏"', NULL, 'It was narrated that ''Abdullah bin Mas''ud said:"The Messenger of Allah said: ''No one of you should bathe in open land or on a roof where he is not concealed; even if he does not see anyone, he can still be seen.''"', 'It was narrated that ''Abdullah bin Mas''ud said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:615', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 616, '"‏ إِذَا أَرَادَ أَحَدُكُمُ الْغَائِطَ وَأُقِيمَتِ الصَّلاَةُ فَلْيَبْدَأْ بِهِ ‏"', NULL, 'It was narrated that ''Abdullah bin Arqam said:"The Messenger of Allah said: ''If anyone of you needs to defecate and the immediate call to prayer (Iqamah) is given, let him start with (relieving himself).''"', 'It was narrated that ''Abdullah bin Arqam said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:616', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 617, 'حَدَّثَنَا بِشْرُ بْنُ آدَمَ، حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ، حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ، عَنِ السَّفْرِ بْنِ نُسَيْرٍ، عَنْ يَزِيدَ بْنِ شُرَيْحٍ، عَنْ أَبِي أُمَامَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ نَهَى أَنْ يُصَلِّيَ الرَّجُلُ وَهُوَ حَاقِنٌ ‏.‏', NULL, 'It was narrated from Abu Umamah that:The Messenger of Allah forbade a man to perform prayer when he was suppressing (the urge to urinate or defecate).', 'It was narrated from Abu Umamah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:617', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 618, '"‏ لاَ يَقُومُ أَحَدُكُمْ إِلَى الصَّلاَةِ وَبِهِ أَذًى ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said, ''No one of you should stand to pray when he feels some discomfort (because of needing to urinate or defecate).''"', 'It was narrated that Abu Hurairah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:618', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 619, '"‏ لاَ يَقُومُ أَحَدٌ مِنَ الْمُسْلِمِينَ وَهُوَ حَاقِنٌ حَتَّى يَتَخَفَّفَ ‏"', NULL, 'It was narrated from Thawban that:The Messenger of Allah said: "No one among the Muslims should stand to pray when he is suppressing (the need to urinate or defecate), until he has to relieve himself."', 'It was narrated from Thawban that', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:619', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 620, '"‏ إِنَّمَا ذَلِكَ عِرْقٌ فَانْظُرِي إِذَا أَتَى قَرْؤُكِ فَلاَ تُصَلِّي فَإِذَا مَرَّ الْقَرْءُ فَتَطَهَّرِي ثُمَّ صَلِّي مَا بَيْنَ الْقَرْءِ إِلَى الْقَرْءِ ‏"', NULL, 'It was narrated from ''Urwah bin Zubair that Fatimah bint Abi Hubaish narrated to him that:She went to the Messenger of Allah and complained to him about bleeding. The Messenger of Allah said: "Rather that is a vein, so look and see when your period comes, then do not perform the prayer. When the period is over, then purify yourself and perform the prayer between one period to the next."', NULL, 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:620', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 621, '"‏ لاَ إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتِ الْحَيْضَةُ فَدَعِي الصَّلاَةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي ‏"', NULL, 'It was narrated that ''Aishah said:"Fatimah bint Abi Hubaish came to the Messenger of Allah and said: ''O Messenger of Allah! I am a woman who bleeds continuously and never becomes pure, should I give up the prayer?'' He said: ''No, rather that is a vein and it is not menstruation. When the time of your period comes, leave off the prayer, and when it is over, take a bath and wash the blood from yourself and perform the prayer." This is the Hadith of Waki''.', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:621', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 622, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، - إِمْلاَءً عَلَىَّ مِنْ كِتَابِهِ وَكَانَ السَّائِلُ غَيْرِي - أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ عُمَرَ بْنِ طَلْحَةَ عَنْ أُمِّ حَبِيبَةَ بِنْتِ جَحْشٍ قَالَتْ كُنْتُ أُسْتَحَاضُ حَيْضَةً كَثِيرَةً طَوِيلَةً ‏.‏ قَالَتْ فَجِئْتُ إِلَى النَّبِيِّ ـ صلى الله عليه وسلم ـ أَسْتَفْتِيهِ وَأُخْبِرُهُ ‏.‏ قَالَتْ فَوَجَدْتُهُ عِنْدَ أُخْتِي زَيْنَبَ ‏.‏ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لِي إِلَيْكَ حَاجَةً ‏.‏ قَالَ ‏"‏ وَمَا هِيَ أَىْ هَنْتَاهْ ‏"‏ ‏.‏ قُلْتُ إِنِّي أُسْتَحَاضُ حَيْضَةً طَوِيلَةً كَبِيرَةً وَقَدْ مَنَعَتْنِي الصَّلاَةَ وَالصَّوْمَ فَمَا تَأْمُرُنِي فِيهَا قَالَ ‏"‏ أَنْعَتُ لَكِ الْكُرْسُفَ فَإِنَّهُ يُذْهِبُ الدَّمَ ‏"‏ ‏.‏ قُلْتُ هُوَ أَكْثَرُ ‏.‏ فَذَكَرَ نَحْوَ حَدِيثِ شَرِيكٍ ‏.‏', NULL, 'It was narrated that Umm Habibah bint Jahsh said:"I used to bleed continuously and heavily. I went to the Prophet asking him for advice and telling him (about my situation). I found him with my sister Zainab and said: ''o Messenger of Allah! I need to ask you something.'' He said: ''What is it?'' I said: ''I bleed continuously and heavily, and that is keeping me from prayer and fasting. What do you command me to do about it?'' He said: ''I advise you to use a piece of cotton, for that will take away the blood.'' I said: ''It is more than that.''" And he mentioned something like the Hadith of Sharik (below).', 'It was narrated that Umm Habibah bint Jahsh said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:622', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 623, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا أَبُو أُسَامَةَ، عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ، عَنْ نَافِعٍ، عَنْ سُلَيْمَانَ بْنِ يَسَارٍ، عَنْ أُمِّ سَلَمَةَ، قَالَتْ سَأَلَتِ امْرَأَةٌ النَّبِيَّ ـ صلى الله عليه وسلم ـ قَالَتْ إِنِّي أُسْتَحَاضُ فَلاَ أَطْهُرُ أَفَأَدَعُ الصَّلاَةَ قَالَ ‏"‏ لاَ وَلَكِنْ دَعِي قَدْرَ الأَيَّامِ وَاللَّيَالِي الَّتِي كُنْتِ تَحِيضِينَ ‏"‏ ‏.‏ قَالَ أَبُو بَكْرٍ فِي حَدِيثِهِ ‏"‏ وَقَدْرَهُنَّ مِنَ الشَّهْرِ ثُمَّ اغْتَسِلِي وَاسْتَثْفِرِي بِثَوْبٍ وَصَلِّي ‏"‏ ‏.‏', NULL, 'It was narrated that Umm Salamah said:"A woman asked the Prophet: ''I bleed continuously and I do not become pure. Should I give up the prayer?'' He said: ''No, but leave off praying for the number of days and nights that used to menstruate.''" (One of the narrators) Abu Bakr (Ibn Abu Shaibah) said in this Hadith: "Estimate the number of days in the month, then take a bath and cover your private part with a cloth and perform prayer."', 'It was narrated that Umm Salamah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:623', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 624, '"‏ لاَ إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَ بِالْحَيْضَةِ اجْتَنِبِي الصَّلاَةَ أَيَّامَ مَحِيضِكِ ثُمَّ اغْتَسِلِي وَتَوَضَّئِي لِكُلِّ صَلاَةٍ وَإِنْ قَطَرَ الدَّمُ عَلَى الْحَصِيرِ ‏"', NULL, 'It was narrated that ''Aishah said:"Fatimah bint Abi Hubaish came to the Prophet: ''O Messenger of Allah! I am a woman who bleeds continuously and never becomes pure. Should I give up prayer?'' he said: ''No, that is just a vein and is not menstruation. Do not perform prayer during the days of your period, then take a bath, and perform ablution for each prayer, even if drops of blood fall on the mat.''"', 'It was narrated that ''Aishah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:624', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 625, '"‏ الْمُسْتَحَاضَةُ تَدَعُ الصَّلاَةَ أَيَّامَ أَقْرَائِهَا ثُمَّ تَغْتَسِلُ وَتَتَوَضَّأُ لِكُلِّ صَلاَةٍ وَتَصُومُ وَتُصَلِّي ‏"', NULL, 'It was narrated from ''Adiyy bin Thabit, from his father, from his grandfather, that:The Prophet said: "The woman who experiences irregular non-menstrual bleeding should leave prayer during the days of her period, then she should take a bath, and perform ablution for each prayer, and she should fast and perform the prayer."', NULL, 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:625', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 626, '"‏ إِنَّ هَذِهِ لَيْسَتْ بِالْحَيْضَةِ وَإِنَّمَا هُوَ عِرْقٌ فَإِذَا أَقْبَلَتِ الْحَيْضَةُ فَدَعِي الصَّلاَةَ وَإِذَا أَدْبَرَتْ فَاغْتَسِلِي وَصَلِّي ‏"', NULL, 'It was narrated from ''Urwah bin Zubair and ''Amrah bint ''Abdur-Rahman that :''Aishah the wife of the Prophet said: "Umm Habibah Jahsh experienced prolonged non-menstrual bleeding for seven years when she was married to ''Abdur-Rahman bin ''Awf. She complained about that to the Prophet and the Prophet said: ''That is not menstruation, rather it is a vein, so when the time of your period comes, leave the prayer, and when it is over, take a bath and perform prayer.''" ''Aishah said: "She used to bathe for every prayer and then perform the prayer. She used to sit in a washtub belonging to her sister Zainab bint Jahsh and the blood would turn the water red."', 'It was narrated from ''Urwah bin Zubair and ''Amrah bint ''Abdur-Rahman that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:626', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 627, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ، أَنْبَأَنَا شَرِيكٌ، عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ، عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ، عَنْ عَمِّهِ، عِمْرَانَ بْنِ طَلْحَةَ عَنْ أُمِّهِ، حَمْنَةَ بِنْتِ جَحْشٍ أَنَّهَا اسْتُحِيضَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ فَأَتَتْ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ فَقَالَتْ إِنِّي اسْتُحِضْتُ حَيْضَةً مُنْكَرَةً شَدِيدَةً ‏.‏ قَالَ لَهَا ‏"‏ احْتَشِي كُرْسُفًا ‏"‏ ‏.‏ قَالَتْ لَهُ إِنَّهُ أَشَدُّ مِنْ ذَلِكَ إِنِّي أَثُجُّ ثَجًّا ‏.‏ قَالَ ‏"‏ تَلَجَّمِي وَتَحَيَّضِي فِي كُلِّ شَهْرٍ فِي عِلْمِ اللَّهِ سِتَّةَ أَيَّامٍ أَوْ سَبْعَةَ أَيَّامٍ ثُمَّ اغْتَسِلِي غُسْلاً فَصَلِّي وَصُومِي ثَلاَثَةً وَعِشْرِينَ أَوْ أَرْبَعَةً وَعِشْرِينَ وَأَخِّرِي الظُّهْرَ وَقَدِّمِي الْعَصْرَ وَاغْتَسِلِي لَهُمَا غُسْلاً وَأَخِّرِي الْمَغْرِبَ وَعَجِّلِي الْعِشَاءَ وَاغْتَسِلِي لَهُمَا غُسْلاً وَهَذَا أَحَبُّ الأَمْرَيْنِ إِلَىَّ ‏"‏ ‏.‏', NULL, 'It was narrated from Hamnah bint Jahsh that:She experienced prolonged non-menstrual bleeding during the time of the Messenger of Allah. She came to the Messenger of Allah and said: "I am suffering prolonged and painful bleeding." He said: "Fill it with a pad of cloth." She said: "It is worse than that, it is flowing copiously." He said: "Then bind yourself with a cloth and observe your menses for six or seven days, in the knowledge of Allah, then have a bath and perform prayer and fast for twenty-three or twenty-four days. Delay Zuhr and bring ''Asr forward, and take (one) bath for both, and delay Maghrib and bring ''Isha'' forward, and have (one) bath for both. That is what I prefer of the two matters.''"', 'It was narrated from Hamnah bint Jahsh that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:627', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 628, '"‏ اغْسِلِيهِ بِالْمَاءِ وَالسِّدْرِ وَحُكِّيهِ وَلَوْ بِضِلَعٍ ‏"', NULL, 'It was narrated that Umm Qais bint Mihsan said:"I asked the Messenger of Allah about menstrual blood that gets on clothing. He said, ''Wash it with water and lote leaves, and rub it, even with a piece of stick.''"', 'It was narrated that Umm Qais bint Mihsan said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:628', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 629, '"‏ اقْرُصِيهِ وَاغْسِلِيهِ وَصَلِّي فِيهِ ‏"', NULL, 'It was narrated that Asma'' bint Abi Bakr said:"The Messenger of Allah was asked about menstrual blood that gets on clothing. He said: ''Rub it off, wash it and perform prayer in (the garment).''"', 'It was narrated that Asma'' bint Abi Bakr said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:629', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 630, 'حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى، حَدَّثَنَا ابْنُ وَهْبٍ، أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ، زَوْجِ النَّبِيِّ ـ صلى الله عليه وسلم ـ أَنَّهَا قَالَتْ إِنْ كَانَتْ إِحْدَانَا لَتَحِيضُ ثُمَّ تَقْتَنِصُ الدَّمَ مِنْ ثَوْبِهَا عِنْدَ طُهْرِهَا فَتَغْسِلُهُ وَتَنْضِحُ عَلَى سَائِرِهِ ثُمَّ تُصَلِّي فِيهِ ‏.‏', NULL, 'It was narrated that ''Aisha the wife of the Prophet said:"One of us used to menstruate, then rub the blood off her garment when she became pure again, and wash it, and sprinkle water over the rest of the garment, then perform prayer in it."', 'It was narrated that ''Aisha the wife of the Prophet said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:630', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 631, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ، عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ، عَنْ قَتَادَةَ، عَنْ مُعَاذَةَ الْعَدَوِيَّةِ، عَنْ عَائِشَةَ، أَنَّ امْرَأَةً، سَأَلَتْهَا أَتَقْضِي الْحَائِضُ الصَّلاَةَ قَالَتْ لَهَا عَائِشَةُ أَحَرُورِيَّةٌ أَنْتِ قَدْ كُنَّا نَحِيضُ عِنْدَ النَّبِيِّ ـ صلى الله عليه وسلم ـ ثُمَّ نَطْهُرُ وَلَمْ يَأْمُرْنَا بِقَضَاءِ الصَّلاَةِ ‏.‏', NULL, 'It was narrated from ''Aishah that:A woman asked her: "Does a woman who menstruates have to make up for the prayers she misses?" ''Aisha said to her: "Are you a Haruriyyah? We used to menstruate with the Prophet and then become pure, and he did not tell us to make up for the prayers we missed."', 'It was narrated from ''Aishah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:631', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 632, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو الأَحْوَصِ، عَنْ أَبِي إِسْحَاقَ، عَنِ الْبَهِيِّ، عَنْ عَائِشَةَ، قَالَتْ قَالَ لِي رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ ‏"‏ نَاوِلِينِي الْخُمْرَةَ مِنَ الْمَسْجِدِ ‏"‏ ‏.‏ فَقُلْتُ إِنِّي حَائِضٌ ‏.‏ فَقَالَ ‏"‏ لَيْسَتْ حَيْضَتُكِ فِي يَدِكِ ‏"‏ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah said to me: ''Get me a mat from the mosque.'' I said: ''I am menstruating.'' He said: ''Your menstruation is not in your hand.''"', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:632', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 633, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنْ هِشَامِ بْنِ عُرْوَةَ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ، قَالَتْ كَانَ النَّبِيُّ ـ صلى الله عليه وسلم ـ يُدْنِي رَأْسَهُ إِلَىَّ وَأَنَا حَائِضٌ وَهُوَ مُجَاوِرٌ - تَعْنِي مُعْتَكِفًا - فَأَغْسِلُهُ وَأُرَجِّلُهُ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Prophet used to bring his head close to me when I was menstruaring and he was in I''tikaf (seclusion in a mosques for the purpose of worship), and I would wash it and comb his hair."', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:633', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 634, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، أَنْبَأَنَا سُفْيَانُ، عَنْ مَنْصُورِ ابْنِ صَفِيَّةَ، عَنْ أُمِّهِ، عَنْ عَائِشَةَ، قَالَتْ لَقَدْ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَضَعُ رَأْسَهُ فِي حِجْرِي وَأَنَا حَائِضٌ وَيَقْرَأُ الْقُرْآنَ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah used to put his head in my lap when I was menstruating and recite Qur''an."', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:634', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 635, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ، حَدَّثَنَا أَبُو الأَحْوَصِ، عَنْ عَبْدِ الْكَرِيمِ، ح وَحَدَّثَنَا أَبُو سَلَمَةَ، يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الأَعْلَى، عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ، ح وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ، عَنِ الشَّيْبَانِيِّ، جَمِيعًا عَنْ عَبْدِ الرَّحْمَنِ بْنِ الأَسْوَدِ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ، قَالَتْ كَانَتْ إِحْدَانَا إِذَا كَانَتْ حَائِضًا أَمَرَهَا النَّبِيُّ ـ صلى الله عليه وسلم ـ أَنْ تَأْتَزِرَ فِي فَوْرِ حَيْضَتِهَا ثُمَّ يُبَاشِرُهَا وَأَيُّكُمْ يَمْلِكُ إِرْبَهُ كَمَا كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يَمْلِكُ إِرْبَهُ', NULL, 'It was narrated that ''Aishah said:"If one of us was menstruating, the Messenger of Allah would tell her to tie her waist-wrapper around herself if the bleeding was heavy, then he would embrace her. And who among you can control his desire as the Messenger of Allah used to control his desire?"', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:635', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 636, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا جَرِيرٌ، عَنْ مَنْصُورٍ، عَنْ إِبْرَاهِيمَ، عَنِ الأَسْوَدِ، عَنْ عَائِشَةَ، قَالَتْ كَانَتْ إِحْدَانَا إِذَا حَاضَتْ أَمَرَهَا النَّبِيُّ ـ صلى الله عليه وسلم ـ أَنْ تَأْتَزِرَ بِإِزَارٍ ثُمَّ يُبَاشِرُهَا ‏.‏', NULL, 'It was narrated that ''Aishah said:"If one of us was menstruating, the Messenger of Allah would tell her to tie her waist-wrapper around herself, then he would embrace her."', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:636', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 637, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ، حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو، حَدَّثَنَا أَبُو سَلَمَةَ، عَنْ أُمِّ سَلَمَةَ، قَالَتْ كُنْتُ مَعَ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ فِي لِحَافِهِ فَوَجَدْتُ مَا تَجِدُ النِّسَاءُ مِنَ الْحَيْضَةِ فَانْسَلَلْتُ مِنَ اللِّحَافِ فَقَالَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ ‏"‏ أَنَفِسْتِ ‏"‏ ‏.‏ قُلْتُ وَجَدْتُ مَا تَجِدُ النِّسَاءُ مِنَ الْحَيْضَةِ ‏.‏ قَالَ ‏"‏ ذَلِكَ مَا كَتَبَ اللَّهُ عَلَى بَنَاتِ آدَمَ ‏"‏ ‏.‏ قَالَتْ فَانْسَلَلْتُ فَأَصْلَحْتُ مِنْ شَأْنِي ثُمَّ رَجَعْتُ فَقَالَ لِي رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ ‏"‏ تَعَالَىْ فَادْخُلِي مَعِي فِي اللِّحَافِ ‏"‏ ‏.‏ قَالَتْ فَدَخَلْتُ مَعَهُ ‏.‏', NULL, 'It was narrated that Umm Salamah said:"I was with the Messenger of Allah under his blanket, then I felt that I was menstruating as women do, so I slipped out from under the cover. The Messenger of Allah said: ''Are you menstruating?'' I said: ''I feel that I am menstruating as women do.'' He said: ''That is what Allah has decreed for the daughters of Adam.'' So I slipped out and sorted myself out, then I came back, and the Messenger of Allah said to me: ''Come under the cover with me,'' so I went in with him.''"', 'It was narrated that Umm Salamah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:637', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 638, 'حَدَّثَنَا الْخَلِيلُ بْنُ عَمْرٍو، حَدَّثَنَا ابْنُ سَلَمَةَ، عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ، عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ، عَنْ سُوَيْدِ بْنِ قَيْسٍ، عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ، عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ، عَنْ أُمِّ حَبِيبَةَ، زَوْجِ النَّبِيِّ ـ صلى الله عليه وسلم ـ قَالَ سَأَلْتُهَا كَيْفَ كُنْتِ تَصْنَعِينَ مَعَ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ فِي الْحَيْضَةِ قَالَتْ كَانَتْ إِحْدَانَا فِي فَوْرِهَا أَوَّلَ مَا تَحِيضُ تَشُدُّ عَلَيْهَا إِزَارًا إِلَى أَنْصَافِ فَخِذَيْهَا ثُمَّ تَضْطَجِعُ مَعَ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ ‏.‏', NULL, 'It was narrated from Mu''awiyah bin Abu Sufyan that :He asked Umm Habibah, the wife of the Prophet: "What did you used to do with the Messenger of Allah when you were menstruating?" She said: "If it was at the beginning of the period when the bleeding is heavy, we would tie the waist-wrapper tightly around our thighs, then lie down with the Messenger of Allah."', 'It was narrated from Mu''awiyah bin Abu Sufyan that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:638', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 639, '"‏ مَنْ أَتَى حَائِضًا أَوِ امْرَأَةً فِي دُبُرِهَا أَوْ كَاهِنًا فَصَدَّقَهُ بِمَا يَقُولُ فَقَدْ كَفَرَ بِمَا أُنْزِلَ عَلَى مُحَمَّدٍ ‏"', NULL, 'It was narrated that Abu Hurairah said:"The Messenger of Allah said: ''Whoever has intercourse with a menstruating woman, or with a woman in her rear, or who goes to a fortuneteller and believes what he says, he has disbelieved in that which was revealed to Muhammad.''"', 'It was narrated that Abu Hurairah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:639', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 640, '"‏ يَتَصَدَّقُ بِدِينَارٍ أَوْ بِنِصْفِ دِينَارٍ ‏"', NULL, 'It was narrated from Ibn ''Abbas that:The Prophet said concerning one who has intercourse with a woman when she is menstruating: "Let him give a Dinar or half a Dinar in charity."', 'It was narrated from Ibn ''Abbas that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:640', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 641, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنْ هِشَامِ بْنِ عُرْوَةَ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ قَالَ لَهَا وَكَانَتْ حَائِضًا ‏"‏ انْقُضِي شَعْرَكِ وَاغْتَسِلِي ‏"‏ ‏.‏ قَالَ عَلِيٌّ فِي حَدِيثِهِ ‏"‏ انَقُضِي رَأْسَكِ ‏"‏ ‏.‏', NULL, 'It was narrated from ''Aishah that:The Prophet said to her, when she was menstruating: "Undo your braids and bathe." (Sahih)(A narrator) ''Ali said in his narration: "Undo your head."', 'It was narrated from ''Aishah that', NULL, 'https://sunnah.com/ibnmajah:641', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 642, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ، قَالَ سَمِعْتُ صَفِيَّةَ، تُحَدِّثُ عَنْ عَائِشَةَ، أَنَّ أَسْمَاءَ، سَأَلَتْ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ عَنِ الْغُسْلِ مِنَ الْمَحِيضِ فَقَالَ ‏"‏ تَأْخُذُ إِحْدَاكُنَّ مَاءَهَا وَسِدْرَهَا فَتَطْهُرُ فَتُحْسِنُ الطُّهُورَ أَوْ تَبْلُغُ فِي الطُّهُورِ ثُمَّ تَصُبُّ عَلَى رَأْسِهَا فَتَدْلُكُهُ دَلْكًا شَدِيدًا حَتَّى تَبْلُغَ شُئُونَ رَأْسِهَا ثُمَّ تَصُبُّ عَلَيْهَا الْمَاءَ ثُمَّ تَأْخُذُ فِرْصَةً مُمَسَّكَةً فَتَطْهُرُ بِهَا ‏"‏ ‏.‏ قَالَتْ أَسْمَاءُ كَيْفَ أَتَطَهَّرُ بِهَا قَالَ ‏"‏ سُبْحَانَ اللَّهِ تَطَهَّرِي بِهَا ‏"‏ ‏.‏ قَالَتْ عَائِشَةُ - كَأَنَّهَا تُخْفِي ذَلِكَ - تَتَبَّعِي بِهَا أَثَرَ الدَّمِ ‏.‏ قَالَتْ وَسَأَلَتْهُ عَنِ الْغُسْلِ مِنَ الْجَنَابَةِ ‏.‏ فَقَالَ ‏"‏ تَأْخُذُ إِحْدَاكُنَّ مَاءَهَا فَتَطْهُرُ فَتُحْسِنُ الطُّهُورَ أَوْ تَبْلُغُ فِي الطُّهُورِ حَتَّى تَصُبَّ الْمَاءَ عَلَى رَأْسِهَا فَتَدْلُكُهُ حَتَّى تَبْلُغَ شُئُونَ رَأْسِهَا ثُمَّ تُفِيضُ الْمَاءَ عَلَى جَسَدِهَا ‏.‏ فَقَالَتْ عَائِشَةُ نِعْمَ النِّسَاءُ نِسَاءُ الأَنْصَارِ لَمْ يَمْنَعْهُنَّ الْحَيَاءُ أَنْ يَتَفَقَّهْنَ فِي الدِّينِ ‏.‏', NULL, 'It was narrated from ''Aishah that:Asma asked the Messenger of Allah about bathing after ones''s period. He said: "One of you should take her water and lote leaves, and purify herself well, or thoroughly. Then she should pour water over her head and rub it vigorously so that the water reaches the roots of her hair. Then she should take a piece of cotton perfumed with musk and purify herself with it." Asma said: "How should I purify myself with it?" He said: "Subhan Allah! Purify yourself with it!" ''Aishah said, as if whispering to her: "Wipe away the traces of blood with it." Then she (Asma) asked him about bathing to cleanse oneself from sexual impurity. He said: "One of you should take her water, and purify herself, and purify herself well, or thoroughly. She should pour water over her head and rub it so that the water reaches the roots of her hair, then she should pour water over her body." ''Aishah said: "How good were the women of the Ansar! For they did not let shyness keep them from understanding their religion properly."', 'It was narrated from ''Aishah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:642', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 643, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، عَنِ الْمِقْدَامِ بْنِ شُرَيْحِ بْنِ هَانِئٍ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ، قَالَتْ كُنْتُ أَتَعَرَّقُ الْعَظْمَ وَأَنَا حَائِضٌ، فَيَأْخُذُهُ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ فَيَضَعُ فَمَهُ حَيْثُ كَانَ فَمِي وَأَشْرَبُ مِنَ الإِنَاءِ فَيَأْخُذُهُ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ فَيَضَعُ فَمَهُ حَيْثُ كَانَ فَمِي وَأَنَا حَائِضٌ ‏.‏', NULL, 'It was narrated that ''Aishah said:"I used to eat the meat from a bone when I was menstruating, then the Messenger of Allah would take it and put his mouth where my mouth had been. And I would drink from a vessel, and the Messenger of Allah would take it and put his mouth where my mouth had been, and I was menstruating."', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:643', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 644, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا أَبُو الْوَلِيدِ، حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ، عَنْ ثَابِتٍ، عَنْ أَنَسٍ، أَنَّ الْيَهُودَ، كَانُوا لاَ يَجْلِسُونَ مَعَ الْحَائِضِ فِي بَيْتٍ وَلاَ يَأْكُلُونَ وَلاَ يَشْرَبُونَ ‏.‏ قَالَ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ ـ صلى الله عليه وسلم ـ فَأَنْزَلَ اللَّهُ ‏{وَيَسْأَلُونَكَ عَنِ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ}‏ فَقَالَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ ‏"‏ اصْنَعُوا كُلَّ شَىْءٍ إِلاَّ الْجِمَاعَ ‏"‏ ‏.‏', NULL, 'It was narrated from Anas that:The Jews would not sit with a menstruating woman in a house, nor eat with her, nor drink with her. That was mentioned to the Messenger of Allah, then Allah revealed the words: "They ask you concerning menstruation. Say: that is a harmful thing, therefore keep away from women during menses." The Messenger of Allah said: "Do everything except sexual intercourse."', 'It was narrated from Anas that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:644', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 645, '"‏ إِنَّ الْمَسْجِدَ لاَ يَحِلُّ لِجُنُبٍ وَلاَ لِحَائِضٍ ‏"', NULL, 'It was narrated that Jasrah said:"Umm Salamah told me: ''The Messenger of Allah entered the courtyard of this mosque and called out at the top of his voice: ''The mosque is not permissible for anyone who is sexually impure or any woman who is menstruating.''''"', 'It was narrated that Jasrah said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:645', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 646, '"‏ إِنَّمَا هِيَ عِرْقٌ أَوْ عُرُوقٌ ‏"', NULL, 'It was narrated from Umm Bakr that:She was told that ''Aishah said: "The Messenger of Allah said concerning a woman who sees that which causes her doubt (i.e. some bleeding) after she becomes pure: ''That is a vein or veins.''" (Da''if)"What was meant by ''after becomes pure'' is after having a bath (following the end of her period)."', 'It was narrated from Umm Bakr that', NULL, 'https://sunnah.com/ibnmajah:646', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 647, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، أَنْبَأَنَا مَعْمَرٌ، عَنْ أَيُّوبَ، عَنِ ابْنِ سِيرِينَ، عَنْ أُمِّ عَطِيَّةَ، قَالَتْ لَمْ نَكُنْ نَرَى الصُّفْرَةَ وَالْكُدْرَةَ شَيْئًا ‏.‏
قَالَ مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ، حَدَّثَنَا وُهَيْبٌ، عَنْ أَيُّوبَ، عَنْ حَفْصَةَ، عَنْ أُمِّ عَطِيَّةَ، قَالَتْ كُنَّا لاَ نَعُدُّ الصُّفْرَةَ وَالْكُدْرَةَ شَيْئًا ‏.
‏ قَالَ مُحَمَّدُ بْنُ يَحْيَى وُهَيْبٌ أَوْلاَهُمَا عِنْدَنَا بِهَذَا ‏.‏', NULL, 'It was narrated that Umm ''Atiyyah said:"We did not think anything of the yellowish or brownish discharge." (Sahih) (Another chain) It was narrated that Umm ''Atiyyah said: "We did not think that the yellowish or brownish discharge counted for anything." Muhammad bin Yahya said: "Wuhaib (who narrated the second version) is the better of them with this according to us."', 'It was narrated that Umm ''Atiyyah said', NULL, 'https://sunnah.com/ibnmajah:647', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 648, 'حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ، حَدَّثَنَا شُجَاعُ بْنُ الْوَلِيدِ، عَنْ عَلِيِّ بْنِ عَبْدِ الأَعْلَى، عَنْ أَبِي سَهْلٍ، عَنْ مُسَّةَ الأَزْدِيَّةِ، عَنْ أُمِّ سَلَمَةَ، قَالَتْ كَانَتِ النُّفَسَاءُ عَلَى عَهْدِ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ تَجْلِسُ أَرْبَعِينَ يَوْمًا وَكُنَّا نَطْلِي وُجُوهَنَا بِالْوَرْسِ مِنَ الْكَلَفِ ‏.‏', NULL, 'It was narrated that Umm Salamah said:"At the time of the Messenger of Allah, women in postnatal bleeding (after childbirth) used to wait for forty days, and we used to put Wars on our faces because of freckles."', 'It was narrated that Umm Salamah said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:648', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 649, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ، حَدَّثَنَا الْمُحَارِبِيُّ، عَنْ سَلاَّمِ بْنِ سُلَيْمٍ، - أَوْ سَلْمٍ شَكَّ أَبُو الْحَسَنِ وَأَظُنُّهُ هُوَ أَبُو الأَحْوَصِ - عَنْ حُمَيْدٍ، عَنْ أَنَسٍ، قَالَ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ وَقَّتَ لِلنُّفَسَاءِ أَرْبَعِينَ يَوْمًا إِلاَّ أَنْ تَرَى الطُّهْرَ قَبْلَ ذَلِكَ ‏.‏', NULL, 'It was narrated that Anas said:"The Messenger of Allah set the time for postnatal bleeding at forty days, except for one who becomes pure before that."', 'It was narrated that Anas said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:649', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 650, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ، حَدَّثَنَا أَبُو الأَحْوَصِ، عَنْ عَبْدِ الْكَرِيمِ، عَنْ مِقْسَمٍ، عَنِ ابْنِ عَبَّاسٍ، قَالَ كَانَ الرَّجُلُ إِذَا وَقَعَ عَلَى امْرَأَتِهِ وَهِيَ حَائِضٌ أَمَرَهُ النَّبِيُّ ـ صلى الله عليه وسلم ـ أَنْ يَتَصَدَّقَ بِنِصْفِ دِينَارٍ ‏.‏', NULL, 'It was narrated that Ibn ''Abbas said:"If a man had intercourse with his wife while she was menstruating, the Prophet commanded him to give half a Dinar in charity."', 'It was narrated that Ibn ''Abbas said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:650', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 651, '"‏ وَاكِلْهَا ‏"', NULL, 'It was narrated that ''Abdullah bin Sa''d said:"I asked the Messenger of Allah about eating with a menstruating woman and he said: ''Eat with her.''"', 'It was narrated that ''Abdullah bin Sa''d said', 'Grade: Hasan (Darussalam)', 'https://sunnah.com/ibnmajah:651', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 652, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا وَكِيعٌ، عَنْ طَلْحَةَ بْنِ يَحْيَى، عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ، عَنْ عَائِشَةَ، قَالَتْ كَانَ رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ يُصَلِّي وَأَنَا إِلَى جَنْبِهِ وَأَنَا حَائِضٌ وَعَلَىَّ مِرْطٌ لِي وَعَلَيْهِ بَعْضُهُ ‏.‏', NULL, 'It was narrated that ''Aishah said:"The Messenger of Allah was performing prayer, and I was by his side. I was menstruating, and I was wearing a wool cloak, and part of it was over him."', 'It was narrated that ''Aishah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:652', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 653, 'حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ، حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ، حَدَّثَنَا الشَّيْبَانِيُّ، عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ، عَنْ مَيْمُونَةَ، أَنَّ رَسُولَ اللَّهِ ـ صلى الله عليه وسلم ـ صَلَّى وَعَلَيْهِ مِرْطٌ عَلَيْهِ بَعْضُهُ وَعَلَيْهَا بَعْضُهُ وَهِيَ حَائِضٌ ‏.‏', NULL, 'It was narrated from Maimunah that:The Messenger of Allah performed prayer wearing a wool cloak. Part of it was over him and part was over her, and she was menstruating.', 'It was narrated from Maimunah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:653', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 654, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَعَلِيُّ بْنُ مُحَمَّدٍ، قَالاَ حَدَّثَنَا وَكِيعٌ، عَنْ سُفْيَانَ، عَنْ عَبْدِ الْكَرِيمِ، عَنْ عَمْرِو بْنِ سَعِيدٍ، عَنْ عَائِشَةَ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ دَخَلَ عَلَيْهَا فَاخْتَبَأَتْ مَوْلاَةٌ لَهَا فَقَالَ النَّبِيُّ ـ صلى الله عليه وسلم ـ ‏"‏ حَاضَتْ ‏"‏ ‏.‏ فَقَالَتْ نَعَمْ ‏.‏ فَشَقَّ لَهَا مِنْ عِمَامَتِهِ فَقَالَ ‏"‏ اخْتَمِرِي بِهَذَا ‏"‏ ‏.‏', NULL, 'It was narrated from ''Aishah that:The Prophet entered upon her, and a freed slave girl of hers concealed herself. The Prophet asked: "Have her periods begun?" She said: "Yes." He tore a piece of his turban and said: "Cover your head with this."', 'It was narrated from ''Aishah that', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:654', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 655, '"‏ لاَ يَقْبَلُ اللَّهُ صَلاَةَ حَائِضٍ إِلاَّ بِخِمَارٍ ‏"', NULL, 'It was narrated from ''Aishah that:The Prophet said: "Allah does not accept the prayer of a woman who menstruates (i.e., an adult woman) except with a head cover."', 'It was narrated from ''Aishah that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:655', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 656, 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، حَدَّثَنَا حَجَّاجٌ، حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ، حَدَّثَنَا أَيُّوبُ، عَنْ مُعَاذَةَ، ‏.‏ أَنَّ امْرَأَةً، سَأَلَتْ عَائِشَةَ قَالَتْ تَخْتَضِبُ الْحَائِضُ فَقَالَتْ قَدْ كُنَّا عِنْدَ النَّبِيِّ ـ صلى الله عليه وسلم ـ وَنَحْنُ نَخْتَضِبُ فَلَمْ يَكُنْ يَنْهَانَا عَنْهُ ‏.‏', NULL, 'It was narrated from Mu''adh that:A woman asked ''Aishah: "Can a woman who is menstruating, dye her hands?" She said: "We were with the Prophet and we used to dye our hands, and he did not tell us not to do that."', 'It was narrated from Mu''adh that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:656', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 657, 'حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ الْبَلْخِيُّ، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، أَنْبَأَنَا إِسْرَائِيلُ، عَنْ عَمْرِو بْنِ خَالِدٍ، عَنْ زَيْدِ بْنِ عَلِيٍّ، عَنْ أَبِيهِ، عَنْ جَدِّهِ، عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ، قَالَ انْكَسَرَتْ إِحْدَى زَنْدَىَّ فَسَأَلْتُ النَّبِيَّ ـ صلى الله عليه وسلم ـ فَأَمَرَنِي أَنْ أَمْسَحَ عَلَى الْجَبَائِرِ ‏.‏
قَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ أَنْبَأَنَا الدَّبَرِيُّ، عَنْ عَبْدِ الرَّزَّاقِ، نَحْوَهُ ‏.‏', NULL, 'It was narrated that ''Ali bin Abu Talib said:"I broke one of my forearms and I asked the Prophet about that. He told me to wipe over the bandages." (Maudu'') Another chain with similar meaning.', 'It was narrated that ''Ali bin Abu Talib said', NULL, 'https://sunnah.com/ibnmajah:657', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 658, 'حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ، حَدَّثَنَا وَكِيعٌ، عَنْ حَمَّادِ بْنِ سَلَمَةَ، عَنْ مُحَمَّدِ بْنِ زِيَادٍ، عَنْ أَبِي هُرَيْرَةَ، قَالَ رَأَيْتُ النَّبِيَّ ـ صلى الله عليه وسلم ـ حَامِلَ الْحُسَيْنِ بْنِ عَلِيٍّ عَلَى عَاتِقِهِ وَلُعَابُهُ يَسِيلُ عَلَيْهِ ‏.‏', NULL, 'It was narrated that Abu Hurairah said:"I saw the Prophet carrying Hasan bin ''Ali on his shoulder, and his saliva was dripping down on him."', 'It was narrated that Abu Hurairah said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:658', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 659, 'حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ، حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ، عَنْ مِسْعَرٍ، ح وَحَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ كَرَامَةَ، حَدَّثَنَا أَبُو أُسَامَةَ، عَنْ مِسْعَرٍ، عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ، عَنْ أَبِيهِ، قَالَ رَأَيْتُ النَّبِيَّ ـ صلى الله عليه وسلم ـ أُتِيَ بِدَلْوٍ فَمَضْمَضَ مِنْهُ فَمَجَّ فِيهِ مِسْكًا أَوْ أَطْيَبَ مِنَ الْمِسْكِ وَاسْتَنْثَرَ خَارِجًا مِنَ الدَّلْوِ ‏.‏', NULL, 'It was narrated from ''Abdul Jabbar bin Wa''il that his father said:"A bucket was brought to the Prophet; he rinsed his mouth and spat into it, and it was like musk or better than musk, and he rinsed his nostrils outside the bucket."', 'It was narrated from ''Abdul Jabbar bin Wa''il that his father said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:659', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 660, 'حَدَّثَنَا أَبُو مَرْوَانَ، حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ، عَنِ الزُّهْرِيِّ، عَنْ مَحْمُودِ بْنِ الرَّبِيعِ، وَكَانَ، قَدْ عَقَلَ مَجَّةً مَجَّهَا رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ فِي دَلْوٍ مِنْ بِئْرٍ لَهُمْ ‏.‏', NULL, 'It was narrated from Zuhri that:Mahmud bin Rabi'' remembered that the Prophet spat into a bucket from a well that belonged to them.', 'It was narrated from Zuhri that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:660', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 661, '"‏ لاَ تَنْظُرِ الْمَرْأَةُ إِلَى عَوْرَةِ الْمَرْأَةِ وَلاَ يَنْظُرِ الرَّجُلُ إِلَى عَوْرَةِ الرَّجُلِ ‏"', NULL, 'It was narrated from ''Abdur-Rahman bin Abu Sa''eed Al-Khudri from his father that:The Messenger of Allah said: "No woman should look at the nakedness of another woman, and no man should look at the nakedness of another man."', 'It was narrated from ''Abdur-Rahman bin Abu Sa''eed Al-Khudri from his father that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:661', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 662, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا وَكِيعٌ، عَنْ سُفْيَانَ، عَنْ مَنْصُورٍ، عَنْ مُوسَى بْنِ عَبْدِ اللَّهِ بْنِ يَزِيدَ، عَنْ مَوْلًى، لِعَائِشَةَ عَنْ عَائِشَةَ، قَالَتْ مَا نَظَرْتُ - أَوْ مَا رَأَيْتُ - فَرْجَ رَسُولِ اللَّهِ ـ صلى الله عليه وسلم ـ قَطُّ ‏.‏ قَالَ أَبُو بَكْرٍ كَانَ أَبُو نُعَيْمٍ يَقُولُ عَنْ مَوْلاَةٍ لِعَائِشَةَ ‏.‏', NULL, 'It was narrated from a freed slave of ''Aishah that:''Aishah said: "I never looked at (or I never saw) the private part of the Messenger of Allah." (Da''if)(One of the narrators) Abu Bakr (Ibn Abu Shaibah) said: "Abu Nu''aim would say: ''(From) a freed female slave of ''Aishah.''"', 'It was narrated from a freed slave of ''Aishah that', NULL, 'https://sunnah.com/ibnmajah:662', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 663, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَإِسْحَاقُ بْنُ مَنْصُورٍ، قَالاَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ، أَنْبَأَنَا مُسْتَلِمُ بْنُ سَعِيدٍ، عَنْ أَبِي عَلِيٍّ الرَّحَبِيِّ، عَنْ عِكْرِمَةَ، عَنِ ابْنِ عَبَّاسٍ، أَنَّ النَّبِيَّ ـ صلى الله عليه وسلم ـ اغْتَسَلَ مِنْ جَنَابَةٍ فَرَأَى لُمْعَةً لَمْ يُصِبْهَا الْمَاءُ فَقَالَ بِجُمَّتِهِ فَبَلَّهَا عَلَيْهَا ‏.‏ قَالَ إِسْحَاقُ فِي حَدِيثِهِ فَعَصَرَ شَعْرَهُ عَلَيْهَا ‏.‏', NULL, 'It was narrated from Ibn ''Abbas:"The Prophet bathed to cleanse himself from sexual impurity, then he saw a spot that the water did not reach." Then he motioned with the hair hanging over his shoulders and squeezed (the water from it) over that spot." (Da''if)In his narration, Ishaq said: "So he wrung his hair over it."', 'It was narrated from Ibn ''Abbas', NULL, 'https://sunnah.com/ibnmajah:663', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 664, '"‏ لَوْ كُنْتَ مَسَحْتَ عَلَيْهِ بِيَدِكَ أَجْزَأَكَ ‏"', NULL, 'It was narrated that ''Ali said:"A man came to the Prophet and said: ''I bathed to cleanse myself from sexual impurity, and I prayed Fajr, then I noticed a spot the size of a fingernail that the water did not reach.'' The Messenger of Allah said: ''If you had wiped it that would have been sufficient for you.''"', 'It was narrated that ''Ali said', 'Grade: Da''if (Darussalam)', 'https://sunnah.com/ibnmajah:664', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 665, '"‏ ارْجِعْ فَأَحْسِنْ وُضُوءَكَ ‏"', NULL, 'It was narrated from Anas that:A man came to the Prophet; he had performed ablution and has missed a spot the size of a fingernail where water had not reached. The Prophet said to him: ''Go back and perform ablution properly.''"', 'It was narrated from Anas that', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:665', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('ibnmajah', 'The Book of Purification and its Sunnah', 666, 'حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى، حَدَّثَنَا ابْنُ وَهْبٍ، ح وَحَدَّثَنَا ابْنُ حُمَيْدٍ، حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ، قَالاَ حَدَّثَنَا ابْنُ لَهِيعَةَ، عَنْ أَبِي الزُّبَيْرِ، عَنْ جَابِرٍ، عَنْ عُمَرَ بْنِ الْخَطَّابِ، قَالَ رَأَى رَسُولُ اللَّهِ ـ صلى الله عليه وسلم ـ رَجُلاً تَوَضَّأَ فَتَرَكَ مَوْضِعَ الظُّفْرِ عَلَى قَدَمِهِ فَأَمَرَهُ أَنْ يُعِيدَ الْوُضُوءَ وَالصَّلاَةَ ‏.‏ قَالَ فَرَجَعَ ‏.‏', NULL, 'It was narrated that ''Umar bin Khattab said:"The Messenger of Allah saw a man performing ablution and he missed a spot the size of a fingernail on his foot. He commanded him to repeat the ablution and his prayer, so he did."', 'It was narrated that ''Umar bin Khattab said', 'Grade: Sahih (Darussalam)', 'https://sunnah.com/ibnmajah:666', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 1, 'حَدَّثَنِي أَبُو خَيْثَمَةَ، زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا وَكِيعٌ، عَنْ كَهْمَسٍ، عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ، عَنْ يَحْيَى بْنِ يَعْمَرَ، ح وَحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ، - وَهَذَا حَدِيثُهُ - حَدَّثَنَا أَبِي، حَدَّثَنَا كَهْمَسٌ، عَنِ ابْنِ بُرَيْدَةَ، عَنْ يَحْيَى بْنِ يَعْمَرَ، قَالَ كَانَ أَوَّلَ مَنْ قَالَ فِي الْقَدَرِ بِالْبَصْرَةِ مَعْبَدٌ الْجُهَنِيُّ فَانْطَلَقْتُ أَنَا وَحُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيُّ حَاجَّيْنِ أَوْ مُعْتَمِرَيْنِ فَقُلْنَا لَوْ لَقِينَا أَحَدًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صلى الله عليه وسلم فَسَأَلْنَاهُ عَمَّا يَقُولُ هَؤُلاَءِ فِي الْقَدَرِ فَوُفِّقَ لَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ الْخَطَّابِ دَاخِلاً الْمَسْجِدَ فَاكْتَنَفْتُهُ أَنَا وَصَاحِبِي أَحَدُنَا عَنْ يَمِينِهِ وَالآخَرُ عَنْ شِمَالِهِ فَظَنَنْتُ أَنَّ صَاحِبِي سَيَكِلُ الْكَلاَمَ إِلَىَّ فَقُلْتُ أَبَا عَبْدِ الرَّحْمَنِ إِنَّهُ قَدْ ظَهَرَ قِبَلَنَا نَاسٌ يَقْرَءُونَ الْقُرْآنَ وَيَتَقَفَّرُونَ الْعِلْمَ - وَذَكَرَ مِنْ شَأْنِهِمْ - وَأَنَّهُمْ يَزْعُمُونَ أَنْ لاَ قَدَرَ وَأَنَّ الأَمْرَ أُنُفٌ ‏.‏ قَالَ فَإِذَا لَقِيتَ أُولَئِكَ فَأَخْبِرْهُمْ أَنِّي بَرِيءٌ مِنْهُمْ وَأَنَّهُمْ بُرَآءُ مِنِّي وَالَّذِي يَحْلِفُ بِهِ عَبْدُ اللَّهِ بْنُ عُمَرَ لَوْ أَنَّ لأَحَدِهِمْ مِثْلَ أُحُدٍ ذَهَبًا فَأَنْفَقَهُ مَا قَبِلَ اللَّهُ مِنْهُ حَتَّى يُؤْمِنَ بِالْقَدَرِ ثُمَّ قَالَ حَدَّثَنِي أَبِي عُمَرُ بْنُ الْخَطَّابِ قَالَ بَيْنَمَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صلى الله عليه وسلم ذَاتَ يَوْمٍ إِذْ طَلَعَ عَلَيْنَا رَجُلٌ شَدِيدُ بَيَاضِ الثِّيَابِ شَدِيدُ سَوَادِ الشَّعَرِ لاَ يُرَى عَلَيْهِ أَثَرُ السَّفَرِ وَلاَ يَعْرِفُهُ مِنَّا أَحَدٌ حَتَّى جَلَسَ إِلَى النَّبِيِّ صلى الله عليه وسلم فَأَسْنَدَ رُكْبَتَيْهِ إِلَى رُكْبَتَيْهِ وَوَضَعَ كَفَّيْهِ عَلَى فَخِذَيْهِ وَقَالَ يَا مُحَمَّدُ أَخْبِرْنِي عَنِ الإِسْلاَمِ ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ الإِسْلاَمُ أَنْ تَشْهَدَ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَتُقِيمَ الصَّلاَةَ وَتُؤْتِيَ الزَّكَاةَ وَتَصُومَ رَمَضَانَ وَتَحُجَّ الْبَيْتَ إِنِ اسْتَطَعْتَ إِلَيْهِ سَبِيلاً ‏.‏ قَالَ صَدَقْتَ ‏.‏ قَالَ فَعَجِبْنَا لَهُ يَسْأَلُهُ وَيُصَدِّقُهُ ‏.‏ قَالَ فَأَخْبِرْنِي عَنِ الإِيمَانِ ‏.‏ قَالَ ‏"‏ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلاَئِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَالْيَوْمِ الآخِرِ وَتُؤْمِنَ بِالْقَدَرِ خَيْرِهِ وَشَرِّهِ ‏"‏ ‏.‏ قَالَ صَدَقْتَ ‏.‏ قَالَ فَأَخْبِرْنِي عَنِ الإِحْسَانِ ‏.‏ قَالَ ‏"‏ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ ‏"‏ ‏.‏ قَالَ فَأَخْبِرْنِي عَنِ السَّاعَةِ ‏.‏ قَالَ ‏"‏ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنَ السَّائِلِ ‏"‏ ‏.‏ قَالَ فَأَخْبِرْنِي عَنْ أَمَارَتِهَا ‏.‏ قَالَ ‏"‏ أَنْ تَلِدَ الأَمَةُ رَبَّتَهَا وَأَنْ تَرَى الْحُفَاةَ الْعُرَاةَ الْعَالَةَ رِعَاءَ الشَّاءِ يَتَطَاوَلُونَ فِي الْبُنْيَانِ ‏"‏ ‏.‏ قَالَ ثُمَّ انْطَلَقَ فَلَبِثْتُ مَلِيًّا ثُمَّ قَالَ لِي ‏"‏ يَا عُمَرُ أَتَدْرِي مَنِ السَّائِلُ ‏"‏ ‏.‏ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ ‏.‏ قَالَ ‏"‏ فَإِنَّهُ جِبْرِيلُ أَتَاكُمْ يُعَلِّمُكُمْ دِينَكُمْ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Yahya b. Ya''mur that the first man who discussed qadr (Divine Decree) in Basra was Ma''bad al-Juhani. I along with Humaid b. ''Abdur-Rahman Himyari set out for pilgrimage or for ''Umrah and said:Should it so happen that we come into contact with one of the Companions of the Messenger of Allah (peace be upon him) we shall ask him about what is talked about taqdir (Divine Decree). Accidentally we came across Abdullah ibn Umar ibn al-Khattab, while he was entering the mosque. My companion and I surrounded him. One of us (stood) on his right and the other stood on his left. I expected that my companion would authorize me to speak. I therefore said: Abu Abdur Rahman! There have appeared some people in our land who recite the Qur''an and pursue knowledge. And then after talking about their affairs, added: They (such people) claim that there is no such thing as Divine Decree and events are not predestined. He (Abdullah ibn Umar) said: When you happen to meet such people tell them that I have nothing to do with them and they have nothing to do with me. And verily they are in no way responsible for my (belief). Abdullah ibn Umar swore by Him (the Lord) (and said): If any one of them (who does not believe in the Divine Decree) had with him gold equal to the bulk of (the mountain) Uhud and spent it (in the way of Allah), Allah would not accept it unless he affirmed his faith in Divine Decree. He further said: My father, Umar ibn al-Khattab, told me: One day we were sitting in the company of Allah''s Apostle (peace be upon him) when there appeared before us a man dressed in pure white clothes, his hair extraordinarily black. There were no signs of travel on him. None amongst us recognized him. At last he sat with the Apostle (peace be upon him) He knelt before him placed his palms on his thighs and said: Muhammad, inform me about al-Islam. The Messenger of Allah (peace be upon him) said: Al-Islam implies that you testify that there is no god but Allah and that Muhammad is the messenger of Allah, and you establish prayer, pay Zakat, observe the fast of Ramadan, and perform pilgrimage to the (House) if you are solvent enough (to bear the expense of) the journey. He (the inquirer) said: You have told the truth. He (Umar ibn al-Khattab) said: It amazed us that he would put the question and then he would himself verify the truth. He (the inquirer) said: Inform me about Iman (faith). He (the Holy Prophet) replied: That you affirm your faith in Allah, in His angels, in His Books, in His Apostles, in the Day of Judgment, and you affirm your faith in the Divine Decree about good and evil. He (the inquirer) said: You have told the truth. He (the inquirer) again said: Inform me about al-Ihsan (performance of good deeds). He (the Holy Prophet) said: That you worship Allah as if you are seeing Him, for though you don''t see Him, He, verily, sees you. He (the enquirer) again said: Inform me about the hour (of the Doom). He (the Holy Prophet) remarked: One who is asked knows no more than the one who is inquiring (about it). He (the inquirer) said: Tell me some of its indications. He (the Holy Prophet) said: That the slave-girl will give birth to her mistress and master, that you will find barefooted, destitute goat-herds vying with one another in the construction of magnificent buildings. He (the narrator, Umar ibn al-Khattab) said: Then he (the inquirer) went on his way but I stayed with him (the Holy Prophet) for a long while. He then, said to me: Umar, do you know who this inquirer was? I replied: Allah and His Apostle knows best. He (the Holy Prophet) remarked: He was Gabriel (the angel). He came to you in order to instruct you in matters of religion.', NULL, NULL, 'https://sunnah.com/muslim:1', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 2, 'حَدَّثَنِي مُحَمَّدُ بْنُ عُبَيْدٍ الْغُبَرِيُّ، وَأَبُو كَامِلٍ الْجَحْدَرِيُّ وَأَحْمَدُ بْنُ عَبْدَةَ قَالُوا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ، عَنْ مَطَرٍ الْوَرَّاقِ، عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ، عَنْ يَحْيَى بْنِ يَعْمَرَ، قَالَ لَمَّا تَكَلَّمَ مَعْبَدٌ بِمَا تَكَلَّمَ بِهِ فِي شَأْنِ الْقَدَرِ أَنْكَرْنَا ذَلِكَ ‏.‏ قَالَ فَحَجَجْتُ أَنَا وَحُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيُّ حِجَّةً ‏.‏ وَسَاقُوا الْحَدِيثَ بِمَعْنَى حَدِيثِ كَهْمَسٍ وَإِسْنَادِهِ ‏.‏ وَفِيهِ بَعْضُ زِيَادَةٍ وَنُقْصَانُ أَحْرُفٍ ‏.‏', NULL, 'It is narrated on the authority of Yahya b. Ya''mur that when Ma''bad discussed the problem pertaining to Divine Decree, we refuted that. He (the narrator) said:I and Humaid b. Abdur-Rahman Himyari argued. And they carried on the conversation about the purport of the hadith related by Kahmas and its chain of transmission too, and there is some variation of words.', NULL, NULL, 'https://sunnah.com/muslim:2', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 3, 'وَحَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ، حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ، حَدَّثَنَا عُثْمَانُ بْنُ غِيَاثٍ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ، عَنْ يَحْيَى بْنِ يَعْمَرَ، وَحُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ، قَالاَ لَقِينَا عَبْدَ اللَّهِ بْنَ عُمَرَ فَذَكَرْنَا الْقَدَرَ وَمَا يَقُولُونَ فِيهِ ‏.‏ فَاقْتَصَّ الْحَدِيثَ كَنَحْوِ حَدِيثِهِمْ عَنْ عُمَرَ - رضى الله عنه - عَنِ النَّبِيِّ صلى الله عليه وسلم وَفِيهِ شَىْءٌ مِنْ زِيَادَةٍ وَقَدْ نَقَصَ مِنْهُ شَيْئًا ‏.‏', NULL, 'It is narrated on the authority of Yahya b. Ya''mur and Humaid b. ''Abdur-Rahman that they said:We met Abdullah b. ''Umar and we discussed about the Divine Decree, and what they talked about it and he narrated the hadith that has been transmitted by ''Umar (may Allah be pleased with him) from the Apostle (ﷺ). There is a slight variation in that.', NULL, NULL, 'https://sunnah.com/muslim:3', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 4, 'وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَزُهَيْرُ بْنُ حَرْبٍ، جَمِيعًا عَنِ ابْنِ عُلَيَّةَ، قَالَ زُهَيْرٌ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ، عَنْ أَبِي حَيَّانَ، عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ، عَنْ أَبِي هُرَيْرَةَ، قَالَ كَانَ رَسُولُ اللَّهِ صلى الله عليه وسلم يَوْمًا بَارِزًا لِلنَّاسِ فَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَا الإِيمَانُ قَالَ ‏"‏ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلاَئِكَتِهِ وَكِتَابِهِ وَلِقَائِهِ وَرُسُلِهِ وَتُؤْمِنَ بِالْبَعْثِ الآخِرِ ‏"‏ ‏.‏ قَالَ يَا رَسُولَ اللَّهِ مَا الإِسْلاَمُ قَالَ ‏"‏ الإِسْلاَمُ أَنْ تَعْبُدَ اللَّهَ وَلاَ تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلاَةَ الْمَكْتُوبَةَ وَتُؤَدِّيَ الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومَ رَمَضَانَ ‏"‏ ‏.‏ قَالَ يَا رَسُولَ اللَّهِ مَا الإِحْسَانُ قَالَ ‏"‏ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ لاَ تَرَاهُ فَإِنَّهُ يَرَاكَ ‏"‏ ‏.‏ قَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ قَالَ ‏"‏ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنَ السَّائِلِ وَلَكِنْ سَأُحَدِّثُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتِ الأَمَةُ رَبَّهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا كَانَتِ الْعُرَاةُ الْحُفَاةُ رُءُوسَ النَّاسِ فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا تَطَاوَلَ رِعَاءُ الْبَهْمِ فِي الْبُنْيَانِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ لاَ يَعْلَمُهُنَّ إِلاَّ اللَّهُ ‏"‏ ‏.‏ ثُمَّ تَلاَ صلى الله عليه وسلم ‏{‏ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَىِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ‏}‏ ‏"‏ ‏.‏ قَالَ ثُمَّ أَدْبَرَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ رُدُّوا عَلَىَّ الرَّجُلَ ‏"‏ ‏.‏ فَأَخَذُوا لِيَرُدُّوهُ فَلَمْ يَرَوْا شَيْئًا ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ هَذَا جِبْرِيلُ جَاءَ لِيُعَلِّمَ النَّاسَ دِينَهُمْ ‏"‏ ‏.‏', NULL, 'Abu Huraira reported:One day the Messenger of Allah (ﷺ) appeared before the public so a man came to him and then said: Prophet of Allah, what is Iman? Upon this he (the Holy Prophet) replied: That you affirm your faith in Allah, His angels, His Books, His meeting, His Messengers and that you affirm your faith in the Resurrection hereafter. He said: Messenger of Allah, what is al-Islam? He replied: Al-Islam is that you worship Allah and do not associate anything with Him and you establish obligatory prayer and you pay the obligatory alms (Zakat) and you observe the fast of Ramadan. He said: Messenger of Allah, what is al-Ihsan? He replied: That you worship Allah as if you are seeing Him, and for if you fail to see Him. He said: Messenger of Allah, when is the Hour (of Doom)? He replied: The one who is asked about it is no better informed than the inquirer, however I will narrate some of its signs to you. When the slave-girl will give birth to her master, then that is from its signs. When the naked, barefooted would become the chiefs of the people, then that is from its signs. When the shepherds of the black (camels) would exult themselves in buildings, then that is from its signs. (The Hour is) Among one of the five which no one knows but Allah. Then he recited (the verse): "Verily Allah! with Him alone is the knowledge of the Hour and He it is Who sends down the rain and knows that which is in the wombs. And no soul knows what it shall earn tomorrow, and a soul knows not in what land it shall die. Verily Allah is Knowing, Aware." He (Abu Huraira) said: Then the person turned back and went away. The Messenger of Allah (ﷺ) said: Bring that man back to me. They went to bring him back, but they saw nothing there. Upon this the Messenger of Allah remarked: he was Gabriel, who came to teach the people their religion.', 'Abu Huraira reported', NULL, 'https://sunnah.com/muslim:4', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 7, 'حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدِ بْنِ جَمِيلِ بْنِ طَرِيفِ بْنِ عَبْدِ اللَّهِ الثَّقَفِيُّ، عَنْ مَالِكِ بْنِ أَنَسٍ، - فِيمَا قُرِئَ عَلَيْهِ - عَنْ أَبِي سُهَيْلٍ، عَنْ أَبِيهِ، أَنَّهُ سَمِعَ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ، يَقُولُ جَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صلى الله عليه وسلم مِنْ أَهْلِ نَجْدٍ ثَائِرُ الرَّأْسِ نَسْمَعُ دَوِيَّ صَوْتِهِ وَلاَ نَفْقَهُ مَا يَقُولُ حَتَّى دَنَا مِنْ رَسُولِ اللَّهِ صلى الله عليه وسلم فَإِذَا هُوَ يَسْأَلُ عَنِ الإِسْلاَمِ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ خَمْسُ صَلَوَاتٍ فِي الْيَوْمِ وَاللَّيْلَةِ ‏"‏ ‏.‏ فَقَالَ هَلْ عَلَىَّ غَيْرُهُنَّ قَالَ ‏"‏ لاَ ‏.‏ إِلاَّ أَنْ تَطَّوَّعَ وَصِيَامُ شَهْرِ رَمَضَانَ ‏"‏ ‏.‏ فَقَالَ هَلْ عَلَىَّ غَيْرُهُ فَقَالَ ‏"‏ لاَ ‏.‏ إِلاَّ أَنْ تَطَّوَّعَ ‏"‏ ‏.‏ وَذَكَرَ لَهُ رَسُولُ اللَّهِ صلى الله عليه وسلم الزَّكَاةَ فَقَالَ هَلْ عَلَىَّ غَيْرُهَا قَالَ ‏"‏ لاَ ‏.‏ إِلاَّ أَنْ تَطَّوَّعَ ‏"‏ قَالَ فَأَدْبَرَ الرَّجُلُ وَهُوَ يَقُولُ وَاللَّهِ لاَ أَزِيدُ عَلَى هَذَا وَلاَ أَنْقُصُ مِنْهُ ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَفْلَحَ إِنْ صَدَقَ ‏"‏ ‏.‏', NULL, 'It is reported on the authority of Talha b. ''Ubaidullah that a person with dishevelled hair, one of the people of Nejd, came to the Messenger of Allah (ﷺ). We heard the humming of his voice but could not fully discern what he had been saying, till he came nigh to the Messenger of Allah (ﷺ). It was then (disclosed to us) that he was asking questions pertaining to Islam. The Messenger of Allah (ﷺ) said:Five prayers during the day and the night. (Upon this he said: Am I obliged to say any other (prayer) besides these? He (the Holy Prophet, ) said: No, but whatever you observe voluntarily, out of your own free will, and the fasts of Ramadan. The inquirer said: Am I obliged to do anything else besides this? He (the Holy Prophet) said: No, but whatever you do out of your own free will. And the Messenger of Allah told him about the Zakat (poor-rate). The inquirer said: Am I obliged to pay anything else besides this? He (the Holy Prophet) said: No, but whatever you pay voluntarily out of your own free will. The man turned back and was saying: I would neither make any addition to this, nor will decrease anything out of it. The Prophet remarked: He is successful, if he is true to what he affirms.', NULL, NULL, 'https://sunnah.com/muslim:7', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 8, 'حَدَّثَنِي يَحْيَى بْنُ أَيُّوبَ، وَقُتَيْبَةُ بْنُ سَعِيدٍ، جَمِيعًا عَنْ إِسْمَاعِيلَ بْنِ جَعْفَرٍ، عَنْ أَبِي سُهَيْلٍ، عَنْ أَبِيهِ، عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِهَذَا الْحَدِيثِ نَحْوَ حَدِيثِ مَالِكٍ غَيْرَ أَنَّهُ قَالَ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَفْلَحَ وَأَبِيهِ إِنْ صَدَقَ ‏"‏ ‏.‏ أَوْ ‏"‏ دَخَلَ الْجَنَّةَ وَأَبِيهِ إِنْ صَدَقَ ‏"‏ ‏.‏', NULL, 'Another hadith, the like of which has been narrated by Malik (b. Anas) (and mentioned above) is also reported by Talha b. ''Ubaidullah, with the only variation that the Prophet remarked:By his father, he shall succeed if he were true (to what he professed), or: By his father, he would enter heaven if he were true (to what he professed).', NULL, NULL, 'https://sunnah.com/muslim:8', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 9, '"‏ إِذَا وَلَدَتِ الأَمَةُ بَعْلَهَا ‏"', NULL, 'This hadith is narrated to us on the authority of Muhammad b. ''Abdullah b. Numair, on the authority of Muhammad b. Bishr, on the authority of Abd Hayyan al-Taymi with the exception that in this narration (instead of the words (Iza Waladat al''amah rabbaha), the words are (Iza Waladat al''amah Ba''laha), i, e, when slave-girl gives birth to her master.', NULL, NULL, 'https://sunnah.com/muslim:9', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 10, 'حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ، حَدَّثَنَا جَرِيرٌ، عَنْ عُمَارَةَ، - وَهُوَ ابْنُ الْقَعْقَاعِ - عَنْ أَبِي زُرْعَةَ، عَنْ أَبِي هُرَيْرَةَ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ سَلُونِي ‏"‏ فَهَابُوهُ أَنْ يَسْأَلُوهُ ‏.‏ فَجَاءَ رَجُلٌ فَجَلَسَ عِنْدَ رُكْبَتَيْهِ ‏.‏ فَقَالَ يَا رَسُولَ اللَّهِ مَا الإِسْلاَمُ قَالَ ‏"‏ لاَ تُشْرِكُ بِاللَّهِ شَيْئًا وَتُقِيمُ الصَّلاَةَ وَتُؤْتِي الزَّكَاةَ وَتَصُومُ رَمَضَانَ ‏"‏ ‏.‏ قَالَ صَدَقْتَ ‏.‏ قَالَ يَا رَسُولَ اللَّهِ مَا الإِيمَانُ قَالَ ‏"‏ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلاَئِكَتِهِ وَكِتَابِهِ وَلِقَائِهِ وَرُسُلِهِ وَتُؤْمِنَ بِالْبَعْثِ وَتُؤْمِنَ بِالْقَدَرِ كُلِّهِ ‏"‏ ‏.‏ قَالَ صَدَقْتَ ‏.‏ قَالَ يَا رَسُولَ اللَّهِ مَا الإِحْسَانُ قَالَ ‏"‏ أَنْ تَخْشَى اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ لاَ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ ‏"‏ ‏.‏ قَالَ صَدَقْتَ ‏.‏ قَالَ يَا رَسُولَ اللَّهِ مَتَى تَقُومُ السَّاعَةُ قَالَ ‏"‏ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنَ السَّائِلِ وَسَأُحَدِّثُكَ عَنْ أَشْرَاطِهَا إِذَا رَأَيْتَ الْمَرْأَةَ تَلِدُ رَبَّهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا رَأَيْتَ الْحُفَاةَ الْعُرَاةَ الصُّمَّ الْبُكْمَ مُلُوكَ الأَرْضِ فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا رَأَيْتَ رِعَاءَ الْبَهْمِ يَتَطَاوَلُونَ فِي الْبُنْيَانِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ مِنَ الْغَيْبِ لاَ يَعْلَمُهُنَّ إِلاَّ اللَّهُ ‏"‏ ‏.‏ ثُمَّ قَرَأَ ‏{‏ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَىِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ‏}‏ قَالَ ثُمَّ قَامَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ رُدُّوهُ عَلَىَّ ‏"‏ فَالْتُمِسَ فَلَمْ يَجِدُوهُ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ هَذَا جِبْرِيلُ أَرَادَ أَنْ تَعَلَّمُوا إِذْ لَمْ تَسْأَلُوا ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) said:Ask me (about religious matters), but they (the Companions) were in awe of asking him. Then came a man, and sat near his knees and said: O Messenger of Allah, what is al-Islam? So he (the Holy Prophet) replied: [That] you do not associate anything with Allah, and establish the prayer, pay the alms (Zakat) and fast Ramadan. He said: You (have) told the truth. He said: Messenger of Allah, what is al-Iman (Faith)? He said: That you affirm your faith in Allah, His angels, His Books, His meeting, His Apostles, and that you believe in Resurrection and that you believe in Qadr (Divine Decree) in all its entirety. He (the inquirer) said: You have told the truth. He said: Messenger of Allah, what is al-Ihsan? Upon this he said: that you fear Allah as if you are seeing Him, and though you see Him not, verily He is seeing you. He (the inquirer) said: You (have) told the truth. He (the inquirer) said: When will the Hour (of Doom) occur? He said: The one who is being asked about it is no better informed than the inquirer and I will narrate some of its signs to you. When you see a [slave] woman giving birth to her master - then that is [one] of its signs. And when you see barefooted, naked, deaf and dumb (ignorant and foolish persons) as the rulers of the earth - then that is [one] of its signs. And when you see the shepherds of black (camels) exult in buildings - then that is [one] of its signs. The (Hour) is one of the five things of the unseen. No one knows them except Allah. Then (the Holy Prophet) recited (the folowing verse):" Verily Allah! with Him alone is the knowledge of the Hour and He it is Who sends down the rain and knows that which is in the wombs. And no soul knows what it shall earn on the morrow and a soul knows not in what land it shall die. Verily Allah is Knowing, Aware." He (Abu Huraira) said: Then the person stood up (and made his way). Then the Messenger of Allah (ﷺ) said: Bring him back to me. He was searched for, but they could not find him. The Messenger of Allah (ﷺ) thereupon said: He was Gabriel and he wanted to teach you when you did not ask.', NULL, NULL, 'https://sunnah.com/muslim:10', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 11, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ، حَدَّثَنَا أَبِي، حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ، حَدَّثَنَا مُوسَى بْنُ طَلْحَةَ، قَالَ حَدَّثَنِي أَبُو أَيُّوبَ، أَنَّ أَعْرَابِيًّا، عَرَضَ لِرَسُولِ اللَّهِ صلى الله عليه وسلم وَهُوَ فِي سَفَرٍ ‏.‏ فَأَخَذَ بِخِطَامِ نَاقَتِهِ أَوْ بِزِمَامِهَا ثُمَّ قَالَ يَا رَسُولَ اللَّهِ - أَوْ يَا مُحَمَّدُ - أَخْبِرْنِي بِمَا يُقَرِّبُنِي مِنَ الْجَنَّةِ وَمَا يُبَاعِدُنِي مِنَ النَّارِ ‏.‏ قَالَ فَكَفَّ النَّبِيُّ صلى الله عليه وسلم ثُمَّ نَظَرَ فِي أَصْحَابِهِ ثُمَّ قَالَ ‏"‏ لَقَدْ وُفِّقَ - أَوْ لَقَدْ هُدِيَ - قَالَ كَيْفَ قُلْتَ ‏"‏ ‏.‏ قَالَ فَأَعَادَ ‏.‏ فَقَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ تَعْبُدُ اللَّهَ لاَ تُشْرِكُ بِهِ شَيْئًا وَتُقِيمُ الصَّلاَةَ وَتُؤْتِي الزَّكَاةَ وَتَصِلُ الرَّحِمَ دَعِ النَّاقَةَ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Abu Ayyub Ansari that once during the journey of the Prophet (may peace of Allah be upon him) a bedouin appeared before him and caught hold of the nosestring of his she-camel and then said, Messenger of Allah (or Muhammad), inform me about that which takes me near to Paradise and draws me away from the Fire (of Hell). He (the narrator) said:The Prophet (ﷺ) stopped for a while and cast a glance upon his companions and then said: He was afforded a good opportunity (or he had been guided well). He (the Holy Prophet) addressing the bedouin said: (Repeat) whatever you have uttered. He (the bedouin) repeated that. Upon this the Apostle (ﷺ) remarked: The deed which can draw you near to Paradise and take you away from Hell is, that you worship Allah and associate none with Him, and you establish prayer and pay Zakat, and do good to your kin. After having uttered these words, the Prophet asked the bedouin to release the nosestring of his she-camel.', NULL, NULL, 'https://sunnah.com/muslim:11', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 12, 'وَحَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ، وَعَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ، قَالاَ حَدَّثَنَا بَهْزٌ، حَدَّثَنَا شُعْبَةُ، حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ، وَأَبُوهُ، عُثْمَانُ أَنَّهُمَا سَمِعَا مُوسَى بْنَ طَلْحَةَ، يُحَدِّثُ عَنْ أَبِي أَيُّوبَ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِمِثْلِ هَذَا الْحَدِيثِ ‏.‏', NULL, 'This hadith is transmitted by Muhammad b. Hatim on the authority of Abu Ayyub Ansari.', NULL, NULL, 'https://sunnah.com/muslim:12', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 13, 'حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ، أَخْبَرَنَا أَبُو الأَحْوَصِ، ح وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو الأَحْوَصِ، عَنْ أَبِي إِسْحَاقَ، عَنْ مُوسَى بْنِ طَلْحَةَ، عَنْ أَبِي أَيُّوبَ، قَالَ جَاءَ رَجُلٌ إِلَى النَّبِيِّ صلى الله عليه وسلم فَقَالَ دُلَّنِي عَلَى عَمَلٍ أَعْمَلُهُ يُدْنِينِي مِنَ الْجَنَّةِ وَيُبَاعِدُنِي مِنَ النَّارِ ‏.‏ قَالَ ‏"‏ تَعْبُدُ اللَّهَ لاَ تُشْرِكُ بِهِ شَيْئًا وَتُقِيمُ الصَّلاَةَ وَتُؤْتِي الزَّكَاةَ وَتَصِلُ ذَا رَحِمِكَ ‏"‏ فَلَمَّا أَدْبَرَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ إِنْ تَمَسَّكَ بِمَا أُمِرَ بِهِ دَخَلَ الْجَنَّةَ ‏"‏ ‏.‏ وَفِي رِوَايَةِ ابْنِ أَبِي شَيْبَةَ ‏"‏ إِنْ تَمَسَّكَ بِهِ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Abu Ayyub that a man came to the Prophet (ﷺ) and said:Direct me to a deed which draws me near to Paradise and takes me away from the Fire (of Hell). Upon this he (the Holy Prophet) said: You worship Allah and never associate anything with Him, establish prayer, and pay Zakat, and do good to your kin. When he turned his back, the Messenger of Allah (ﷺ) remarked: If he adheres to what he has been ordered to do, he would enter Paradise.', NULL, NULL, 'https://sunnah.com/muslim:13', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 14, 'وَحَدَّثَنِي أَبُو بَكْرِ بْنُ إِسْحَاقَ، حَدَّثَنَا عَفَّانُ، حَدَّثَنَا وُهَيْبٌ، حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ، عَنْ أَبِي زُرْعَةَ، عَنْ أَبِي هُرَيْرَةَ، أَنَّ أَعْرَابِيًّا، جَاءَ إِلَى رَسُولِ اللَّهِ صلى الله عليه وسلم فَقَالَ يَا رَسُولَ اللَّهِ دُلَّنِي عَلَى عَمَلٍ إِذَا عَمِلْتُهُ دَخَلْتُ الْجَنَّةَ ‏.‏ قَالَ ‏"‏ تَعْبُدُ اللَّهَ لاَ تُشْرِكُ بِهِ شَيْئًا وَتُقِيمُ الصَّلاَةَ الْمَكْتُوبَةَ وَتُؤَدِّي الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومُ رَمَضَانَ ‏"‏ ‏.‏ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لاَ أَزِيدُ عَلَى هَذَا شَيْئًا أَبَدًا وَلاَ أَنْقُصُ مِنْهُ ‏.‏ فَلَمَّا وَلَّى قَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ مَنْ سَرَّهُ أَنْ يَنْظُرَ إِلَى رَجُلٍ مِنْ أَهْلِ الْجَنَّةِ فَلْيَنْظُرْ إِلَى هَذَا ‏"‏ ‏.‏', NULL, 'It is reported on the authority of Abu Huraira that a bedouin came to the Messenger of Allah (ﷺ) and said:Messenger of Allah, direct me to a deed by which I may be entitled to enter Paradise. Upon this he (the Holy Prophet) remarked: You worship Allah and never associate anything with Him, establish the obligatory prayer, and pay the Zakat which is incumbent upon you, and observe the fast of Ramadan. He (the bedouin) said: By Him in Whose hand is my life, I will never add anything to it, nor will I diminish anything from it. When he (the bedouin) turned his back, the Prophet (ﷺ) said: He who is pleased to see a man from the dwellers of Paradise should catch a glimpse of him.', NULL, NULL, 'https://sunnah.com/muslim:14', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 15, '"‏ نَعَمْ ‏"', NULL, 'It is narrated on the authority of Jabir that Nu''man b. Qaufal came to the Prophet (ﷺ) and said:Would I enter Paradise if I say the obligatory prayers and deny myself that which is forbidden and treat that as lawful what has been made permissible (by the Shari''ah)? The Prophet (ﷺ) replied in the affirmative.', NULL, NULL, 'https://sunnah.com/muslim:15', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 16, 'وَحَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ، وَالْقَاسِمُ بْنُ زَكَرِيَّاءَ، قَالاَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى، عَنْ شَيْبَانَ، عَنِ الأَعْمَشِ، عَنْ أَبِي صَالِحٍ، وَأَبِي، سُفْيَانَ عَنْ جَابِرٍ، قَالَ قَالَ النُّعْمَانُ بْنُ قَوْقَلٍ يَا رَسُولَ اللَّهِ ‏.‏ بِمِثْلِهِ ‏.‏ وَزَادَ فِيهِ وَلَمْ أَزِدْ عَلَى ذَلِكَ شَيْئًا ‏.‏', NULL, 'A similar hadith is narrated on Jabir''s authority in which the following words are added:I will do nothing more.', NULL, NULL, 'https://sunnah.com/muslim:16', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 17, '"‏ نَعَمْ ‏"', NULL, 'It is narrated on the authority of Jabir that a man once said to the Messenger of Allah (ﷺ):Shall I enter Paradise in case I say the obligatory prayers, observe the (fasts) of Ramadan and treat that as lawful which has been made permissible (by the Shari''ah) and deny myself that what is forbidden, and make no addition to it? He (the Holy Prophet) replied in the affirmative. He (the inquirer) said: By Allah, I would add nothing to it.', NULL, NULL, 'https://sunnah.com/muslim:17', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 18, '"‏ بُنِيَ الإِسْلاَمُ عَلَى خَمْسَةٍ عَلَى أَنْ يُوَحَّدَ اللَّهُ وَإِقَامِ الصَّلاَةِ وَإِيتَاءِ الزَّكَاةِ وَصِيَامِ رَمَضَانَ وَالْحَجِّ ‏"', NULL, 'It is narrated on the authority of (''Abdullah) son of Umar (may Allah be pleased with them) that the Prophet (may peace of Allah be upon him) said:(The superstructure of) al-Islam is raised on five (pillars), i. e. the oneness of Allah, the establishment of prayer, payment of Zakat, the, fast of Ramadan, Pilgrimage (to Mecca). A person said (to ''Abdullah b. Umar the narrator): Which of the two precedes the other-Pilgrimage or the fasts of Rarnadan? Upon this he (the narrator) replied: No (it is not the Pilgrimage first) but the fasts of Ramadan precede the Pilgrimage.', NULL, NULL, 'https://sunnah.com/muslim:18', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 19, '"‏ بُنِيَ الإِسْلاَمُ عَلَى خَمْسٍ عَلَى أَنْ يُعْبَدَ اللَّهُ وَيُكْفَرَ بِمَا دُونَهُ وَإِقَامِ الصَّلاَةِ وَإِيتَاءِ الزَّكَاةِ وَحَجِّ الْبَيْتِ وَصَوْمِ رَمَضَانَ ‏"', NULL, 'It is narrated on the authority of (''Abdullah) son of ''Umar, that the Prophet (may peace of Allah be upon him) said:(The superstructure of) al-Islam is raised on five (pillars), i. e. Allah (alone) should be worshipped, and (all other gods) beside Him should be (categorically) denied. Establishment of prayer, the payment of Zakat, Pilgrimage to the House, and the fast of Ramadan (are the other obligatory acts besides the belief in the oneness of Allah and denial of all other gods).', NULL, NULL, 'https://sunnah.com/muslim:19', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 20, '"‏ بُنِيَ الإِسْلاَمُ عَلَى خَمْسٍ شَهَادَةِ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَإِقَامِ الصَّلاَةِ وَإِيتَاءِ الزَّكَاةِ وَحَجِّ الْبَيْتِ وَصَوْمِ رَمَضَانَ ‏"', NULL, 'It is narrated on the authority of ''Abdullah son of ''Umar that the Messenger of Allah (ﷺ) said:(The superstructure of) al-Islam is raised on five (pillars), testifying (the fact) that there is no god but Allah, that Muhammad is His bondsman and messenger, and the establishment of prayer, payment of Zakat, Pilgrimage to the House (Ka''ba) and the fast of Ramadan.', NULL, NULL, 'https://sunnah.com/muslim:20', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 21, '"‏ إِنَّ الإِسْلاَمَ بُنِيَ عَلَى خَمْسٍ شَهَادَةِ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَإِقَامِ الصَّلاَةِ وَإِيتَاءِ الزَّكَاةِ وَصِيَامِ رَمَضَانَ وَحَجِّ الْبَيْتِ ‏"', NULL, 'It is reported on the authority of Ta''us that a man said to ''Abdullah son of ''Umar (may Allah be pleased with him). Why don''t you carry out a military expedition? Upon which he replied:I heard the messenger of Allah (ﷺ) say: Verily, al-Islam is founded on five (pillars): testifying the fact that there is no god but Allah, establishment of prayer, payment of Zakat, fast of Ramadan and Pilgrimage to the House.', NULL, NULL, 'https://sunnah.com/muslim:21', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 22, 'حَدَّثَنَا خَلَفُ بْنُ هِشَامٍ، حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ، عَنْ أَبِي جَمْرَةَ، قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ، ح وَحَدَّثَنَا يَحْيَى بْنُ يَحْيَى، - وَاللَّفْظُ لَهُ - أَخْبَرَنَا عَبَّادُ بْنُ عَبَّادٍ، عَنْ أَبِي جَمْرَةَ، عَنِ ابْنِ عَبَّاسٍ، قَالَ قَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى رَسُولِ اللَّهِ صلى الله عليه وسلم فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا هَذَا الْحَىَّ مِنْ رَبِيعَةَ وَقَدْ حَالَتْ بَيْنَنَا وَبَيْنَكَ كُفَّارُ مُضَرَ فَلاَ نَخْلُصُ إِلَيْكَ إِلاَّ فِي شَهْرِ الْحَرَامِ فَمُرْنَا بِأَمْرٍ نَعْمَلُ بِهِ وَنَدْعُو إِلَيْهِ مَنْ وَرَاءَنَا ‏.‏ قَالَ ‏"‏ آمُرُكُمْ بِأَرْبَعٍ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ الإِيمَانِ بِاللَّهِ - ثُمَّ فَسَّرَهَا لَهُمْ فَقَالَ - شَهَادَةِ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامِ الصَّلاَةِ وَإِيتَاءِ الزَّكَاةِ وَأَنْ تُؤَدُّوا خُمُسَ مَا غَنِمْتُمْ وَأَنْهَاكُمْ عَنِ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْمُقَيَّرِ ‏"‏ ‏.‏ زَادَ خَلَفٌ فِي رِوَايَتِهِ ‏"‏ شَهَادَةِ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ ‏"‏ ‏.‏ وَعَقَدَ وَاحِدَةً ‏.‏', NULL, 'It is narrated on the authority of Ibn ''Abbas that a delegation of Abdul Qais came to the Messenger of Allah (ﷺ) and said:Messenger of Allah, verily ours is a tribe of Rabi''a and there stand between you and us the unbelievers of Mudar and we find no freedom to come to you except in the sacred month. Direct us to an act which we should ourselves perform and invite those who live beside us. Upon this the Prophet remarked: I command you to do four things and prohibit you against four acts. (The four deeds which you are commanded to do are): Faith in Allah, and then he explained it for them and said: Testifying the fact. that there is no god but Allah, that Muhammad is the messenger of Allah, performance of prayer, payment of Zakat, that you pay Khums (one-fifth) of the booty fallen to your lot, and I prohibit you to use round gourd, wine jars, wooden pots or skins for wine. Khalaf b. Hisham has made this addition in his narration: Testifying the fact that there is no god but Allah, and then he with his finger pointed out the oneness of the Lord.', NULL, NULL, 'https://sunnah.com/muslim:22', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 23, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَمُحَمَّدُ بْنُ الْمُثَنَّى، وَمُحَمَّدُ بْنُ بَشَّارٍ، وَأَلْفَاظُهُمْ، مُتَقَارِبَةٌ - قَالَ أَبُو بَكْرٍ حَدَّثَنَا غُنْدَرٌ، عَنْ شُعْبَةَ، وَقَالَ الآخَرَانِ، حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، - عَنْ أَبِي جَمْرَةَ، قَالَ كُنْتُ أُتَرْجِمُ بَيْنَ يَدَىِ ابْنِ عَبَّاسٍ وَبَيْنَ النَّاسِ فَأَتَتْهُ امْرَأَةٌ تَسْأَلُهُ عَنْ نَبِيذِ الْجَرِّ، فَقَالَ إِنَّ وَفْدَ عَبْدِ الْقَيْسِ أَتَوْا رَسُولَ اللَّهِ صلى الله عليه وسلم فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ مَنِ الْوَفْدُ أَوْ مَنِ الْقَوْمُ ‏"‏ ‏.‏ قَالُوا رَبِيعَةُ ‏.‏ قَالَ ‏"‏ مَرْحَبًا بِالْقَوْمِ أَوْ بِالْوَفْدِ غَيْرَ خَزَايَا وَلاَ النَّدَامَى ‏"‏ ‏.‏ قَالَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا نَأْتِيكَ مِنْ شُقَّةٍ بَعِيدَةٍ وَإِنَّ بَيْنَنَا وَبَيْنَكَ هَذَا الْحَىَّ مِنْ كُفَّارِ مُضَرَ وَإِنَّا لاَ نَسْتَطِيعُ أَنْ نَأْتِيَكَ إِلاَّ فِي شَهْرِ الْحَرَامِ فَمُرْنَا بِأَمْرٍ فَصْلٍ نُخْبِرْ بِهِ مَنْ وَرَاءَنَا نَدْخُلُ بِهِ الْجَنَّةَ ‏.‏ قَالَ فَأَمَرَهُمْ بِأَرْبَعٍ وَنَهَاهُمْ عَنْ أَرْبَعٍ ‏.‏ قَالَ أَمَرَهُمْ بِالإِيمَانِ بِاللَّهِ وَحْدَهُ ‏.‏ وَقَالَ ‏"‏ هَلْ تَدْرُونَ مَا الإِيمَانُ بِاللَّهِ ‏"‏ ‏.‏ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ ‏.‏ قَالَ ‏"‏ شَهَادَةُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامُ الصَّلاَةِ وَإِيتَاءُ الزَّكَاةِ وَصَوْمُ رَمَضَانَ وَأَنْ تُؤَدُّوا خُمُسًا مِنَ الْمَغْنَمِ ‏"‏ ‏.‏ وَنَهَاهُمْ عَنِ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ ‏.‏ قَالَ شُعْبَةُ وَرُبَّمَا قَالَ النَّقِيرِ ‏.‏ قَالَ شُعْبَةُ وَرُبَّمَا قَالَ الْمُقَيَّرِ ‏.‏ وَقَالَ ‏"‏ احْفَظُوهُ وَأَخْبِرُوا بِهِ مِنْ وَرَائِكُمْ ‏"‏ ‏.‏ وَقَالَ أَبُو بَكْرٍ فِي رِوَايَتِهِ ‏"‏ مَنْ وَرَاءَكُمْ ‏"‏ وَلَيْسَ فِي رِوَايَتِهِ الْمُقَيَّرِ ‏.‏', NULL, 'Abu Jamra reported:I was an interpreter between Ibn Abbas and the people, that a woman happened to come there and asked about nabidh or the pitcher of wine. He replied: A delegation of the people of ''Abdul-Qais came to the Messenger of Allah (ﷺ). He (the Holy Prophet) asked the delegation or the people (of the delegation about their identity). They replied that they belonged to the tribe of Rabi''a. He (the Holy Prophet) welcomed the people or the delegation which were neither humiliated nor put to shame. They (the members of the delegation) said: Messenger of Allah, we come to you from a far-off distance and there lives between you and us a tribe of the unbelievers of Mudar and, therefore, it is not possible for us to come to you except in the sacred months. Thus direct us to a clear command, about which we should inform people beside us and by which we may enter heaven. He (the Holy Prophet) replied: I command you to do four deeds and forbid you to do four (acts), and added: I direct you to affirm belief in Allah alone, and then asked them: Do you know what belief in Allah really implies? They said: Allah and His Messenger know best. The Prophet said: It implies testimony to the fact that there is no god but Allah, and that Muhammad is the messenger of Allah, establishment of prayer, payment of Zakat, fast of Ramadan, that you pay one-fifth of the booty (fallen to your lot) and I forbid you to use gourd, wine jar, or a receptacle for wine. Shu''ba sometimes narrated the word naqir (wooden pot) and sometimes narrated it as muqayyar. The Prophet also said: Keep it in your mind and inform those who have been left behind.', 'Abu Jamra reported', NULL, 'https://sunnah.com/muslim:23', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 24, 'وَحَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ، حَدَّثَنَا أَبِي ح، وَحَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ، قَالَ أَخْبَرَنِي أَبِي قَالاَ، جَمِيعًا حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ، عَنْ أَبِي جَمْرَةَ، عَنِ ابْنِ عَبَّاسٍ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِهَذَا الْحَدِيثِ نَحْوَ حَدِيثِ شُعْبَةَ ‏.‏ وَقَالَ ‏"‏ أَنْهَاكُمْ عَمَّا يُنْبَذُ فِي الدُّبَّاءِ وَالنَّقِيرِ وَالْحَنْتَمِ وَالْمُزَفَّتِ ‏"‏ ‏.‏ وَزَادَ ابْنُ مُعَاذٍ فِي حَدِيثِهِ عَنْ أَبِيهِ قَالَ وَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم لِلأَشَجِّ أَشَجِّ عَبْدِ الْقَيْسِ ‏"‏ إِنَّ فِيكَ خَصْلَتَيْنِ يُحِبُّهُمَا اللَّهُ الْحِلْمُ وَالأَنَاةُ ‏"‏ ‏.‏', NULL, 'There is another hadith narrated on the authority of Ibn Abbas (the contents of which are similar to the one) narrated by Shu''ba in which the Prophet (ﷺ) said:I forbid you to prepare nabidh in a gourd, hollowed block of wood, a varnished jar or receptacle. Ibn Mu''adh made this addition on the authority of his father that the Messenger of Allah said to Ashajj, of the tribe of ''Abdul-Qais: You possess two qualities which are liked by Allah: insight and deliberateness.', NULL, NULL, 'https://sunnah.com/muslim:24', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 25, 'حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ، حَدَّثَنَا ابْنُ عُلَيَّةَ، حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ، عَنْ قَتَادَةَ، قَالَ حَدَّثَنَا مَنْ، لَقِيَ الْوَفْدَ الَّذِينَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صلى الله عليه وسلم مِنْ عَبْدِ الْقَيْسِ ‏.‏ قَالَ سَعِيدٌ وَذَكَرَ قَتَادَةُ أَبَا نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ فِي حَدِيثِهِ هَذَا ‏.‏ أَنَّ أُنَاسًا مِنْ عَبْدِ الْقَيْسِ قَدِمُوا عَلَى رَسُولِ اللَّهِ صلى الله عليه وسلم فَقَالُوا يَا نَبِيَّ اللَّهِ إِنَّا حَىٌّ مِنْ رَبِيعَةَ وَبَيْنَنَا وَبَيْنَكَ كُفَّارُ مُضَرَ وَلاَ نَقْدِرُ عَلَيْكَ إِلاَّ فِي أَشْهُرِ الْحُرُمِ فَمُرْنَا بِأَمْرٍ نَأْمُرُ بِهِ مَنْ وَرَاءَنَا وَنَدْخُلُ بِهِ الْجَنَّةَ إِذَا نَحْنُ أَخَذْنَا بِهِ ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ آمُرُكُمْ بِأَرْبَعٍ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ اعْبُدُوا اللَّهَ وَلاَ تُشْرِكُوا بِهِ شَيْئًا وَأَقِيمُوا الصَّلاَةَ وَآتُوا الزَّكَاةَ وَصُومُوا رَمَضَانَ وَأَعْطُوا الْخُمُسَ مِنَ الْغَنَائِمِ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ عَنِ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ ‏"‏ ‏.‏ قَالُوا يَا نَبِيَّ اللَّهِ مَا عِلْمُكَ بِالنَّقِيرِ قَالَ ‏"‏ بَلَى جِذْعٌ تَنْقُرُونَهُ فَتَقْذِفُونَ فِيهِ مِنَ الْقُطَيْعَاءِ - قَالَ سَعِيدٌ أَوْ قَالَ مِنَ التَّمْرِ - ثُمَّ تَصُبُّونَ فِيهِ مِنَ الْمَاءِ حَتَّى إِذَا سَكَنَ غَلَيَانُهُ شَرِبْتُمُوهُ حَتَّى إِنَّ أَحَدَكُمْ - أَوْ إِنَّ أَحَدَهُمْ - لَيَضْرِبُ ابْنَ عَمِّهِ بِالسَّيْفِ ‏"‏ ‏.‏ قَالَ وَفِي الْقَوْمِ رَجُلٌ أَصَابَتْهُ جِرَاحَةٌ كَذَلِكَ ‏.‏ قَالَ وَكُنْتُ أَخْبَأُهَا حَيَاءً مِنْ رَسُولِ اللَّهِ صلى الله عليه وسلم فَقُلْتُ فَفِيمَ نَشْرَبُ يَا رَسُولَ اللَّهِ قَالَ ‏"‏ فِي أَسْقِيَةِ الأَدَمِ الَّتِي يُلاَثُ عَلَى أَفْوَاهِهَا ‏"‏ ‏.‏ قَالُوا يَا رَسُولَ اللَّهِ إِنَّ أَرْضَنَا كَثِيرَةُ الْجِرْذَانِ وَلاَ تَبْقَى بِهَا أَسْقِيَةُ الأَدَمِ ‏.‏ فَقَالَ نَبِيُّ اللَّهِ صلى الله عليه وسلم ‏"‏ وَإِنْ أَكَلَتْهَا الْجِرْذَانُ وَإِنْ أَكَلَتْهَا الْجِرْذَانُ وَإِنْ أَكَلَتْهَا الْجِرْذَانُ ‏"‏ ‏.‏ قَالَ وَقَالَ نَبِيُّ اللَّهِ صلى الله عليه وسلم لأَشَجِّ عَبْدِ الْقَيْسِ ‏"‏ إِنَّ فِيكَ لَخَصْلَتَيْنِ يُحِبُّهُمَا اللَّهُ الْحِلْمُ وَالأَنَاةُ ‏"‏ ‏.‏', NULL, 'It is reported on the authority of Qatada that one among the delegates of the ''Abdul-Qais tribe narrated this tradition to him. Sa''id said that Qatada had mentioned the name of Abu Nadra on the authority of Abu Sa''id Khudri who narrated this tradition:That people from the- tribe of ''Abdul-Qais came to the Messenger of Allah (ﷺ) and said: Messenger of Allah, we belong to the tribe of Rabi''a and there live between you and us the unbelievers of the Mudar tribe and we find it impossible to come to you except in the sacred months; direct us to a deed which we must communicate to those who have been left behind us and by doing which we may enter heaven. Upon this the Messenger of Allah (ﷺ) said: I enjoin upon you four (things) and forbid you to do four (things): worship Allah and associate none with Him, establish prayer, pay Zakat, and observe the fast of Ramadan, and pay the fifth part out of the booty. And I prohibit you from four (things): dry gourds, green-coloured jars, hollowed stumps of palm-trees, and receptacles. They (the members of the delegation) said: Do you know what al-naqir is? He replied: Yes, it is a stump which you hollow out and in which you throw small dates. Sa''id said: He (the Holy Prophet) used the word tamar (dates). (The Prophet then added): Then you sprinkle water over it and when its ebullition subsides, you drink it (and you are so intoxicated) that one amongst you, or one amongst them (the other members of your tribe, who were not present there) strikes his cousin with the sword. He (the narrator) said: There was a man amongst us who had sustained injury on this very account due to (intoxication), and he told that he tried to conceal it out of shame from the Messenger of Allah (ﷺ). I, however, inquired from the Messenger of Allah (it we discard those utensils which you have forbidden us to use), then what type of vessels should be used for drink? He (the Holy Prophet) replied: In the waterskin the mouths of which are tied (with a string). They (again) said: Prophet of Allah, our land abounds in rats and water-skins cannot remain preserved. The holy Prophet of Allah (ﷺ) said: (Drink in water-skins) even if these arenibbled by rats. And then (addressing) al-Ashajj of ''Abdul-Qais he said: Verily, you possess two such qualities which Allah loves: insight and deliberateness.', NULL, NULL, 'https://sunnah.com/muslim:25', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 26, 'حَدَّثَنِي مُحَمَّدُ بْنُ بَكَّارٍ الْبَصْرِيُّ، حَدَّثَنَا أَبُو عَاصِمٍ، عَنِ ابْنِ جُرَيْجٍ، ح وَحَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ، - وَاللَّفْظُ لَهُ - حَدَّثَنَا عَبْدُ الرَّزَّاقِ، أَخْبَرَنَا ابْنُ جُرَيْجٍ، قَالَ أَخْبَرَنِي أَبُو قَزَعَةَ، أَنَّ أَبَا نَضْرَةَ، أَخْبَرَهُ وَحَسَنًا، أَخْبَرَهُمَا أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ أَخْبَرَهُ أَنَّ وَفْدَ عَبْدِ الْقَيْسِ لَمَّا أَتَوْا نَبِيَّ اللَّهِ صلى الله عليه وسلم قَالُوا يَا نَبِيَّ اللَّهِ جَعَلَنَا اللَّهُ فِدَاءَكَ مَاذَا يَصْلُحُ لَنَا مِنَ الأَشْرِبَةِ فَقَالَ ‏"‏ لاَ تَشْرَبُوا فِي النَّقِيرِ ‏"‏ ‏.‏ قَالُوا يَا نَبِيَّ اللَّهِ جَعَلَنَا اللَّهُ فِدَاءَكَ أَوَتَدْرِي مَا النَّقِيرُ قَالَ ‏"‏ نَعَمِ الْجِذْعُ يُنْقَرُ وَسَطُهُ وَلاَ فِي الدُّبَّاءِ وَلاَ فِي الْحَنْتَمَةِ وَعَلَيْكُمْ بِالْمُوكَى ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Abu Said al-Khudri that when the delegation of the tribe of Abdul-Qais came to the Prophet of Allah (ﷺ), (its members) said:Apostle of Allah, may God enable us to lay down our lives for you, which beverage is good for us? He (the Prophet) said: (Not to speak of beverages, I would lay stress) that you should not drink in the wine jars. They said: Apostle of Allah, may God enable us to lay down our lives for you, do you know what al-naqir is? He (the Holy Prophet) replied: Yes, it is a stump which you hollow out in the middle, and added: Do not use gourd or receptacle (for drink). Use water-skin the mouth of which is tied with a thong (for this purpose).', NULL, NULL, 'https://sunnah.com/muslim:26', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 27, '"‏ إِنَّكَ تَأْتِي قَوْمًا مِنْ أَهْلِ الْكِتَابِ ‏.‏ فَادْعُهُمْ إِلَى شَهَادَةِ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنِّي رَسُولُ اللَّهِ فَإِنْ هُمْ أَطَاعُوا لِذَلِكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ افْتَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَإِنْ هُمْ أَطَاعُوا لِذَلِكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ افْتَرَضَ عَلَيْهِمْ صَدَقَةً تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ فَتُرَدُّ فِي فُقَرَائِهِمْ فَإِنْ هُمْ أَطَاعُوا لِذَلِكَ فَإِيَّاكَ وَكَرَائِمَ أَمْوَالِهِمْ وَاتَّقِ دَعْوَةَ الْمَظْلُومِ فَإِنَّهُ لَيْسَ بَيْنَهَا وَبَيْنَ اللَّهِ حِجَابٌ ‏"', NULL, 'It is reported on the authority of Ibn ''Abbas that Mu''adh said:The Messenger of Allah sent me (as a governor of Yemen) and (at the time of departure) instructed me thus: You will soon find yourself in a community one among the people of the Book, so first call them to testify that there is no god but Allah, that I (Muhammad) am the messenger of Allah, and if they accept this, then tell them Allah has enjoined upon them five prayers during the day and the night and if they accept it, then tell them that Allah has made Zakat obligatory for them that it should be collected from the rich and distributed among the poor, and if they agree to it don''t pick up (as a share of Zakat) the best of their wealths. Beware of the supplication of the oppressed for there is no barrier between him and Allah.', 'It is reported on the authority of Ibn ''Abbas that Mu''adh said', NULL, 'https://sunnah.com/muslim:27', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 28, '"‏ إِنَّكَ تَقْدَمُ عَلَى قَوْمٍ أَهْلِ كِتَابٍ فَلْيَكُنْ أَوَّلَ مَا تَدْعُوهُمْ إِلَيْهِ عِبَادَةُ اللَّهِ عَزَّ وَجَلَّ فَإِذَا عَرَفُوا اللَّهَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ فَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي يَوْمِهِمْ وَلَيْلَتِهِمْ فَإِذَا فَعَلُوا فَأَخْبِرْهُمْ أَنَّ اللَّهَ قَدْ فَرَضَ عَلَيْهِمْ زَكَاةً تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ فَتُرَدُّ عَلَى فُقَرَائِهِمْ فَإِذَا أَطَاعُوا بِهَا فَخُذْ مِنْهُمْ وَتَوَقَّ كَرَائِمَ أَمْوَالِهِمْ ‏"', NULL, 'It is narrated on the authority of Ibn ''Abbas that when the Messenger of Allah (ﷺ) sent Mu''adh towards Yemen (as governor) he said to him:Verily you would reach a community of the people of the Book, the very first thing to which you should call them is the worship of Allah, may His Glory be Magnificent, and when they become fully aware of Allah, instruct them that He has enjoined five prayers on them during the day and the night, and when they begin observing it, then instruct them that verily Allah has made Zakat obligatory for them which would be collected from the wealthy amongst them and distributed to their needy ones, and when they submit to it, then collect it from them and avoid (the temptation) of selecting the best (items) of their riches.', NULL, NULL, 'https://sunnah.com/muslim:28', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 29, '"‏ مَنْ شَهِدَ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَرَّمَ اللَّهُ عَلَيْهِ النَّارَ ‏"', NULL, 'It is narrated on the authority of Sunabihi that he went to Ubada b. Samit when he was about to die. I burst into tears. Upon this he said to me:Allow me some time (so that I may talk with you). Why do you weep? By Allah, if I am asked to bear witness, I would certainly testify for you (that you are a believer). Should I be asked to intercede, I would certainly intercede for you, and if I have the power, I would certainly do good to you, and then observed: By Allah, never did I hear anything from the Messenger of Allah (ﷺ) which could have been a source of benefit to you and then not conveyed it to you except this single hadith. That I intend to narrate to you today, since I am going to breathe my last. I heard the Messenger of Allah (ﷺ) say: He who testifies that there is no god but Allah and that Muhammad is the messenger of Allah, Allah would prohibit the fire of Hell for him.', NULL, NULL, 'https://sunnah.com/muslim:29', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 30, '"‏ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لاَ إِلَهَ إِلاَّ اللَّهُ فَمَنْ قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ عَصَمَ مِنِّي مَالَهُ وَنَفْسَهُ إِلاَّ بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِ ‏"', NULL, 'It is reported on the authority of Abu Huraira that the Messenger of Allah said:I have been commanded to fight against people so long as they do not declare that there is no god but Allah, and he who professed it was guaranteed the protection of his property and life on my behalf except for the right affairs rest with Allah.', 'It is reported on the authority of Abu Huraira that the Messenger of Allah said', NULL, 'https://sunnah.com/muslim:30', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 31, '"‏ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَيُؤْمِنُوا بِي وَبِمَا جِئْتُ بِهِ فَإِذَا فَعَلُوا ذَلِكَ عَصَمُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلاَّ بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ ‏"', NULL, 'It is reported on the authority of Abu Huraira that he heard the Messenger of Allah say:I have been commanded to fight against people, till they testify to the fact that there is no god but Allah, and believe in me (that) I am the messenger (from the Lord) and in all that I have brought. And when they do it, their blood and riches are guaranteed protection on my behalf except where it is justified by law, and their affairs rest with Allah.', NULL, NULL, 'https://sunnah.com/muslim:31', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 32, 'وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ، عَنِ الأَعْمَشِ، عَنْ أَبِي سُفْيَانَ، عَنْ جَابِرٍ، وَعَنْ أَبِي صَالِحٍ، عَنْ أَبِي هُرَيْرَةَ، قَالاَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ ‏"‏ ‏.‏ بِمِثْلِ حَدِيثِ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ ح
وَحَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا وَكِيعٌ، ح وَحَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى، حَدَّثَنَا عَبْدُ الرَّحْمَنِ، - يَعْنِي ابْنَ مَهْدِيٍّ - قَالاَ جَمِيعًا حَدَّثَنَا سُفْيَانُ، عَنْ أَبِي الزُّبَيْرِ، عَنْ جَابِرٍ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لاَ إِلَهَ إِلاَّ اللَّهُ فَإِذَا قَالُوا لاَ إِلَهَ إِلاَّ اللَّهُ عَصَمُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلاَّ بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ ‏"‏ ‏.‏ ثُمَّ قَرَأَ ‏{‏ إِنَّمَا أَنْتَ مُذَكِّرٌ * لَسْتَ عَلَيْهِمْ بِمُسَيْطِرٍ‏}‏', NULL, 'It is narrated on the authority of Jabir that the Messenger of Allah said:I have been commanded that I should fight against people till they declare that there is no god but Allah, and when they profess it that there is no god but Allah, their blood and riches are guaranteed protection on my behalf except where it is justified by law, and their affairs rest with Allah, and then he (the Holy Prophet) recited (this verse of the Holy Qur''an):" Thou art not over them a warden" (lxxxviii, 22).', 'It is narrated on the authority of Jabir that the Messenger of Allah said', NULL, 'https://sunnah.com/muslim:32', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 34, '"‏ مَنْ قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ وَكَفَرَ بِمَا يُعْبَدُ مِنْ دُونِ اللَّهِ حَرُمَ مَالُهُ وَدَمُهُ وَحِسَابُهُ عَلَى اللَّهِ ‏"', NULL, 'It Is narrated on the authority of Abu Malik:I heard the Messenger of Allah (ﷺ) say: He who professed that there is no god but Allah and made a denial of everything which the people worship beside Allah, his property and blood became inviolable, an their affairs rest with Allah.', 'It Is narrated on the authority of Abu Malik', NULL, 'https://sunnah.com/muslim:34', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 35, '"‏ مَنْ وَحَّدَ اللَّهَ ‏"', NULL, 'Abu Malik narrated on the authority of his father that he heard the Apostle (ﷺ) say:He who held belief in the unity of Allah, and then narrated what has been stated above.', NULL, NULL, 'https://sunnah.com/muslim:35', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 36, 'وَحَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ، أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ، قَالَ أَخْبَرَنِي يُونُسُ، عَنِ ابْنِ شِهَابٍ، قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ، عَنْ أَبِيهِ، قَالَ لَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ جَاءَهُ رَسُولُ اللَّهِ صلى الله عليه وسلم فَوَجَدَ عِنْدَهُ أَبَا جَهْلٍ وَعَبْدَ اللَّهِ بْنَ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ يَا عَمِّ قُلْ لاَ إِلَهَ إِلاَّ اللَّهُ ‏.‏ كَلِمَةً أَشْهَدُ لَكَ بِهَا عِنْدَ اللَّهِ ‏"‏ ‏.‏ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ ‏.‏ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صلى الله عليه وسلم يَعْرِضُهَا عَلَيْهِ وَيُعِيدُ لَهُ تِلْكَ الْمَقَالَةَ حَتَّى قَالَ أَبُو طَالِبٍ آخِرَ مَا كَلَّمَهُمْ هُوَ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ ‏.‏ وَأَبَى أَنْ يَقُولَ لاَ إِلَهَ إِلاَّ اللَّهُ ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَمَا وَاللَّهِ لأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ ‏"‏ ‏.‏ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ ‏{‏ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ‏}‏ ‏.‏ وَأَنْزَلَ اللَّهُ تَعَالَى فِي أَبِي طَالِبٍ فَقَالَ لِرَسُولِ اللَّهِ صلى الله عليه وسلم ‏{‏ إِنَّكَ لاَ تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَ‏}‏‏.‏', NULL, 'It is reported by Sa''id b. Musayyib who narrated it on the authority of his father (Musayyib b. Hazm) that when Abu Talib was about to die, the Messenger of Allah (ﷺ) came to him and found with him Abu Jahl (''Amr b. Hisham) and ''Abdullah b. Abi Umayya ibn al-Mughirah. The Messenger of Allah (ﷺ) said:My uncle, you just make a profession that there is no god but Allah, and I will bear testimony before Allah (of your being a believer), Abu Jahl and ''Abdullah b. Abi Umayya addressing him said: Abu Talib, would you abandon the religion of ''Abdul-Muttalib? The Messenger of Allah (ﷺ) constantly requested him (to accept his offer), and (on the other hand) was repeated the same statement (of Abu Jahl and ''Abdullah b. Abi Umayya) till Abu Talib gave his final decision and be stuck to the religion of ''Abdul-Muttalib and refused to profess that there is no god but Allah. Upon this the Messenger of Allah remarked: By Allah, I will persistently beg pardon for you till I am forbidden to do so (by God), It was then that Allah, the Magnificent and the Glorious, revealed this verse: " It is not meet for the Prophet and for those who believe that they should beg pardon for the polytheists, even though they were their kith and kin, after it had been made known to them that they were the denizens of Hell" (ix. 113) And it was said to the Messenger of Allah (ﷺ): " Verily thou canst not guide to the right path whom thou lovest. And it is Allah Who guideth whom He will, and He knoweth best who are the guided" (xxviii, 56).', NULL, NULL, 'https://sunnah.com/muslim:36', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 37, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ، وَابْنُ أَبِي عُمَرَ، قَالاَ حَدَّثَنَا مَرْوَانُ، عَنْ يَزِيدَ، - وَهُوَ ابْنُ كَيْسَانَ - عَنْ أَبِي حَازِمٍ، عَنْ أَبِي هُرَيْرَةَ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم لِعَمِّهِ عِنْدَ الْمَوْتِ ‏"‏ قُلْ لاَ إِلَهَ إِلاَّ اللَّهُ أَشْهَدُ لَكَ بِهَا يَوْمَ الْقِيَامَةِ ‏"‏ ‏.‏ فَأَبَى فَأَنْزَلَ اللَّهُ ‏{‏ إِنَّكَ لاَ تَهْدِي مَنْ أَحْبَبْتَ‏}‏ الآيَةَ ‏.‏', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah said to his uncle at the time of his death:Make a profession of it that there is no god but Allah and I will bear testimony (of your being a Muslim) on the Day of judgment. But he (Abu Talib) refused to do so. Then Allah revealed this verse: "Indeed, [O Muḥammad], you do not guide whom you like, but Allāh guides whom He wills. And He is most knowing of the [rightly] guided."(Quran 28:56).', NULL, NULL, 'https://sunnah.com/muslim:37', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 38, 'حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ مَيْمُونٍ، حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ، حَدَّثَنَا يَزِيدُ بْنُ كَيْسَانَ، عَنْ أَبِي حَازِمٍ الأَشْجَعِيِّ، عَنْ أَبِي هُرَيْرَةَ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم لِعَمِّهِ ‏"‏ قُلْ لاَ إِلَهَ إِلاَّ اللَّهُ أَشْهَدُ لَكَ بِهَا يَوْمَ الْقِيَامَةِ ‏"‏ ‏.‏ قَالَ لَوْلاَ أَنْ تُعَيِّرَنِي قُرَيْشٌ يَقُولُونَ إِنَّمَا حَمَلَهُ عَلَى ذَلِكَ الْجَزَعُ لأَقْرَرْتُ بِهَا عَيْنَكَ فَأَنْزَلَ اللَّهُ ‏{‏ إِنَّكَ لاَ تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ‏}‏', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah said to his uncle (at the time of his death):Make a profession of it that there is no god but Allah and I will bear testimony (of your being a Muslim) on the Day of judgment. He (Abu Talib) said: Were it not the fear of the Quraysh blaming me (and) saying that it was the fear of (approaching death) that induced me to do so, I would have certainly delighted your eyes. It was then that Allah revealed: "Indeed, [O Muḥammad], you do not guide whom you like, but Allāh guides whom He wills. And He is most knowing of the [rightly] guided."(Quran 28:56).', NULL, NULL, 'https://sunnah.com/muslim:38', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 39, '"‏ مَنْ مَاتَ وَهُوَ يَعْلَمُ أَنَّهُ لاَ إِلَهَ إِلاَّ اللَّهُ دَخَلَ الْجَنَّةَ ‏"', NULL, 'It is narrated on the authority of ''Uthman that the Messenger of Allah (ﷺ) said. He who died knowing (fully well) that there is no god but Allah entered Paradise.', NULL, NULL, 'https://sunnah.com/muslim:39', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 40, 'حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ، حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ، حَدَّثَنَا خَالِدٌ الْحَذَّاءُ، عَنِ الْوَلِيدِ أَبِي بِشْرٍ، قَالَ سَمِعْتُ حُمْرَانَ، يَقُولُ سَمِعْتُ عُثْمَانَ، يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم يَقُولُ مِثْلَهُ سَوَاءً ‏.‏', NULL, 'It is narrated on the authority of Humran that he heard Uthman saying this:I heard the Messenger of Allah (ﷺ) uttering these words (as stated above).', 'It is narrated on the authority of Humran that he heard Uthman saying this', NULL, 'https://sunnah.com/muslim:40', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 41, '"‏ أَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنِّي رَسُولُ اللَّهِ لاَ يَلْقَى اللَّهَ بِهِمَا عَبْدٌ غَيْرَ شَاكٍّ فِيهِمَا إِلاَّ دَخَلَ الْجَنَّةَ ‏"', NULL, 'It is narrated on the authority of Abu Huraira:We were accompanying the Apostle (ﷺ) in a march (towards Tabuk). He (the narrator) said: The provisions with the people were almost depleted. He (the narrator) said: (And the situation became so critical) that they (the men of the army) decided to slaughter some of their camels. He (the narrator) said: Upon this Umar said: Messenger of Allah, I wish that you should pool together what has been left out of the provisions with the people and then invoke (the blessings of) Allah upon it. He (the narrator) said: He (the Holy Prophet) did it accordingly. He (the narrator) said: The one who had wheat in his possession came there with wheat. He who had dates with him came there with dates. And Mujahid said: He who possessed stones of dates came there with stones. I (the narrator) said: What did they do with the date-stones. They said: They (the people) sucked them and then drank water over them. He (the narrator said): He (the Holy Prophet) invoked the blessings (of Allah) upon them (provisions). He (the narrator) said: (And there was such a miraculous increase in the stocks) that the people replenished their provisions fully. He (the narrator) said: At that time he (the Holy Prophet) said: I bear testimony to the fact that there is no god but Allah, and I am His messenger. The bondsman who would meet Allah without entertaining any doubt about these (two fundamentals) would enter heaven.', 'It is narrated on the authority of Abu Huraira', NULL, 'https://sunnah.com/muslim:41', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 42, 'حَدَّثَنَا سَهْلُ بْنُ عُثْمَانَ، وَأَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلاَءِ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ، - قَالَ أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ، - عَنِ الأَعْمَشِ، عَنْ أَبِي صَالِحٍ، عَنْ أَبِي هُرَيْرَةَ، أَوْ عَنْ أَبِي سَعِيدٍ، - شَكَّ الأَعْمَشُ - قَالَ لَمَّا كَانَ غَزْوَةُ تَبُوكَ أَصَابَ النَّاسَ مَجَاعَةٌ ‏.‏ قَالُوا يَا رَسُولَ اللَّهِ لَوْ أَذِنْتَ لَنَا فَنَحَرْنَا نَوَاضِحَنَا فَأَكَلْنَا وَادَّهَنَّا ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ افْعَلُوا ‏"‏ ‏.‏ قَالَ فَجَاءَ عُمَرُ فَقَالَ يَا رَسُولَ اللَّهِ إِنْ فَعَلْتَ قَلَّ الظَّهْرُ وَلَكِنِ ادْعُهُمْ بِفَضْلِ أَزْوَادِهِمْ ثُمَّ ادْعُ اللَّهَ لَهُمْ عَلَيْهَا بِالْبَرَكَةِ لَعَلَّ اللَّهَ أَنْ يَجْعَلَ فِي ذَلِكَ ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ نَعَمْ ‏"‏ ‏.‏ قَالَ فَدَعَا بِنِطَعٍ فَبَسَطَهُ ثُمَّ دَعَا بِفَضْلِ أَزْوَادِهِمْ - قَالَ - فَجَعَلَ الرَّجُلُ يَجِيءُ بِكَفِّ ذُرَةٍ - قَالَ - وَيَجِيءُ الآخَرُ بَكَفِّ تَمْرٍ - قَالَ - وَيَجِيءُ الآخَرُ بِكِسْرَةٍ حَتَّى اجْتَمَعَ عَلَى النِّطَعِ مِنْ ذَلِكَ شَىْءٌ يَسِيرٌ - قَالَ - فَدَعَا رَسُولُ اللَّهِ صلى الله عليه وسلم عَلَيْهِ بِالْبَرَكَةِ ثُمَّ قَالَ ‏"‏ خُذُوا فِي أَوْعِيَتِكُمْ ‏"‏ ‏.‏ قَالَ فَأَخَذُوا فِي أَوْعِيَتِهِمْ حَتَّى مَا تَرَكُوا فِي الْعَسْكَرِ وِعَاءً إِلاَّ مَلأُوهُ - قَالَ - فَأَكَلُوا حَتَّى شَبِعُوا وَفَضِلَتْ فَضْلَةٌ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنِّي رَسُولُ اللَّهِ لاَ يَلْقَى اللَّهَ بِهِمَا عَبْدٌ غَيْرَ شَاكٍّ فَيُحْجَبَ عَنِ الْجَنَّةِ ‏"‏ ‏.‏', NULL, 'It is narrated either on the authority of Abu Huraira or that of Abu Sa''id Khudri. The narrator A''mash has narrated this hadith with a little bit of doubt (about the name of the very first narrator who was in direct contact with the Holy Prophet. He was either Abu Huraira or Abu Sa''id Khudri. Both are equally reliable transmitters of the traditions). He (the narrator) said:During the time of Tabuk expedition, the (provisions) ran short and the men (of the army) suffered starvation; they said: Messenger of Allah, would you permit us to slay our camels? We would eat them and use their fat. The Messenger of Allah (ﷺ) said: Do as you please. He (the narrator) said: Then ''Umar came there and said: Messenger of Allah, if you do that (if you give your consent and the men begin to slay their camels), the riding animals would become short. But (I would suggest you to) summon them along with the provisions left with them Then invoke Allah''s blessings on them (different items of the provisions) It is hoped Allah shall bless them. The Messenger of Allah replied in the affirmative. (the narrator) said: He called for a leather mat to be used as a table cloth and spread it out. Then he called people along with the remaining portions of their provisions. He (the narrator) said: Someone was coming with handful of mote, another was coming with a handful of dates, still another was coming with a portion of bread, till small quantities of these things were collected on the table cloth. He (the narrator said): Then the messenger of Allah invoked blessing (on them) and said: Fill your utensils with these provisions. He (the narrator) said: They filled their vessel to the brim with them, and no one amongst the army (which comprised of 30,000 persons) was left even with a single empty vessel. He (the narrator) aid: They ate to their fill, and there was still a surplus. Upon this the Messenger of Allah (ﷺ) remarked: I bear testimony that there is no god but Allah and I am the messenger of Allah. The man who meets his Lord without harboring any doubt about these two (truths) would never be kept away from Paradise.', NULL, NULL, 'https://sunnah.com/muslim:42', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 43, '"‏ مَنْ قَالَ أَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَحْدَهُ لاَ شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَأَنَّ عِيسَى عَبْدُ اللَّهِ وَابْنُ أَمَتِهِ وَكَلِمَتُهُ أَلْقَاهَا إِلَى مَرْيَمَ وَرُوحٌ مِنْهُ وَأَنَّ الْجَنَّةَ حَقٌّ وَأَنَّ النَّارَ حَقٌّ أَدْخَلَهُ اللَّهُ مِنْ أَىِّ أَبْوَابِ الْجَنَّةِ الثَّمَانِيَةِ شَاءَ ‏"', NULL, 'It is narrated on the authority of Ubadah b. Samit that the messenger of Allah (ﷺ) observed:He who said:" There is no god but Allah, He is One and there is no associate with Him, that Muhammad is his servant and His messenger, that Christ is servant and the son of His slave-girl and he (Christ) His word which He communicated to Mary and is His Spirit, that Paradise is a fact and Hell is a fact," Allah would make him (he who affirms these truths enter Paradise through any one of its eight doors which he would like.', NULL, NULL, 'https://sunnah.com/muslim:43', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 44, 'وَحَدَّثَنِي أَحْمَدُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ، حَدَّثَنَا مُبَشِّرُ بْنُ إِسْمَاعِيلَ، عَنِ الأَوْزَاعِيِّ، عَنْ عُمَيْرِ بْنِ هَانِئٍ، فِي هَذَا الإِسْنَادِ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ ‏"‏ أَدْخَلَهُ اللَّهُ الْجَنَّةَ عَلَى مَا كَانَ مِنْ عَمَلٍ ‏"‏ ‏.‏ وَلَمْ يَذْكُرْ ‏"‏ مِنْ أَىِّ أَبْوَابِ الْجَنَّةِ الثَّمَانِيَةِ شَاءَ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Umar b. Hani with the same chain of transmitters with the exception of these words:Allah would make him (he who affirms these truths) enter Paradise through one of the eight doors which he would like.', NULL, NULL, 'https://sunnah.com/muslim:44', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 46, 'حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ الأَزْدِيُّ، حَدَّثَنَا هَمَّامٌ، حَدَّثَنَا قَتَادَةُ، حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ، عَنْ مُعَاذِ بْنِ جَبَلٍ، قَالَ كُنْتُ رِدْفَ النَّبِيِّ صلى الله عليه وسلم لَيْسَ بَيْنِي وَبَيْنَهُ إِلاَّ مُؤْخِرَةُ الرَّحْلِ فَقَالَ ‏"‏ يَا مُعَاذَ بْنَ جَبَلٍ ‏"‏ ‏.‏ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ ‏.‏ ثُمَّ سَارَ سَاعَةً ثُمَّ قَالَ ‏"‏ يَا مُعَاذَ بْنَ جَبَلٍ ‏"‏ ‏.‏ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ ‏.‏ ثُمَّ سَارَ سَاعَةَ ثُمَّ قَالَ ‏"‏ يَا مُعَاذَ بْنَ جَبَلٍ ‏"‏ ‏.‏ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ ‏.‏ قَالَ ‏"‏ هَلْ تَدْرِي مَا حَقُّ اللَّهِ عَلَى الْعِبَادِ ‏"‏ ‏.‏ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ ‏.‏ قَالَ ‏"‏ فَإِنَّ حَقَّ اللَّهِ عَلَى الْعِبَادِ أَنْ يَعْبُدُوهُ وَلاَ يُشْرِكُوا بِهِ شَيْئًا ‏"‏ ‏.‏ ثُمَّ سَارَ سَاعَةً ثُمَّ قَالَ ‏"‏ يَا مُعَاذَ بْنَ جَبَلٍ ‏"‏ ‏.‏ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ ‏.‏ قَالَ ‏"‏ هَلْ تَدْرِي مَا حَقُّ الْعِبَادِ عَلَى اللَّهِ إِذَا فَعَلُوا ذَلِكَ ‏"‏ ‏.‏ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ ‏.‏ قَالَ ‏"‏ أَنْ لاَ يُعَذِّبَهُمْ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Mu''adh b. Jabal:I was riding behind the Prophet (ﷺ) and there was nothing between him and me but the rear part of the saddle, when he said: Mu''adh b. Jabal: To which I replied: At your beck and call, and at your pleasure, Messenger of Allah! He moved along for a few minutes, when again he said: Mu''adh b. Jabal: To which I replied: At your beck and call, and at your pleasure, Messenger of Allah! He then again moved along for a few minutes and said: Mu''adh b. Jabal: To which I replied. At your beck and call, and at your pleasure. Messenger of Allah He, (the Holy Prophet) said: Do you know what right has Allah upon His servants? I said: Allah and His Messenger know best. He (the Holy Prophet) said: Verily the right of Allah over His servants is that they should worship Him, not associating anything with Him. He (the Holy Prophet) with Mu''adh behind him, moved along for a few minutes and said: Mu''adh b. Jabal: To which I replied: At your beck and call, and at your pleasure, Messenger of Allah! He (the Holy Prophet) said: Do you know what rights have servants upon Allah in case they do it (i. e. they worship Allah without associating anything with Him)? I (Mu''adh b. Jabal) replied: Allah and His Messenger know best. (Upon this) he (the Holy Prophet) remarked: That He would not torment them (with the fire of Hell).', 'It is narrated on the authority of Mu''adh b. Jabal', NULL, 'https://sunnah.com/muslim:46', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 47, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو الأَحْوَصِ، سَلاَّمُ بْنُ سُلَيْمٍ عَنْ أَبِي إِسْحَاقَ، عَنْ عَمْرِو بْنِ مَيْمُونٍ، عَنْ مُعَاذِ بْنِ جَبَلٍ، قَالَ كُنْتُ رِدْفَ رَسُولِ اللَّهِ صلى الله عليه وسلم عَلَى حِمَارٍ يُقَالُ لَهُ عُفَيْرٌ قَالَ فَقَالَ ‏"‏ يَا مُعَاذُ تَدْرِي مَا حَقُّ اللَّهِ عَلَى الْعِبَادِ وَمَا حَقُّ الْعِبَادِ عَلَى اللَّهِ ‏"‏ ‏.‏ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ ‏.‏ قَالَ ‏"‏ فَإِنَّ حَقَّ اللَّهِ عَلَى الْعِبَادِ أَنْ يَعْبُدُوا اللَّهَ وَلاَ يُشْرِكُوا بِهِ شَيْئًا وَحَقُّ الْعِبَادِ عَلَى اللَّهِ عَزَّ وَجَلَّ أَنْ لاَ يُعَذِّبَ مَنْ لاَ يُشْرِكُ بِهِ شَيْئًا ‏"‏ ‏.‏ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَفَلاَ أُبَشِّرُ النَّاسَ قَالَ ‏"‏ لاَ تُبَشِّرْهُمْ فَيَتَّكِلُوا ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Mu''adh b. Jabal that he observed:I was riding behind the Messenger of Allah (ﷺ) on an ass known as ''Ufair. He (Mu''adh) observed: He (the Holy Prophet) said: Mu''adh, do you know what right has Allah over His bondsmen and what right have His bondsmen over Him? Mu''adh added: I replied: Allah and his Messenger know best. Upon this he (the Prophet remarked: The right of Allah over His bondsmen is that they should worship Allah and should not associate anything with Him, and the right of His bondsmen over Allah, Glorious and Sublime, is that He does not punish him who associates not anything with Him. He (Mu''adh) added: I said to the Messenger of Allah: Should I then give the tidings to the people? He (the Holy Prophet) said: Do not tell them this good news, for they would trust in it alone.', 'It is narrated on the authority of Mu''adh b. Jabal that he observed', NULL, 'https://sunnah.com/muslim:47', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 48, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، وَابْنُ، بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، عَنْ أَبِي حَصِينٍ، وَالأَشْعَثِ بْنِ سُلَيْمٍ، أَنَّهُمَا سَمِعَا الأَسْوَدَ بْنَ هِلاَلٍ، يُحَدِّثُ عَنْ مُعَاذِ بْنِ جَبَلٍ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ يَا مُعَاذُ أَتَدْرِي مَا حَقُّ اللَّهِ عَلَى الْعِبَادِ ‏"‏ ‏.‏ قَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ ‏.‏ قَالَ ‏"‏ أَنْ يُعْبَدَ اللَّهُ وَلاَ يُشْرَكَ بِهِ شَىْءٌ - قَالَ - أَتَدْرِي مَا حَقُّهُمْ عَلَيْهِ إِذَا فَعَلُوا ذَلِكَ ‏"‏ ‏.‏ فَقَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ ‏.‏ قَالَ ‏"‏ أَنْ لاَ يُعَذِّبَهُمْ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Mu''adh b. Jabal that the Messenger of Allah (ﷺ) said:Mu''adh, do you know the right of Allah over His bondsmen? He (Mu''adh) said: Allah and His Apostle know best. He (the Messenger of Allah) said: That Allah alone should be worshipped and nothing should be associated with Him. He (the Holy Prophet) said: What right have they (bondsmen) upon Him in case they do it? He (Mu''adh) said: Allah and His Apostle know best. He (the Holy Prophet) said: That He would not punish them.', NULL, NULL, 'https://sunnah.com/muslim:48', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 49, '"‏ هَلْ تَدْرِي مَا حَقُّ اللَّهِ عَلَى النَّاسِ ‏"', NULL, 'It is narrated on the authority of Aswad b. Hilal that he heard Mu''adh say this:The Messenger of Allah (ﷺ) called, me and I replied to him. He (the Holy Prophet) said: Do you know the right of Allah upon the people? and then followed the hadith (mentioned above).', 'It is narrated on the authority of Aswad b. Hilal that he heard Mu''adh say this', NULL, 'https://sunnah.com/muslim:49', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 51, '"‏ أَلاَ إِنَّ الإِيمَانَ هَا هُنَا وَإِنَّ الْقَسْوَةَ وَغِلَظَ الْقُلُوبِ فِي الْفَدَّادِينَ عِنْدَ أُصُولِ أَذْنَابِ الإِبِلِ حَيْثُ يَطْلُعُ قَرْنَا الشَّيْطَانِ فِي رَبِيعَةَ وَمُضَرَ ‏"', NULL, 'It is narrated on the authority of Ibn Mas''ud that the Messenger of Allah (may peace and blessings be upon him) pointed towards Yemen with his hand and said:Verily Iman is towards this side, and harshness and callousness of the hearts is found amongst the rude owners of the camels who drive them behind their tails (to the direction) where emerge the two horns of Satan, they are the tribes of Rabi''a and Mudar.', NULL, NULL, 'https://sunnah.com/muslim:51', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 52, 'حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ، حَدَّثَنَا سُلَيْمَانُ، - يَعْنِي ابْنَ الْمُغِيرَةِ - قَالَ حَدَّثَنَا ثَابِتٌ، عَنْ أَنَسِ بْنِ مَالِكٍ، قَالَ حَدَّثَنِي مَحْمُودُ بْنُ الرَّبِيعِ، عَنْ عِتْبَانَ بْنِ مَالِكٍ، قَالَ قَدِمْتُ الْمَدِينَةَ فَلَقِيتُ عِتْبَانَ فَقُلْتُ حَدِيثٌ بَلَغَنِي عَنْكَ قَالَ أَصَابَنِي فِي بَصَرِي بَعْضُ الشَّىْءِ فَبَعَثْتُ إِلَى رَسُولِ اللَّهِ صلى الله عليه وسلم أَنِّي أُحِبُّ أَنْ تَأْتِيَنِي فَتُصَلِّيَ فِي مَنْزِلِي فَأَتَّخِذَهُ مُصَلًّى - قَالَ - فَأَتَى النَّبِيُّ صلى الله عليه وسلم وَمَنْ شَاءَ اللَّهُ مِنْ أَصْحَابِهِ فَدَخَلَ وَهُوَ يُصَلِّي فِي مَنْزِلِي وَأَصْحَابُهُ يَتَحَدَّثُونَ بَيْنَهُمْ ثُمَّ أَسْنَدُوا عُظْمَ ذَلِكَ وَكِبْرَهُ إِلَى مَالِكِ بْنِ دُخْشُمٍ قَالُوا وَدُّوا أَنَّهُ دَعَا عَلَيْهِ فَهَلَكَ وَوَدُّوا أَنَّهُ أَصَابَهُ شَرٌّ ‏.‏ فَقَضَى رَسُولُ اللَّهِ صلى الله عليه وسلم الصَّلاَةَ وَقَالَ ‏"‏ أَلَيْسَ يَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنِّي رَسُولُ اللَّهِ ‏"‏ ‏.‏ قَالُوا إِنَّهُ يَقُولُ ذَلِكَ وَمَا هُوَ فِي قَلْبِهِ ‏.‏ قَالَ ‏"‏ لاَ يَشْهَدُ أَحَدٌ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنِّي رَسُولُ اللَّهِ فَيَدْخُلَ النَّارَ أَوْ تَطْعَمَهُ ‏"‏ ‏.‏ قَالَ أَنَسٌ فَأَعْجَبَنِي هَذَا الْحَدِيثُ فَقُلْتُ لاِبْنِي اكْتُبْهُ فَكَتَبَهُ ‏.‏', NULL, 'It is narrated on the authority of ''Itban b. Malik that he came to Medina and said:Something had gone wrong with my eyesight. I, therefore, sent (a message to the Holy Prophet): Verily it is my ardent desire that you should kindly grace my house with your presence and observe prayer there so, that I should make that corner a place of worship. He said: The Prophet (ﷺ) came there, and those amongst the Companions whom Allah willed also accompanied him. He entered (my place) and offered prayer at my residence and his Companions began to talk amongst themselves (and this conversation centered round hypocrites), and then the conspicuous one, Malik b. Dukhshum was made the target and they wished that he (the Holy Prophet) should curse him and he should die or he should meet some calamity. In the meanwhile the Messenger of Allah (may peace and blessings be upon him) completed his prayer and said: Does Malik b. Dukhshum not testify the fact that there is no god but Allah and verily I am the messenger of Allah. They replied: He makes a profession of it (no doubt) but does not do it out of (sincere) heart. He (the Holy Prophet) said: He who testifies that there is no god but Allah and I am the messenger of Allah would not enter Hell or its (flames) would not consume him. Anas said: This hadith impressed me very much and I told my son to write it down.', NULL, NULL, 'https://sunnah.com/muslim:52', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 53, 'حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ الْعَبْدِيُّ، حَدَّثَنَا بَهْزٌ، حَدَّثَنَا حَمَّادٌ، حَدَّثَنَا ثَابِتٌ، عَنْ أَنَسٍ، قَالَ حَدَّثَنِي عِتْبَانُ بْنُ مَالِكٍ، أَنَّهُ عَمِيَ فَأَرْسَلَ إِلَى رَسُولِ اللَّهِ صلى الله عليه وسلم فَقَالَ تَعَالَ فَخُطَّ لِي مَسْجِدًا ‏.‏ فَجَاءَ رَسُولُ اللَّهِ صلى الله عليه وسلم وَجَاءَ قَوْمُهُ وَنُعِتَ رَجُلٌ مِنْهُمْ يُقَالُ لَهُ مَالِكُ بْنُ الدُّخْشُمِ ‏.‏ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِ سُلَيْمَانَ بْنِ الْمُغِيرَةِ ‏.‏', NULL, 'It is narrated on the authority of Anas that ''Itban b. Malik told him that he became blind. He sent a message to the Messenger of Allah (ﷺ) that he should come and mark a place of worship for him. Thereupon came the Messenger of Allah (ﷺ) and his people and then there was a discussion among them about a man who was known as Malik b. Dukhshum, and subsequently the narrator described the hadith of Sulaiman b. Mughira as stated above.', NULL, NULL, 'https://sunnah.com/muslim:53', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 55, '"‏ الإِيمَانُ بِضْعٌ وَسَبْعُونَ شُعْبَةً وَالْحَيَاءُ شُعْبَةٌ مِنَ الإِيمَانِ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Prophet (ﷺ) said:Iman has over seventy branches, and modesty is a branch of Iman.', 'It is narrated on the authority of Abu Huraira that the Prophet (ﷺ) said', NULL, 'https://sunnah.com/muslim:55', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 56, '"‏ الإِيمَانُ بِضْعٌ وَسَبْعُونَ أَوْ بِضْعٌ وَسِتُّونَ شُعْبَةً فَأَفْضَلُهَا قَوْلُ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَدْنَاهَا إِمَاطَةُ الأَذَى عَنِ الطَّرِيقِ وَالْحَيَاءُ شُعْبَةٌ مِنَ الإِيمَانِ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (may peace and blessings be upon him) said:Faith has over seventy branches or over sixty branches, the most excellent of which is the declaration that there is no god but Allah, and the humblest of which is the, removal of what is injurious from the path: and modesty is a branch of faith.', NULL, NULL, 'https://sunnah.com/muslim:56', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 57, '"‏ الْحَيَاءُ مِنَ الإِيمَانِ ‏"', NULL, 'Salim reported on the authority of his father that the Prophet (may peace and blessings be upon him) heard a man censuring his brother regarding modesty. Upon this the Prophet remarked:Modesty is part of Iman (faith).', NULL, NULL, 'https://sunnah.com/muslim:57', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 58, 'حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، أَخْبَرَنَا مَعْمَرٌ، عَنِ الزُّهْرِيِّ، بِهَذَا الإِسْنَادِ وَقَالَ مَرَّ بِرَجُلٍ مِنَ الأَنْصَارِ يَعِظُ أَخَاهُ ‏.‏', NULL, 'Zuhri has narrated this hadith with the addition of these words:He (the Holy Prophet) happened to pass by a mass of Ansar who was instructing his brother (about modesty).', 'Zuhri has narrated this hadith with the addition of these words', NULL, 'https://sunnah.com/muslim:58', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 59, '"‏ الْحَيَاءُ لاَ يَأْتِي إِلاَّ بِخَيْرٍ ‏"', NULL, 'It is narrated on the authority of ''Imran b. Husain that the Prophet (may peace and blessings be upon him) said:Modesty brings forth nothing but goodness. Bushair b. Ka''b said: It is recorded in the books of wisdom, there lies sobriety in it and calmness of mind in it, Imran said: I am narrating to you the tradition of the Messenger of Allah (may peace and blessings be upon him) and you talk of your books.', NULL, NULL, 'https://sunnah.com/muslim:59', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 60, 'حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ، حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ، عَنْ إِسْحَاقَ، - وَهُوَ ابْنُ سُوَيْدٍ - أَنَّ أَبَا قَتَادَةَ، حَدَّثَ قَالَ كُنَّا عِنْدَ عِمْرَانَ بْنِ حُصَيْنٍ فِي رَهْطٍ مِنَّا وَفِينَا بُشَيْرُ بْنُ كَعْبٍ فَحَدَّثَنَا عِمْرَانُ، يَوْمَئِذٍ قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ الْحَيَاءُ خَيْرٌ كُلُّهُ ‏"‏ ‏.‏ قَالَ أَوْ قَالَ ‏"‏ الْحَيَاءُ كُلُّهُ خَيْرٌ ‏"‏ ‏.‏ فَقَالَ بُشَيْرُ بْنُ كَعْبٍ إِنَّا لَنَجِدُ فِي بَعْضِ الْكُتُبِ أَوِ الْحِكْمَةِ أَنَّ مِنْهُ سَكِينَةً وَوَقَارًا لِلَّهِ وَمِنْهُ ضَعْفٌ ‏.‏ قَالَ فَغَضِبَ عِمْرَانُ حَتَّى احْمَرَّتَا عَيْنَاهُ وَقَالَ أَلاَ أُرَانِي أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ صلى الله عليه وسلم وَتُعَارِضُ فِيهِ ‏.‏ قَالَ فَأَعَادَ عِمْرَانُ الْحَدِيثَ قَالَ فَأَعَادَ بُشَيْرٌ فَغَضِبَ عِمْرَانُ قَالَ فَمَا زِلْنَا نَقُولُ فِيهِ إِنَّهُ مِنَّا يَا أَبَا نُجَيْدٍ إِنَّهُ لاَ بَأْسَ بِهِ ‏.‏', NULL, 'It is narrated on the authority of Qatada. We were sitting with ''Imran b. Husain in a company and Bushair ibn Ka''b was also amongst us. ''Imran narrated to us that on a certain occasion the Messenger of Allah (may peace and blessings be upon him) said:Modesty is a virtue through and through, or said: Modesty is a goodness complete. Upon this Bushair ibn Ka''b said: Verily we find in certain books or books of (wisdom) that it is God-inspired peace of mind or sobriety for the sake of Allah and there is also a weakness in it. Imran was so much enraged that his eyes became red and he said: I am narrating to you the hadith of the Messenger of Allah (ﷺ) and you are contradicting it. He (the narrator) said: Imran reported the hadith, He (the narrator) said: Bushair repeated, (the same thing). Imran was enraged. He (the narrator) said: We asserted: Verily Bushair is one amongst us. Abu Nujaid! There is nothing wrong, with him (Bushair).', NULL, NULL, 'https://sunnah.com/muslim:60', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 61, 'حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ، أَخْبَرَنَا النَّضْرُ، حَدَّثَنَا أَبُو نَعَامَةَ الْعَدَوِيُّ، قَالَ سَمِعْتُ حُجَيْرَ بْنَ الرَّبِيعِ الْعَدَوِيَّ، يَقُولُ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ، عَنِ النَّبِيِّ صلى الله عليه وسلم نَحْوَ حَدِيثِ حَمَّادِ بْنِ زَيْدٍ ‏.‏', NULL, 'Ishaq b. Ibrahim narrates this hadith of the Prophet on the authority of Imran b. Husain, like the one narrated by Hammad b. Zaid.', NULL, NULL, 'https://sunnah.com/muslim:61', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 62, '"‏ لاَ تَرْغَبُوا عَنْ آبَائِكُمْ فَمَنْ رَغِبَ عَنْ أَبِيهِ فَهُوَ كُفْرٌ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (may peace and blessings be upon him) observed:Do not detest your fathers; he who detested his father committed infidelity.', NULL, NULL, 'https://sunnah.com/muslim:62', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 65, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَمُحَمَّدُ بْنُ الْمُثَنَّى، وَابْنُ، بَشَّارٍ جَمِيعًا عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ، عَنْ شُعْبَةَ، ح وَحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ، - وَاللَّفْظُ لَهُ - حَدَّثَنَا أَبِي، حَدَّثَنَا شُعْبَةُ، عَنْ عَلِيِّ بْنِ مُدْرِكٍ، سَمِعَ أَبَا زُرْعَةَ، يُحَدِّثُ عَنْ جَدِّهِ، جَرِيرٍ قَالَ قَالَ لِيَ النَّبِيُّ صلى الله عليه وسلم فِي حَجَّةِ الْوَدَاعِ ‏"‏ اسْتَنْصِتِ النَّاسَ ‏"‏ ‏.‏ ثُمَّ قَالَ ‏"‏ لاَ تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Jarir b. ''Abdullah that the Messenger of Allah (may peace and blessings be upon him) asked him on the occasion of the Farewell Pilgrimage to make the people silent and then said:Do not return to unbelief after me by striking the necks of one another.', NULL, NULL, 'https://sunnah.com/muslim:65', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 66, '"‏ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ ‏"', NULL, 'It is narrated on the authority of Abu Musa Ash''ari:I asked the Messenger of Allah which (attribute) of Islam is more excellent. Upon this he remarked: One in which the Muslims are safe, protected from the tongue and hand of (other Muslims).', 'It is narrated on the authority of Abu Musa Ash''ari', NULL, 'https://sunnah.com/muslim:66', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 67, '"‏ ثَلاَثٌ مَنْ كُنَّ فِيهِ وَجَدَ بِهِنَّ حَلاَوَةَ الإِيمَانِ مَنْ كَانَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَأَنْ يُحِبَّ الْمَرْءَ لاَ يُحِبُّهُ إِلاَّ لِلَّهِ وَأَنْ يَكْرَهَ أَنْ يَعُودَ فِي الْكُفْرِ بَعْدَ أَنْ أَنْقَذَهُ اللَّهُ مِنْهُ كَمَا يَكْرَهُ أَنْ يُقْذَفَ فِي النَّارِ ‏"', NULL, 'It is reported on the authority of Anas that the Prophet of Allah (may peace and blessings be upon him ) said:There are three qualities for which anyone who is characterised by them will relish the sweetness of faith: he to whom Allah and His Messenger are dearer than all else; he who loves a man for Allah''s sake alone; and he who has as great an abhorrence of returning to unbelief after Allah has rescued him from it as he has of being cast into Hell.', NULL, NULL, 'https://sunnah.com/muslim:67', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 68, '"‏ ثَلاَثٌ مَنْ كُنَّ فِيهِ وَجَدَ طَعْمَ الإِيمَانِ مَنْ كَانَ يُحِبُّ الْمَرْءَ لاَ يُحِبُّهُ إِلاَّ لِلَّهِ وَمَنْ كَانَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَمَنْ كَانَ أَنْ يُلْقَى فِي النَّارِ أَحَبَّ إِلَيْهِ مِنْ أَنْ يَرْجِعَ فِي الْكُفْرِ بَعْدَ أَنْ أَنْقَذَهُ اللَّهُ مِنْهُ ‏"', NULL, 'It is reported on the authority of Anas that the Messenger of Allah (ﷺ) said:There are three qualities for which any one who is characterised by them will relish the savour of faith: that he loves man and he does not love him but for Allah''s sake alone; he is to whom Allah and His Messenger are dearer than all else; he who prefers to be thrown into fire than to return to unbelief after Allah has rescued him out of it.', 'It is reported on the authority of Anas that the Messenger of Allah (ﷺ) said', NULL, 'https://sunnah.com/muslim:68', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 69, '"‏ مِنْ أَنْ يَرْجِعَ يَهُودِيًّا أَوْ نَصْرَانِيًّا ‏"', NULL, 'A similar hadith has been reported on the authority of Anas (with another chain of transmitters) with the exception of these words:that he again becomes a Jew or a Christian.', NULL, NULL, 'https://sunnah.com/muslim:69', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 70, '"‏ لاَ يُؤْمِنُ عَبْدٌ - وَفِي حَدِيثِ عَبْدِ الْوَارِثِ الرَّجُلُ - حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ أَهْلِهِ وَمَالِهِ وَالنَّاسِ أَجْمَعِينَ ‏"', NULL, 'It is reported on the authority of Anas that the Messenger of Allah (ﷺ) said:No bondsman believes, and, in the hadith narrated by Abdul Warith, no person believes, till I am dearer to him than the members of his household, his wealth and the whole of mankind.', 'It is reported on the authority of Anas that the Messenger of Allah (ﷺ) said', NULL, 'https://sunnah.com/muslim:70', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 71, '"‏ لاَ يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَلَدِهِ وَوَالِدِهِ وَالنَّاسِ أَجْمَعِينَ ‏"', NULL, 'It is reported on the authority of Anas b. Malik that the Messenger of Allah said:None of you is a believer until I am dearer to him than his child, his father, and the whole of mankind.', NULL, NULL, 'https://sunnah.com/muslim:71', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 72, '"‏ لاَ يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لأَخِيهِ - أَوْ قَالَ لِجَارِهِ - مَا يُحِبُّ لِنَفْسِهِ ‏"', NULL, 'It is narrated on the authority of Anas b. Malik that the Prophet (may peace and blessings be upon him) observed:"None amongst you believes (truly) until he loves for his brother" - or he said "for his neighbour" - "that which he loves for himself."', NULL, NULL, 'https://sunnah.com/muslim:72', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 73, '"‏ وَالَّذِي نَفْسِي بِيَدِهِ لاَ يُؤْمِنُ عَبْدٌ حَتَّى يُحِبَّ لِجَارِهِ - أَوْ قَالَ لأَخِيهِ - مَا يُحِبُّ لِنَفْسِهِ ‏"', NULL, 'It is narrated on the authority of Anas that the Prophet (may peace blessings be upon him) observed:By Him in whose Hand is my life, no, bondsman (truly) believes till he likes for his neighbour, or he (the Holy Prophet) said: for his brother, whatever he likes for himself.', NULL, NULL, 'https://sunnah.com/muslim:73', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 75, '"‏ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيُكْرِمْ جَارَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيُكْرِمْ ضَيْفَهُ ‏"', NULL, 'It is reported on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:He who believes in Allah and the Last Day should either utter good words or better keep silence; and he who believes in Allah and the Last Day should treat his neighbour with kindness and he who believes in Allah and the Last Day should show hospitality to his guest.', NULL, NULL, 'https://sunnah.com/muslim:75', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 76, '"‏ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلاَ يُؤْذِي جَارَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيُكْرِمْ ضَيْفَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَسْكُتْ ‏"', NULL, 'It is reported on the authority of Abu Huraira that the Messenger of Allah (may peace and blessings be upon him) observed:He who believes in Allah and the Last Day does not harm is neighbour, and he who believes in Allah and the Last Day shows hospitality to his guest and he who believes in Allah and the Last Day speaks good or remains silent.', NULL, NULL, 'https://sunnah.com/muslim:76', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 77, '"‏ فَلْيُحْسِنْ إِلَى جَارِهِ ‏"', NULL, 'Another hadith similar to one narrated (above) by Abu Husain is also reported by Abu Huraira with the exception of these words:He (the Prophet) said: He should do good to the neighbour.', NULL, NULL, 'https://sunnah.com/muslim:77', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 78, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا وَكِيعٌ، وَأَبُو مُعَاوِيَةَ عَنِ الأَعْمَشِ، ح وَحَدَّثَنَا يَحْيَى بْنُ يَحْيَى، - وَاللَّفْظُ لَهُ - أَخْبَرَنَا أَبُو مُعَاوِيَةَ، عَنِ الأَعْمَشِ، عَنْ عَدِيِّ بْنِ ثَابِتٍ، عَنْ زِرٍّ، قَالَ قَالَ عَلِيٌّ وَالَّذِي فَلَقَ الْحَبَّةَ وَبَرَأَ النَّسَمَةَ إِنَّهُ لَعَهْدُ النَّبِيِّ الأُمِّيِّ صلى الله عليه وسلم إِلَىَّ أَنْ لاَ يُحِبَّنِي إِلاَّ مُؤْمِنٌ وَلاَ يُبْغِضَنِي إِلاَّ مُنَافِقٌ ‏.‏', NULL, 'Zirr reported:''Ali observed: By Him Who split up the seed and created something living, the Apostle (may peace and blessings be upon him) gave me a promise that no one but a believer would love me, and none but a hypocrite would nurse grudge against me.', 'Zirr reported', NULL, 'https://sunnah.com/muslim:78', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 79, '"‏ مَنْ رَأَى مِنْكُمْ مُنْكَرًا فَلْيُغَيِّرْهُ بِيَدِهِ فَإِنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ فَإِنْ لَمْ يَسْتَطِعْ فَبِقَلْبِهِ وَذَلِكَ أَضْعَفُ الإِيمَانِ ‏"', NULL, 'It is narrated on the authority of Tariq b. Shihab:It was Marwan who initiated (the practice) of delivering khutbah (address) before the prayer on the ''Id day. A man stood up and said: Prayer should precede khutbah. He (Marwan) remarked, This (practice) has been done away with. Upon this Abu Sa''id remarked: This man has performed (his duty) laid on him. I heard the Messenger of Allah as saying: He who amongst you sees something abominable should modify it with the help of his hand; and if he has not strength enough to do it, then he should do it with his tongue, and if he has not strength enough to do it, (even) then he should (abhor it) from his heart, and that is the least of faith.', 'It is narrated on the authority of Tariq b. Shihab', NULL, 'https://sunnah.com/muslim:79', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 80, 'حَدَّثَنَا أَبُو كُرَيْبٍ، مُحَمَّدُ بْنُ الْعَلاَءِ حَدَّثَنَا أَبُو مُعَاوِيَةَ، حَدَّثَنَا الأَعْمَشُ، عَنْ إِسْمَاعِيلَ بْنِ رَجَاءٍ، عَنْ أَبِيهِ، عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ، وَعَنْ قَيْسِ بْنِ مُسْلِمٍ، عَنْ طَارِقِ بْنِ شِهَابٍ، عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ، فِي قِصَّةِ مَرْوَانَ وَحَدِيثِ أَبِي سَعِيدٍ عَنِ النَّبِيِّ صلى الله عليه وسلم بِمِثْلِ حَدِيثِ شُعْبَةَ وَسُفْيَانَ ‏.‏', NULL, 'The same hadith of the Prophet (may peace and blessings be upon him) has been reported by Abu Sa''id al-Khudri in connection with the story of Marwan.', NULL, NULL, 'https://sunnah.com/muslim:80', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 81, '"‏ مَا مِنْ نَبِيٍّ بَعَثَهُ اللَّهُ فِي أُمَّةٍ قَبْلِي إِلاَّ كَانَ لَهُ مِنْ أُمَّتِهِ حَوَارِيُّونَ وَأَصْحَابٌ يَأْخُذُونَ بِسُنَّتِهِ وَيَقْتَدُونَ بِأَمْرِهِ ثُمَّ إِنَّهَا تَخْلُفُ مِنْ بَعْدِهِمْ خُلُوفٌ يَقُولُونَ مَا لاَ يَفْعَلُونَ وَيَفْعَلُونَ مَا لاَ يُؤْمَرُونَ فَمَنْ جَاهَدَهُمْ بِيَدِهِ فَهُوَ مُؤْمِنٌ وَمَنْ جَاهَدَهُمْ بِلِسَانِهِ فَهُوَ مُؤْمِنٌ وَمَنْ جَاهَدَهُمْ بِقَلْبِهِ فَهُوَ مُؤْمِنٌ وَلَيْسَ وَرَاءَ ذَلِكَ مِنَ الإِيمَانِ حَبَّةُ خَرْدَلٍ ‏"', NULL, 'It is narrated on the authority ''Abdullah b. Mas''ud that the Messenger of Allah (may peace and blessings be upon him) observed:Never a Prophet had been sent before me by Allah towards his nation who had not among his people (his) disciples and companions who followed his ways and obeyed his command. Then there came after them their successors who said whatever they did not practise, and practised whatever they were not commanded to do. He who strove against them with his hand was a believer: he who strove against them with his tongue was a believer, and he who strove against them with his heart was a believer and beyond that there is no faith even to the extent of a mustard seed. Abu Rafi'' said: I narrated this hadith to ''Abdullah b. ''Umar; he contradicted me. There happened to come ''Abdullah b. Mas''ud who stayed at Qanat, and ''Abdullah b ''Umar wanted me to accompany him for visiting him (as ''Abdullah b. Mas''ud was ailing), so I went along with him and as we sat (before him) I asked Ibn Mas''ud about this hadith. He narrated it in the same way as I narrated it to Ibn ''Umar.', NULL, NULL, 'https://sunnah.com/muslim:81', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 82, '"‏ مَا كَانَ مِنْ نَبِيٍّ إِلاَّ وَقَدْ كَانَ لَهُ حَوَارِيُّونَ يَهْتَدُونَ بِهَدْيِهِ وَيَسْتَنُّونَ بِسُنَّتِهِ ‏"', NULL, 'The same hadith has been transmitted by another chain of narrators on the authority of ''Abdullah b. Mas''ud who observed:Never was there one among the prophets who had had not disciples who followed his direction and followed his ways. The remaining part of the hadith is like that as narrated by Salih but the arrival of Ibn Mas''ud and the meeting of Ibn ''Umar with him is not mentioned.', NULL, NULL, 'https://sunnah.com/muslim:82', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 83, 'وَحَدَّثَنَا مَنْصُورُ بْنُ أَبِي مُزَاحِمٍ، حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ، ح وَحَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرِ بْنِ زِيَادٍ، أَخْبَرَنَا إِبْرَاهِيمُ، - يَعْنِي ابْنَ سَعْدٍ - عَنِ ابْنِ شِهَابٍ، عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ، عَنْ أَبِي هُرَيْرَةَ، قَالَ سُئِلَ رَسُولُ اللَّهِ صلى الله عليه وسلم أَىُّ الأَعْمَالِ أَفْضَلُ قَالَ ‏"‏ إِيمَانٌ بِاللَّهِ ‏"‏ ‏.‏ قَالَ ثُمَّ مَاذَا قَالَ ‏"‏ الْجِهَادُ فِي سَبِيلِ اللَّهِ ‏"‏ ‏.‏ قَالَ ثُمَّ مَاذَا قَالَ ‏"‏ حَجٌّ مَبْرُورٌ ‏"‏ ‏.‏ وَفِي رِوَايَةِ مُحَمَّدِ بْنِ جَعْفَرٍ قَالَ ‏"‏ إِيمَانٌ بِاللَّهِ وَرَسُولِهِ ‏"‏ ‏.‏
وَحَدَّثَنِيهِ مُحَمَّدُ بْنُ رَافِعٍ، وَعَبْدُ بْنُ حُمَيْدٍ، عَنْ عَبْدِ الرَّزَّاقِ، أَخْبَرَنَا مَعْمَرٌ، عَنِ الزُّهْرِيِّ، بِهَذَا الإِسْنَادِ مِثْلَهُ ‏.‏', NULL, 'Abu Huraira reported:The Messenger of Allah was asked about the best of deeds. He observed: Belief in Allah. He (the inquirer) said: What next? He (the Holy Prophet) replied: Jihad (struggle to the utmost) in the cause of Allah. He (the inquirer) again said: What next? He (the Holy Prophet) replied: Pilgrimage accepted into the grace of the Lord. In the. tradition narrated on the authority of Muhammad b. Ja''far (the words are) that he (the Holy Prophet) said: Belief in Allah and His Messenger. Muhammad b. Rafi and ''Abd b. Humaid, ''Abdur-Razzaq and Ma''mar and Zuhri have narrated a hadith like this on the authority of the same chain of transmitters.', 'Abu Huraira reported', NULL, 'https://sunnah.com/muslim:83', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 84, '"‏ جَاءَ أَهْلُ الْيَمَنِ هُمْ أَرَقُّ أَفْئِدَةً الإِيمَانُ يَمَانٍ وَالْفِقْهُ يَمَانٍ وَالْحِكْمَةُ يَمَانِيَةٌ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah observed:There have come the people of Yemen; they are tender of hearts, the belief is that of the Yemenites, the understanding (of the faith) is that of the Yemenites and sagacity is that of the Yemenites.', NULL, NULL, 'https://sunnah.com/muslim:84', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 85, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ، ح وَحَدَّثَنِي عَمْرٌو النَّاقِدُ، حَدَّثَنَا إِسْحَاقُ بْنُ يُوسُفَ الأَزْرَقُ، كِلاَهُمَا عَنِ ابْنِ عَوْنٍ، عَنْ مُحَمَّدٍ، عَنْ أَبِي هُرَيْرَةَ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم بِمِثْلِهِ ‏.‏', NULL, 'Abu Huraira reported the same hadith which is transmitted to us by another chain of transmitters, e. g. Muhammad b. al-Muthanna, Ishaq b. Yusuf Azraq, Ibn ''Aun, etc.', NULL, NULL, 'https://sunnah.com/muslim:85', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 86, '"‏ أَتَاكُمْ أَهْلُ الْيَمَنِ هُمْ أَضْعَفُ قُلُوبًا وَأَرَقُّ أَفْئِدَةً الْفِقْهُ يَمَانٍ وَالْحِكْمَةُ يَمَانِيَةٌ ‏"', NULL, 'Abu Huraira reported:The Messenger of Allah (may peace and blessings be upon him) observed: There came to you the people from Yemen; they are tender of hearts and mild of feelings, the understanding is Yemenite, the sagacity is Yemenite.', 'Abu Huraira reported', NULL, 'https://sunnah.com/muslim:86', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 87, '"‏ رَأْسُ الْكُفْرِ نَحْوَ الْمَشْرِقِ وَالْفَخْرُ وَالْخُيَلاَءُ فِي أَهْلِ الْخَيْلِ وَالإِبِلِ الْفَدَّادِينَ أَهْلِ الْوَبَرِ وَالسَّكِينَةُ فِي أَهْلِ الْغَنَمِ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (may peace and blessings be upon him) remarked:The summit of unbelief is towards the East and the pride and conceitedness is found among the owners of horses and camels who are rude and uncivil, people of the tents, and tranquillity is found among those who rear goats and sheep.', NULL, NULL, 'https://sunnah.com/muslim:87', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 88, '"‏ الإِيمَانُ يَمَانٍ وَالْكُفْرُ قِبَلَ الْمَشْرِقِ وَالسَّكِينَةُ فِي أَهْلِ الْغَنَمِ وَالْفَخْرُ وَالرِّيَاءُ فِي الْفَدَّادِينَ أَهْلِ الْخَيْلِ وَالْوَبَرِ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (may peace and blessings be upon him) observed:The belief is among the Yemenites, and the unbelief is towards the East, and tranquillity is among those who rear goats and sheep, and pride and simulation is among the uncivil and rude owners of horses and camels.', NULL, NULL, 'https://sunnah.com/muslim:88', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 89, '"‏ الْفَخْرُ وَالْخُيَلاَءُ فِي الْفَدَّادِينَ أَهْلِ الْوَبَرِ وَالسَّكِينَةُ فِي أَهْلِ الْغَنَمِ ‏"', NULL, 'It is reported on the authority of Abu Huraira:I heard the Messenger of Allah saying this: Pride and conceitedness is found among the uncivil owners of the camels and tranquillity is found among the owners of sheep and goats.', 'It is reported on the authority of Abu Huraira', NULL, 'https://sunnah.com/muslim:89', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 90, '"‏ الإِيمَانُ يَمَانٍ وَالْحِكْمَةُ يَمَانِيَةٌ ‏"', NULL, 'The same hadith has been narrated by Zuhri with the same chain of authorities with the addition:The belief is among the Yemenites, the sagacity is that of the Yemenites.', NULL, NULL, 'https://sunnah.com/muslim:90', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 91, '"‏ جَاءَ أَهْلُ الْيَمَنِ هُمْ أَرَقُّ أَفْئِدَةً وَأَضْعَفُ قُلُوبًا الإِيمَانُ يَمَانٍ وَالْحِكْمَةُ يَمَانِيَةٌ السَّكِينَةُ فِي أَهْلِ الْغَنَمِ وَالْفَخْرُ وَالْخُيَلاَءُ فِي الْفَدَّادِينَ أَهْلِ الْوَبَرِ قِبَلَ مَطْلِعِ الشَّمْسِ ‏"', NULL, 'Abu Huraira said:I heard the Prophet (may peace and blessings be upon him) saying: There came the people of Yemen, they are tender of feelings and meek of hearts. The belief is that of the Yemenites, the sagacity is that of the Yemenites, the tranquillity is among the owners of goats and sheep, and pride and conceitedness is among the uncivil owners of the camels, the people of the tents in the direction of sunrise.', 'Abu Huraira said', NULL, 'https://sunnah.com/muslim:91', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 92, '"‏ أَتَاكُمْ أَهْلُ الْيَمَنِ هُمْ أَلْيَنُ قُلُوبًا وَأَرَقُّ أَفْئِدَةً الإِيمَانُ يَمَانٍ وَالْحِكْمَةُ يَمَانِيَةٌ رَأْسُ الْكُفْرِ قِبَلَ الْمَشْرِقِ ‏"', NULL, 'It is reporter on the authority of Abu Huraira that the Messenger of Allah (may peace and blessings be upon him) observed:There came the people of Yemen who are soft of hearts, tender in feelings: the belief is that of the Yemenites, the sagacity is that of the Yemenites and the summit of unbelief is towards the East.', NULL, NULL, 'https://sunnah.com/muslim:92', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 93, '"‏ رَأْسُ الْكُفْرِ قِبَلَ الْمَشْرِقِ ‏"', NULL, 'Qutaiba b. Sa''id and Zubair b. Harb say:Jarir narrated this on the authority of A''mash with the same chain of narrators (as mentioned above).', 'Qutaiba b. Sa''id and Zubair b. Harb say', NULL, 'https://sunnah.com/muslim:93', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 94, '"‏ وَالْفَخْرُ وَالْخُيَلاَءُ فِي أَصْحَابِ الإِبِلِ وَالسَّكِينَةُ وَالْوَقَارُ فِي أَصْحَابِ الشَّاءِ ‏"', NULL, 'Shu''ba narrated the hadith as reported by Jarir with the same chain of narrators with this addition:Pride and conceitedness is among the owners of the camels and tranquillity and sobriety is found amongst the owners of sheep.', NULL, NULL, 'https://sunnah.com/muslim:94', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 96, '"‏ لاَ تَدْخُلُونَ الْجَنَّةَ حَتَّى تُؤْمِنُوا وَلاَ تُؤْمِنُوا حَتَّى تَحَابُّوا ‏.‏ أَوَلاَ أَدُلُّكُمْ عَلَى شَىْءٍ إِذَا فَعَلْتُمُوهُ تَحَابَبْتُمْ أَفْشُوا السَّلاَمَ بَيْنَكُمْ ‏"', NULL, 'Abu Huraira reported:The Messenger of Allah (may peace and blessing be upon him) observed: You shall not enter Paradise so long as you do not affirm belief (in all those things which are the articles of faith) and you will not believe as long as you do not love one another. Should I not direct you to a thing which, if you do, will foster love amongst you: (i. e.) give currency to (the practice of paying salutation to one another by saying) as-salamu alaikum.', 'Abu Huraira reported', NULL, 'https://sunnah.com/muslim:96', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 97, '"‏ وَالَّذِي نَفْسِي بِيَدِهِ لاَ تَدْخُلُونَ الْجَنَّةَ حَتَّى تُؤْمِنُوا ‏"', NULL, 'Zuhair b. Harb said:Jarir reported on the authority of A''mash with this chain of transmitters that the Messenger of Allah (ﷺ) observed: By him in Whose hand is my life, you shall not enter Paradise unless you believe. The rest of the hadith is the same as narrated by Abd Mu''awiya and Waki''.', 'Zuhair b. Harb said', NULL, 'https://sunnah.com/muslim:97', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 98, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ الْمَكِّيُّ، حَدَّثَنَا سُفْيَانُ، قَالَ قُلْتُ لِسُهَيْلٍ إِنَّ عَمْرًا حَدَّثَنَا عَنِ الْقَعْقَاعِ، عَنْ أَبِيكَ، قَالَ وَرَجَوْتُ أَنْ يُسْقِطَ، عَنِّي رَجُلاً قَالَ فَقَالَ سَمِعْتُهُ مِنَ الَّذِي سَمِعَهُ مِنْهُ أَبِي كَانَ صَدِيقًا لَهُ بِالشَّامِ ثُمَّ حَدَّثَنَا سُفْيَانُ عَنْ سُهَيْلٍ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ تَمِيمٍ الدَّارِيِّ أَنَّ النَّبِيَّ صلى الله عليه وسلم قَالَ ‏"‏ الدِّينُ النَّصِيحَةُ ‏"‏ قُلْنَا لِمَنْ قَالَ ‏"‏ لِلَّهِ وَلِكِتَابِهِ وَلِرَسُولِهِ وَلأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Tamim ad-Dari that the Prophet (ﷺ) said:"The Religion is sincerity." We said, "To whom?" He said "To Allah, to His Book, To His Messenger, and to the leaders of the Muslims and their masses."', 'It is narrated on the authority of Tamim ad-Dari that the Prophet (ﷺ) said', NULL, 'https://sunnah.com/muslim:98', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 99, 'حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ، حَدَّثَنَا ابْنُ مَهْدِيٍّ، حَدَّثَنَا سُفْيَانُ، عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ، عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ، عَنْ تَمِيمٍ الدَّارِيِّ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِمِثْلِهِ ‏.‏', NULL, 'Muhammad b. Hatim and others narrate the same hadith of the Apostle (may peace and blessings be upon him) on the authority of Tamim ad-Dari.', NULL, NULL, 'https://sunnah.com/muslim:99', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 100, 'وَحَدَّثَنِي أُمَيَّةُ بْنُ بِسْطَامَ، حَدَّثَنَا يَزِيدُ، - يَعْنِي ابْنَ زُرَيْعٍ - حَدَّثَنَا رَوْحٌ، - وَهُوَ ابْنُ الْقَاسِمِ - حَدَّثَنَا سُهَيْلٌ، عَنْ عَطَاءِ بْنِ يَزِيدَ، سَمِعَهُ وَهُوَ، يُحَدِّثُ أَبَا صَالِحٍ عَنْ تَمِيمٍ الدَّارِيِّ، عَنْ رَسُولِ اللَّهِ صلى الله عليه وسلم بِمِثْلِهِ ‏.‏', NULL, 'Umayya b. Bistam narrates the same hadith of the Messenger of Allah (may peace and blessings be upon him) on the authority of Tamim ad-Dari.', NULL, NULL, 'https://sunnah.com/muslim:100', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 101, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ، وَأَبُو أُسَامَةَ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ، عَنْ قَيْسٍ، عَنْ جَرِيرٍ، قَالَ بَايَعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم عَلَى إِقَامِ الصَّلاَةِ وَإِيتَاءِ الزَّكَاةِ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ ‏.‏', NULL, 'It is narrated on the authority of Jarir that he observed I gave pledge of allegiance to the Messenger of Allah (may peace and blessings be upon him) on the observance of prayer, payment of Zakat, and sincerity and well-wishing for every Muslim.', NULL, NULL, 'https://sunnah.com/muslim:101', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 102, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَزُهَيْرُ بْنُ حَرْبٍ، وَابْنُ، نُمَيْرٍ قَالُوا حَدَّثَنَا سُفْيَانُ، عَنْ زِيَادِ بْنِ عِلاَقَةَ، سَمِعَ جَرِيرَ بْنَ عَبْدِ اللَّهِ، يَقُولُ بَايَعْتُ النَّبِيَّ صلى الله عليه وسلم عَلَى النُّصْحِ لِكُلِّ مُسْلِمٍ ‏.‏', NULL, 'Sufyan narrated on the authority of Ziyad b. ''Ilaqa that he heard Jarir b. ''Abdullah saying:I pledged allegiance to the Messenger of Allah may peace and blessings be upon him) on sincerity and well-wishing for every Muslim.', NULL, NULL, 'https://sunnah.com/muslim:102', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 103, '"‏ فِيمَا اسْتَطَعْتَ ‏"', NULL, 'It is narrated on the authority of Jarir that he observed:I owed allegiance to the Messenger of Allah (may peace and blessings be upon him) on hearing ( is commands) and obeying (them) and the Prophet) instructed me (to act) as lay in my power, and sincerity and goodwill for every Muslim.', 'It is narrated on the authority of Jarir that he observed', NULL, 'https://sunnah.com/muslim:103', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 104, 'حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ عِمْرَانَ التُّجِيبِيُّ، أَنْبَأَنَا ابْنُ وَهْبٍ، قَالَ أَخْبَرَنِي يُونُسُ، عَنِ ابْنِ شِهَابٍ، قَالَ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ، وَسَعِيدَ بْنَ الْمُسَيَّبِ، يَقُولاَنِ قَالَ أَبُو هُرَيْرَةَ إِنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ لاَ يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلاَ يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلاَ يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ ‏"‏ ‏.‏ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا بَكْرٍ كَانَ يُحَدِّثُهُمْ هَؤُلاَءِ عَنْ أَبِي هُرَيْرَةَ ثُمَّ يَقُولُ وَكَانَ أَبُو هُرَيْرَةَ يُلْحِقُ مَعَهُنَّ ‏"‏ وَلاَ يَنْتَهِبُ نُهْبَةً ذَاتَ شَرَفٍ يَرْفَعُ النَّاسُ إِلَيْهِ فِيهَا أَبْصَارَهُمْ حِينَ يَنْتَهِبُهَا وَهُوَ مُؤْمِنٌ ‏"‏ ‏.‏', NULL, 'Abu Huraira reported that the Messenger of Allah observed:The fornicator who fornicates is not a believer so long as he commits it and no thief who steals is a believer as long as he commits theft, and no drunkard who drinks wine is a believer as long as he drinks it. ''Abdul-Malik b. Abi Bakr'' narrated this on the authority of Abu Bakr b. Abdur-Rahman b. Harith and then said: Abu Huraira made this addition: No plunderer who plunders a valuable thing that attracts the attention of people is a believer so long as he commits this act.', 'Abu Huraira reported that the Messenger of Allah observed', NULL, 'https://sunnah.com/muslim:104', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 105, '"‏ لاَ يَزْنِي الزَّانِي ‏"', NULL, '''Abdul-Malik b. Shu''aib narrated this hadith on the authority of Abu Huraira that he observed:The Messenger of Allah said that a fornicator does not fornicate, and then narrated the hadith like this, and he also made mention of plundering too, but did not mention of a thin having value. Ibn Shihab said: Sa''id b. al-Musayyib and Abu Salama narrated this hadith on the authority of Abu Huraira a hadith like that of Abu Bakr with the exception of (the mention) of plundering.', NULL, NULL, 'https://sunnah.com/muslim:105', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 106, 'وَحَدَّثَنِي مُحَمَّدُ بْنُ مِهْرَانَ الرَّازِيُّ، قَالَ أَخْبَرَنِي عِيسَى بْنُ يُونُسَ، حَدَّثَنَا الأَوْزَاعِيُّ، عَنِ الزُّهْرِيِّ، عَنِ ابْنِ الْمُسَيَّبِ، وَأَبِي، سَلَمَةَ وَأَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِمِثْلِ حَدِيثِ عُقَيْلٍ عَنِ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ وَذَكَرَ النُّهْبَةَ وَلَمْ يَقُلْ ذَاتَ شَرَفٍ ‏.‏', NULL, 'Muhammad b. Mihran narrates this hadith on the authority of Abu Huraira and made mention of plundering but did not talk of (a thing) having value.', NULL, NULL, 'https://sunnah.com/muslim:106', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 107, 'وَحَدَّثَنِي حَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ، حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ، حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُطَّلِبِ، عَنْ صَفْوَانَ بْنِ سُلَيْمٍ، عَنْ عَطَاءِ بْنِ يَسَارٍ، مَوْلَى مَيْمُونَةَ وَحُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم ح
وَحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، أَخْبَرَنَا مَعْمَرٌ، عَنْ هَمَّامِ بْنِ مُنَبِّهٍ، عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم ‏.‏', NULL, 'Imam Muslim has reported this hadith by Hasan b. ''Ali al-Halwani and other traditions.', NULL, NULL, 'https://sunnah.com/muslim:107', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 108, 'حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ، حَدَّثَنَا عَبْدُ الْعَزِيزِ، - يَعْنِي الدَّرَاوَرْدِيَّ - عَنِ الْعَلاَءِ بْنِ عَبْدِ الرَّحْمَنِ، عَنْ أَبِيهِ، عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم كُلُّ هَؤُلاَءِ بِمِثْلِ حَدِيثِ الزُّهْرِيِّ غَيْرَ أَنَّ الْعَلاَءَ وَصَفْوَانَ بْنَ سُلَيْمٍ لَيْسَ فِي حَدِيثِهِمَا ‏"‏ يَرْفَعُ النَّاسُ إِلَيْهِ فِيهَا أَبْصَارَهُمْ ‏"‏ ‏.‏ وَفِي حَدِيثِ هَمَّامٍ ‏"‏ يَرْفَعُ إِلَيْهِ الْمُؤْمِنُونَ أَعْيُنَهُمْ فِيهَا وَهُوَ حِينَ يَنْتَهِبُهَا مُؤْمِنٌ ‏"‏ ‏.‏ وَزَادَ ‏"‏ وَلاَ يَغُلُّ أَحَدُكُمْ حِينَ يَغُلُّ وَهُوَ مُؤْمِنٌ فَإِيَّاكُمْ إِيَّاكُمْ ‏"‏ ‏.‏', NULL, 'It is reported on the authority of Qutaiba b. Sa''id who reported on the authority of Abu Huraira the hadith like that narrated from Zuhri with this exception that in the hadith narrated by ''Ala '' and Safwan b. Sulaim there is no mention of:People raise there eyes towards him, and in the hadith narrated by Hammam: The believers raise their eyes towards him, and such like words, so long as he plunders (is not) a believer, and these words were added: And no exploiter who makes an exploitation is a believer as long as he exploits It; therefore avoid and shun (these evils).', NULL, NULL, 'https://sunnah.com/muslim:108', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 109, '"‏ لاَ يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلاَ يَسْرِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلاَ يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَالتَّوْبَةُ مَعْرُوضَةٌ بَعْدُ ‏"', NULL, 'It is narrated on the authority of Abu Huraira:A fornicator who fornicates is not a believer as long as he commits fornication, and no one who steals is a believer as long as he commits theft, and no one who drinks wine is a believer as long as he drinks it, and repentance may be accepted after that.', 'It is narrated on the authority of Abu Huraira', NULL, 'https://sunnah.com/muslim:109', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 110, '"‏ لاَ يَزْنِي الزَّانِي ‏"', NULL, 'Muhammad b. Rafi'', Abdur-Razzaq, Sufyan, A''mash narrated this hadith like one narrated by Shu''ba, on the authority of Abu Huraira tracing, it (right to the Holy Prophet).', NULL, NULL, 'https://sunnah.com/muslim:110', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 111, 'وَحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ، وَعَبْدُ بْنُ حُمَيْدٍ، جَمِيعًا عَنْ عَبْدِ الرَّزَّاقِ، - قَالَ ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ، - أَخْبَرَنَا مَعْمَرٌ، عَنِ الزُّهْرِيِّ، عَنِ ابْنِ الْمُسَيَّبِ، عَنْ أَبِي هُرَيْرَةَ، قَالَ شَهِدْنَا مَعَ رَسُولِ اللَّهِ صلى الله عليه وسلم حُنَيْنًا فَقَالَ لِرَجُلٍ مِمَّنْ يُدْعَى بِالإِسْلاَمِ ‏"‏ هَذَا مِنْ أَهْلِ النَّارِ ‏"‏ فَلَمَّا حَضَرْنَا الْقِتَالَ قَاتَلَ الرَّجُلُ قِتَالاً شَدِيدًا فَأَصَابَتْهُ جِرَاحَةٌ فَقِيلَ يَا رَسُولَ اللَّهِ الرَّجُلُ الَّذِي قُلْتَ لَهُ آنِفًا ‏"‏ إِنَّهُ مِنْ أَهْلِ النَّارِ ‏"‏ فَإِنَّهُ قَاتَلَ الْيَوْمَ قِتَالاً شَدِيدًا وَقَدْ مَاتَ ‏.‏ فَقَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ إِلَى النَّارِ ‏"‏ فَكَادَ بَعْضُ الْمُسْلِمِينَ أَنْ يَرْتَابَ فَبَيْنَمَا هُمْ عَلَى ذَلِكَ إِذْ قِيلَ إِنَّهُ لَمْ يَمُتْ وَلَكِنَّ بِهِ جِرَاحًا شَدِيدًا فَلَمَّا كَانَ مِنَ اللَّيْلِ لَمْ يَصْبِرْ عَلَى الْجِرَاحِ فَقَتَلَ نَفْسَهُ فَأُخْبِرَ النَّبِيُّ صلى الله عليه وسلم بِذَلِكَ فَقَالَ ‏"‏ اللَّهُ أَكْبَرُ أَشْهَدُ أَنِّي عَبْدُ اللَّهِ وَرَسُولُهُ ‏"‏ ‏.‏ ثُمَّ أَمَرَ بِلاَلاً فَنَادَى فِي النَّاسِ ‏"‏ إِنَّهُ لاَ يَدْخُلُ الْجَنَّةَ إِلاَّ نَفْسٌ مُسْلِمَةٌ وَإِنَّ اللَّهَ يُؤَيِّدُ هَذَا الدِّينَ بِالرَّجُلِ الْفَاجِرِ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Abu Huraira:We participated in the Battle of Hunain along with the Messenger of Allah (ﷺ). He (the Holy Prophet) said about a man who claimed to be a Muslim that he was one of the denizens of the Fire (of Hell). When we were in the thick of the battle that man fought desperately and was wounded. It was said: Messenger of Allah, the person whom you at first called as the denizen of Fire fought desperately and died. Upon this the Messenger of Allah (ﷺ) remarked: He was doomed to the Fire (of Hell). Some men were on the verge of doubt (about his fate) when it was said that he was not dead but fatally wounded. When it was night he could not stand the (pain of his) wound and killed himself. The Apostle (ﷺ) was informed of that. He (the Holy Prophet) observed: Allah is Great, I bear testimony to the fact that I am the servant of Allah and His messenger. He then commanded Bilal to announce to the people that none but a Muslim would enter Paradise. Verily Allah helps this faith even by a sinful person.', 'It is narrated on the authority of Abu Huraira', NULL, 'https://sunnah.com/muslim:111', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 112, '"‏ آيَةُ الْمُنَافِقِ ثَلاَثٌ إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ وَإِذَا ائْتُمِنَ خَانَ ‏"', NULL, 'It is reported on the authority of Abu Huraira that the Messenger of Allah (may peace and blessings be upon him) said:Three are the signs of a hypocrite: when he spoke he told a lie, when he made a promise he acted treacherously against it, when he was trusted he betrayed.', NULL, NULL, 'https://sunnah.com/muslim:112', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 113, '"‏ مِنْ عَلاَمَاتِ الْمُنَافِقِ ثَلاَثَةٌ إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ وَإِذَا ائْتُمِنَ خَانَ ‏"', NULL, 'Abu Huraira reported that the Messenger of Allah (may peace and blessings be upon him) observed:There are three characteristics of a hypocrite: when he spoke he told a lie, when he made promise he acted treacherously, and when he was trusted he betrayed.', NULL, NULL, 'https://sunnah.com/muslim:113', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 114, '"‏ آيَةُ الْمُنَافِقِ ثَلاَثٌ وَإِنْ صَامَ وَصَلَّى وَزَعَمَ أَنَّهُ مُسْلِمٌ ‏"', NULL, '''Uqba b. Mukarram al-''Ami reported that he heard ''Ala'' b. ''Abdur-Rahman narrating this hadith with this chain of transmitters and he said:Three are the signs of a hypocrite, even if he observed fast and prayed and asserted that he was a Muslim.', NULL, NULL, 'https://sunnah.com/muslim:114', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 115, '"‏ وَإِنْ صَامَ وَصَلَّى وَزَعَمَ أَنَّهُ مُسْلِمٌ ‏"', NULL, 'It is reported on the authority of Abu Huraira that the Messenger of Allah (may peace and blessings of Allah be upon him) made observations like them embodied in the hadith narrated by Yahya b. Muhammad on the authority of ''Ala'', and added to it:even if he observed fast and prayed and asserted that he was a Muslim.', NULL, NULL, 'https://sunnah.com/muslim:115', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 116, '"‏ إِذَا كَفَّرَ الرَّجُلُ أَخَاهُ فَقَدْ بَاءَ بِهَا أَحَدُهُمَا ‏"', NULL, 'It is reported on the authority of Ibn ''Umar that the Apostle (may peace and blessings be upon him) observed:When a man calls his brother an unbeliever, it returns (at least) to one of them.', NULL, NULL, 'https://sunnah.com/muslim:116', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 117, '"‏ أَيُّمَا امْرِئٍ قَالَ لأَخِيهِ يَا كَافِرُ ‏.‏ فَقَدْ بَاءَ بِهَا أَحَدُهُمَا إِنْ كَانَ كَمَا قَالَ وَإِلاَّ رَجَعَتْ عَلَيْهِ ‏"', NULL, 'It is reported on the authority of Ibn ''Umar that the Messenger of Allah (may peace and blessings be upon him) said:Any person who called his brother: "O unbeliever" (has in fact done an act by which this unbelief) would return to one of them. If it were so, as he asserted (then the unbelief of man was confirmed but if it was not true), then it returned to him (to the man who labeled it on his brother Muslim).', NULL, NULL, 'https://sunnah.com/muslim:117', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 118, '"‏ بَادِرُوا بِالأَعْمَالِ فِتَنًا كَقِطَعِ اللَّيْلِ الْمُظْلِمِ يُصْبِحُ الرَّجُلُ مُؤْمِنًا وَيُمْسِي كَافِرًا أَوْ يُمْسِي مُؤْمِنًا وَيُصْبِحُ كَافِرًا يَبِيعُ دِينَهُ بِعَرَضٍ مِنَ الدُّنْيَا ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:Be prompt in doing good deeds (before you are overtaken) by turbulence which would be like a part of the dark night. During (that stormy period) a man would be a Muslim in the morning and an unbeliever in the evening or he would be a believer in the evening and an unbeliever in the morning, and would sell his faith for worldly goods.', NULL, NULL, 'https://sunnah.com/muslim:118', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 120, '"‏ مَنِ ادَّعَى أَبًا فِي الإِسْلاَمِ غَيْرَ أَبِيهِ يَعْلَمُ أَنَّهُ غَيْرُ أَبِيهِ فَالْجَنَّةُ عَلَيْهِ حَرَامٌ ‏"', NULL, 'It is reported on the authority of Sa''d b. Abi Waqqas:Both of my ears heard the Messenger of Allah saying this: He who claimed the fatherhood of anyone else besides his real father knowingly (committed a great sin) ;Paradise is forbidden to him. Abu Bakra asserted that he too heard it from the Messenger of Allah (may peace be upon him ).', 'It is reported on the authority of Sa''d b. Abi Waqqas', NULL, 'https://sunnah.com/muslim:120', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 121, '"‏ مَنِ ادَّعَى إِلَى غَيْرِ أَبِيهِ وَهُوَ يَعْلَمُ أَنَّهُ غَيْرُ أَبِيهِ فَالْجَنَّةُ عَلَيْهِ حَرَامٌ ‏"', NULL, 'Sa''d and Abu Bakra each one of them said:My ears heard and my hearing preserved it that Muhammad (peace and blessings be upon him) observed: He who claimed for another one his fatherhood besides his own father knowingly that he was not his father-to him Paradise is forbidden.', 'Sa''d and Abu Bakra each one of them said', NULL, 'https://sunnah.com/muslim:121', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 122, '"‏ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ ‏"', NULL, 'It is narrated on the authority of ''Abdullah b. Mas''ud that the Messenger of Allah (may peace and blessings be upon him) observed:Abusing a Muslim is an outrage and fighting against him is unbelief. Zubaid said: I asked Abu Wa''il: Did you hear it from Abdullah narrating if from the Messenger of Allah (may peace and blessings be upon him)? He replied: Yes. But there is mention of the talk between Zubaid and Abu Wa''il in the hadith narrated by Shu''ba.', NULL, NULL, 'https://sunnah.com/muslim:122', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 123, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَابْنُ الْمُثَنَّى، عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ، عَنْ شُعْبَةَ، عَنْ مَنْصُورٍ، ح وَحَدَّثَنَا ابْنُ نُمَيْرٍ، حَدَّثَنَا عَفَّانُ، حَدَّثَنَا شُعْبَةُ، عَنِ الأَعْمَشِ، كِلاَهُمَا عَنْ أَبِي وَائِلٍ، عَنْ عَبْدِ اللَّهِ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِمِثْلِهِ ‏.‏', NULL, 'Abu Bakr b. Abu Shaiba narrated a hadith like this from the Apostle (may peace and blessings be upon him) on the authority of Abdullah.', NULL, NULL, 'https://sunnah.com/muslim:123', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 125, 'وَحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ، حَدَّثَنَا أَبِي، حَدَّثَنَا شُعْبَةُ، عَنْ وَاقِدِ بْنِ مُحَمَّدٍ، عَنْ أَبِيهِ، عَنِ ابْنِ عُمَرَ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِمِثْلِهِ ‏.‏', NULL, 'Abdullah b. Mu''adh narrated from the Apostle (may peace and blessings be upon him) a hadith like this on the authority on Ibn Umar.', NULL, NULL, 'https://sunnah.com/muslim:125', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 126, '"‏ وَيْحَكُمْ - أَوْ قَالَ وَيْلَكُمْ - لاَ تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ ‏"', NULL, 'It is narrated on the authority of Abdullah b. Umar that the Apostle (may peace and blessings be upon him) observed on the occasion of the Farewell Pilgrimage Woe unto you distress unto you! Don''t turn back as unbelievers after me by striking the necks of one another.', NULL, NULL, 'https://sunnah.com/muslim:126', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 127, 'حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى، أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ، قَالَ حَدَّثَنِي عُمَرُ بْنُ مُحَمَّدٍ، أَنَّ أَبَاهُ، حَدَّثَهُ عَنِ ابْنِ عُمَرَ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِمِثْلِ حَدِيثِ شُعْبَةَ عَنْ وَاقِدٍ ‏.‏', NULL, 'Harmala b. Yahya, Abdullah b. Wahb, Umar b. Muhammad, Ibn Umar narrated like the hadith reported by Shu''ba on the authority of Waqid.', NULL, NULL, 'https://sunnah.com/muslim:127', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 129, 'وَحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، أَخْبَرَنَا مَعْمَرٌ، عَنْ هَمَّامِ بْنِ مُنَبِّهٍ، قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ، عَنْ مُحَمَّدٍ، رَسُولِ اللَّهِ صلى الله عليه وسلم فَذَكَرَ أَحَادِيثَ مِنْهَا قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ قَالَ اللَّهُ عَزَّ وَجَلَّ إِذَا تَحَدَّثَ عَبْدِي بِأَنْ يَعْمَلَ حَسَنَةً فَأَنَا أَكْتُبُهَا لَهُ حَسَنَةً مَا لَمْ يَعْمَلْ فَإِذَا عَمِلَهَا فَأَنَا أَكْتُبُهَا بِعَشْرِ أَمْثَالِهَا وَإِذَا تَحَدَّثَ بِأَنْ يَعْمَلَ سَيِّئَةً فَأَنَا أَغْفِرُهَا لَهُ مَا لَمْ يَعْمَلْهَا فَإِذَا عَمِلَهَا فَأَنَا أَكْتُبُهَا لَهُ بِمِثْلِهَا ‏"‏ ‏.‏
وَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ قَالَتِ الْمَلاَئِكَةُ رَبِّ ذَاكَ عَبْدُكَ يُرِيدُ أَنْ يَعْمَلَ سَيِّئَةً - وَهُوَ أَبْصَرُ بِهِ - فَقَالَ ارْقُبُوهُ فَإِنْ عَمِلَهَا فَاكْتُبُوهَا لَهُ بِمِثْلِهَا ‏.‏ وَإِنْ تَرَكَهَا فَاكْتُبُوهَا لَهُ حَسَنَةً - إِنَّمَا تَرَكَهَا مِنْ جَرَّاىَ ‏"‏ ‏.‏
وَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ إِذَا أَحْسَنَ أَحَدُكُمْ إِسْلاَمَهُ فَكُلُّ حَسَنَةٍ يَعْمَلُهَا تُكْتَبُ بِعَشْرِ أَمْثَالِهَا إِلَى سَبْعِمِائَةِ ضِعْفٍ وَكُلُّ سَيِّئَةٍ يَعْمَلُهَا تُكْتَبُ بِمِثْلِهَا حَتَّى يَلْقَى اللَّهَ ‏"‏ ‏.‏', NULL, 'Abu Huraira reported that Muhammad, the Messenger of Allah (ﷺ), said:When it occurs to my bondsman that he should do a good deed but he actually does not do it, record one good to him, but if he puts it into practice, I make an entry of ten good acts in his favour. When it occurs to him to do evil, but he does not commit it, I forgive that. But if he commits it, I record one evil against his name. The Messenger of Allah (ﷺ) observed. The angels said: That bondsman of Yours intends to commit evil. though His Lord is more Vigilant than he. Upon this He (the Lord) said: Watch him; if he commits (evil), write it against his name but if he refrains from doing it, write one good deed or him, for he desisted from doing it for My sake. The Messenger of Allah said: He who amongst you is good of faith, all his good acts are multiplied from ten to seven hundred times (and are recorded in his name) and all the evils that he commits are recorded as such (i, e. without increase) till he meets Allah.', 'Abu Huraira reported that Muhammad, the Messenger of Allah (ﷺ), said', NULL, 'https://sunnah.com/muslim:129', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 130, '"‏ مَنْ هَمَّ بِحَسَنَةٍ فَلَمْ يَعْمَلْهَا كُتِبَتْ لَهُ حَسَنَةً وَمَنْ هَمَّ بِحَسَنَةٍ فَعَمِلَهَا كُتِبَتْ لَهُ عَشْرًا إِلَى سَبْعِمِائَةِ ضِعْفٍ وَمَنْ هَمَّ بِسَيِّئَةٍ فَلَمْ يَعْمَلْهَا لَمْ تُكْتَبْ وَإِنْ عَمِلَهَا كُتِبَتْ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:He who intended to do good, but did not do it, one good was recorded for him, and he who intended to do good and also did it, ten to seven hundred good deeds were recorded for him. And he who intended evil, but did not commit it, no entry was made against his name, but if he committed that, it was recorded.', NULL, NULL, 'https://sunnah.com/muslim:130', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 133, '"‏ أَلَمْ تَرَوْا إِلَى مَا قَالَ رَبُّكُمْ قَالَ مَا أَنْعَمْتُ عَلَى عِبَادِي مِنْ نِعْمَةٍ إِلاَّ أَصْبَحَ فَرِيقٌ مِنْهُمْ بِهَا كَافِرِينَ ‏.‏ يَقُولُونَ الْكَوَاكِبُ وَبِالْكَوَاكِبِ ‏"', NULL, 'It is reported on the authority of Abu Huraira that the Messenger of Allah (may peace and blessings be upon him) said:Don''t you know what your Lord said? He observed: I have never endowed My bondsmen with a favor, but a section amongst them disbelieved it and said: Stars, it was due to the stars.', NULL, NULL, 'https://sunnah.com/muslim:133', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 134, 'وَحَدَّثَنِي مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ، عَنْ عَمْرِو بْنِ الْحَارِثِ، ح وَحَدَّثَنِي عَمْرُو بْنُ سَوَّادٍ، أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ، أَخْبَرَنَا عَمْرُو بْنُ الْحَارِثِ، أَنَّ أَبَا يُونُسَ، مَوْلَى أَبِي هُرَيْرَةَ حَدَّثَهُ عَنْ أَبِي هُرَيْرَةَ، عَنْ رَسُولِ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ مَا أَنْزَلَ اللَّهُ مِنَ السَّمَاءِ مِنْ بَرَكَةٍ إِلاَّ أَصْبَحَ فَرِيقٌ مِنَ النَّاسِ بِهَا كَافِرِينَ يُنْزِلُ اللَّهُ الْغَيْثَ فَيَقُولُونَ الْكَوْكَبُ كَذَا وَكَذَا ‏"‏ وَفِي حَدِيثِ الْمُرَادِيِّ ‏"‏ بِكَوْكَبِ كَذَا وَكَذَا ‏"‏ ‏.‏', NULL, 'It is reported on the authority of Abu Huraira that the Messenger of Allah (may peace and blessing be upon him) observed:Allah does not shower His blessings from the heaven that in the morning a group of men disbelieve it (to be a blessing from Allah). Allah sends down rain, but they (the disbelievers) say: Such and such star (is responsible for that).', NULL, NULL, 'https://sunnah.com/muslim:134', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 136, '"‏ آيَةُ الْمُنَافِقِ بُغْضُ الأَنْصَارِ وَآيَةُ الْمُؤْمِنِ حُبُّ الأَنْصَارِ ‏"', NULL, 'It is reported on the authority of Anas that the Messenger of Allah (may peace and blessings Be upon him) observed:The sign of a hypocrite is the hatred against the Ansar and the sign of a believer is the love for the Ansar.', NULL, NULL, 'https://sunnah.com/muslim:136', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 137, '"‏ حُبُّ الأَنْصَارِ آيَةُ الإِيمَانِ وَبُغْضُهُمْ آيَةُ النِّفَاقِ ‏"', NULL, 'It is narrated on the authority of Anas that the Apostle (may peace and blessings be upon him) said:The love of the Ansar is the sign of faith and hatred against them is the sign of dissemblance.', NULL, NULL, 'https://sunnah.com/muslim:137', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 140, 'حَدَّثَنِي أَبُو كُرَيْبٍ، مُحَمَّدُ بْنُ الْعَلاَءِ حَدَّثَنَا خَالِدٌ، - يَعْنِي ابْنَ مَخْلَدٍ - حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، عَنِ الْعَلاَءِ بْنِ عَبْدِ الرَّحْمَنِ، عَنْ أَبِيهِ، عَنْ أَبِي هُرَيْرَةَ، قَالَ جَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صلى الله عليه وسلم فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ جَاءَ رَجُلٌ يُرِيدُ أَخْذَ مَالِي قَالَ ‏"‏ فَلاَ تُعْطِهِ مَالَكَ ‏"‏ ‏.‏ قَالَ أَرَأَيْتَ إِنْ قَاتَلَنِي قَالَ ‏"‏ قَاتِلْهُ ‏"‏ ‏.‏ قَالَ أَرَأَيْتَ إِنْ قَتَلَنِي قَالَ ‏"‏ فَأَنْتَ شَهِيدٌ ‏"‏ ‏.‏ قَالَ أَرَأَيْتَ إِنْ قَتَلْتُهُ قَالَ ‏"‏ هُوَ فِي النَّارِ ‏"‏ ‏.‏', NULL, 'Abu Huraira reported:A person came to the Messenger of Allah (ﷺ) and said: Messenger of Allah, what do you think if a man comes to me in order to appropriate my possession? He (the Holy Prophet) said: Don''t surrender your possession to him. He (the inquirer) said: If he fights me? He (the Holy Prophet) remarked: Then fight (with him). He (the inquirer) again said: What do you think if I am killed? He (the Holy Prophet) observed: You would be a martyr. He (the inquirer) said: What do you think of him (Messenger of Allah) If I kill him. He (the Holy Prophet) said: he would be in the Fire.', 'Abu Huraira reported', NULL, 'https://sunnah.com/muslim:140', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 142, 'حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحِ بْنِ الْمُهَاجِرِ الْمِصْرِيُّ، أَخْبَرَنَا اللَّيْثُ، عَنِ ابْنِ الْهَادِ، عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ، عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ، عَنْ رَسُولِ اللَّهِ صلى الله عليه وسلم أَنَّهُ قَالَ ‏"‏ يَا مَعْشَرَ النِّسَاءِ تَصَدَّقْنَ وَأَكْثِرْنَ الاِسْتِغْفَارَ فَإِنِّي رَأَيْتُكُنَّ أَكْثَرَ أَهْلِ النَّارِ ‏"‏ ‏.‏ فَقَالَتِ امْرَأَةٌ مِنْهُنَّ جَزْلَةٌ وَمَا لَنَا يَا رَسُولَ اللَّهِ أَكْثَرَ أَهْلِ النَّارِ ‏.‏ قَالَ ‏"‏ تُكْثِرْنَ اللَّعْنَ وَتَكْفُرْنَ الْعَشِيرَ وَمَا رَأَيْتُ مِنْ نَاقِصَاتِ عَقْلٍ وَدِينٍ أَغْلَبَ لِذِي لُبٍّ مِنْكُنَّ ‏"‏ ‏.‏ قَالَتْ يَا رَسُولَ اللَّهِ وَمَا نُقْصَانُ الْعَقْلِ وَالدِّينِ قَالَ ‏"‏ أَمَّا نُقْصَانُ الْعَقْلِ فَشَهَادَةُ امْرَأَتَيْنِ تَعْدِلُ شَهَادَةَ رَجُلٍ فَهَذَا نُقْصَانُ الْعَقْلِ وَتَمْكُثُ اللَّيَالِيَ مَا تُصَلِّي وَتُفْطِرُ فِي رَمَضَانَ فَهَذَا نُقْصَانُ الدِّينِ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of ''Abdullah b. Umar that the Messenger of Allah observed:O womenfolk, you should give charity and ask much forgiveness for I saw you in bulk amongst the dwellers of Hell. A wise lady among them said: Why is it, Messenger of Allah, that our folk is in bulk in Hell? Upon this the Prophet observed: You curse too much and are ungrateful to your spouses. I have seen none lacking in common sense and failing in religion but (at the same time) robbing the wisdom of the wise, besides you. Upon this the woman remarked: What is wrong with our common sense and with religion? He (the Holy Prophet) observed: Your lack of common sense (can be well judged from the fact) that the evidence of two women is equal to one man, that is a proof of the lack of common sense, and you spend some nights (and days) in which you do not offer prayer and in the month of Ramadan (during the days) you do not observe fast, that is a failing in religion.', NULL, NULL, 'https://sunnah.com/muslim:142', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 143, 'وَحَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ، وَقُتَيْبَةُ، وَابْنُ، حُجْرٍ قَالُوا حَدَّثَنَا إِسْمَاعِيلُ، - وَهُوَ ابْنُ جَعْفَرٍ - عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو، عَنِ الْمَقْبُرِيِّ، عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِمِثْلِ مَعْنَى حَدِيثِ ابْنِ عُمَرَ عَنِ النَّبِيِّ صلى الله عليه وسلم ‏.‏', NULL, 'A hadith like this as narrated by Ibn ''Umar has also been transmitted by Abu Huraira.', NULL, NULL, 'https://sunnah.com/muslim:143', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 144, '"‏ إِذَا قَرَأَ ابْنُ آدَمَ السَّجْدَةَ فَسَجَدَ اعْتَزَلَ الشَّيْطَانُ يَبْكِي يَقُولُ يَا وَيْلَهُ - وَفِي رِوَايَةِ أَبِي كُرَيْبٍ يَا وَيْلِي - أُمِرَ ابْنُ آدَمَ بِالسُّجُودِ فَسَجَدَ فَلَهُ الْجَنَّةُ وَأُمِرْتُ بِالسُّجُودِ فَأَبَيْتُ فَلِيَ النَّارُ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that when, the son of Adam recites the Ayat of Sajdah (prostration) and then falls down in prostration, the Satan goes into seclusion and weeps and says:Alas, and in the narration of Abu Kuraib the words are: Woe unto me, the son of Adam was commanded to prostrate, and he prostrated and Paradise was entitled to him and I was commanded to prostrate, but I refused and am doomed to Hell.', NULL, NULL, 'https://sunnah.com/muslim:144', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 145, '"‏ فَعَصَيْتُ فَلِيَ النَّارُ ‏"', NULL, 'A''mash narrated this hadith with the same chain of transmitters, with this change of words that he (the Satan) said:I disobeyed and I am doomed to Hell.', NULL, NULL, 'https://sunnah.com/muslim:145', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 146, '"‏ إِنَّ بَيْنَ الرَّجُلِ وَبَيْنَ الشِّرْكِ وَالْكُفْرِ تَرْكَ الصَّلاَةِ ‏"', NULL, 'It is narrated on the authority of Jabir that he heard the Apostle (may peace and blessings be upon him) saying. Verily between man and between polytheism and unbelief is the negligence of prayer.', NULL, NULL, 'https://sunnah.com/muslim:146', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 147, '"‏ بَيْنَ الرَّجُلِ وَبَيْنَ الشِّرْكِ وَالْكُفْرِ تَرْكُ الصَّلاَةِ ‏"', NULL, 'It is narrated on the authority of Abu Zubair that he heard Jabir b. ''Abdullah saying. I heard the Messenger of Allah (may peace and blessings be upon him) observing this:Between man and polytheism and unbelief is the abandonment of salat.', NULL, NULL, 'https://sunnah.com/muslim:147', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 149, 'حَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ، حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ، حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ، ح وَحَدَّثَنَا خَلَفُ بْنُ هِشَامٍ، - وَاللَّفْظُ لَهُ - حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ، عَنْ هِشَامِ بْنِ عُرْوَةَ، عَنْ أَبِيهِ، عَنْ أَبِي مُرَاوِحٍ اللَّيْثِيِّ، عَنْ أَبِي ذَرٍّ، قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَىُّ الأَعْمَالِ أَفْضَلُ قَالَ ‏"‏ الإِيمَانُ بِاللَّهِ وَالْجِهَادُ فِي سَبِيلِهِ ‏"‏ ‏.‏ قَالَ قُلْتُ أَىُّ الرِّقَابِ أَفْضَلُ قَالَ ‏"‏ أَنْفَسُهَا عِنْدَ أَهْلِهَا وَأَكْثَرُهَا ثَمَنًا ‏"‏ ‏.‏ قَالَ قُلْتُ فَإِنْ لَمْ أَفْعَلْ قَالَ ‏"‏ تُعِينُ صَانِعًا أَوْ تَصْنَعُ لأَخْرَقَ ‏"‏ ‏.‏ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ ضَعُفْتُ عَنْ بَعْضِ الْعَمَلِ قَالَ ‏"‏ تَكُفُّ شَرَّكَ عَنِ النَّاسِ فَإِنَّهَا صَدَقَةٌ مِنْكَ عَلَى نَفْسِكَ ‏"‏ ‏.‏', NULL, 'Abu Dharr reported:I said: Messenger of Allah, which of the deeds is the best? He (the Holy Prophet) replied: Belief in Allah and Jihad in His cause. I again asked: Who is the slave whose emancipation is the best? He (the Holy Prophet) replied: One who is valuable for his master and whose price is high. I said: If I can''t afford to do it? He (the Holy Prophet) replied: Help an artisan or make anything for the unskilled (labourer). I (Abu Dharr) said: Messenger of Allah, you see that I am helpless in doing some of these deeds. He (the Holy Prophet) replied: Desist from doing mischief to the people. That is the charity of your person on your behalf.', 'Abu Dharr reported', NULL, 'https://sunnah.com/muslim:149', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 150, '"‏ فَتُعِينُ الصَّانِعَ أَوْ تَصْنَعُ لأَخْرَقَ ‏"', NULL, 'Muhammad b. Abu Rafi'' narrated the hadith on the authority of Abu Dharr with a slight difference.', NULL, NULL, 'https://sunnah.com/muslim:150', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 151, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ، عَنِ الشَّيْبَانِيِّ، عَنِ الْوَلِيدِ بْنِ الْعَيْزَارِ، عَنْ سَعْدِ بْنِ إِيَاسٍ أَبِي عَمْرٍو الشَّيْبَانِيِّ، عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ، قَالَ سَأَلْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم أَىُّ الْعَمَلِ أَفْضَلُ قَالَ ‏"‏ الصَّلاَةُ لِوَقْتِهَا ‏"‏ ‏.‏ قَالَ قُلْتُ ثُمَّ أَىٌّ قَالَ ‏"‏ بِرُّ الْوَالِدَيْنِ ‏"‏ ‏.‏ قَالَ قُلْتُ ثُمَّ أَىٌّ قَالَ ‏"‏ الْجِهَادُ فِي سَبِيلِ اللَّهِ ‏"‏ ‏.‏ فَمَا تَرَكْتُ أَسْتَزِيدُهُ إِلاَّ إِرْعَاءً عَلَيْهِ ‏.‏', NULL, 'It is narrated on the authority of ''Abdullah b. Mas''ud that he observed. I asked the Messenger of Allah (ﷺ) which deed was the best. He (the Holy Prophet) replied:Prayer at its appointed hour. I (again) said: Then what? He (the Holy Prophet) replied: Kindness to the parents. I (again) said: Then what? He replied: Earnest endeavour (Jihad) in the cause of Allah. And I would have not ceased asking more questions but out of regard (for his feelings).', NULL, NULL, 'https://sunnah.com/muslim:151', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 152, 'حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْمَكِّيُّ، حَدَّثَنَا مَرْوَانُ الْفَزَارِيُّ، حَدَّثَنَا أَبُو يَعْفُورٍ، عَنِ الْوَلِيدِ بْنِ الْعَيْزَارِ، عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ، عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ، قَالَ قُلْتُ يَا نَبِيَّ اللَّهِ أَىُّ الأَعْمَالِ أَقْرَبُ إِلَى الْجَنَّةِ قَالَ ‏"‏ الصَّلاَةُ عَلَى مَوَاقِيتِهَا ‏"‏ ‏.‏ قُلْتُ وَمَاذَا يَا نَبِيَّ اللَّهِ قَالَ ‏"‏ بِرُّ الْوَالِدَيْنِ ‏"‏ ‏.‏ قُلْتُ وَمَاذَا يَا نَبِيَّ اللَّهِ قَالَ ‏"‏ الْجِهَادُ فِي سَبِيلِ اللَّهِ ‏"‏ ‏.‏', NULL, '''Abdullah b. Mas''ud reported:I said: Messenger of Allah, which of the deeds (takes one) nearer to Paradise? He (the Holy Prophet) replied: Prayer at its proper time, I said: What next, Messenger of Allah? He replied: Kindness to the parents. I said: What next? He replied: Jihad in the cause of Allah.', '''Abdullah b. Mas''ud reported', NULL, 'https://sunnah.com/muslim:152', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 153, 'وَحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ، حَدَّثَنَا أَبِي، حَدَّثَنَا شُعْبَةُ، عَنِ الْوَلِيدِ بْنِ الْعَيْزَارِ، أَنَّهُ سَمِعَ أَبَا عَمْرٍو الشَّيْبَانِيَّ، قَالَ حَدَّثَنِي صَاحِبُ، هَذِهِ الدَّارِ - وَأَشَارَ إِلَى دَارِ عَبْدِ اللَّهِ - قَالَ سَأَلْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم أَىُّ الأَعْمَالِ أَحَبُّ إِلَى اللَّهِ قَالَ ‏"‏ الصَّلاَةُ عَلَى وَقْتِهَا ‏"‏ ‏.‏ قُلْتُ ثُمَّ أَىٌّ قَالَ ‏"‏ ثُمَّ بِرُّ الْوَالِدَيْنِ ‏"‏ ‏.‏ قُلْتُ ثُمَّ أَىٌّ قَالَ ‏"‏ ثُمَّ الْجِهَادُ فِي سَبِيلِ اللَّهِ ‏"‏ قَالَ حَدَّثَنِي بِهِنَّ وَلَوِ اسْتَزَدْتُهُ لَزَادَنِي ‏.‏', NULL, 'It was heard from Abu ''Amr Shaibani that, pointing towards the house of Abdullah, he said:The owner of this house told me that he asked the Messenger of Allah (ﷺ): Which of the deeds are liked by Allah? He (the Holy Prophet) observed: Prayer at its proper time. I (again) said: What next? He replied: Then goodness to the parents. I (again) said: What then? He replied: Then Jihad in the cause of Allah. He (''Abdullah) said: This is what I was told (by the Holy Prophet). Had I questioned further, he would have made additions for me.', NULL, NULL, 'https://sunnah.com/muslim:153', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 154, 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، بِهَذَا الإِسْنَادِ مِثْلَهُ ‏.‏ وَزَادَ وَأَشَارَ إِلَى دَارِ عَبْدِ اللَّهِ وَمَا سَمَّاهُ لَنَا ‏.‏', NULL, 'This hadith has been transmitted by Muhammad b. Bashshar, Muhammad b. Ja''far Shu''ba with this chain of narrators, with the addition that he pointed towards the house of ''Abdullah, but he did not mention his name for us.', NULL, NULL, 'https://sunnah.com/muslim:154', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 155, '"‏ أَفْضَلُ الأَعْمَالِ - أَوِ الْعَمَلِ - الصَّلاَةُ لِوَقْتِهَا وَبِرُّ الْوَالِدَيْنِ ‏"', NULL, 'It is reported on the authority of ''Abdullah that the Messenger of Allah observed:The best of'' the deeds or deed is the (observance of) prayer at its proper time and kindness to the parents.', NULL, NULL, 'https://sunnah.com/muslim:155', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 156, 'حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ، وَإِسْحَاقُ بْنُ إِبْرَاهِيمَ، قَالَ إِسْحَاقُ أَخْبَرَنَا جَرِيرٌ، وَقَالَ، عُثْمَانُ حَدَّثَنَا جَرِيرٌ، عَنْ مَنْصُورٍ، عَنْ أَبِي وَائِلٍ، عَنْ عَمْرِو بْنِ شُرَحْبِيلَ، عَنْ عَبْدِ اللَّهِ، قَالَ سَأَلْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم أَىُّ الذَّنْبِ أَعْظَمُ عِنْدَ اللَّهِ قَالَ ‏"‏ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ ‏"‏ ‏.‏ قَالَ قُلْتُ لَهُ إِنَّ ذَلِكَ لَعَظِيمٌ ‏.‏ قَالَ قُلْتُ ثُمَّ أَىٌّ قَالَ ‏"‏ ثُمَّ أَنْ تَقْتُلَ وَلَدَكَ مَخَافَةَ أَنْ يَطْعَمَ مَعَكَ ‏"‏ ‏.‏ قَالَ قُلْتُ ثُمَّ أَىٌّ قَالَ ‏"‏ ثُمَّ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ ‏"‏ ‏.‏', NULL, '''Abdullah reported:I asked the Messenger of Allah (ﷺ): Which sin is the gravest in the eye of Allah? He (the Holy Prophet) replied: That you associate a partner with Allah (despite the fact) that He has created you. He (the reporter) said: I told him (the, Holy Prophet): Verily it is indeed grave. He (the reporter) said: I asked him what the next (gravest sin) was. He (the Holy Prophet) replied: That you kill your child out of fear that he shall join you in food. He (the reporter) said: I asked (him) what the next (gravest sin) was. He (the Holy Prophet) observed: Then (the next gravest sin) is that you commit adultery with the wife of your neighbour.', '''Abdullah reported', NULL, 'https://sunnah.com/muslim:156', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 157, 'حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ، وَإِسْحَاقُ بْنُ إِبْرَاهِيمَ، جَمِيعًا عَنْ جَرِيرٍ، قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ، عَنِ الأَعْمَشِ، عَنْ أَبِي وَائِلٍ، عَنْ عَمْرِو بْنِ شُرَحْبِيلَ، قَالَ قَالَ عَبْدُ اللَّهِ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَىُّ الذَّنْبِ أَكْبَرُ عِنْدَ اللَّهِ قَالَ ‏"‏ أَنْ تَدْعُوَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ ‏"‏ ‏.‏ قَالَ ثُمَّ أَىٌّ قَالَ ‏"‏ أَنْ تَقْتُلَ وَلَدَكَ مَخَافَةَ أَنْ يَطْعَمَ مَعَكَ ‏"‏ ‏.‏ قَالَ ثُمَّ أَىٌّ قَالَ ‏"‏ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ ‏"‏ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ تَصْدِيقَهَا ‏{‏ وَالَّذِينَ لاَ يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلاَ يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلاَّ بِالْحَقِّ وَلاَ يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا‏}‏', NULL, 'It is narrated on the authority of Abdullah b. Mas''ud that a man said:Messenger of Allah, which offence is the most grievous in the eye of Allah? He (the Holy Prophet) replied: That you associate a partner with Allah (despite the fact) that He created you. He (the man) said: What next? He (the Holy Prophet) replied: That you kill your child out of fear that he would join you in food. He (the inquirer) said (again): What next? He (the Holy Prophet) replied: That you commit adultery with the wife of your neighbour. And the Almighty and Exalted Lord testified it (with this verse): All those who call not unto another god along with Allah, and slay not any soul which Allah has forbidden, except in the cause of justice, nor commit fornication, and he who does this shall meet a requital of sin (xxv. 68).', 'It is narrated on the authority of Abdullah b. Mas''ud that a man said', NULL, 'https://sunnah.com/muslim:157', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 158, '"‏ ثَلاَثٌ إِذَا خَرَجْنَ لاَ يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ أَوْ كَسَبَتْ فِي إِيمَانِهَا خَيْرًا طُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا وَالدَّجَّالُ وَدَابَّةُ الأَرْضِ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:When three things appear faith will not benefit one who has not previously believed or has derived no good from his faith: the rising of the sun in its place of setting, the Dajjal, and the beast of the earth.', NULL, NULL, 'https://sunnah.com/muslim:158', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 159, '"‏ الشِّرْكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَقَتْلُ النَّفْسِ وَقَوْلُ الزُّورِ ‏"', NULL, 'Anas narrated from the Apostle (ﷺ) about the major sins. He (the Holy Prophet) observed:Associating anyone with Allah, disobedience to parents, killing a person and false utterance.', NULL, NULL, 'https://sunnah.com/muslim:159', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 160, 'وَحَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ بْنِ عَبْدِ الْحَمِيدِ، حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرٍ، قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ، قَالَ ذَكَرَ رَسُولُ اللَّهِ صلى الله عليه وسلم الْكَبَائِرَ - أَوْ سُئِلَ عَنِ الْكَبَائِرِ - فَقَالَ ‏"‏ الشِّرْكُ بِاللَّهِ وَقَتْلُ النَّفْسِ وَعُقُوقُ الْوَالِدَيْنِ ‏"‏ ‏.‏ وَقَالَ ‏"‏ أَلاَ أُنَبِّئُكُمْ بِأَكْبَرِ الْكَبَائِرِ ‏"‏ ‏.‏ قَالَ ‏"‏ قَوْلُ الزُّورِ ‏"‏ ‏.‏ أَوْ قَالَ ‏"‏ شَهَادَةُ الزُّورِ ‏"‏ ‏.‏ قَالَ شُعْبَةُ وَأَكْبَرُ ظَنِّي أَنَّهُ شَهَادَةُ الزُّورِ ‏.‏', NULL, 'Ubaidullah b. Abu Bakr said:I heard Anas b. Malik saying: The Messenger of Allah (ﷺ) talked about the major sins, or he was asked about the major sins. Upon this he observed: Associating anyone with Allah, killing of a person, disobedience to parents. He (the Prophet further) said: Should I not inform you about the gravest of the major sins, and (in this connection) observed: False utterance or false testimony. Shu''ba said. It was most probably" false testimony".', 'Ubaidullah b. Abu Bakr said', NULL, 'https://sunnah.com/muslim:160', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 162, 'حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ، حَدَّثَنَا اللَّيْثُ، عَنِ ابْنِ الْهَادِ، عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ، عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ، عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ مِنَ الْكَبَائِرِ شَتْمُ الرَّجُلِ وَالِدَيْهِ ‏"‏ ‏.‏ قَالُوا يَا رَسُولَ اللَّهِ هَلْ يَشْتِمُ الرَّجُلُ وَالِدَيْهِ قَالَ ‏"‏ نَعَمْ يَسُبُّ أَبَا الرَّجُلِ فَيَسُبُّ أَبَاهُ وَيَسُبُّ أُمَّهُ فَيَسُبُّ أُمَّهُ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of ''Abdullah b. Amr b. al-''As that the Messenger of Allah (ﷺ) observed:Abusing one''s parents is one of the major sins. They (the hearers) said: Messenger of Allah, does a man abuse his parents too? He (the Holy Prophet) replied: Yes, one abuses the father of another man, who in turn abuses his father. One abuses his mother and he in turn abuses his (the former''s) mother.', NULL, NULL, 'https://sunnah.com/muslim:162', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 163, 'وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَمُحَمَّدُ بْنُ الْمُثَنَّى، وَابْنُ، بَشَّارٍ جَمِيعًا عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ، عَنْ شُعْبَةَ، ح وَحَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ، حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ، حَدَّثَنَا سُفْيَانُ، كِلاَهُمَا عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ، بِهَذَا الإِسْنَادِ مِثْلَهُ ‏.‏', NULL, 'This hadith has also been transmitted on the authority of Sa''d b. Ibrahim with this chain of narrators.', NULL, NULL, 'https://sunnah.com/muslim:163', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 164, 'وَحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، وَمُحَمَّدُ بْنُ بَشَّارٍ، وَإِبْرَاهِيمُ بْنُ دِينَارٍ، جَمِيعًا عَنْ يَحْيَى بْنِ حَمَّادٍ، - قَالَ ابْنُ الْمُثَنَّى حَدَّثَنِي يَحْيَى بْنُ حَمَّادٍ، - أَخْبَرَنَا شُعْبَةُ، عَنْ أَبَانَ بْنِ تَغْلِبَ، عَنْ فُضَيْلٍ الْفُقَيْمِيِّ، عَنْ إِبْرَاهِيمَ النَّخَعِيِّ، عَنْ عَلْقَمَةَ، عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ لاَ يَدْخُلُ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ كِبْرٍ ‏"‏ ‏.‏ قَالَ رَجُلٌ إِنَّ الرَّجُلَ يُحِبُّ أَنْ يَكُونَ ثَوْبُهُ حَسَنًا وَنَعْلُهُ حَسَنَةً ‏.‏ قَالَ ‏"‏ إِنَّ اللَّهَ جَمِيلٌ يُحِبُّ الْجَمَالَ الْكِبْرُ بَطَرُ الْحَقِّ وَغَمْطُ النَّاسِ ‏"‏ ‏.‏', NULL, 'It Is narrated on the authority of Abdullah b. Mas''ud that the Messenger of Allah (ﷺ), observed:He who has in his heart the weight of a mustard seed of pride shall not enter Paradise. A person (amongst his hearers) said: Verily a person loves that his dress should be fine, and his shoes should be fine. He (the Holy Prophet) remarked: Verily, Allah is Graceful and He loves Grace. Pride is disdaining the truth (out of self-conceit) and contempt for the people.', NULL, NULL, 'https://sunnah.com/muslim:164', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 165, '"‏ لاَ يَدْخُلُ النَّارَ أَحَدٌ فِي قَلْبِهِ مِثْقَالُ حَبَّةِ خَرْدَلٍ مِنْ إِيمَانٍ وَلاَ يَدْخُلُ الْجَنَّةَ أَحَدٌ فِي قَلْبِهِ مِثْقَالُ حَبَّةِ خَرْدَلٍ مِنْ كِبْرِيَاءَ ‏"', NULL, 'It is narrated on the authority of ''Abdullah b. Mas''ud that the Messenger of Allah (ﷺ) observed:None shall enter the Fire (of Hell) who has in his heart the weight of a mustard seed of Iman and none shall enter Paradise who has in his heart the weight of a mustard seed of pride.', NULL, NULL, 'https://sunnah.com/muslim:165', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 166, '"‏ لاَ يَدْخُلُ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ كِبْرٍ ‏"', NULL, 'It is narrated on the authority of ''Abdullah that the Messenger of Allah (ﷺ) observed:He who has in his heart the weight of a mustard seed of pride shall not enter Paradise.', NULL, NULL, 'https://sunnah.com/muslim:166', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 167, 'حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ، حَدَّثَنَا لَيْثٌ، ح وَحَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ، أَخْبَرَنَا اللَّيْثُ، عَنْ أَبِي الزُّبَيْرِ، عَنْ جَابِرٍ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ عُرِضَ عَلَىَّ الأَنْبِيَاءُ فَإِذَا مُوسَى ضَرْبٌ مِنَ الرِّجَالِ كَأَنَّهُ مِنْ رِجَالِ شَنُوءَةَ وَرَأَيْتُ عِيسَى ابْنَ مَرْيَمَ - عَلَيْهِ السَّلاَمُ - فَإِذَا أَقْرَبُ مَنْ رَأَيْتُ بِهِ شَبَهًا عُرْوَةُ بْنُ مَسْعُودٍ وَرَأَيْتُ إِبْرَاهِيمَ صَلَوَاتُ اللَّهِ عَلَيْهِ فَإِذَا أَقْرَبُ مَنْ رَأَيْتُ بِهِ شَبَهًا صَاحِبُكُمْ - يَعْنِي نَفْسَهُ - وَرَأَيْتُ جِبْرِيلَ - عَلَيْهِ السَّلاَمُ - فَإِذَا أَقْرَبُ مَنْ رَأَيْتُ بِهِ شَبَهًا دِحْيَةُ ‏"‏ ‏.‏ وَفِي رِوَايَةِ ابْنِ رُمْحٍ ‏"‏ دِحْيَةُ بْنُ خَلِيفَةَ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Jabir that the Messenger of Allah (ﷺ) said:There appeared before me the apostles, and Moses was among men as if he was one of the people of Shanu''a, and I saw Jesus son of Mary (peace be upon him) and I saw nearest in resemblance with him was ''Urwa b. Mas''ud, and I saw Ibrahim (blessings of Allah be upon him) and I see your companions much in resemblance with him, i. e. his personality, and I saw Gabriel (peace be upon him) and I saw Dihya nearest in resemblance to him; but in the narration of Ibn Rumh it is Dihya b. Khalifa.', 'It is narrated on the authority of Jabir that the Messenger of Allah (ﷺ) said', NULL, 'https://sunnah.com/muslim:167', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 168, '"‏ مَنْ مَاتَ لاَ يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ وَمَنْ مَاتَ يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ النَّارَ ‏"', NULL, 'It is narrated on the authority of Jabir that a man came to the Messenger of Allah (ﷺ) and said:Messenger of Allah, what are the two things quite unavoidable? He replied: He who dies without associating anyone with Allah would (necessarily) enter Paradise and he who dies associating anything with Allah would enter the (Fire of) Hell.', NULL, NULL, 'https://sunnah.com/muslim:168', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 169, '"‏ مَنْ لَقِيَ اللَّهَ لاَ يُشْرِكُ بِهِ شَيْئًا دَخَلَ الْجَنَّةَ وَمَنْ لَقِيَهُ يُشْرِكُ بِهِ دَخَلَ النَّارِ ‏"', NULL, 'It is narrated on the authority of Jabir b. Abdullah:I heard the Messenger of Allah (ﷺ) saying: He who met Allah without associating anything with Allah entered Paradise and he who met Him associating (anything) with Him entered Fire.', 'It is narrated on the authority of Jabir b. Abdullah', NULL, 'https://sunnah.com/muslim:169', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 170, 'وَحَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ، أَخْبَرَنَا مُعَاذٌ، - وَهُوَ ابْنُ هِشَامٍ - قَالَ حَدَّثَنِي أَبِي، عَنْ أَبِي الزُّبَيْرِ، عَنْ جَابِرٍ، أَنَّ نَبِيَّ اللَّهِ صلى الله عليه وسلم قَالَ بِمِثْلِهِ ‏.‏', NULL, 'The same hadith has been narrated by Ishaq b. Mansur on the authority of Jabir with another chain of transmitters.', NULL, NULL, 'https://sunnah.com/muslim:170', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 171, 'وَحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، وَابْنُ، بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، عَنْ وَاصِلٍ الأَحْدَبِ، عَنِ الْمَعْرُورِ بْنِ سُوَيْدٍ، قَالَ سَمِعْتُ أَبَا ذَرٍّ، يُحَدِّثُ عَنِ النَّبِيِّ صلى الله عليه وسلم أَنَّهُ قَالَ ‏"‏ أَتَانِي جِبْرِيلُ - عَلَيْهِ السَّلاَمُ - فَبَشَّرَنِي أَنَّهُ مَنْ مَاتَ مِنْ أُمَّتِكَ لاَ يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ ‏"‏ ‏.‏ قُلْتُ وَإِنْ زَنَى وَإِنْ سَرَقَ ‏.‏ قَالَ ‏"‏ وَإِنْ زَنَى وَإِنْ سَرَقَ ‏"‏ ‏.‏', NULL, 'I heard Abu Dharr narrating it from the Apostle (ﷺ) that he observed:Gabriel came to me and gave me the tidings: Verily he who died amongst your Ummah without associating anything with Allah would enter Paradise. I (the narrator) said: Even if he committed adultery and theft. He (the Holy Prophet) said: (Yes), even if he committed adultery and theft.', 'I heard Abu Dharr narrating it from the Apostle (ﷺ) that he observed', NULL, 'https://sunnah.com/muslim:171', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 172, 'حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ، وَأَحْمَدُ بْنُ خِرَاشٍ، قَالاَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ، حَدَّثَنَا أَبِي قَالَ، حَدَّثَنِي حُسَيْنٌ الْمُعَلِّمُ، عَنِ ابْنِ بُرَيْدَةَ، أَنَّ يَحْيَى بْنَ يَعْمَرَ، حَدَّثَهُ أَنَّ أَبَا الأَسْوَدِ الدِّيلِيَّ حَدَّثَهُ أَنَّ أَبَا ذَرٍّ حَدَّثَهُ قَالَ أَتَيْتُ النَّبِيَّ صلى الله عليه وسلم وَهُوَ نَائِمٌ عَلَيْهِ ثَوْبٌ أَبْيَضُ ثُمَّ أَتَيْتُهُ فَإِذَا هُوَ نَائِمٌ ثُمَّ أَتَيْتُهُ وَقَدِ اسْتَيْقَظَ فَجَلَسْتُ إِلَيْهِ فَقَالَ ‏"‏ مَا مِنْ عَبْدٍ قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ ثُمَّ مَاتَ عَلَى ذَلِكَ إِلاَّ دَخَلَ الْجَنَّةَ ‏"‏ ‏.‏ قُلْتُ وَإِنْ زَنَى وَإِنْ سَرَقَ قَالَ ‏"‏ وَإِنْ زَنَى وَإِنْ سَرَقَ ‏"‏ ‏.‏ قُلْتُ وَإِنْ زَنَى وَإِنْ سَرَقَ قَالَ ‏"‏ وَإِنْ زَنَى وَإِنْ سَرَقَ ‏"‏ ‏.‏ ثَلاَثًا ثُمَّ قَالَ فِي الرَّابِعَةِ ‏"‏ عَلَى رَغْمِ أَنْفِ أَبِي ذَرٍّ ‏"‏ قَالَ فَخَرَجَ أَبُو ذَرٍّ وَهُوَ يَقُولُ وَإِنْ رَغِمَ أَنْفُ أَبِي ذَرٍّ ‏.‏', NULL, 'Abu Dharr reported,:I came to the Apostle (may peace be upon him ) and he was asleep with a white mantle over him. I again came, he was still asleep, I came again and he had awakened. I sat by his side and (the Holy Prophet) observed: There is none among the bondsmen who affirmed his faith in La illaha ill-Allah there is no God but Allah) and died in this state and did not enter Paradise. I (Abu Dharr) said: Even if he committed adultery and theft? He (the Holy Prophet) replied: (Yes) even though he committed adultery and theft. I (again said): Even if he committed adultery and theft? He replied: (Yes) even though he committed adultery and theft. (Th Holy Prophet repeated it three times) and said for the fourth time: In defiance of Abu Dharr. Abu Dharr then went out and he repeated (these words): In defiance of Abu Dharr.', 'Abu Dharr reported,', NULL, 'https://sunnah.com/muslim:172', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 173, 'حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ، حَدَّثَنَا لَيْثٌ، ح وَحَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ، - وَاللَّفْظُ مُتَقَارِبٌ - أَخْبَرَنَا اللَّيْثُ، عَنِ ابْنِ شِهَابٍ، عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ، عَنْ عُبَيْدِ اللَّهِ بْنِ عَدِيِّ بْنِ الْخِيَارِ، عَنِ الْمِقْدَادِ بْنِ الأَسْوَدِ، أَنَّهُ أَخْبَرَهُ أَنَّهُ، قَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ لَقِيتُ رَجُلاً مِنَ الْكُفَّارِ فَقَاتَلَنِي فَضَرَبَ إِحْدَى يَدَىَّ بِالسَّيْفِ فَقَطَعَهَا ‏.‏ ثُمَّ لاَذَ مِنِّي بِشَجَرَةٍ فَقَالَ أَسْلَمْتُ لِلَّهِ ‏.‏ أَفَأَقْتُلُهُ يَا رَسُولَ اللَّهِ بَعْدَ أَنْ قَالَهَا قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ لاَ تَقْتُلْهُ ‏"‏ ‏.‏ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُ قَدْ قَطَعَ يَدِي ثُمَّ قَالَ ذَلِكَ بَعْدَ أَنْ قَطَعَهَا أَفَأَقْتُلُهُ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ لاَ تَقْتُلْهُ فَإِنْ قَتَلْتَهُ فَإِنَّهُ بِمَنْزِلَتِكَ قَبْلَ أَنْ تَقْتُلَهُ وَإِنَّكَ بِمَنْزِلَتِهِ قَبْلَ أَنْ يَقُولَ كَلِمَتَهُ الَّتِي قَالَ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Miqdad b. Aswad that he said. Messenger of Allah, you just see (here is a point):If I encountered a person amongst the infidels (in the battlefield) and he attacked me and struck me and cut off one of my hands with the sword. Then he (in order to protect himself from me) took shelter of a tree and said: I become Muslim for Allah''s sake. Messenger of Allah, can I kill him after he had uttered this? The Messenger of Allah (ﷺ) said: Do not kill him. I (the narrator) said: Messenger of Allah, he cut off my hand and uttered this after amputating it; should I then kill him? The Messenger of Allah (ﷺ) said: Don''t kill him, for I you kill him, verily he would be in a position where you had been before killing him and verily you would be in a position where he had been before uttering (kalima).', NULL, NULL, 'https://sunnah.com/muslim:173', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 174, 'حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ، وَعَبْدُ بْنُ حُمَيْدٍ، قَالاَ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ، قَالَ أَخْبَرَنَا مَعْمَرٌ، ح وَحَدَّثَنَا إِسْحَاقُ بْنُ مُوسَى الأَنْصَارِيُّ، حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ، عَنِ الأَوْزَاعِيِّ، ح وَحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، أَخْبَرَنَا ابْنُ جُرَيْجٍ، جَمِيعًا عَنِ الزُّهْرِيِّ، بِهَذَا الإِسْنَادِ أَمَّا الأَوْزَاعِيُّ وَابْنُ جُرَيْجٍ فَفِي حَدِيثِهِمَا قَالَ أَسْلَمْتُ لِلَّهِ ‏.‏ كَمَا قَالَ اللَّيْثُ فِي حَدِيثِهِ ‏.‏ وَأَمَّا مَعْمَرٌ فَفِي حَدِيثِهِ فَلَمَّا أَهْوَيْتُ لأَقْتُلَهُ قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ ‏.‏', NULL, 'The same hadith has been transmitted by the same chain of narrators. The hadith transmitted by Auza''i and Ibn Juraij contains these words:I embraced Islam for Allah''s sake. and in the hadith narrated by Ma''mar the words are: I knelt down to kill him, that he said; There is no god but Allah.', NULL, NULL, 'https://sunnah.com/muslim:174', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 175, 'وَحَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى، أَخْبَرَنَا ابْنُ وَهْبٍ، قَالَ أَخْبَرَنِي يُونُسُ، عَنِ ابْنِ شِهَابٍ، قَالَ حَدَّثَنِي عَطَاءُ بْنُ يَزِيدَ اللَّيْثِيُّ، ثُمَّ الْجُنْدَعِيُّ أَنَّ عُبَيْدَ، اللَّهِ بْنَ عَدِيِّ بْنِ الْخِيَارِ أَخْبَرَهُ أَنَّ الْمِقْدَادَ بْنَ عَمْرِو بْنِ الأَسْوَدِ الْكِنْدِيَّ - وَكَانَ حَلِيفًا لِبَنِي زُهْرَةَ وَكَانَ مِمَّنْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صلى الله عليه وسلم - أَنَّهُ قَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ لَقِيتُ رَجُلاً مِنَ الْكُفَّارِ ثُمَّ ذَكَرَ بِمِثْلِ حَدِيثِ اللَّيْثِ ‏.‏', NULL, 'It is narrated by Miqdad, and he was an ally of B. Zuhra and was of those who participated in the Battle of Badr along with the Messenger of Allah, that he said:Messenger of Allah, here is a point: If I happened to encounter a person amongst the infidels (in the battle). Then he narrated a hadith similar to the one transmitted by Laith.', NULL, NULL, 'https://sunnah.com/muslim:175', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 176, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو خَالِدٍ الأَحْمَرُ، ح وَحَدَّثَنَا أَبُو كُرَيْبٍ، وَإِسْحَاقُ بْنُ إِبْرَاهِيمَ، عَنْ أَبِي مُعَاوِيَةَ، كِلاَهُمَا عَنِ الأَعْمَشِ، عَنْ أَبِي ظِبْيَانَ، عَنْ أُسَامَةَ بْنِ زَيْدٍ، وَهَذَا، حَدِيثُ ابْنِ أَبِي شَيْبَةَ قَالَ بَعَثَنَا رَسُولُ اللَّهِ صلى الله عليه وسلم فِي سَرِيَّةٍ فَصَبَّحْنَا الْحُرَقَاتِ مِنْ جُهَيْنَةَ فَأَدْرَكْتُ رَجُلاً فَقَالَ لاَ إِلَهَ إِلاَّ اللَّهُ ‏.‏ فَطَعَنْتُهُ فَوَقَعَ فِي نَفْسِي مِنْ ذَلِكَ فَذَكَرْتُهُ لِلنَّبِيِّ صلى الله عليه وسلم فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَقَالَ لاَ إِلَهَ إِلاَّ اللَّهُ وَقَتَلْتَهُ ‏"‏ ‏.‏ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا قَالَهَا خَوْفًا مِنَ السِّلاَحِ ‏.‏ قَالَ ‏"‏ أَفَلاَ شَقَقْتَ عَنْ قَلْبِهِ حَتَّى تَعْلَمَ أَقَالَهَا أَمْ لاَ ‏"‏ ‏.‏ فَمَازَالَ يُكَرِّرُهَا عَلَىَّ حَتَّى تَمَنَّيْتُ أَنِّي أَسْلَمْتُ يَوْمَئِذٍ ‏.‏ قَالَ فَقَالَ سَعْدٌ وَأَنَا وَاللَّهِ لاَ أَقْتُلُ مُسْلِمًا حَتَّى يَقْتُلَهُ ذُو الْبُطَيْنِ ‏.‏ يَعْنِي أُسَامَةَ قَالَ قَالَ رَجُلٌ أَلَمْ يَقُلِ اللَّهُ ‏{‏ وَقَاتِلُوهُمْ حَتَّى لاَ تَكُونَ فِتْنَةٌ وَيَكُونَ الدِّينُ كُلُّهُ لِلَّهِ‏}‏ فَقَالَ سَعْدٌ قَدْ قَاتَلْنَا حَتَّى لاَ تَكُونَ فِتْنَةٌ وَأَنْتَ وَأَصْحَابُكَ تُرِيدُونَ أَنْ تُقَاتِلُوا حَتَّى تَكُونَ فِتْنَةٌ ‏.‏', NULL, 'It is narrated on the authority of Usama b. Zaid that the Messenger of Allah (ﷺ) sent us in a raiding party. We raided Huraqat of Juhaina in the morning. I caught hold of a man and he said:There is no god but Allah, I attacked him with a spear. It once occurred to me and I talked about it to the Apostle (ﷺ). The Messenger of Allah (ﷺ) said: Did he profess" There is no god but Allah," and even then you killed him? I said: Messenger of Allah, he made a profession of it out of the fear of the weapon. He (the Holy Prophet) observed: Did you tear his heart in order to find out whether it had professed or not? And he went on repeating it to me till I wished I had embraced Islam that day. Sa''d said: By Allah, I would never kill any Muslim so long as a person with a heavy belly, i. e., Usama, would not kill. Upon this a person remarked: Did Allah not say this: And fight them until there is no more mischief and religion is wholly for Allah? Sa''d said: We fought so that there should be no mischief, but you and your companions wish to fight so that there should be mischief.', NULL, NULL, 'https://sunnah.com/muslim:176', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 177, 'حَدَّثَنَا يَعْقُوبُ الدَّوْرَقِيُّ، حَدَّثَنَا هُشَيْمٌ، أَخْبَرَنَا حُصَيْنٌ، حَدَّثَنَا أَبُو ظِبْيَانَ، قَالَ سَمِعْتُ أُسَامَةَ بْنَ زَيْدِ بْنِ حَارِثَةَ، يُحَدِّثُ قَالَ بَعَثَنَا رَسُولُ اللَّهِ صلى الله عليه وسلم إِلَى الْحُرَقَةِ مِنْ جُهَيْنَةَ فَصَبَّحْنَا الْقَوْمَ فَهَزَمْنَاهُمْ وَلَحِقْتُ أَنَا وَرَجُلٌ مِنَ الأَنْصَارِ رَجُلاً مِنْهُمْ فَلَمَّا غَشَيْنَاهُ قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ ‏.‏ فَكَفَّ عَنْهُ الأَنْصَارِيُّ وَطَعَنْتُهُ بِرُمْحِي حَتَّى قَتَلْتُهُ ‏.‏ قَالَ فَلَمَّا قَدِمْنَا بَلَغَ ذَلِكَ النَّبِيَّ صلى الله عليه وسلم فَقَالَ لِي ‏"‏ يَا أُسَامَةُ أَقَتَلْتَهُ بَعْدَ مَا قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ ‏"‏ ‏.‏ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا كَانَ مُتَعَوِّذًا ‏.‏ قَالَ فَقَالَ ‏"‏ أَقَتَلْتَهُ بَعْدَ مَا قَالَ لاَ إِلَهَ إِلاَّ اللَّهُ ‏"‏ ‏.‏ قَالَ فَمَازَالَ يُكَرِّرُهَا عَلَىَّ حَتَّى تَمَنَّيْتُ أَنِّي لَمْ أَكُنْ أَسْلَمْتُ قَبْلَ ذَلِكَ الْيَوْمِ ‏.‏', NULL, 'It is narrated on the authority of Usama b. Zaid:The Messenger of Allah may peace be upon him) sent us to Huraqat, a tribe of Juhaina. We attacked that tribe early in the morning and defeated them and I and a man from the Ansar caught hold of a person (of the defeated tribe). When we overcame him, he said: There is no god but Allah. At that moment the Ansari spared him, but I attacked him with my spear and killed him. The news had already reached the Apostle (peace be upon him), so when we came back he (the Apostle) said to me: Usama, did you kill him after he had made the profession: There is no god but Allah? I said. Messenger of Allah, he did it only as a shelter. The Prophet observed: Did you kill him after he had made the profession that there is no god but Allah? He (the Holy Prophet) went on repeating this to me till I wished I had not embraced Islam before that day.', 'It is narrated on the authority of Usama b. Zaid', NULL, 'https://sunnah.com/muslim:177', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 180, '"‏ جَنَّتَانِ مِنْ فِضَّةٍ آنِيَتُهُمَا وَمَا فِيهِمَا وَجَنَّتَانِ مِنْ ذَهَبٍ آنِيَتُهُمَا وَمَا فِيهِمَا وَمَا بَيْنَ الْقَوْمِ وَبَيْنَ أَنْ يَنْظُرُوا إِلَى رَبِّهِمْ إِلاَّ رِدَاءُ الْكِبْرِيَاءِ عَلَى وَجْهِهِ فِي جَنَّةِ عَدْنٍ ‏"', NULL, '''Abdullah b. Qais transmitted on the authority of his father (Abu Musa Ash''ari) that the Apostle (ﷺ) said:There would be two gardens (in Paradise) the vessels and contents of which would be of silver, and two gardens whose vessels and contents would be of gold. The only thing intervening to hinder the people from looking at their Lord will be the mantle of Grandeur over His face in the Garden of Eden.', NULL, NULL, 'https://sunnah.com/muslim:180', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 184, 'حَدَّثَنَا يَحْيَى بْنُ يَحْيَى، أَخْبَرَنَا أَبُو مُعَاوِيَةَ، ح وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو مُعَاوِيَةَ، وَوَكِيعٌ، ح وَحَدَّثَنَا ابْنُ نُمَيْرٍ، حَدَّثَنَا أَبِي جَمِيعًا، عَنِ الأَعْمَشِ، عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ، عَنْ مَسْرُوقٍ، عَنْ عَبْدِ اللَّهِ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ لَيْسَ مِنَّا مَنْ ضَرَبَ الْخُدُودَ أَوْ شَقَّ الْجُيُوبَ أَوْ دَعَا بِدَعْوَى الْجَاهِلِيَّةِ ‏"‏ ‏.‏ هَذَا حَدِيثُ يَحْيَى وَأَمَّا ابْنُ نُمَيْرٍ وَأَبُو بَكْرٍ فَقَالاَ ‏"‏ وَشَقَّ وَدَعَا ‏"‏ بِغَيْرِ أَلِفٍ ‏.‏', NULL, 'It is narrated on the authority of Abdullah b. Mas''ud that the Prophet observed:He is not one of us (one among the Ummah of Islam) who beat the cheeks or tore the front opening of the shirt or uttered the slogans of (the days of) Jahiliya (ignorance). Ibn Numair and Abu Bakr said (instead of the word" au" (or) it is" wa" [and] the words are) and tore and uttered (the slogans) of Jahiliya without" alif".', 'It is narrated on the authority of Abdullah b. Mas''ud that the Prophet observed', NULL, 'https://sunnah.com/muslim:184', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 185, '"‏ وَشَقَّ وَدَعَا ‏"', NULL, 'This hadith has been narrated by A''mash with the same chain of narrators and the transmitters said:He tore and called.', NULL, NULL, 'https://sunnah.com/muslim:185', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 186, 'حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى الْقَنْطَرِيُّ، حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ، عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ، أَنَّ الْقَاسِمَ بْنَ مُخَيْمِرَةَ، حَدَّثَهُ قَالَ حَدَّثَنِي أَبُو بُرْدَةَ بْنُ أَبِي مُوسَى، قَالَ وَجِعَ أَبُو مُوسَى وَجَعًا فَغُشِيَ عَلَيْهِ وَرَأْسُهُ فِي حَجْرِ امْرَأَةٍ مِنْ أَهْلِهِ فَصَاحَتِ امْرَأَةٌ مِنْ أَهْلِهِ فَلَمْ يَسْتَطِعْ أَنْ يَرُدَّ عَلَيْهَا شَيْئًا فَلَمَّا أَفَاقَ قَالَ أَنَا بَرِيءٌ مِمَّا بَرِئَ مِنْهُ رَسُولُ اللَّهِ صلى الله عليه وسلم فَإِنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم بَرِئَ مِنَ الصَّالِقَةِ وَالْحَالِقَةِ وَالشَّاقَّةِ ‏.‏', NULL, 'It is narrated on the authority of Abu Burda b. Abu Musa that Abu Musa was afflicted with grave pain and he became unconscious and his head was in the lap of a lady of his household. One of the women of his household walled. He (Abu Musa) was unable (because of weakness) to say anything to her. But when he was a bit recovered he said:I have no concern with one with whom the Messenger of Allah (ﷺ) has no concern, Verily the Messenger of Allah (ﷺ) has no concern with that woman who wails loudly, shaves her hair and tears (her garment in grief).', NULL, NULL, 'https://sunnah.com/muslim:186', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 187, '"‏ أَنَا بَرِيءٌ مِمَّنْ حَلَقَ وَسَلَقَ وَخَرَقَ ‏"', NULL, 'It is narrated on the authority of Abu Burda that Abu Musa fell unconscious and his wife Umm Abdullah came there and wailed loudly. When he felt relief he said:Don''t you know? -and narrated to her: Verily the Messenger of Allah (ﷺ) said: I have no concern with one who shaved her hair, lamented loudly and tore (her clothes in grief).', NULL, NULL, 'https://sunnah.com/muslim:187', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 188, 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُطِيعٍ، حَدَّثَنَا هُشَيْمٌ، عَنْ حُصَيْنٍ، عَنْ عِيَاضٍ الأَشْعَرِيِّ، عَنِ امْرَأَةِ أَبِي مُوسَى، عَنْ أَبِي مُوسَى، عَنِ النَّبِيِّ صلى الله عليه وسلم ح
وَحَدَّثَنِيهِ حَجَّاجُ بْنُ الشَّاعِرِ، حَدَّثَنَا عَبْدُ الصَّمَدِ، قَالَ حَدَّثَنِي أَبِي، حَدَّثَنَا دَاوُدُ، - يَعْنِي ابْنَ أَبِي هِنْدٍ - حَدَّثَنَا عَاصِمٌ، عَنْ صَفْوَانَ بْنِ مُحْرِزٍ، عَنْ أَبِي مُوسَى، عَنِ النَّبِيِّ صلى الله عليه وسلم ح
وَحَدَّثَنِي الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ، حَدَّثَنَا عَبْدُ الصَّمَدِ، أَخْبَرَنَا شُعْبَةُ، عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ، عَنْ رِبْعِيِّ بْنِ حِرَاشٍ، عَنْ أَبِي مُوسَى، عَنِ النَّبِيِّ صلى الله عليه وسلم بِهَذَا الْحَدِيثِ ‏.‏ غَيْرَ أَنَّ فِي حَدِيثِ عِيَاضٍ الأَشْعَرِيِّ قَالَ ‏"‏ لَيْسَ مِنَّا ‏"‏ ‏.‏ وَلَمْ يَقُلْ ‏"‏ بَرِيءٌ ‏"‏ ‏.‏', NULL, 'This hadith is narrated on the authority of Abu Musa with this change only:That (the Holy Prophet) did not say that he had no concern but said: He is not one of us.', 'This hadith is narrated on the authority of Abu Musa with this change only', NULL, 'https://sunnah.com/muslim:188', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 189, '"‏ لاَ يَدْخُلُ الْجَنَّةَ نَمَّامٌ ‏"', NULL, 'It is reported from Hudhaifa that news reached him (the Holy Prophet) that a certain man carried tales. Upon this Hudhaifa remarked:I heard Allah''s Messenger (ﷺ) saying: The tale-bearer shall not enter Paradise.', NULL, NULL, 'https://sunnah.com/muslim:189', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 190, '"‏ لاَ يَدْخُلُ الْجَنَّةَ قَتَّاتٌ ‏"', NULL, 'It is reported on the authority of Hammam b, al-Harith that a man used to carry tales to the governor. We were sitting in the mosque. the people said:He is one who carries tales to the governor. He (the narrator) said: Then he came and sat with us. Thereupon Hudhaifa remarked: I heard the Messenger of Allah (ﷺ) saying: The beater of false tales would never enter heaven.', NULL, NULL, 'https://sunnah.com/muslim:190', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 191, '"‏ لاَ يَدْخُلُ الْجَنَّةَ قَتَّاتٌ ‏"', NULL, 'It is narrated on the authority of Hammam b. al-Harith:We were sitting with Hudhaifa in the mosque. A man came and sat along with us. It was said to Hudhaifa that he was the man who carried tales to the ruler. Hudhaifa remarked with the intention of conveying to him: I have heard the Messenger of Allah (ﷺ) saying: The tale-bearer will not enter Paradise.', 'It is narrated on the authority of Hammam b. al-Harith', NULL, 'https://sunnah.com/muslim:191', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 192, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَمُحَمَّدُ بْنُ الْمُثَنَّى، وَابْنُ، بَشَّارٍ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، عَنْ شُعْبَةَ، عَنْ عَلِيِّ بْنِ مُدْرِكٍ، عَنْ أَبِي زُرْعَةَ، عَنْ خَرَشَةَ بْنِ الْحُرِّ، عَنْ أَبِي ذَرٍّ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ ثَلاَثَةٌ لاَ يُكَلِّمُهُمُ اللَّهُ يَوْمَ الْقِيَامَةِ وَلاَ يَنْظُرُ إِلَيْهِمْ وَلاَ يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ ‏"‏ قَالَ فَقَرَأَهَا رَسُولُ اللَّهِ صلى الله عليه وسلم ثَلاَثَ مِرَارٍ ‏.‏ قَالَ أَبُو ذَرٍّ خَابُوا وَخَسِرُوا مَنْ هُمْ يَا رَسُولَ اللَّهِ قَالَ ‏"‏ الْمُسْبِلُ وَالْمَنَّانُ وَالْمُنَفِّقُ سِلْعَتَهُ بِالْحَلِفِ الْكَاذِبِ ‏"‏ ‏.‏', NULL, 'It is narrated o the authority of Abu Dharr that the Messenger of Allah (may ace he upon him) observed:Three are the (persons) with whom Allah would neither speak on the Day of Resurrection, nor would look at them nor would absolve the and there is a painful chastisement for them. The Messenger of Allah (ﷺ) repeated it three times. Abu Dharr remarked: They failed and they lost; who are these persons, Messenger of Allah? Upon this he (the Holy) Prophet) observed: They are: the dragger of lower garment, the recounter of obligation the seller of goods by false oath.', NULL, NULL, 'https://sunnah.com/muslim:192', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 193, '"‏ ثَلاَثَةٌ لاَ يُكَلِّمُهُمُ اللَّهُ يَوْمَ الْقِيَامَةِ الْمَنَّانُ الَّذِي لاَ يُعْطِي شَيْئًا إِلاَّ مَنَّهُ وَالْمُنَفِّقُ سِلْعَتَهُ بِالْحَلِفِ الْفَاجِرِ وَالْمُسْبِلُ إِزَارَهُ ‏"', NULL, 'It is narrated on the authority of Abu Dharr who narrates that the Prophet (ﷺ) observed:Three are the persons with whom Allah would not speak on the Day of Resurrection: the bestower of gift who does not give anything but by laying obligation on him, the seller of goods who sells them by taking false oath and one who hangs low his lower garment.', NULL, NULL, 'https://sunnah.com/muslim:193', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 194, '"‏ ثَلاَثَةٌ لاَ يُكَلِّمُهُمُ اللَّهُ وَلاَ يَنْظُرُ إِلَيْهِمْ وَلاَ يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ ‏"', NULL, 'Bishr b. Khalid has narrated this hadith on the authority of Sulaiman with the same chain of transmitters with this addition:Allah shall neither speak nor look at nor absolve then, and there is a tormenting punishment for them.', NULL, NULL, 'https://sunnah.com/muslim:194', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 195, 'حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفِ بْنِ خَلِيفَةَ الْبَجَلِيُّ، حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ، حَدَّثَنَا أَبُو مَالِكٍ الأَشْجَعِيُّ، عَنْ أَبِي حَازِمٍ، عَنْ أَبِي هُرَيْرَةَ، وَأَبُو مَالِكٍ عَنْ رِبْعِيٍّ، عَنْ حُذَيْفَةَ، قَالاَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ يَجْمَعُ اللَّهُ تَبَارَكَ وَتَعَالَى النَّاسَ فَيَقُومُ الْمُؤْمِنُونَ حَتَّى تُزْلَفَ لَهُمُ الْجَنَّةُ فَيَأْتُونَ آدَمَ فَيَقُولُونَ يَا أَبَانَا اسْتَفْتِحْ لَنَا الْجَنَّةَ ‏.‏ فَيَقُولُ وَهَلْ أَخْرَجَكُمْ مِنَ الْجَنَّةِ إِلاَّ خَطِيئَةُ أَبِيكُمْ آدَمَ لَسْتُ بِصَاحِبِ ذَلِكَ اذْهَبُوا إِلَى ابْنِي إِبْرَاهِيمَ خَلِيلِ اللَّهِ - قَالَ - فَيَقُولُ إِبْرَاهِيمُ لَسْتُ بِصَاحِبِ ذَلِكَ إِنَّمَا كُنْتُ خَلِيلاً مِنْ وَرَاءَ وَرَاءَ اعْمِدُوا إِلَى مُوسَى صلى الله عليه وسلم الَّذِي كَلَّمَهُ اللَّهُ تَكْلِيمًا ‏.‏ فَيَأْتُونَ مُوسَى صلى الله عليه وسلم فَيَقُولُ لَسْتُ بِصَاحِبِ ذَلِكَ اذْهَبُوا إِلَى عِيسَى كَلِمَةِ اللَّهِ وَرُوحِهِ ‏.‏ فَيَقُولُ عِيسَى صلى الله عليه وسلم لَسْتُ بِصَاحِبِ ذَلِكَ ‏.‏ فَيَأْتُونَ مُحَمَّدًا صلى الله عليه وسلم فَيَقُومُ فَيُؤْذَنُ لَهُ وَتُرْسَلُ الأَمَانَةُ وَالرَّحِمُ فَتَقُومَانِ جَنَبَتَىِ الصِّرَاطِ يَمِينًا وَشِمَالاً فَيَمُرُّ أَوَّلُكُمْ كَالْبَرْقِ ‏"‏ ‏.‏ قَالَ قُلْتُ بِأَبِي أَنْتَ وَأُمِّي أَىُّ شَىْءٍ كَمَرِّ الْبَرْقِ قَالَ ‏"‏ أَلَمْ تَرَوْا إِلَى الْبَرْقِ كَيْفَ يَمُرُّ وَيَرْجِعُ فِي طَرْفَةِ يْنٍ ثُمَّ كَمَرِّ الرِّيحِ ثُمَّ كَمَرِّ الطَّيْرِ وَشَدِّ الرِّجَالِ تَجْرِي بِهِمْ أَعْمَالُهُمْ وَنَبِيُّكُمْ قَائِمٌ عَلَى الصِّرَاطِ يَقُولُ رَبِّ سَلِّمْ سَلِّمْ حَتَّى تَعْجِزَ أَعْمَالُ الْعِبَادِ حَتَّى يَجِيءَ الرَّجُلُ فَلاَ يَسْتَطِيعُ السَّيْرَ إِلاَّ زَحْفًا - قَالَ - وَفِي حَافَتَىِ الصِّرَاطِ كَلاَلِيبُ مُعَلَّقَةٌ مَأْمُورَةٌ بِأَخْذِ مَنْ أُمِرَتْ بِهِ فَمَخْدُوشٌ نَاجٍ وَمَكْدُوسٌ فِي النَّارِ ‏"‏ ‏.‏ وَالَّذِي نَفْسُ أَبِي هُرَيْرَةَ بِيَدِهِ إِنَّ قَعْرَ جَهَنَّمَ لَسَبْعُونَ خَرِيفًا ‏.‏', NULL, 'It is narrated on the authority of Abu Huraira and Hudhaifa that the Messenger of Allah (ﷺ) said:Allah, the Blessed and Exalted, would gather people. The believers would stand till the Paradise would be brought near them. They would come to Adam and say: O our father, open for us the Paradise. He would say: What turned ye out from the Paradise was the sin of your father Adam. I am not in a position to do that; better go to my son Ibrahim, the Friend of Allah. He (the Holy Prophet) said: He (Ibrahim) would say: I am not in a position to do that. Verily I had been the Friend (of Allah) from beyond, beyond; you better approach Moses (peace be upon him) with whom Allah conversed. They would come to Moses (peace be upon him), but he would say: I am not in a position to do that; you better go to Jesus, the Word of Allah and His Spirit. Jesus (peace be upon him) would say: I am not in a position to do that. So they would come to Muhammad (ﷺ). He would then be permitted (to open the door of Paradise). Trustworthiness and kinship would be despatched, and these would stand on the right and left of the Path and the first of you would pass with (the swiftness) of lightning. He (the narrator) said: I said, O thou who art far dearer to me than my father and my mother I which thing is like the passing of lightning? He said: Have you not seen lightning, how it passes and then comes back within the twinkling of an eye? Then (they would pass) like the passing of the wind, then like the passing of a bird, and the hastening of persons would be according to their deeds, and your Apostle would be standing on the Path saying: Save, O my Lord, save. (The people would go on passing) till the deeds of the servants would be failing in strength, till a man would come who would find it hard to go along (that Path) but crawlingly. He (the narrator) said: And on the sides of the Path hooks would be suspended ready to catch anyone whom these would be required (to catch). There would be those who would somehow or other succeed in trasversing that Path and some would be piled up in Hell. By Him in Whose Hand is the life of Abu Huraira it would take one seventy years to fathom the depth of Hell.', NULL, NULL, 'https://sunnah.com/muslim:195', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 196, '"‏ ثَلاَثٌ لاَ يُكَلِّمُهُمُ اللَّهُ يَوْمَ الْقِيَامَةِ وَلاَ يَنْظُرُ إِلَيْهِمْ وَلاَ يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ رَجُلٌ عَلَى فَضْلِ مَاءٍ بِالْفَلاَةِ يَمْنَعُهُ مِنِ ابْنِ السَّبِيلِ وَرَجُلٌ بَايَعَ رَجُلاً بِسِلْعَةٍ بَعْدَ الْعَصْرِ فَحَلَفَ لَهُ بِاللَّهِ لأَخَذَهَا بِكَذَا وَكَذَا فَصَدَّقَهُ وَهُوَ عَلَى غَيْرِ ذَلِكَ وَرَجُلٌ بَايَعَ إِمَامًا لاَ يُبَايِعُهُ إِلاَّ لِدُنْيَا فَإِنْ أَعْطَاهُ مِنْهَا وَفَى وَإِنْ لَمْ يُعْطِهِ مِنْهَا لَمْ يَفِ ‏"', NULL, 'Abu Huraira narrated on the authority of Abu Bakr that the Messenger of Allah (ﷺ) said:Three are the persons with whom Allah would neither speak on the Day of Resurrection, nor would He look towards them, nor would purify them (from sins), and there would be a tormenting chastisement for them: a person who in the waterless desert has more water (than his need) and he refuses to give it to the traveller and a person who sold a commodity to another person in the afternoon and took an oath of Allah that he had bought it at such and such price and he (the buyer) accepted it to be true though it was not a fact, and a person who pledged allegiance to the Imam but for the sake of the world (material gains). And if the Imam bestowed on him (something) out of that (worldly riches) he stood by his allegiance and if he did not give him, he did not fulfil the allegiance.', NULL, NULL, 'https://sunnah.com/muslim:196', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 197, '"‏ وَرَجُلٌ سَاوَمَ رَجُلاً بِسِلْعَةٍ ‏"', NULL, 'The same hadith has been transmitted by another chain of transmitters with the exception of these words:He offered for sale a commodity to another person.', NULL, NULL, 'https://sunnah.com/muslim:197', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 198, '"‏ ثَلاَثَةٌ لاَ يُكَلِّمُهُمُ اللَّهُ وَلاَ يَنْظُرُ إِلَيْهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ رَجُلٌ حَلَفَ عَلَى يَمِينٍ بَعْدَ صَلاَةِ الْعَصْرِ عَلَى مَالِ مُسْلِمٍ فَاقْتَطَعَهُ ‏"', NULL, 'This hadith has been narrated on the authority of Abu Huraira that he (the Messenger of Allah) observed:Three are the persons with whom Allah would neither speak (on the Day of Resurrection) nor would He look at them, and there would be a painful chastisement for them, a person who took an oath on the goods of a Muslim in the afternoon and then broke it. The rest of the hadith is the same as narrated by A''mash.', NULL, NULL, 'https://sunnah.com/muslim:198', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 199, '"‏ مَنَ قَتَلَ نَفْسَهُ بِحَدِيدَةٍ فَحَدِيدَتُهُ فِي يَدِهِ يَتَوَجَّأُ بِهَا فِي بَطْنِهِ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ شَرِبَ سَمًّا فَقَتَلَ نَفْسَهُ فَهُوَ يَتَحَسَّاهُ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ تَرَدَّى مِنْ جَبَلٍ فَقَتَلَ نَفْسَهُ فَهُوَ يَتَرَدَّى فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:He who killed himself with steel (weapon) would be the eternal denizen of the Fire of Hell and he would have that weapon in his hand and would be thrusting that in his stomach for ever and ever, he who drank poison and killed himself would sip that in the Fire of Hell where he is doomed for ever and ever; and he who killed himself by falling from (the top of) a mountain would constantly fall in the Fire of Hell and would live there for ever and ever.', NULL, NULL, 'https://sunnah.com/muslim:199', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 200, 'وَحَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ، حَدَّثَنَا جَرِيرٌ، ح وَحَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الأَشْعَثِيُّ، حَدَّثَنَا عَبْثَرٌ، ح وَحَدَّثَنِي يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ، حَدَّثَنَا خَالِدٌ، - يَعْنِي ابْنَ الْحَارِثِ - حَدَّثَنَا شُعْبَةُ، كُلُّهُمْ بِهَذَا الإِسْنَادِ مِثْلَهُ ‏.‏ وَفِي رِوَايَةِ شُعْبَةَ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ ذَكْوَانَ ‏.‏', NULL, 'This hadith has been narrated by another chain of transmitters.', NULL, NULL, 'https://sunnah.com/muslim:200', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 201, '"‏ مَنْ حَلَفَ عَلَى يَمِينٍ بِمِلَّةٍ غَيْرِ الإِسْلاَمِ كَاذِبًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَىْءٍ عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ وَلَيْسَ عَلَى رَجُلٍ نَذْرٌ فِي شَىْءٍ لاَ يَمْلِكُهُ ‏"', NULL, 'Thabit b. Dahhak reported that he pledged allegiance to the Messenger of Allah (ﷺ) under the Tree, and verily the Messenger of Allah (ﷺ) observed:He who took an oath of a religion other than Islam, in the state of being a liar, would became so, as he professed. He who killed himself with a thing would be tormented on the Day of Resurrection with that very thing. One is not obliged to offer votive offering of a thing which is not in his possession.', NULL, NULL, 'https://sunnah.com/muslim:201', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 202, '"‏ لَيْسَ عَلَى رَجُلٍ نَذْرٌ فِيمَا لاَ يَمْلِكُ وَلَعْنُ الْمُؤْمِنِ كَقَتْلِهِ وَمَنْ قَتَلَ نَفْسَهُ بِشَىْءٍ فِي الدُّنْيَا عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ وَمَنِ ادَّعَى دَعْوَى كَاذِبَةً لِيَتَكَثَّرَ بِهَا لَمْ يَزِدْهُ اللَّهُ إِلاَّ قِلَّةً وَمَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ فَاجِرَةٍ ‏"', NULL, 'It is narrated on the authority of Thabit b. al-Dahhak that the Messenger of Allah (ﷺ) observes:None is obliged to give votive offering (of a thing) which is not in his possession and the cursing of a believer is tantamount to killing him, and he who killed himself with a thing in this world would be tormented with that (very thing) on the Day of Resurrection, and he who made a false claim to increase (his wealth), Allah would make no addition but that of paucity, and he who perjured would earn the wrath of God', NULL, NULL, 'https://sunnah.com/muslim:202', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 203, 'حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ، وَإِسْحَاقُ بْنُ مَنْصُورٍ، وَعَبْدُ الْوَارِثِ بْنُ عَبْدِ الصَّمَدِ، كُلُّهُمْ عَنْ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ، عَنْ شُعْبَةَ، عَنْ أَيُّوبَ، عَنْ أَبِي قِلاَبَةَ، عَنْ ثَابِتِ بْنِ الضَّحَّاكِ الأَنْصَارِيِّ، ح', NULL, 'It is narrated on the authority of Thabit b. Dahhak that the Messenger of Allah (ﷺ) observed:He who took deliberately a false oath on a religion other than Islam would become that which he had professed. And he who killed himself with anything Allah would torment him with that in the Fire of Hell.', NULL, NULL, 'https://sunnah.com/muslim:203', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 204, 'وَحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ، عَنْ عَبْدِ الرَّزَّاقِ، عَنِ الثَّوْرِيِّ، عَنْ خَالِدٍ الْحَذَّاءِ، عَنْ أَبِي قِلاَبَةَ، عَنْ ثَابِتِ بْنِ الضَّحَّاكِ، قَالَ قَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ مَنْ حَلَفَ بِمِلَّةٍ سِوَى الإِسْلاَمِ كَاذِبًا مُتَعَمِّدًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَىْءٍ عَذَّبَهُ اللَّهُ بِهِ فِي نَارِ جَهَنَّمَ ‏"‏ ‏.‏ هَذَا حَدِيثُ سُفْيَانَ ‏.‏ وَأَمَّا شُعْبَةُ فَحَدِيثُهُ أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ مَنْ حَلَفَ بِمِلَّةٍ سِوَى الإِسْلاَمِ كَاذِبًا فَهُوَ كَمَا قَالَ وَمَنْ ذَبَحَ نَفْسَهُ بِشَىْءٍ ذُبِحَ بِهِ يَوْمَ الْقِيَامَةِ ‏"‏ ‏.‏', NULL, 'In the hadith narrated by Shu''ba the words are:Verily the Messenger of Allah (ﷺ) said: He who took an oath on a religion other than Islam as a liar would become so as he said, and he who slaughtered himself with a thing would be slaughtered with that on the Day of Resurrection.', 'In the hadith narrated by Shu''ba the words are', NULL, 'https://sunnah.com/muslim:204', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 205, 'حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ، حَدَّثَنَا وَكِيعٌ، وَيُونُسُ بْنُ بُكَيْرٍ، قَالاَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ، قَالَتْ لَمَّا نَزَلَتْ ‏{‏ وَأَنْذِرْ عَشِيرَتَكَ الأَقْرَبِينَ‏}‏ قَامَ رَسُولُ اللَّهِ صلى الله عليه وسلم عَلَى الصَّفَا فَقَالَ ‏"‏ يَا فَاطِمَةَ بِنْتَ مُحَمَّدٍ يَا صَفِيَّةُ بِنْتَ عَبْدِ الْمُطَّلِبِ يَا بَنِي عَبْدِ الْمُطَّلِبِ لاَ أَمْلِكُ لَكُمْ مِنَ اللَّهِ شَيْئًا سَلُونِي مِنْ مَالِي مَا شِئْتُمْ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of ''A''isha that when this verse was revealed:" And warn thy nearest kindred," the Messenger of Allah (ﷺ) stood up on Safa'' and said: O Fatima, daughter of Muhammad. O Safiya, daughter of ''Abd al-Muttalib, O sons of ''Abd al-Muttalib. I have nothing which can avail you against Allah; you may ask me what you want of my worldly belongings.', 'It is narrated on the authority of ''A''isha that when this verse was revealed', NULL, 'https://sunnah.com/muslim:205', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 207, '"‏ إِنَّ رَجُلاً مِمَّنْ كَانَ قَبْلَكُمْ خَرَجَتْ بِهِ قَرْحَةٌ فَلَمَّا آذَتْهُ انْتَزَعَ سَهْمًا مِنْ كِنَانَتِهِ فَنَكَأَهَا فَلَمْ يَرْقَإِ الدَّمُ حَتَّى مَاتَ ‏.‏ قَالَ رَبُّكُمْ قَدْ حَرَّمْتُ عَلَيْهِ الْجَنَّةَ ‏"', NULL, 'It is reported on the authority of Hasan:A person belonging to the people of the past suffered from a boil, when it pained him, he drew out an arrow from the quiver and pierced it. And the bleeding did not stop till he died. Your Lord said: I forbade his entrance into Paradise. Then he (Hasan) stretched his hand towards the mosque and said: By God, Jundab transmitted this hadith to me from the Messenger of Allah (ﷺ) in this very mosque.', 'It is reported on the authority of Hasan', NULL, 'https://sunnah.com/muslim:207', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 208, '"‏ خَرَجَ بِرَجُلٍ فِيمَنْ كَانَ قَبْلَكُمْ خُرَاجٌ ‏"', NULL, 'It is reported on the authority of Hasan:Jundab b. ''Abdullah al-Bajali narrated this hadith in this mosque which we can neither forget and at the same time we have no apprehension that Jundab could attribute a lie to the Messenger of Allah (ﷺ). He (the Holy Prophet) observed: A person belonging to the people of the past suffered from a boil, and then the rest of the hadith was narrated.', 'It is reported on the authority of Hasan', NULL, 'https://sunnah.com/muslim:208', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 210, '"‏ لَعَلَّهُ تَنْفَعُهُ شَفَاعَتِي يَوْمَ الْقِيَامَةِ فَيُجْعَلُ فِي ضَحْضَاحٍ مِنْ نَارٍ يَبْلُغُ كَعْبَيْهِ يَغْلِي مِنْهُ دِمَاغُهُ ‏"', NULL, 'Abu Sa''id al-Khudri reported:A mention was made of his uncle Abu Talib before the Messenger of Allah (ﷺ) He said: My intercession may benefit him on the Day of Resurrection and he may be placed in the shallow part of the Fire which would reach his ankles and his brain would be boiling.', 'Abu Sa''id al-Khudri reported', NULL, 'https://sunnah.com/muslim:210', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 211, '"‏ إِنَّ أَدْنَى أَهْلِ النَّارِ عَذَابًا يَنْتَعِلُ بِنَعْلَيْنِ مِنْ نَارٍ يَغْلِي دِمَاغُهُ مِنْ حَرَارَةِ نَعْلَيْهِ ‏"', NULL, 'Abu Sa''id al-Khudri reported:Verily, the Messenger of Allah (ﷺ) said: The least tormented of the inhabitants of the Fire would be he who would wear two shoes of Fire and his brain would boil on account of the heat of the shoes.', 'Abu Sa''id al-Khudri reported', NULL, 'https://sunnah.com/muslim:211', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 212, '"‏ أَهْوَنُ أَهْلِ النَّارِ عَذَابًا أَبُو طَالِبٍ وَهُوَ مُنْتَعِلٌ بِنَعْلَيْنِ يَغْلِي مِنْهُمَا دِمَاغُهُ ‏"', NULL, 'Ibn ''Abbas reported:The Prophet (ﷺ) said: Among the inhabitants of the Fire Abu Talib would have the least suffering, and he would be wearing two shoes (of Fire) which would boil his brain.', 'Ibn ''Abbas reported', NULL, 'https://sunnah.com/muslim:212', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 214, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى، حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ، عَنْ ثَابِتٍ الْبُنَانِيِّ، عَنْ أَنَسِ بْنِ مَالِكٍ، أَنَّهُ قَالَ لَمَّا نَزَلَتْ هَذِهِ الآيَةُ ‏{‏ يَا أَيُّهَا الَّذِينَ آمَنُوا لاَ تَرْفَعُوا أَصْوَاتَكُمْ فَوْقَ صَوْتِ النَّبِيِّ‏}‏ إِلَى آخِرِ الآيَةِ جَلَسَ ثَابِتُ بْنُ قَيْسٍ فِي بَيْتِهِ وَقَالَ أَنَا مِنْ أَهْلِ النَّارِ ‏.‏ وَاحْتَبَسَ عَنِ النَّبِيِّ صلى الله عليه وسلم فَسَأَلَ النَّبِيُّ صلى الله عليه وسلم سَعْدَ بْنَ مُعَاذٍ فَقَالَ ‏"‏ يَا أَبَا عَمْرٍو مَا شَأْنُ ثَابِتٍ أَشْتَكَى ‏"‏ ‏.‏ قَالَ سَعْدٌ إِنَّهُ لَجَارِي وَمَا عَلِمْتُ لَهُ بِشَكْوَى ‏.‏ قَالَ فَأَتَاهُ سَعْدٌ فَذَكَرَ لَهُ قَوْلَ رَسُولِ اللَّهِ صلى الله عليه وسلم فَقَالَ ثَابِتٌ أُنْزِلَتْ هَذِهِ الآيَةُ وَلَقَدْ عَلِمْتُمْ أَنِّي مِنْ أَرْفَعِكُمْ صَوْتًا عَلَى رَسُولِ اللَّهِ صلى الله عليه وسلم فَأَنَا مِنْ أَهْلِ النَّارِ ‏.‏ فَذَكَرَ ذَلِكَ سَعْدٌ لِلنَّبِيِّ صلى الله عليه وسلم فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ بَلْ هُوَ مِنْ أَهْلِ الْجَنَّةِ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Anas b. Malik that when this verse:" O ye who believe I raise not your voices above the voice of the Prophet, nor shout loud unto him in discourse, as ye shout loud unto one another, lest your deeds should become null and void, while you perceive not" (xlix. 2-5), was revealed. Thabit b. Qais confined himself in his house and said: I am one of the denizens of Fire, and he deliberately avoided coming to the Apostle (ﷺ). The Apostle (ﷺ) asked Sa''d b, Mu''adh about him and said, Abu Amr, how is Thabit? Has he fallen sick? Sa''d said: He is my neighbour, but I do not know of his illness. Sa''d came to him (Thabit), and conveyed to him the message of the Messenger of Allah (ﷺ). Upon this Thabit said: This verse was revealed, and you are well aware of the fact that, amongst all of you, mine is the voice louder than that of the Messenger of Allah, and so I am one amongst the denizens of Fire, Sa''d Informed the Prophet about it. Upon this the Messenger of Allah observed: (Nay, not so) but he (Thabit) is one of the dwellers of Paradise.', 'It is narrated on the authority of Anas b. Malik that when this verse', NULL, 'https://sunnah.com/muslim:214', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 215, 'وَحَدَّثَنَا قَطَنُ بْنُ نُسَيْرٍ، حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ، حَدَّثَنَا ثَابِتٌ، عَنْ أَنَسِ بْنِ مَالِكٍ، قَالَ كَانَ ثَابِتُ بْنُ قَيْسِ بْنِ شَمَّاسٍ خَطِيبَ الأَنْصَارِ فَلَمَّا نَزَلَتْ هَذِهِ الآيَةُ ‏.‏ بِنَحْوِ حَدِيثِ حَمَّادٍ ‏.‏ وَلَيْسَ فِي حَدِيثِهِ ذِكْرُ سَعْدِ بْنِ مُعَاذٍ ‏.‏', NULL, 'This hadith has been narrated on the authority of Anas b. Malik by another chain of transmitters in which these words are found:Thabit b. Qais was the orator of the Ansar, when this verse was revealed: the rest of the hadith is the same with the exception that there is no mention of Sa''d b. Mu''adh in it.', NULL, NULL, 'https://sunnah.com/muslim:215', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 216, 'وَحَدَّثَنَا هُرَيْمُ بْنُ عَبْدِ الأَعْلَى الأَسَدِيُّ، حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ، قَالَ سَمِعْتُ أَبِي يَذْكُرُ، عَنْ ثَابِتٍ، عَنْ أَنَسٍ، قَالَ لَمَّا نَزَلَتْ هَذِهِ الآيَةُ ‏.‏ وَاقْتَصَّ الْحَدِيثَ ‏.‏ وَلَمْ يَذْكُرْ سَعْدَ بْنَ مُعَاذٍ وَزَادَ فَكُنَّا نَرَاهُ يَمْشِي بَيْنَ أَظْهُرِنَا رَجُلٌ مِنْ أَهْلِ الْجَنَّةِ ‏.‏', NULL, 'This hadith is narrated on the authority of Anas by another chain of transmitters in which there is no mention of Sa''d b. Mu''adh, but the following words are there:We observed a man, one of the dwellers of Paradise, walking about amongst us.', NULL, NULL, 'https://sunnah.com/muslim:216', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 217, '"‏ أَمَّا مَنْ أَحْسَنَ مِنْكُمْ فِي الإِسْلاَمِ فَلاَ يُؤَاخَذُ بِهَا وَمَنْ أَسَاءَ أُخِذَ بِعَمَلِهِ فِي الْجَاهِلِيَّةِ وَالإِسْلاَمِ ‏"', NULL, 'It is narrated on the authority of Abdullah b. Mas''ud that some people said to the Messenger of Allah (ﷺ):Messenger of Allah, would we be held responsible for our deeds committed in the state of ignorance (before embracing Islam)? Upon his he (the Holy Prophet) remarked: He who amongst you performed good deeds in Islam, He would not be held responsible for them (misdeeds which he committed in ignorance) and he who committed evil (even after embracing Islam) would be held responsible or his misdeeds that he committed in the state of ignorance as well as in that of Islam.', NULL, NULL, 'https://sunnah.com/muslim:217', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 218, '"‏ مَنْ أَحْسَنَ فِي الإِسْلاَمِ لَمْ يُؤَاخَذْ بِمَا عَمِلَ فِي الْجَاهِلِيَّةِ ‏.‏ وَمَنْ أَسَاءَ فِي الإِسْلاَمِ أُخِذَ بِالأَوَّلِ وَالآخِرِ ‏"', NULL, 'It is narrated on the authority of Abdullah b. Mas''ud:We once said: Messenger of Allah, would we be held responsible for our deeds committed in the state of ignorance? He (the Holy Prophet) observed: He who did good deeds in Islam would not be held responsible for what he did in the state of ignorance, but he who committed evil (after having come within the fold of Islam) would be held responsible for his previous and later deeds.', 'It is narrated on the authority of Abdullah b. Mas''ud', NULL, 'https://sunnah.com/muslim:218', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 219, 'حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ، أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ، عَنِ الأَعْمَشِ، بِهَذَا الإِسْنَادِ مِثْلَهُ ‏.‏', NULL, 'This hadith has been transmitted by Minjab b. al-Harith Tamimi with the same chain of transmitters.', NULL, NULL, 'https://sunnah.com/muslim:219', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 222, '"‏ أَسْلَمْتَ عَلَى مَا أَسْلَفْتَ مِنْ خَيْرٍ ‏"', NULL, 'Hakim b. Hizam reported to ''Urwa b. Zubair that he said to the Messenger of Allah:Do you think that there is any thing for me (of he reward with the Lord) for the deed of religious purification that I did in the state of ignorance? Upon this he (the Messenger of Allah) said to him: You accepted Islam with all the previous virtues that you practised.', NULL, NULL, 'https://sunnah.com/muslim:222', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 223, '"‏ أَسْلَمْتَ عَلَى مَا أَسْلَفْتَ مِنْ خَيْرٍ ‏"', NULL, 'Hakim b. Hizam reported to ''Urwa b. Zubair that he said to the Messenger of Allah (ﷺ):Messenger of Allah, do you think if there is any reward (of the Lord with me on the Day of Resurrection) for the deeds of religious purification that I performed in the state of ignorance, such as charity, freeing a slave, cementing of blood-relations? Upon this he (the Messenger of Allah) said to him: You have accepted Islam with all the previous virtues that you had practised.', NULL, NULL, 'https://sunnah.com/muslim:223', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 224, '"‏ أَسْلَمْتَ عَلَى مَا أَسْلَفْتَ لَكَ مِنَ الْخَيْرِ ‏"', NULL, 'It is narrate on the authority of Hakim b. Hizam:I said: Messenger of Allah, I did so some of the deeds in the state of ignorance. (One of the transmitters Hisham b. Urwa explained them as acts of piety. Upon this the Messenger, of Allah remarked: You have embraced Islam with all the previous acts of virtue. I said: By God, I would leave nothing undone in Islam the like of which I did in the state of ignorance.', 'It is narrate on the authority of Hakim b. Hizam', NULL, 'https://sunnah.com/muslim:224', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 225, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ، عَنْ هِشَامِ بْنِ عُرْوَةَ، عَنْ أَبِيهِ، أَنَّ حَكِيمَ بْنَ حِزَامٍ، أَعْتَقَ فِي الْجَاهِلِيَّةِ مِائَةَ رَقَبَةٍ وَحَمَلَ عَلَى مِائَةِ بَعِيرٍ ثُمَّ أَعْتَقَ فِي الإِسْلاَمِ مِائَةَ رَقَبَةٍ وَحَمَلَ عَلَى مِائَةِ بَعِيرٍ ثُمَّ أَتَى النَّبِيَّ صلى الله عليه وسلم فَذَكَرَ نَحْوَ حَدِيثِهِمْ ‏.‏', NULL, 'Hisham b. Urwa narrated it on the authority of his father:Hakim b. Hizam freed one hundred slave and donated one hundred camels (for the sake of Allah) during the state of ignorance. Then he freed one hundred slaves and donated one hundred camel (for the sake of Allah) after) he had embraced Islam. He subsequently came to the Apostle (ﷺ). The rest of the hadith is the same as narrated above.', 'Hisham b. Urwa narrated it on the authority of his father', NULL, 'https://sunnah.com/muslim:225', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 226, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ، وَأَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنِ الأَعْمَشِ، عَنْ إِبْرَاهِيمَ، عَنْ عَلْقَمَةَ، عَنْ عَبْدِ اللَّهِ، قَالَ لَمَّا نَزَلَتْ ‏{‏ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ‏}‏ شَقَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللَّهِ صلى الله عليه وسلم وَقَالُوا أَيُّنَا لاَ يَظْلِمُ نَفْسَهُ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ لَيْسَ هُوَ كَمَا تَظُنُّونَ إِنَّمَا هُوَ كَمَا قَالَ لُقْمَانُ لاِبْنِهِ ‏{‏ يَا بُنَىَّ لاَ تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ‏{‏', NULL, 'It is narrated on the authority of ''Abdullah (b. Mas''ud) that when this verse was revealed:" It is those who believe and confound not their belief with wrongdoing" (vi. 82), the Companions of the Messenger of Allah wore greatly perturbed. They said: Who amongst us (is so fortunate) that he does not wrong himself? Upon this the Messenger of Allah (ﷺ) remarked: It does not mean that which you presume It implies that which Luqman said to his son: O my son, do not associate anything with Allah, for indeed it is the gravest wrongdoing (xxxi. 13).', NULL, NULL, 'https://sunnah.com/muslim:226', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 227, 'حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ، وَعَلِيُّ بْنُ خَشْرَمٍ، قَالاَ أَخْبَرَنَا عِيسَى، - وَهُوَ ابْنُ يُونُسَ ح وَحَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ، أَخْبَرَنَا ابْنُ مُسْهِرٍ، ح وَحَدَّثَنَا أَبُو كُرَيْبٍ، أَخْبَرَنَا ابْنُ إِدْرِيسَ، كُلُّهُمْ عَنِ الأَعْمَشِ، بِهَذَا الإِسْنَادِ قَالَ أَبُو كُرَيْبٍ قَالَ ابْنُ إِدْرِيسَ حَدَّثَنِيهِ أَوَّلاً أَبِي، عَنْ أَبَانِ بْنِ تَغْلِبَ، عَنِ الأَعْمَشِ، ثُمَّ سَمِعْتُهُ مِنْهُ، ‏.‏', NULL, 'This hadith is narrated by another chain of transmitters, (namely) lshaq b. Ibrahim. Ibn Idris says:My father transmitted it from Aban b. Taghlib who heard it from A''mash; then I heard it also from him (A''mash).', NULL, NULL, 'https://sunnah.com/muslim:227', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 230, '"‏ إِنَّ اللَّهَ تَجَاوَزَ لأُمَّتِي مَا حَدَّثَتْ بِهِ أَنْفُسَهَا مَا لَمْ يَتَكَلَّمُوا أَوْ يَعْمَلُوا بِهِ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:Verily Allah forgave my people the evil promptings which arise within their hearts as long as they did not speak about them or did not act upon them.', NULL, NULL, 'https://sunnah.com/muslim:230', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 231, '"‏ إِنَّ اللَّهَ عَزَّ وَجَلَّ تَجَاوَزَ لأُمَّتِي عَمَّا حَدَّثَتْ بِهِ أَنْفُسَهَا مَا لَمْ تَعْمَلْ أَوْ تَكَلَّمْ بِهِ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:Verily the Great and Mighty Allah forgave my people the evil promptings arising in their minds, but they neither talked about them nor acted upon them.', NULL, NULL, 'https://sunnah.com/muslim:231', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 232, 'وَحَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ، حَدَّثَنَا وَكِيعٌ، حَدَّثَنَا مِسْعَرٌ، وَهِشَامٌ، ح وَحَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ، أَخْبَرَنَا الْحُسَيْنُ بْنُ عَلِيٍّ، عَنْ زَائِدَةَ، عَنْ شَيْبَانَ، جَمِيعًا عَنْ قَتَادَةَ، بِهَذَا الإِسْنَادِ مِثْلَهُ ‏.‏', NULL, 'The same hadith has been narrated by Zuhair b. Harb, Waki, Ishaq b. Mansur, Husain b. ''Ali.', NULL, NULL, 'https://sunnah.com/muslim:232', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 233, '"‏ قَالَ اللَّهُ عَزَّ وَجَلَّ إِذَا هَمَّ عَبْدِي بِسَيِّئَةٍ فَلاَ تَكْتُبُوهَا عَلَيْهِ فَإِنْ عَمِلَهَا فَاكْتُبُوهَا سَيِّئَةً وَإِذَا هَمَّ بِحَسَنَةٍ فَلَمْ يَعْمَلْهَا فَاكْتُبُوهَا حَسَنَةً فَإِنْ عَمِلَهَا فَاكْتُبُوهَا عَشْرًا ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) said:The Great and the Glorious Lord said (to angels): Whenever My servant intends to commit an evil, do not record it against him, but if he actually commits it, then write it as one evil. And when he intends to do good but does not do it, then take it down is one act of goodness, but if he does it, then write down ten good deeds (in his record).', NULL, NULL, 'https://sunnah.com/muslim:233', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 234, '"‏ قَالَ اللَّهُ عَزَّ وَجَلَّ إِذَا هَمَّ عَبْدِي بِحَسَنَةٍ وَلَمْ يَعْمَلْهَا كَتَبْتُهَا لَهُ حَسَنَةً فَإِنْ عَمِلَهَا كَتَبْتُهَا عَشْرَ حَسَنَاتٍ إِلَى سَبْعِمِائَةِ ضِعْفٍ وَإِذَا هَمَّ بِسَيِّئَةٍ وَلَمْ يَعْمَلْهَا لَمْ أَكْتُبْهَا عَلَيْهِ فَإِنْ عَمِلَهَا كَتَبْتُهَا سَيِّئَةً وَاحِدَةً ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:Allah, the Great and Glorious, said: Whenever my bondsman intends to do good, but does not do it, I write one good act for him, but if he puts it into practice I wrote from ten to seven hundred good deeds in favour of him. When he intends to commit an evil, but does not actually do it, do not record it. But if he does it, I write only one evil.', NULL, NULL, 'https://sunnah.com/muslim:234', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 237, '"‏ إِنَّ اللَّهَ كَتَبَ الْحَسَنَاتِ وَالسَّيِّئَاتِ ثُمَّ بَيَّنَ ذَلِكَ فَمَنْ هَمَّ بِحَسَنَةٍ فَلَمْ يَعْمَلْهَا كَتَبَهَا اللَّهُ عِنْدَهُ حَسَنَةً كَامِلَةً وَإِنْ هَمَّ بِهَا فَعَمِلَهَا كَتَبَهَا اللَّهُ عَزَّ وَجَلَّ عِنْدَهُ عَشْرَ حَسَنَاتٍ إِلَى سَبْعِمِائَةِ ضِعْفٍ إِلَى أَضْعَافٍ كَثِيرَةٍ وَإِنْ هَمَّ بِسَيِّئَةٍ فَلَمْ يَعْمَلْهَا كَتَبَهَا اللَّهُ عِنْدَهُ حَسَنَةً كَامِلَةً وَإِنْ هَمَّ بِهَا فَعَمِلَهَا كَتَبَهَا اللَّهُ سَيِّئَةً وَاحِدَةً ‏"', NULL, 'It is narrated on the authority of Ibn Abbas that the Messenger of Allah (ﷺ) transmitted it from the Blessed and Great Lord:Verily Allah recorded the good and the evil and then made it clear that he who intended good but did not do it, Allah recorded one complete good in his favour, but if he intended it and also did it, the Glorious and Great Allah recorded ten to seven hundred virtues and even more to his credit. But it he intended evil, but did not commit it, Allah wrote down full one good in his favour. If he intended that and also committed it, Allah made an entry of one evil against him.', NULL, NULL, 'https://sunnah.com/muslim:237', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 238, '"‏ وَمَحَاهَا اللَّهُ وَلاَ يَهْلِكُ عَلَى اللَّهِ إِلاَّ هَالِكٌ ‏"', NULL, 'This hadith has been narrated with another chain of transmitters with the addition of these words:Allah would even wipe out (the evil committed by a man) and Allah does not put to destruction anyone except he who is doomed to destruction.', NULL, NULL, 'https://sunnah.com/muslim:238', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 239, 'حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ، حَدَّثَنَا جَرِيرٌ، عَنْ سُهَيْلٍ، عَنْ أَبِيهِ، عَنْ أَبِي هُرَيْرَةَ، قَالَ جَاءَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صلى الله عليه وسلم فَسَأَلُوهُ إِنَّا نَجِدُ فِي أَنْفُسِنَا مَا يَتَعَاظَمُ أَحَدُنَا أَنْ يَتَكَلَّمَ بِهِ ‏.‏ قَالَ ‏"‏ وَقَدْ وَجَدْتُمُوهُ ‏"‏ ‏.‏ قَالُوا نَعَمْ ‏.‏ قَالَ ‏"‏ ذَاكَ صَرِيحُ الإِيمَانِ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Abu Huraira that some people from amongst the Companions of the Apostle (ﷺ) came to him and said:Verily we perceive in our minds that which every one of us considers it too grave to express. He (the Holy Prophet) said: Do you really perceive it? They said: Yes. Upon this he remarked: That is the faith manifest.', NULL, NULL, 'https://sunnah.com/muslim:239', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 240, 'وَحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ، عَنْ شُعْبَةَ، ح وَحَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ جَبَلَةَ بْنِ أَبِي رَوَّادٍ، وَأَبُو بَكْرِ بْنُ إِسْحَاقَ قَالاَ حَدَّثَنَا أَبُو الْجَوَّابِ، عَنْ عَمَّارِ بْنِ رُزَيْقٍ، كِلاَهُمَا عَنِ الأَعْمَشِ، عَنْ أَبِي صَالِحٍ، عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِهَذَا الْحَدِيثِ ‏.‏', NULL, 'The same hadith has been transmitted by Muhammad b. ''Amr, Abu Baker b. Ishaq, Abu''l-Jawwab, A''mash and Abu Huraira.', NULL, NULL, 'https://sunnah.com/muslim:240', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 242, '"‏ لاَ يَزَالُ النَّاسُ يَتَسَاءَلُونَ حَتَّى يُقَالَ هَذَا خَلَقَ اللَّهُ الْخَلْقَ فَمَنْ خَلَقَ اللَّهَ فَمَنْ وَجَدَ مِنْ ذَلِكَ شَيْئًا فَلْيَقُلْ آمَنْتُ بِاللَّهِ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) said:Men will continue to question one another till this is propounded: Allah created all things but who created Allah? He who found himself confronted with such a situation should say: I affirm my faith in Allah.', NULL, NULL, 'https://sunnah.com/muslim:242', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 243, 'وَحَدَّثَنَا مَحْمُودُ بْنُ غَيْلاَنَ، حَدَّثَنَا أَبُو النَّضْرِ، حَدَّثَنَا أَبُو سَعِيدٍ الْمُؤَدِّبُ، عَنْ هِشَامِ بْنِ عُرْوَةَ، بِهَذَا الإِسْنَادِ أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ يَأْتِي الشَّيْطَانُ أَحَدَكُمْ فَيَقُولُ مَنْ خَلَقَ السَّمَاءَ مَنْ خَلَقَ الأَرْضَ فَيَقُولُ اللَّهُ ‏"‏ ‏.‏ ثُمَّ ذَكَرَ بِمِثْلِهِ وَزَادَ ‏"‏ وَرُسُلِهِ ‏"‏ ‏.‏', NULL, 'This hadith has been transmitted by Mahmud b. Ghailan by another chain of transmitters (and the words are):The Messenger of Allah (ﷺ) said: The Satan will come to everyone of you and say: Who created the heaven, who created the earth? (And the man) replies: It is Allah, Then the remaining part of the hadith was narrated as mentioned above and the words ''His prophets" were added to it.', NULL, NULL, 'https://sunnah.com/muslim:243', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 244, '"‏ يَأْتِي الشَّيْطَانُ أَحَدَكُمْ فَيَقُولُ مَنْ خَلَقَ كَذَا وَكَذَا حَتَّى يَقُولَ لَهُ مَنْ خَلَقَ رَبَّكَ فَإِذَا بَلَغَ ذَلِكَ فَلْيَسْتَعِذْ بِاللَّهِ وَلْيَنْتَهِ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah may peace be upon him) observed:The Satan comes to everyone. of you and says: Who created this and that? till he questions: Who created your Lord? When he comes to that, one should seek refuge in Allah and keep away (from such idle thoughts).', NULL, NULL, 'https://sunnah.com/muslim:244', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 245, '"‏ يَأْتِي الْعَبْدَ الشَّيْطَانُ فَيَقُولُ مَنْ خَلَقَ كَذَا وَكَذَا ‏"', NULL, 'This hadith is transmitted by Urwa b. Zubair on the authority of Abu Huraira (and the words are):The Satan comes to the bondsman (of Allah) and says: Who created this and that? The remaining part of the hadith is the same.', NULL, NULL, 'https://sunnah.com/muslim:245', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 246, '"‏ لاَ يَزَالُ النَّاسُ يَسْأَلُونَكُمْ عَنِ الْعِلْمِ حَتَّى يَقُولُوا هَذَا اللَّهُ خَلَقَنَا فَمَنْ خَلَقَ اللَّهَ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:People will constantly ask you questions pertaining to knowledge till they would say: Allah created us, but who created Allah? he (the narrator) says: he (Abu Huraira) was (at the time of narrating this hadith) catching hold of the hand of a man and he said: Allah and the Messenger told the truth. Two persons have already put me this question, and this is the third one, or he said: One man has put me this question and he is the second one.', NULL, NULL, 'https://sunnah.com/muslim:246', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 247, '"‏ لاَ يَزَالُ النَّاسُ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that he said:The people will constantly, and the rest of the hadith is the same as that transmitted by ''Abdul-Warith with the exception that there is no mention of the Messenger of Allah in that, but he observed at the end of the hadith: Allah and His Messenger told the truth.', 'It is narrated on the authority of Abu Huraira that he said', NULL, 'https://sunnah.com/muslim:247', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 248, '"‏ لاَ يَزَالُونَ يَسْأَلُونَكَ يَا أَبَا هُرَيْرَةَ حَتَّى يَقُولُوا هَذَا اللَّهُ فَمَنْ خَلَقَ اللَّهَ ‏"', NULL, 'Abu Huraira reported:The Messenger of Allah (ﷺ) said to me: they (the people) till constantly ask you, Abu Huraira, (about different things pertaining to religion) the they would say: Well, there is Allah, but after all who created Allah? He (Abu Huraira) narrated: Once we were in the mosque that some of the Bedouins came there and said: Well, there is Allah, but who created Allah? He (the narrator) said: I took hold of the pebbles in my fist and flung at them and remarked: Stand up, stand up (go away) my friend (the Holy Prophet) told the truth.', 'Abu Huraira reported', NULL, 'https://sunnah.com/muslim:248', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 249, '"‏ لَيَسْأَلَنَّكُمُ النَّاسُ عَنْ كُلِّ شَىْءٍ حَتَّى يَقُولُوا اللَّهُ خَلَقَ كُلَّ شَىْءٍ فَمَنْ خَلَقَهُ ‏"', NULL, 'Yazid b. al-Asamm said:I heard Abu Huraira saying that the Messenger of Allah (ﷺ) observed: people will certainly ask you about everything till they will propound: Allah created every thing, but who created Allah?', 'Yazid b. al-Asamm said', NULL, 'https://sunnah.com/muslim:249', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 250, '"‏ قَالَ اللَّهُ عَزَّ وَجَلَّ إِنَّ أُمَّتَكَ لاَ يَزَالُونَ يَقُولُونَ مَا كَذَا مَا كَذَا حَتَّى يَقُولُوا هَذَا اللَّهُ خَلَقَ الْخَلْقَ فَمَنْ خَلَقَ اللَّهَ ‏"', NULL, 'Anas b. Malik transmitted it from the Messenger of Allah (ﷺ) that the Great and Glorious Allah said:Verily your people would constantly question about this and that till they would say: Well, it is Allah Who created the creation, but who created Allah?', NULL, NULL, 'https://sunnah.com/muslim:250', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 251, '"‏ قَالَ اللَّهُ إِنَّ أُمَّتَكَ ‏"', NULL, 'This hadith has been narrated by another chain of transmitters with the exception that Ishaq made no mention of this:Allah said: Verily your people.', NULL, NULL, 'https://sunnah.com/muslim:251', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 252, 'حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ، وَقُتَيْبَةُ بْنُ سَعِيدٍ، وَعَلِيُّ بْنُ حُجْرٍ، جَمِيعًا عَنْ إِسْمَاعِيلَ بْنِ جَعْفَرٍ، - قَالَ ابْنُ أَيُّوبَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ، - قَالَ أَخْبَرَنَا الْعَلاَءُ، - وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ مَوْلَى الْحُرَقَةِ - عَنْ مَعْبَدِ بْنِ كَعْبٍ السَّلَمِيِّ، عَنْ أَخِيهِ عَبْدِ اللَّهِ بْنِ كَعْبٍ، عَنْ أَبِي أُمَامَةَ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ مَنِ اقْتَطَعَ حَقَّ امْرِئٍ مُسْلِمٍ بِيَمِينِهِ فَقَدْ أَوْجَبَ اللَّهُ لَهُ النَّارَ وَحَرَّمَ عَلَيْهِ الْجَنَّةَ ‏"‏ ‏.‏ فَقَالَ لَهُ رَجُلٌ وَإِنْ كَانَ شَيْئًا يَسِيرًا يَا رَسُولَ اللَّهِ قَالَ ‏"‏ وَإِنْ قَضِيبًا مِنْ أَرَاكٍ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Abu Umama that the Messenger of Allah (ﷺ) observed:He who appropriated the right of a Muslim by (swearing a false) oath, Allah would make Hell-fire necessary for him and would declare Paradise forbidden for him. A person said to him: Messenger of Allah, even if it is something insignificant? He (the Holy Prophet) replied: (Yes) even if it is the twig of the arak tree.', NULL, NULL, 'https://sunnah.com/muslim:252', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 253, 'وَحَدَّثَنَاهُ أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَإِسْحَاقُ بْنُ إِبْرَاهِيمَ، وَهَارُونُ بْنُ عَبْدِ اللَّهِ، جَمِيعًا عَنْ أَبِي أُسَامَةَ، عَنِ الْوَلِيدِ بْنِ كَثِيرٍ، عَنْ مُحَمَّدِ بْنِ كَعْبٍ، أَنَّهُ سَمِعَ أَخَاهُ عَبْدَ اللَّهِ بْنَ كَعْبٍ، يُحَدِّثُ أَنَّ أَبَا أُمَامَةَ الْحَارِثِيَّ، حَدَّثَهُ أَنَّهُ، سَمِعَ رَسُولَ اللَّهِ صلى الله عليه وسلم بِمِثْلِهِ ‏.‏', NULL, 'This hadith has been transmitted by another chain of narrators:Abu Bakr b. Abi Shaiba, Ishaq b. Ibrahim, Harun b. Abdullah, Abi Usama, Walid b. Kathir, Muhammad b. Ka''b, his brother Abdullah b. Ka''b and Abi Usama.', 'This hadith has been transmitted by another chain of narrators', NULL, 'https://sunnah.com/muslim:253', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 254, 'وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا وَكِيعٌ، ح وَحَدَّثَنَا ابْنُ نُمَيْرٍ، حَدَّثَنَا أَبُو مُعَاوِيَةَ، وَوَكِيعٌ، ح وَحَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ، - وَاللَّفْظُ لَهُ - أَخْبَرَنَا وَكِيعٌ، حَدَّثَنَا الأَعْمَشُ، عَنْ أَبِي وَائِلٍ، عَنْ عَبْدِ اللَّهِ، عَنْ رَسُولِ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ هُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ ‏"‏ ‏.‏ قَالَ فَدَخَلَ الأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ قَالُوا كَذَا وَكَذَا ‏.‏ قَالَ صَدَقَ أَبُو عَبْدِ الرَّحْمَنِ فِيَّ نَزَلَتْ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ أَرْضٌ بِالْيَمَنِ فَخَاصَمْتُهُ إِلَى النَّبِيِّ صلى الله عليه وسلم فَقَالَ ‏"‏ هَلْ لَكَ بَيِّنَةٌ ‏"‏ ‏.‏ فَقُلْتُ لاَ ‏.‏ قَالَ ‏"‏ فَيَمِينُهُ ‏"‏ ‏.‏ قُلْتُ إِذًا يَحْلِفُ ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم عِنْدَ ذَلِكَ ‏"‏ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ هُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ ‏"‏ ‏.‏ فَنَزَلَتْ ‏{‏ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلاً‏}‏ إِلَى آخِرِ الآيَةِ ‏.‏', NULL, 'It is narrated on the authority of Abdullah (b. Umar) that the Messenger of Allah (ﷺ) observed:He who perjured with a view to appropriating the property of a Muslim, and he is in fact a liar and would meet Allah in a state that He would be angry with him. He (the narrator) said: There came Ash''ath b. Qais and said (to the people): What does Abu Abdur-Rahman (the Kunya of Abdullah b. Umar) narrate to you? They replied: So and so. Upon this he remarked: Abu Abdur-Rahman told the truth. This (command) has been revealed in my case. There was a piece of land in Yemen over which I and another person had a claim. I brought the dispute with him to the Messenger of Allah (to decide) He (the Holy Prophet) said: Can you produce an evidence (in your support)? I said: No. He (the Holy Prophet) observed: (Then the decision would be made) on his oath. I said: He would readily take an oath. Upon this the Messenger of Allah (ﷺ) remarked: He who perjured for appropriating the wealth of a Muslim, whereas he is a liar, would meet Allah while He would be angry with him. This verse was then revealed:" Verily those who barter Allah''s covenant and their oaths at a small price..." (iii 77).', NULL, NULL, 'https://sunnah.com/muslim:254', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 255, '"‏ شَاهِدَاكَ أَوْ يَمِينُهُ ‏"', NULL, 'It is narrated on the authority of Abdullah that he heard the Prophet (ﷺ) saying:He who took an oath in order to entitle himself (to the possession) of a property, whereas he is a liar, would meet Allah in a state that He would be very much angry with him. Then the remaining part of the hadith was narrated as transmitted by A''mash but with the exception of these words: There was a dispute between me and another person in regard to a well. We referred this dispute to the Messenger of Allah (ﷺ). Upon this he remarked: Either (you should produce) two witnesses (to support your contention) or his oath (would be accepted as valid).', 'It is narrated on the authority of Abdullah that he heard the Prophet (ﷺ) saying', NULL, 'https://sunnah.com/muslim:255', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 256, 'وَحَدَّثَنَا ابْنُ أَبِي عُمَرَ الْمَكِّيُّ، حَدَّثَنَا سُفْيَانُ، عَنْ جَامِعِ بْنِ أَبِي رَاشِدٍ، وَعَبْدِ الْمَلِكِ بْنِ أَعْيَنَ، سَمِعَا شَقِيقَ بْنَ سَلَمَةَ، يَقُولُ سَمِعْتُ ابْنَ مَسْعُودٍ، يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم يَقُولُ ‏"‏ مَنْ حَلَفَ عَلَى مَالِ امْرِئٍ مُسْلِمٍ بِغَيْرِ حَقِّهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ ‏"‏ قَالَ عَبْدُ اللَّهِ ثُمَّ قَرَأَ عَلَيْنَا رَسُولُ اللَّهِ صلى الله عليه وسلم مِصْدَاقَهُ مِنْ كِتَابِ اللَّهِ ‏{‏ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلاً‏}‏ إِلَى آخِرِ الآيَةِ ‏.‏', NULL, 'Ibn Mas''ud says:I heard the Messenger of Allah observing: He who took an oath on the property of a Muslim without legitimate right would meet Allah and He would be angry, with him. Then the Messenger of Allah (ﷺ) in support of his contention recited the verse:" Verily those who barter Allah''s covenant and their oaths at a small price.', 'Ibn Mas''ud says', NULL, 'https://sunnah.com/muslim:256', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 257, 'حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ، وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهَنَّادُ بْنُ السَّرِيِّ وَأَبُو عَاصِمٍ الْحَنَفِيُّ - وَاللَّفْظُ لِقُتَيْبَةَ - قَالُوا حَدَّثَنَا أَبُو الأَحْوَصِ، عَنْ سِمَاكٍ، عَنْ عَلْقَمَةَ بْنِ وَائِلٍ، عَنْ أَبِيهِ، قَالَ جَاءَ رَجُلٌ مِنْ حَضْرَمَوْتَ وَرَجُلٌ مِنْ كِنْدَةَ إِلَى النَّبِيِّ صلى الله عليه وسلم فَقَالَ الْحَضْرَمِيُّ يَا رَسُولَ اللَّهِ إِنَّ هَذَا قَدْ غَلَبَنِي عَلَى أَرْضٍ لِي كَانَتْ لأَبِي ‏.‏ فَقَالَ الْكِنْدِيُّ هِيَ أَرْضِي فِي يَدِي أَزْرَعُهَا لَيْسَ لَهُ فِيهَا حَقٌّ ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم لِلْحَضْرَمِيِّ ‏"‏ أَلَكَ بَيِّنَةٌ ‏"‏ ‏.‏ قَالَ لاَ ‏.‏ قَالَ ‏"‏ فَلَكَ يَمِينُهُ ‏"‏ ‏.‏ قَالَ يَا رَسُولَ اللَّهِ إِنَّ الرَّجُلَ فَاجِرٌ لاَ يُبَالِي عَلَى مَا حَلَفَ عَلَيْهِ وَلَيْسَ يَتَوَرَّعُ مِنْ شَىْءٍ ‏.‏ فَقَالَ ‏"‏ لَيْسَ لَكَ مِنْهُ إِلاَّ ذَلِكَ ‏"‏ فَانْطَلَقَ لِيَحْلِفَ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم لَمَّا أَدْبَرَ ‏"‏ أَمَا لَئِنْ حَلَفَ عَلَى مَالِهِ لِيَأْكُلَهُ ظُلْمًا لَيَلْقَيَنَّ اللَّهَ وَهُوَ عَنْهُ مُعْرِضٌ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Wa''il that there came a person from Hadramaut and another one from Kinda to the Apostle (ﷺ). One who had come from Hadramaut said:Messenger of Allah, only this man has appropriated my land which belonged to my father. The one who had came from Kinda contended. This is my land and is in my possession: I cultivate it. There is no right for him in it. The Messenger of Allah said to the Hadramite: Have you any evidence (to support you)? He replied in the negative. He (the Messenger of Allah) said: Then your case is to be decided on his oath. He (the Hadramite) said: Messenger of Allah, he is a liar and cares not what he swears and has no regard for anything. Upon this he (the Messenger of Allah) remarked: For you then there is no other help to it. He (the man from Kinda) set out to take an oath. When he turned his back the Messenger of Allah (ﷺ) observed: If he took an oath on his property with a view to usurping it, he would certainly meet his Lord in a state that He would turn away from him.', NULL, NULL, 'https://sunnah.com/muslim:257', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 258, 'وَحَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ، وَإِسْحَاقُ بْنُ إِبْرَاهِيمَ، جَمِيعًا عَنْ أَبِي الْوَلِيدِ، قَالَ زُهَيْرٌ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ، حَدَّثَنَا أَبُو عَوَانَةَ، عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ، عَنْ عَلْقَمَةَ بْنِ وَائِلٍ، عَنْ وَائِلِ بْنِ حُجْرٍ، قَالَ كُنْتُ عِنْدَ رَسُولِ اللَّهِ صلى الله عليه وسلم فَأَتَاهُ رَجُلاَنِ يَخْتَصِمَانِ فِي أَرْضٍ فَقَالَ أَحَدُهُمَا إِنَّ هَذَا انْتَزَى عَلَى أَرْضِي يَا رَسُولَ اللَّهِ فِي الْجَاهِلِيَّةِ - وَهُوَ امْرُؤُ الْقَيْسِ بْنُ عَابِسٍ الْكِنْدِيُّ وَخَصْمُهُ رَبِيعَةُ بْنُ عِبْدَانَ - قَالَ ‏"‏ بَيِّنَتُكَ ‏"‏ ‏.‏ قَالَ لَيْسَ لِي بَيِّنَةٌ ‏.‏ قَالَ ‏"‏ يَمِينُهُ ‏"‏ ‏.‏ قَالَ إِذًا يَذْهَبُ بِهَا ‏.‏ قَالَ ‏"‏ لَيْسَ لَكَ إِلاَّ ذَاكَ ‏"‏ ‏.‏ قَالَ فَلَمَّا قَامَ لِيَحْلِفَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ مَنِ اقْتَطَعَ أَرْضًا ظَالِمًا لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ ‏"‏ ‏.‏ قَالَ إِسْحَاقُ فِي رِوَايَتِهِ رَبِيعَةُ بْنُ عَيْدَانَ ‏.‏', NULL, 'Wa''il reported it on the authority of his father Hujr:I was with the Messenger of Allah (ﷺ) that two men came there disputing over a piece of land. One of them said: Messenger of Allah, this man appropriated my land without justification in the days of ignorance. The (claimant) was Imru''l-Qais b. ''Abis al-Kindi and his opponent was Rabi''a b. ''Iban He (the Holy Prophet) said (to the claimant): Have you evidence (to substantiate your claim)? He replied: I have no evidence. Upon this he (the Messenger of Allah) remarked: Then his (that is of the defendant) is the oath. He (the claimant) said: In this case he (the defendant) would appropriate this (the property). He (the Holy Prophet) said: There is than no other way left for you but this. He (the narrator) said: When he (the defendant) stood up to take oath, the Messenger of Allah (ﷺ) said: He who appropriated the land wrongfully would meet Allah in a state that He would be angry with him. Ishaq in his narration mentions Rabi''a b. ''Aidan (instead of Rabi''a b. ''Ibdan).', 'Wa''il reported it on the authority of his father Hujr', NULL, 'https://sunnah.com/muslim:258', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 260, '"‏ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ ‏"', NULL, 'It is narrated on the authority of Thabit, that when ''Abdullah b. ''Amr and ''Anbasa b. Abi Sufyan were about to fight against each other, Khalid b. ''As rode to ''Abdullah b. ''Amr and persuaded him (not to do so). Upon this Abdullah b. ''Amr said:Are you not aware that the Messenger of Allah (ﷺ) had observed:" He who died in protecting his property is a martyr."', NULL, NULL, 'https://sunnah.com/muslim:260', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 261, '"‏ مَا مِنْ عَبْدٍ يَسْتَرْعِيهِ اللَّهُ رَعِيَّةً يَمُوتُ يَوْمَ يَمُوتُ وَهُوَ غَاشٌّ لِرَعِيَّتِهِ إِلاَّ حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ ‏"', NULL, 'Hasan reported:''Ubaidullah b. Ziyad paid a visit to Ma''qil b. Yasar Muzani in his illness of which he (later on) died. (At this juncture) Ma''qil said: I am going to narrate to you a hadith which I have heard from the Messenger of Allah (ﷺ) and which I would not have transmitted if I knew that I would survive. Verily I have heard the Messenger of Allah (ﷺ) say: There is none amongst the bondsmen who was entrusted with the affairs of his subjects and he died in such a state that he was dishonest in his dealings with those over whom he ruled except that Paradise is forbidden for him.', 'Hasan reported', NULL, 'https://sunnah.com/muslim:261', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 262, '"‏ لاَ يَسْتَرْعِي اللَّهُ عَبْدًا رَعِيَّةً يَمُوتُ حِينَ يَمُوتُ وَهُوَ غَاشٌّ لَهَا إِلاَّ حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ ‏"', NULL, 'Hasan reported:Ubaidullah b. Ziyad went to see Ma''qil b. Yasir and he was ailing. He (''Ubaidullah) inquired (about his health) to which he (Ma''qil) replied: I am narrating to you a hadith which I avoided narrating to you (before). Verily the Messenger of Allah (ﷺ) observed: Allah does not entrust to his bondsman the responsibility of managing the affairs of his subjects and he dies as a dishonest (ruler) but Paradise is forbidden by Allah for such a (ruler). He (Ibn Ziyad) said: Why did you not narrate it to me before this day? He replied: I (in fact) did not narrate it to you as it was not (fit) for me to narrate that to you.', 'Hasan reported', NULL, 'https://sunnah.com/muslim:262', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 263, 'وَحَدَّثَنِي الْقَاسِمُ بْنُ زَكَرِيَّاءَ، حَدَّثَنَا حُسَيْنٌ، - يَعْنِي الْجُعْفِيَّ - عَنْ زَائِدَةَ، عَنْ هِشَامٍ، قَالَ قَالَ الْحَسَنُ كُنَّا عِنْدَ مَعْقِلِ بْنِ يَسَارٍ نَعُودُهُ فَجَاءَ عُبَيْدُ اللَّهِ بْنُ زِيَادٍ فَقَالَ لَهُ مَعْقِلٌ إِنِّي سَأُحَدِّثُكَ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صلى الله عليه وسلم ثُمَّ ذَكَرَ بِمَعْنَى حَدِيثِهِمَا ‏.‏', NULL, 'Hasan reported:We were with Ma''qil b. Yasar inquiring about his health that Ubaidullah b. Ziyad came there. Ma''qil said to him: Verily I am going to narrate to you a hadith which I heard from the Messenger of Allah (ﷺ). Then he narrated the hadith like those two (mentioned above).', 'Hasan reported', NULL, 'https://sunnah.com/muslim:263', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 264, '"‏ مَا مِنْ أَمِيرٍ يَلِي أَمْرَ الْمُسْلِمِينَ ثُمَّ لاَ يَجْهَدُ لَهُمْ وَيَنْصَحُ إِلاَّ لَمْ يَدْخُلْ مَعَهُمُ الْجَنَّةَ ‏"', NULL, 'It is narrated on the authority of Abu Malih that Ubaidullah b. Ziyad visited Ma''qil b. Yasar in his illness. Ma''qil said to him:I am narrating to you a hadith which I would have never narrated to you had I not been in death-bed. I heard Allah''s apostle (ﷺ) say: A ruler who has been entrusted with the affairs of the Muslims but he makes no endeavors ( for the material and moral uplift) and does not sincerely mean (their welfare) would not enter Paradise along with them.', NULL, NULL, 'https://sunnah.com/muslim:264', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 265, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو مُعَاوِيَةَ، وَوَكِيعٌ، ح وَحَدَّثَنَا أَبُو كُرَيْبٍ، حَدَّثَنَا أَبُو مُعَاوِيَةَ، عَنِ الأَعْمَشِ، عَنْ زَيْدِ بْنِ وَهْبٍ، عَنْ حُذَيْفَةَ، قَالَ حَدَّثَنَا رَسُولُ اللَّهِ صلى الله عليه وسلم حَدِيثَيْنِ قَدْ رَأَيْتُ أَحَدَهُمَا وَأَنَا أَنْتَظِرُ الآخَرَ حَدَّثَنَا ‏"‏ أَنَّ الأَمَانَةَ نَزَلَتْ فِي جِذْرِ قُلُوبِ الرِّجَالِ ثُمَّ نَزَلَ الْقُرْآنُ فَعَلِمُوا مِنَ الْقُرْآنِ وَعَلِمُوا مِنَ السُّنَّةِ ‏"‏ ‏.‏ ثُمَّ حَدَّثَنَا عَنْ رَفْعِ الأَمَانَةِ قَالَ ‏"‏ يَنَامُ الرَّجُلُ النَّوْمَةَ فَتُقْبَضُ الأَمَانَةُ مِنْ قَلْبِهِ فَيَظَلُّ أَثَرُهَا مِثْلَ الْوَكْتِ ثُمَّ يَنَامُ النَّوْمَةَ فَتُقْبَضُ الأَمَانَةُ مِنْ قَلْبِهِ فَيَظَلُّ أَثَرُهَا مِثْلَ الْمَجْلِ كَجَمْرٍ دَحْرَجْتَهُ عَلَى رِجْلِكَ فَنَفِطَ فَتَرَاهُ مُنْتَبِرًا وَلَيْسَ فِيهِ شَىْءٌ - ثُمَّ أَخَذَ حَصًى فَدَحْرَجَهُ عَلَى رِجْلِهِ - فَيُصْبِحُ النَّاسُ يَتَبَايَعُونَ لاَ يَكَادُ أَحَدٌ يُؤَدِّي الأَمَانَةَ حَتَّى يُقَالَ إِنَّ فِي بَنِي فُلاَنٍ رَجُلاً أَمِينًا ‏.‏ حَتَّى يُقَالَ لِلرَّجُلِ مَا أَجْلَدَهُ مَا أَظْرَفَهُ مَا أَعْقَلَهُ وَمَا فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ خَرْدَلٍ مِنْ إِيمَانٍ ‏"‏ ‏.‏ وَلَقَدْ أَتَى عَلَىَّ زَمَانٌ وَمَا أُبَالِي أَيَّكُمْ بَايَعْتُ لَئِنْ كَانَ مُسْلِمًا لَيَرُدَّنَّهُ عَلَىَّ دِينُهُ وَلَئِنْ كَانَ نَصْرَانِيًّا أَوْ يَهُودِيًّا لَيَرُدَّنَّهُ عَلَىَّ سَاعِيهِ وَأَمَّا الْيَوْمَ فَمَا كُنْتُ لأُبَايِعَ مِنْكُمْ إِلاَّ فُلاَنًا وَفُلاَنًا ‏.‏', NULL, 'Hudhaifa reported:The Messenger of Allah (ﷺ) narrated to us two ahadith. I have seen one (crystallized into reality), and I am waiting for the other. He told us: Trustworthiness descended in the innermost (root) of the hearts of people. Then the Qur''an was revealed and they learnt from the Qur''an and they learnt from the Sunnah. Then he (the Holy Prophet) told us about the removal of trustworthiness. He said: The man would have a wink of sleep and trustworthiness would be taken away from his heart leaving the impression of a faint mark. He would again sleep and trustworthiness would be taken away from his heart leaving an impression of a blister, as if you rolled down an ember on your foot and it was vesicled. He would see a swelling having nothing in it. He (the Holy Prophet) then took up a pebble and rolled it down over his foot and (said): The people would enter into transactions amongst one another and hardly a person would be left who would return (things) entrusted to him. (And there would be so much paucity of honest persons) till it would be said: There in such a such tribe is a trustworthy man. And they would also say about a person: How prudent he is, how broad-minded he is and how intelligent he is, whereas in his heart there would not be faith even to the weight of a mustard seed. I have passed through a time in which I did not care with whom amongst you I entered into a transaction, for if he were a Muslim his faith would compel him to discharge his obligations to me and it he were a Christian or a Jew, the ruler would compel him to discharge his obligations to me. But today I would not enter into a transaction with you except so and so.', 'Hudhaifa reported', NULL, 'https://sunnah.com/muslim:265', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 266, 'وَحَدَّثَنَا ابْنُ نُمَيْرٍ، حَدَّثَنَا أَبِي وَوَكِيعٌ، ح وَحَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ، حَدَّثَنَا عِيسَى بْنُ يُونُسَ، جَمِيعًا عَنِ الأَعْمَشِ، بِهَذَا الإِسْنَادِ مِثْلَهُ ‏.‏', NULL, 'This hadith has been transmitted by another chain of transmitters:Ibn Numair, Waki'', Ishaq b. Ibrahim, ''Isa b. Yunus on the authority of A''mash.', 'This hadith has been transmitted by another chain of transmitters', NULL, 'https://sunnah.com/muslim:266', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 267, '"‏ تُعْرَضُ الْفِتَنُ عَلَى الْقُلُوبِ كَالْحَصِيرِ عُودًا عُودًا فَأَىُّ قَلْبٍ أُشْرِبَهَا نُكِتَ فِيهِ نُكْتَةٌ سَوْدَاءُ وَأَىُّ قَلْبٍ أَنْكَرَهَا نُكِتَ فِيهِ نُكْتَةٌ بَيْضَاءُ حَتَّى تَصِيرَ عَلَى قَلْبَيْنِ عَلَى أَبْيَضَ مِثْلِ الصَّفَا فَلاَ تَضُرُّهُ فِتْنَةٌ مَا دَامَتِ السَّمَوَاتُ وَالأَرْضُ وَالآخَرُ أَسْوَدُ مُرْبَادًّا كَالْكُوزِ مُجَخِّيًا لاَ يَعْرِفُ مَعْرُوفًا وَلاَ يُنْكِرُ مُنْكَرًا إِلاَّ مَا أُشْرِبَ مِنْ هَوَاهُ ‏"', NULL, 'It is narrated on the authority of Hudhaifa:We were sitting in the company of Umar and he said: Who amongst you has heard the Messenger of Allah (ﷺ) talking about the turmoil? Some people said: It is we who heard it. Upon this be remarked: Perhaps by turmoil you presume the unrest of man in regard to his household or neighbour, they replied: Yes. He (''Umar) observed: Such (an unrest) would be done away with by prayer, fasting and charity. But who amongst you has heard from the Apostle (ﷺ) describing that turmoil which would come like the wave of the ocean. Hudhaifa said: The people hushed into silence, I replied: It is I. He (''Umar) said: Ye, well, your father was also very pious. Hudhaifa said: I heard the Messenger of Allah (may peace be, upon him ) observing: Temptations will be presented to men''s hearts as reed mat is woven stick by stick and any heart which is impregnated by them will have a black mark put into it, but any heart which rejects them will have a white mark put in it. The result is that there will become two types of hearts: one white like a white stone which will not be harmed by any turmoil or temptation, so long as the heavens and the earth endure; and the other black and dust-coloured like a vessel which is upset, not recognizing what is good or rejecting what is abominable, but being impregnated with passion. Hudhaifa said: I narrated to him (''Umar): There is between you and that (turmoil) a closed door, but there is every likelihood of its being broken. ''Umar said: Would it be broken? You have, been rendered fatherless. Had it been opened, it would have been perhaps closed also. I said: No, it would be broken, and I narrated to him: Verily that door implies a person who would be killed or die. There is no mistake in this hadith. Abu Khalid narrated: I said to Sa''d, O Abu Malik, what do you mean by the term" Aswad Murbadda"? He replied: High degree of whiteness in blackness. I said: What is meant by" Alkoozu Mujakhiyyan"? He replied: A vessel turned upside down.', 'It is narrated on the authority of Hudhaifa', NULL, 'https://sunnah.com/muslim:267', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 268, '"‏ مُرْبَادًّا مُجَخِّيًا ‏"', NULL, 'It is narrated on the authority of Rib''i (b. Hirash). When Hudhaifa came from ''Umar he sat down to narrate to us and said:Verily yesterday when I was sitting with the Commander of the believers he asked his companions: When amongst you retains in his memory the utterance of the Messenger of Allah (ﷺ) with regard to the turmoil? -and he cited the hadith like the hadith narrated on the authority of Abu Khalid, but he did not mention the exposition of his words (Murbaddan) and (Mujakhiyyan).', NULL, NULL, 'https://sunnah.com/muslim:268', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 269, 'وَحَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى، وَعَمْرُو بْنُ عَلِيٍّ، وَعُقْبَةُ بْنُ مُكْرَمٍ الْعَمِّيُّ، قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ، عَنْ سُلَيْمَانَ التَّيْمِيِّ، عَنْ نُعَيْمِ بْنِ أَبِي هِنْدٍ، عَنْ رِبْعِيِّ بْنِ حِرَاشٍ، عَنْ حُذَيْفَةَ، أَنَّ عُمَرَ، قَالَ مَنْ يُحَدِّثُنَا أَوْ قَالَ أَيُّكُمْ يُحَدِّثُنَا - وَفِيهِمْ حُذَيْفَةُ - مَا قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم فِي الْفِتْنَةِ قَالَ حُذَيْفَةُ أَنَا ‏.‏ وَسَاقَ الْحَدِيثَ كَنَحْوِ حَدِيثِ أَبِي مَالِكٍ عَنْ رِبْعِيٍّ وَقَالَ فِي الْحَدِيثِ قَالَ حُذَيْفَةُ حَدَّثْتُهُ حَدِيثًا لَيْسَ بِالأَغَالِيطِ وَقَالَ يَعْنِي أَنَّهُ عَنْ رَسُولِ اللَّهِ صلى الله عليه وسلم ‏.‏', NULL, 'It is transmitted by Rib''i b. Hirash. who narrated it on the authority of Hudhaifa that verily ''Umar said:Who would narrate to us or who amongst you would narrate to us (and Hudhaifa was one amongst them) what the Messenger of Allah (ﷺ) had said about the turmoil? Hudhaifa said: I will, and recited the hadith like that transmitted by Abu Malik on the authority of Rib''i and he observed in connection with this hadith that Hudhaifa remarked: I am narrating to you a hadith and it has no mistake, and said: That it is transmitted from he Messenger of Allah (ﷺ).', NULL, NULL, 'https://sunnah.com/muslim:269', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 273, '"‏ لاَ تَقُومُ السَّاعَةُ حَتَّى لاَ يُقَالَ فِي الأَرْضِ اللَّهُ اللَّهُ ‏"', NULL, 'It is narrated on the authority of Anas that verily the Messenger of Allah (ﷺ) said:"The Hour (Resurrection) will not occur until ''Allah, Allah'' is not said on earth."', NULL, NULL, 'https://sunnah.com/muslim:273', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 274, '"‏ لاَ تَقُومُ السَّاعَةُ عَلَى أَحَدٍ يَقُولُ اللَّهُ اللَّهُ ‏"', NULL, 'It is narrated on the authority of Anas that the Messenger of Allah (ﷺ) said:"The Hour (Resurrection) will not occur as long as anyone says: ''Allah, Allah.''"', 'It is narrated on the authority of Anas that the Messenger of Allah (ﷺ) said', NULL, 'https://sunnah.com/muslim:274', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 276, 'حَدَّثَنَا ابْنُ أَبِي عُمَرَ، حَدَّثَنَا سُفْيَانُ، عَنِ الزُّهْرِيِّ، عَنْ عَامِرِ بْنِ سَعْدٍ، عَنْ أَبِيهِ، قَالَ قَسَمَ رَسُولُ اللَّهِ صلى الله عليه وسلم قَسْمًا فَقُلْتُ يَا رَسُولَ اللَّهِ أَعْطِ فُلاَنًا فَإِنَّهُ مُؤْمِنٌ ‏.‏ فَقَالَ النَّبِيُّ صلى الله عليه وسلم ‏"‏ أَوْ مُسْلِمٌ ‏"‏ أَقُولُهَا ثَلاَثًا ‏.‏ وَيُرَدِّدُهَا عَلَىَّ ثَلاَثًا ‏"‏ أَوْ مُسْلِمٌ ‏"‏ ثُمَّ قَالَ ‏"‏ إِنِّي لأُعْطِي الرَّجُلَ وَغَيْرُهُ أَحَبُّ إِلَىَّ مِنْهُ مَخَافَةَ أَنْ يَكُبَّهُ اللَّهُ فِي النَّارِ ‏"‏ ‏.‏', NULL, 'Sa''d narrated it on the authority of his father (Abi Waqqas) that he observed:The Messenger of Allah (ﷺ) distributed shares (of booty among his Companions). I said: Messenger of Allah! Give it to so and so, for verily he is a believer. Upon this the Messenger of Allah remarked: Or a Muslim. I (the narrator) repeated it (the word" believer" ) thrice and he (the Holy Prophet) turned his back upon me (and substituted the word)" Muslim," and then observed: I bestow it (this share) to a man out of apprehension lest Allah should throw him prostrate into the fire (of Hell) whereas in fact the other man is dearer to me than he.', 'Sa''d narrated it on the authority of his father (Abi Waqqas) that he observed', NULL, 'https://sunnah.com/muslim:276', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 277, 'حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ، حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ، حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ، عَنْ عَمِّهِ، قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدِ بْنِ أَبِي وَقَّاصٍ، عَنْ أَبِيهِ، سَعْدٍ أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم أَعْطَى رَهْطًا وَسَعْدٌ جَالِسٌ فِيهِمْ قَالَ سَعْدٌ فَتَرَكَ رَسُولُ اللَّهِ صلى الله عليه وسلم مِنْهُمْ مَنْ لَمْ يُعْطِهِ وَهُوَ أَعْجَبُهُمْ إِلَىَّ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا لَكَ عَنْ فُلاَنٍ فَوَاللَّهِ إِنِّي لأَرَاهُ مُؤْمِنًا ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَوْ مُسْلِمًا ‏"‏ ‏.‏ قَالَ فَسَكَتُّ قَلِيلاً ثُمَّ غَلَبَنِي مَا أَعْلَمُ مِنْهُ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا لَكَ عَنْ فُلاَنٍ فَوَاللَّهِ إِنِّي لأَرَاهُ مُؤْمِنًا فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَوْ مُسْلِمًا ‏"‏ ‏.‏ قَالَ فَسَكَتُّ قَلِيلاً ثُمَّ غَلَبَنِي مَا عَلِمْتُ مِنْهُ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا لَكَ عَنْ فُلاَنٍ فَوَاللَّهِ إِنِّي لأَرَاهُ مُؤْمِنًا ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَوْ مُسْلِمًا ‏.‏ إِنِّي لأُعْطِي الرَّجُلَ وَغَيْرُهُ أَحَبُّ إِلَىَّ مِنْهُ خَشْيَةَ أَنْ يُكَبَّ فِي النَّارِ عَلَى وَجْهِهِ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Sa''d that the Messenger of Allah (ﷺ) bestowed upon a group of persons (things), and Sa''d was sitting amongst them. Sa''d said:The Messenger of Allah (ﷺ) ignored some of them. And he who was ignored seemed to be more deserving in my eyes (as compared with others). I (Sa''d) said: Messenger of Allah I why is it that you did not give to such and such (man)? Verily I see him a believer. Upon this the Messenger of Allah (ﷺ) observed: Or a Muslim? I kept quiet for some time but I was again impelled (to express) what I knew about him. I said: Messenger of Allah why is it that you did not give it to such and such? Verily, by Allah, see him a believer. Upon this the Messenger of Allah (ﷺ) remarked: (Nay, not a believer) but a Muslim. He (Sa''d) said: I again kept quite for some time but what I knew about him again impelled me (to express my opinion) and I said: Why is it that you did not give (the share) to so and so: By Allah, verily I see him a believer. The Messenger of Allah (ﷺ) remarked; (Nay, not so) but a Muslim. Verily (at times) I give (a share) to a certain man apprehending that he may not be thrown prostrate in the Fire, whereas the other man (who is not given) is dearer to me (as compared with him).', NULL, NULL, 'https://sunnah.com/muslim:277', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 278, 'حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ، وَعَبْدُ بْنُ حُمَيْدٍ، قَالاَ حَدَّثَنَا يَعْقُوبُ، - وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ - حَدَّثَنَا أَبِي، عَنْ صَالِحٍ، عَنِ ابْنِ شِهَابٍ، قَالَ حَدَّثَنِي عَامِرُ بْنُ سَعْدٍ، عَنْ أَبِيهِ، سَعْدٍ أَنَّهُ قَالَ أَعْطَى رَسُولُ اللَّهِ صلى الله عليه وسلم رَهْطًا وَأَنَا جَالِسٌ فِيهِمْ ‏.‏ بِمِثْلِ حَدِيثِ ابْنِ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ ‏.‏ وَزَادَ فَقُمْتُ إِلَى رَسُولِ اللَّهِ صلى الله عليه وسلم فَسَارَرْتُهُ فَقُلْتُ مَا لَكَ عَنْ فُلاَنٍ ‏.‏', NULL, 'Sa''d reported:The Messenger of Allah (ﷺ) bestowed upon a group of persons (booty) and I was sitting with them. The remaining part of the hadith is the same as mentioned (above) with the additionI stood up and went to the Messenger of Allah (ﷺ) and whispered to him: Why did you omit such and such a man?', 'Sa''d reported', NULL, 'https://sunnah.com/muslim:278', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 279, '"‏ أَقِتَالاً أَىْ سَعْدُ إِنِّي لأُعْطِي الرَّجُلَ ‏"', NULL, 'The same hadith has been narrated on the authority of Muhammad b Sa''d and these words (are also there):The Messenger of Allah (ﷺ) gave a stroke on my neck or between my two shoulders and said: Sa''d, do you fight with me simply because I gave (a share) to a man?', NULL, NULL, 'https://sunnah.com/muslim:279', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 280, 'وَحَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى، أَخْبَرَنَا ابْنُ وَهْبٍ، أَخْبَرَنِي يُونُسُ، عَنِ ابْنِ شِهَابٍ، عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ، وَسَعِيدِ بْنِ الْمُسَيَّبِ، عَنْ أَبِي هُرَيْرَةَ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ نَحْنُ أَحَقُّ بِالشَّكِّ مِنْ إِبْرَاهِيمَ صلى الله عليه وسلم إِذْ قَالَ ‏{‏ رَبِّ أَرِنِي كَيْفَ تُحْيِي الْمَوْتَى قَالَ أَوَلَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي‏}‏ قَالَ ‏"‏ وَيَرْحَمُ اللَّهُ لُوطًا لَقَدْ كَانَ يَأْوِي إِلَى رُكْنٍ شَدِيدٍ وَلَوْ لَبِثْتُ فِي السِّجْنِ طُولَ لَبْثِ يُوسُفَ لأَجَبْتُ الدَّاعِيَ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:We have more claim to doubt than Ibrahim (ﷺ) when he said: My Lord! Show me how Thou wilt quicken the dead. He said: Believeth thou not? He said: Yes! But that my heart may rest at ease. He (the Holy Prophet) observed: May Lord take mercy on Lot, that he wanted a strong support, and had I stayed (in the prison) as long as Yusuf stayed, I would have responded to him who invited me.', NULL, NULL, 'https://sunnah.com/muslim:280', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 281, '"‏ وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي ‏"', NULL, '''Abdullah b. Muhammad narrated the same hadith on the authority of Abu Huraira and in the transmission by Malik the words are that he (the Holy Prophet) recited the verse:" but that my heart may rest at ease" and completed it. This hadith has also been narrated by Abd b. Humaid Ya''qub, i. e. son of Ibrahim b. Sa''d, Abu Uwais, Zuhri, like the one narrated by Malik with the same chain of transmission and said: He recited this verse till he completed it.', NULL, NULL, 'https://sunnah.com/muslim:281', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 285, '"‏ ثَلاَثَةٌ يُؤْتَوْنَ أَجْرَهُمْ مَرَّتَيْنِ رَجُلٌ مِنْ أَهْلِ الْكِتَابِ آمَنَ بِنَبِيِّهِ وَأَدْرَكَ النَّبِيَّ صلى الله عليه وسلم فَآمَنَ بِهِ وَاتَّبَعَهُ وَصَدَّقَهُ فَلَهُ أَجْرَانِ وَعَبْدٌ مَمْلُوكٌ أَدَّى حَقَّ اللَّهِ تَعَالَى وَحَقَّ سَيِّدِهِ فَلَهُ أَجْرَانِ وَرَجُلٌ كَانَتْ لَهُ أَمَةٌ فَغَذَاهَا فَأَحْسَنَ غِذَاءَهَا ثُمَّ أَدَّبَهَا فَأَحْسَنَ أَدَبَهَا ثُمَّ أَعْتَقَهَا وَتَزَوَّجَهَا فَلَهُ أَجْرَانِ ‏"', NULL, 'It is narrated on the authority of Sha''bi that one among the citizens of Khurasan asked him:0 Abu! some of the people amongst us who belong to Khurasan say that a person who freed his bondswoman and then married her is like one who rode over a sacrificial animal. Sha''bi said: Abu Burda b. Abi Musa narrated it to me on the authority of his father that verily the Messenger of Allah (ﷺ) said: There are three (classes of persons) who would be given a double reward. One who is amongst the People of the Book and believed in his apostle and (lived) to see the time of Apostle Muhammad (ﷺ) and affirmed his faith in him and followed him and attested his truth, for him is the double reward; and the slave of the master who discharges all those obligations that he owes to Allah and discharges his duties that he owes to his master, for him there is a double reward. And a man who had a bondswoman and fed her and fed her well, then taught her good manners, and did that well and later on granted her freedom and married her, for him is the double reward. Then Sha''bi said: Accept this hadith without (giving) anything. Formerly a man was (obliged) to travel to Medina even for a smaller hadith than this. This hadith has been narrated by another chain of transmitters like Abu Bakr b. Abi Shaiba, ''Abda b. Sulaiman Ibn Abi ''Umar Sufyan, ''Ubaidullah b. Mu''adh, Shu''ba; all of them heard it from Salih b. Salih.', NULL, NULL, 'https://sunnah.com/muslim:285', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 287, '"‏ وَالَّذِي نَفْسِي بِيَدِهِ لَيُوشِكَنَّ أَنْ يَنْزِلَ فِيكُمُ ابْنُ مَرْيَمَ صلى الله عليه وسلم حَكَمًا مُقْسِطًا فَيَكْسِرَ الصَّلِيبَ وَيَقْتُلَ الْخِنْزِيرَ وَيَضَعَ الْجِزْيَةَ وَيَفِيضَ الْمَالُ حَتَّى لاَ يَقْبَلَهُ أَحَدٌ ‏"', NULL, 'Abu Huraira reported that the Messenger of Allah (ﷺ) said:By Him in Whose hand is my life, the son of Mary (ﷺ) will soon descend among you as a just judge. He will break crosses, kill swine and abolish Jizya and the wealth will pour forth to such an extent that no one will accept it.', 'Abu Huraira reported that the Messenger of Allah (ﷺ) said', NULL, 'https://sunnah.com/muslim:287', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 288, 'وَحَدَّثَنَاهُ عَبْدُ الأَعْلَى بْنُ حَمَّادٍ، وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ، ح وَحَدَّثَنِيهِ حَرْمَلَةُ بْنُ يَحْيَى، أَخْبَرَنَا ابْنُ وَهْبٍ، قَالَ حَدَّثَنِي يُونُسُ، ح وَحَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ، وَعَبْدُ بْنُ حُمَيْدٍ، عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ، حَدَّثَنَا أَبِي، عَنْ صَالِحٍ، كُلُّهُمْ عَنِ الزُّهْرِيِّ، بِهَذَا الإِسْنَادِ وَفِي رِوَايَةِ ابْنِ عُيَيْنَةَ ‏"‏ إِمَامًا مُقْسِطًا وَحَكَمًا عَدْلاً ‏"‏ ‏.‏ وَفِي رِوَايَةِ يُونُسَ ‏"‏ حَكَمًا عَادِلاً ‏"‏ ‏.‏ وَلَمْ يَذْكُرْ ‏"‏ إِمَامًا مُقْسِطًا ‏"‏ ‏.‏ وَفِي حَدِيثِ صَالِحٍ ‏"‏ حَكَمًا مُقْسِطًا ‏"‏ كَمَا قَالَ اللَّيْثُ ‏.‏ وَفِي حَدِيثِهِ مِنَ الزِّيَادَةِ ‏"‏ وَحَتَّى تَكُونَ السَّجْدَةُ الْوَاحِدَةُ خَيْرًا مِنَ الدُّنْيَا وَمَا فِيهَا ‏"‏ ‏.‏ ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ اقْرَءُوا إِنْ شِئْتُمْ ‏{‏ وَإِنْ مِنْ أَهْلِ الْكِتَابِ إِلاَّ لَيُؤْمِنَنَّ بِهِ قَبْلَ مَوْتِهِ‏}‏ الآيَةَ ‏.‏', NULL, 'The same hadith is transmitted from Zuhri with the same chain of transmission. But in the tradition narrated by Ibn ''Uyaina the words are:" impartial leader and just judge" and in the tradition narrated by Yunus: the" judge judging with justice" and" impartial leader" are not mentioned. And in the hadith narrated by Salih like the one transmitted by Laith the words are:" impartial judge". And in the hadith transmitted by Ziyad the words are:" Till one sajda is better than the worldand what it contains. Then Abu Huraira used to say," recite" if you like: Not one of the People of the Book will fail to believe in him before his death.', NULL, NULL, 'https://sunnah.com/muslim:288', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 289, '"‏ وَاللَّهِ لَيَنْزِلَنَّ ابْنُ مَرْيَمَ حَكَمًا عَادِلاً فَلَيَكْسِرَنَّ الصَّلِيبَ وَلَيَقْتُلَنَّ الْخِنْزِيرَ وَلَيَضَعَنَّ الْجِزْيَةَ وَلَتُتْرَكَنَّ الْقِلاَصُ فَلاَ يُسْعَى عَلَيْهَا وَلَتَذْهَبَنَّ الشَّحْنَاءُ وَالتَّبَاغُضُ وَالتَّحَاسُدُ وَلَيَدْعُوَنَّ إِلَى الْمَالِ فَلاَ يَقْبَلُهُ أَحَدٌ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger or Allah (ﷺ) observed:I swear by Allah that the son of Mary will certainly descend as a just judge and he would definitely break the cross, and kill swine and abolish Jizya and would leave the young she-camel and no one would endeavour to (collect Zakat on it). Spite, mutual hatred and jealousy against one another will certainly disappear and when he summons people to accept wealth, not even one would do so.', NULL, NULL, 'https://sunnah.com/muslim:289', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 290, '"‏ كَيْفَ أَنْتُمْ إِذَا نَزَلَ ابْنُ مَرْيَمَ فِيكُمْ وَإِمَامُكُمْ مِنْكُمْ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:What will be your state when the son of Mary descends amongst you and there will be an Imam amongst you?', NULL, NULL, 'https://sunnah.com/muslim:290', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 291, '"‏ كَيْفَ أَنْتُمْ إِذَا نَزَلَ ابْنُ مَرْيَمَ فِيكُمْ وَأَمَّكُمْ ‏"', NULL, 'It is narrated on the authority of Abu Huraira that he heard the Messenger of Allah (ﷺ) as saying:What would you do when the son of Mary would descend and lead you?', NULL, NULL, 'https://sunnah.com/muslim:291', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 292, 'وَحَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ، حَدَّثَنِي الْوَلِيدُ بْنُ مُسْلِمٍ، حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ، عَنِ ابْنِ شِهَابٍ، عَنْ نَافِعٍ، مَوْلَى أَبِي قَتَادَةَ عَنْ أَبِي هُرَيْرَةَ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ كَيْفَ أَنْتُمْ إِذَا نَزَلَ فِيكُمُ ابْنُ مَرْيَمَ فَأَمَّكُمْ مِنْكُمْ ‏"‏ ‏.‏ فَقُلْتُ لاِبْنِ أَبِي ذِئْبٍ إِنَّ الأَوْزَاعِيَّ حَدَّثَنَا عَنِ الزُّهْرِيِّ عَنْ نَافِعٍ عَنْ أَبِي هُرَيْرَةَ ‏"‏ وَإِمَامُكُمْ مِنْكُمْ ‏"‏ ‏.‏ قَالَ ابْنُ أَبِي ذِئْبٍ تَدْرِي مَا أَمَّكُمْ مِنْكُمْ قُلْتُ تُخْبِرُنِي ‏.‏ قَالَ فَأَمَّكُمْ بِكِتَابِ رَبِّكُمْ تَبَارَكَ وَتَعَالَى وَسُنَّةِ نَبِيِّكُمْ صلى الله عليه وسلم ‏.‏', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) observed:What would you do when the son of Mary would descend amongst you and would lead you as one amongst you? Ibn Abi Dhi''b on the authority of Abu Huraira narrated: Your leader amongst you. Ibn Abi Dhi''b said: Do you know what the words:" He would lead as one amongst you" mean? I said: Explain these to me. He said: He would lead you according to the Book of your: Lord (hallowed be He and most exalted) and the Sunnah of your Apostle (ﷺ).', NULL, NULL, 'https://sunnah.com/muslim:292', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 294, '"‏ لاَ تَقُومُ السَّاعَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا فَإِذَا طَلَعَتْ مِنْ مَغْرِبِهَا آمَنَ النَّاسُ كُلُّهُمْ أَجْمَعُونَ فَيَوْمَئِذٍ لاَ يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ أَوْ كَسَبَتْ فِي إِيمَانِهَا خَيْرًا ‏"', NULL, 'It is narrated on the authority of Abu Huraira that the Messenger of Allah (ﷺ) said:The (Last) Hour shall not came till the sun rises from the place of its setting And on the day when it rises from the place of its setting even if all the people together affirmed their faith, it would not be of any avail to one who did not believe previously and derived no good out of his belief.', NULL, NULL, 'https://sunnah.com/muslim:294', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 295, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَابْنُ، نُمَيْرٍ وَأَبُو كُرَيْبٍ قَالُوا حَدَّثَنَا ابْنُ فُضَيْلٍ، ح وَحَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ، حَدَّثَنَا جَرِيرٌ، كِلاَهُمَا عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ، عَنْ أَبِي زُرْعَةَ، عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم ح
وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ، عَنْ زَائِدَةَ، عَنْ عَبْدِ اللَّهِ بْنِ ذَكْوَانَ، عَنْ عَبْدِ الرَّحْمَنِ الأَعْرَجِ، عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم ح
وَحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، حَدَّثَنَا مَعْمَرٌ، عَنْ هَمَّامِ بْنِ مُنَبِّهٍ، عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم بِمِثْلِ حَدِيثِ الْعَلاَءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنِ النَّبِيِّ صلى الله عليه وسلم ‏.‏', NULL, 'This hadith has been narrated by another chain of transmitters, Abu Bakr b. Abi Shaiba, Ibn Numair, Abu Kuraib, Ibn Fudail. This hadith has also been narrated through several other chains on the authority of Abu Huraira.', NULL, NULL, 'https://sunnah.com/muslim:295', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 297, 'حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ، وَإِسْحَاقُ بْنُ إِبْرَاهِيمَ، جَمِيعًا عَنِ ابْنِ عُلَيَّةَ، - قَالَ ابْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ، - حَدَّثَنَا يُونُسُ، عَنْ إِبْرَاهِيمَ بْنِ يَزِيدَ التَّيْمِيِّ، - سَمِعَهُ فِيمَا، أَعْلَمُ - عَنْ أَبِيهِ، عَنْ أَبِي ذَرٍّ، أَنَّ النَّبِيَّ صلى الله عليه وسلم قَالَ يَوْمًا ‏"‏ أَتَدْرُونَ أَيْنَ تَذْهَبُ هَذِهِ الشَّمْسُ ‏"‏ ‏.‏ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ ‏.‏ قَالَ ‏"‏ إِنَّ هَذِهِ تَجْرِي حَتَّى تَنْتَهِيَ إِلَى مُسْتَقَرِّهَا تَحْتَ الْعَرْشِ فَتَخِرُّ سَاجِدَةً وَلاَ تَزَالُ كَذَلِكَ حَتَّى يُقَالَ لَهَا ارْتَفِعِي ارْجِعِي مِنْ حَيْثُ جِئْتِ فَتَرْجِعُ فَتُصْبِحُ طَالِعَةً مِنْ مَطْلِعِهَا ثُمَّ تَجْرِي حَتَّى تَنْتَهِيَ إِلَى مُسْتَقَرِّهَا تَحْتَ الْعَرْشِ فَتَخِرُّ سَاجِدَةً وَلاَ تَزَالُ كَذَلِكَ حَتَّى يُقَالَ لَهَا ارْتَفِعِي ارْجِعِي مِنْ حَيْثُ جِئْتِ فَتَرْجِعُ فَتُصْبِحُ طَالِعَةً مِنْ مَطْلِعِهَا ثُمَّ تَجْرِي لاَ يَسْتَنْكِرُ النَّاسُ مِنْهَا شَيْئًا حَتَّى تَنْتَهِيَ إِلَى مُسْتَقَرِّهَا ذَاكَ تَحْتَ الْعَرْشِ فَيُقَالُ لَهَا ارْتَفِعِي أَصْبِحِي طَالِعَةً مِنْ مَغْرِبِكِ فَتُصْبِحُ طَالِعَةً مِنْ مَغْرِبِهَا ‏"‏ ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَتَدْرُونَ مَتَى ذَاكُمْ ذَاكَ حِينَ لاَ يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ أَوْ كَسَبَتْ فِي إِيمَانِهَا خَيْرًا ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Abu Dharr that the Messenger of Allah (ﷺ) one day said:Do you know where the sun goes? They replied: Allah and His Apostle know best. He (the Holy Prophet) observed: Verily it (the sun) glides till it reaches its resting place under the Throne. Then it falls prostrate and remains there until it is asked: Rise up and go to the place whence you came, and it goes back and continues emerging out from its rising place and then glides till it reaches its place of rest under the Throne and falls prostrate and remains in that state until it is asked: Rise up and return to the place whence you came, and it returns and emerges out from it rising place and the it glides (in such a normal way) that the people do not discern anything ( unusual in it) till it reaches its resting place under the Throne. Then it would be said to it: Rise up and emerge out from the place of your setting, and it will rise from the place of its setting. The Messenger of Allah (ﷺ) said. Do you know when it would happen? It would happen at the time when faith will not benefit one who has not previously believed or has derived no good from the faith.', NULL, NULL, 'https://sunnah.com/muslim:297', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 298, '"‏ أَتَدْرُونَ أَيْنَ تَذْهَبُ هَذِهِ الشَّمْسُ ‏"', NULL, 'It is narrated on the authority of Abu Dharr that the Messenger of Allah (ﷺ) one day said:Do you know where the sun goes? The remaining part of the hadith is the same.', NULL, NULL, 'https://sunnah.com/muslim:298', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 299, 'وَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَأَبُو كُرَيْبٍ - وَاللَّفْظُ لأَبِي كُرَيْبٍ - قَالاَ حَدَّثَنَا أَبُو مُعَاوِيَةَ، حَدَّثَنَا الأَعْمَشُ، عَنْ إِبْرَاهِيمَ التَّيْمِيِّ، عَنْ أَبِيهِ، عَنْ أَبِي ذَرٍّ، قَالَ دَخَلْتُ الْمَسْجِدَ وَرَسُولُ اللَّهِ صلى الله عليه وسلم جَالِسٌ فَلَمَّا غَابَتِ الشَّمْسُ قَالَ ‏"‏ يَا أَبَا ذَرٍّ هَلْ تَدْرِي أَيْنَ تَذْهَبُ هَذِهِ ‏"‏ ‏.‏ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ ‏.‏ قَالَ ‏"‏ فَإِنَّهَا تَذْهَبُ فَتَسْتَأْذِنُ فِي السُّجُودِ فَيُؤْذَنُ لَهَا وَكَأَنَّهَا قَدْ قِيلَ لَهَا ارْجِعِي مِنْ حَيْثُ جِئْتِ فَتَطْلُعُ مِنْ مَغْرِبِهَا ‏"‏ ‏.‏ قَالَ ثُمَّ قَرَأَ فِي قِرَاءَةِ عَبْدِ اللَّهِ وَذَلِكَ مُسْتَقَرٌّ لَهَا ‏.‏', NULL, 'Abu Dharr reported:I entered the mosque and the Messenger of Allah (ﷺ) was sitting there. When the sun disappeared (from the sight) he said: O Abu Dharr! Do you know where it goes? He (the narrator) said: Allah and His Apostle know best. He (the Holy Prophet) said. Verily it goes and begs permission, for prostration (to Allah) and the permission is granted to it. Once it would be said: Return to the place whence you came, and then it would rise from its setting place. Then he, after the recitation of ''Abdullah recited it: And that is its appointed term.', 'Abu Dharr reported', NULL, 'https://sunnah.com/muslim:299', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 300, 'حَدَّثَنَا أَبُو سَعِيدٍ الأَشَجُّ، وَإِسْحَاقُ بْنُ إِبْرَاهِيمَ، - قَالَ إِسْحَاقُ أَخْبَرَنَا وَقَالَ الأَشَجُّ، حَدَّثَنَا - وَكِيعٌ، حَدَّثَنَا الأَعْمَشُ، عَنْ إِبْرَاهِيمَ التَّيْمِيِّ، عَنْ أَبِيهِ، عَنْ أَبِي ذَرٍّ، قَالَ سَأَلْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم عَنْ قَوْلِ اللَّهِ تَعَالَى ‏{‏ وَالشَّمْسُ تَجْرِي لِمُسْتَقَرٍّ لَهَا‏}‏ قَالَ ‏"‏ مُسْتَقَرُّهَا تَحْتَ الْعَرْشِ ‏"‏ ‏.‏', NULL, 'Abu Dharr reported:I asked the Messenger of Allah (ﷺ) the (implication of the) words of Allah, the Exalted: The sun glides to its appointed resting place. He replied: Its appointed resting place is under the Throne.', 'Abu Dharr reported', NULL, 'https://sunnah.com/muslim:300', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 301, 'حَدَّثَنِي أَبُو الطَّاهِرِ، أَحْمَدُ بْنُ عَمْرِو بْنِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ سَرْحٍ أَخْبَرَنَا ابْنُ وَهْبٍ، قَالَ أَخْبَرَنِي يُونُسُ، عَنِ ابْنِ شِهَابٍ، قَالَ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ، أَنَّ عَائِشَةَ، زَوْجَ النَّبِيِّ صلى الله عليه وسلم أَخْبَرَتْهُ أَنَّهَا قَالَتْ كَانَ أَوَّلُ مَا بُدِئَ بِهِ رَسُولُ اللَّهِ صلى الله عليه وسلم مِنَ الْوَحْىِ الرُّؤْيَا الصَّادِقَةَ فِي النَّوْمِ فَكَانَ لاَ يَرَى رُؤْيَا إِلاَّ جَاءَتْ مِثْلَ فَلَقِ الصُّبْحِ ثُمَّ حُبِّبَ إِلَيْهِ الْخَلاَءُ فَكَانَ يَخْلُو بِغَارِ حِرَاءٍ يَتَحَنَّثُ فِيهِ - وَهُوَ التَّعَبُّدُ - اللَّيَالِيَ أُولاَتِ الْعَدَدِ قَبْلَ أَنْ يَرْجِعَ إِلَى أَهْلِهِ وَيَتَزَوَّدُ لِذَلِكَ ثُمَّ يَرْجِعُ إِلَى خَدِيجَةَ فَيَتَزَوَّدُ لِمِثْلِهَا حَتَّى فَجِئَهُ الْحَقُّ وَهُوَ فِي غَارِ حِرَاءٍ فَجَاءَهُ الْمَلَكُ فَقَالَ اقْرَأْ ‏.‏ قَالَ ‏"‏ مَا أَنَا بِقَارِئٍ - قَالَ - فَأَخَذَنِي فَغَطَّنِي حَتَّى بَلَغَ مِنِّي الْجَهْدَ ثُمَّ أَرْسَلَنِي فَقَالَ اقْرَأْ ‏.‏ قَالَ قُلْتُ مَا أَنَا بِقَارِئٍ - قَالَ - فَأَخَذَنِي فَغَطَّنِي الثَّانِيَةَ حَتَّى بَلَغَ مِنِّي الْجَهْدَ ثُمَّ أَرْسَلَنِي فَقَالَ اقْرَأْ ‏.‏ فَقُلْتُ مَا أَنَا بِقَارِئٍ فَأَخَذَنِي فَغَطَّنِي الثَّالِثَةَ حَتَّى بَلَغَ مِنِّي الْجَهْدَ ثُمَّ أَرْسَلَنِي ‏.‏ فَقَالَ ‏{‏ اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ * خَلَقَ الإِنْسَانَ مِنْ عَلَقٍ * اقْرَأْ وَرَبُّكَ الأَكْرَمُ * الَّذِي عَلَّمَ بِالْقَلَمِ * عَلَّمَ الإِنْسَانَ مَا لَمْ يَعْلَمْ‏}‏ ‏"‏ ‏.‏ فَرَجَعَ بِهَا رَسُولُ اللَّهِ صلى الله عليه وسلم تَرْجُفُ بَوَادِرُهُ حَتَّى دَخَلَ عَلَى خَدِيجَةَ فَقَالَ ‏"‏ زَمِّلُونِي زَمِّلُونِي ‏"‏ ‏.‏ فَزَمَّلُوهُ حَتَّى ذَهَبَ عَنْهُ الرَّوْعُ ثُمَّ قَالَ لِخَدِيجَةَ ‏"‏ أَىْ خَدِيجَةُ مَا لِي ‏"‏ ‏.‏ وَأَخْبَرَهَا الْخَبَرَ قَالَ ‏"‏ لَقَدْ خَشِيتُ عَلَى نَفْسِي ‏"‏ ‏.‏ قَالَتْ لَهُ خَدِيجَةُ كَلاَّ أَبْشِرْ فَوَاللَّهِ لاَ يُخْزِيكَ اللَّهُ أَبَدًا وَاللَّهِ إِنَّكَ لَتَصِلُ الرَّحِمَ وَتَصْدُقُ الْحَدِيثَ وَتَحْمِلُ الْكَلَّ وَتَكْسِبُ الْمَعْدُومَ وَتَقْرِي الضَّيْفَ وَتُعِينُ عَلَى نَوَائِبِ الْحَقِّ ‏.‏ فَانْطَلَقَتْ بِهِ خَدِيجَةُ حَتَّى أَتَتْ بِهِ وَرَقَةَ بْنَ نَوْفَلِ بْنِ أَسَدِ بْنِ عَبْدِ الْعُزَّى وَهُوَ ابْنُ عَمِّ خَدِيجَةَ أَخِي أَبِيهَا وَكَانَ امْرَأً تَنَصَّرَ فِي الْجَاهِلِيَّةِ وَكَانَ يَكْتُبُ الْكِتَابَ الْعَرَبِيَّ وَيَكْتُبُ مِنَ الإِنْجِيلِ بِالْعَرَبِيَّةِ مَا شَاءَ اللَّهُ أَنْ يَكْتُبَ وَكَانَ شَيْخًا كَبِيرًا قَدْ عَمِيَ ‏.‏ فَقَالَتْ لَهُ خَدِيجَةُ أَىْ عَمِّ اسْمَعْ مِنِ ابْنِ أَخِيكَ ‏.‏ قَالَ وَرَقَةُ بْنُ نَوْفَلٍ يَا ابْنَ أَخِي مَاذَا تَرَى فَأَخْبَرَهُ رَسُولُ اللَّهِ صلى الله عليه وسلم خَبَرَ مَا رَآهُ فَقَالَ لَهُ وَرَقَةُ هَذَا النَّامُوسُ الَّذِي أُنْزِلَ عَلَى مُوسَى صلى الله عليه وسلم يَا لَيْتَنِي فِيهَا جَذَعًا يَا لَيْتَنِي أَكُونُ حَيًّا حِينَ يُخْرِجُكَ قَوْمُكَ ‏.‏ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَوَمُخْرِجِيَّ هُمْ ‏"‏ ‏.‏ قَالَ وَرَقَةُ نَعَمْ لَمْ يَأْتِ رَجُلٌ قَطُّ بِمَا جِئْتَ بِهِ إِلاَّ عُودِيَ وَإِنْ يُدْرِكْنِي يَوْمُكَ أَنْصُرْكَ نَصْرًا مُؤَزَّرًا ‏"‏ ‏.‏', NULL, 'A''isha, the wife of the Messenger of Allah (ﷺ), reported:The first (form) with which was started the revelation to the Messenger of Allah was the true vision in sleep. And he did not see any vision but it came like the bright gleam of dawn. Thenceforth solitude became dear to him and he used to seclude himself in the cave of Hira'', where he would engage in tahannuth (and that is a worship for a number of nights) before returning to his family and getting provisions again for this purpose. He would then return to Khadija and take provisions for a like period, till Truth came upon him while he was in the cave of Hira''. There came to him the angel and said: Recite, to which he replied: I am not lettered. He took hold of me [the Apostle said] and pressed me, till I was hard pressed; thereafter he let me off and said: Recite. I said: I am not lettered. He then again took hold of me and pressed me for the second time till I was hard pressed and then let me off and said: Recite, to which I replied: I am not lettered. He took hold of me and pressed me for the third time, till I was hard pressed and then let me go and said: Recite in the name of your Lord Who created, created man from a clot of blood. Recite. And your most bountiful Lord is He Who taught the use of pen, taught man what he knew not (al-Qur''an, xcvi. 1-4). Then the Prophet returned therewith, his heart was trembling, and he went to Khadija and said: Wrap me up, wrap me up! So they wrapped him till the fear had left him. He then said to Khadija: O Khadija! what has happened to me? and he informed her of the happening, saying: I fear for myself. She replied: It can''t be. Be happy. I swear by Allah that He shall never humiliate you. By Allah, you join ties of relationship, you speak the truth, you bear people''s burden, you help the destitute, you entertain guests, and you help against the vicissitudes which affect people. Khadija then took him to Waraqa b. Naufal b. Asad b. ''Abd al-''Uzza, and he was the son of Khadija''s uncle, i. e., the brother of her father. And he was the man who had embraced Christianity in the Days of Ignorance (i. e. before Islam) and he used to write books in Arabic and, therefore, wrote Injil in Arabic as God willed that he should write. He was very old and had become blind Khadija said to him: O uncle! listen to the son of your brother. Waraqa b. Naufal said: O my nephew! what did you see? The Messenger of Allah (ﷺ), then, informed him what he had seen, and Waraqa said to him: It is namus that God sent down to Musa. Would that I were then (during your prophetic career) a young man. Would that I might be alive when your people would expel you! The Messenger of Allah (ﷺ) said: Will they drive me out? Waraqa said: Yes. Never came a man with a like of what you have brought but met hostilities. If I see your day I shall help you wholeheartedly.', 'A''isha, the wife of the Messenger of Allah (ﷺ), reported', NULL, 'https://sunnah.com/muslim:301', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 302, 'وَحَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ، حَدَّثَنَا عَبْدُ الرَّزَّاقِ، أَخْبَرَنَا مَعْمَرٌ، قَالَ قَالَ الزُّهْرِيُّ وَأَخْبَرَنِي عُرْوَةُ، عَنْ عَائِشَةَ، أَنَّهَا قَالَتْ أَوَّلُ مَا بُدِئَ بِهِ رَسُولُ اللَّهِ صلى الله عليه وسلم مِنَ الْوَحْىِ ‏.‏ وَسَاقَ الْحَدِيثَ بِمِثْلِ حَدِيثِ يُونُسَ ‏.‏ غَيْرَ أَنَّهُ قَالَ فَوَاللَّهِ لاَ يُحْزِنُكَ اللَّهُ أَبَدًا ‏.‏ وَقَالَ قَالَتْ خَدِيجَةُ أَىِ ابْنَ عَمِّ اسْمَعْ مِنِ ابْنِ أَخِيكَ ‏.‏', NULL, 'This hadith has been narrated on the authority of ''A''isha with another chain of narrators like one transmitted by Yunus, i. e. the first thing with which the revelation was initiated with the Messenger of Allah (ﷺ) except the words:By Allah, Allah would never humiliate you, and Khadija said: O son of my uncle! Listen to the son of your brother.', NULL, NULL, 'https://sunnah.com/muslim:302', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 303, 'وَحَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ، قَالَ حَدَّثَنِي أَبِي، عَنْ جَدِّي، قَالَ حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ، قَالَ ابْنُ شِهَابٍ سَمِعْتُ عُرْوَةَ بْنَ الزُّبَيْرِ، يَقُولُ قَالَتْ عَائِشَةُ زَوْجُ النَّبِيِّ صلى الله عليه وسلم فَرَجَعَ إِلَى خَدِيجَةَ يَرْجُفُ فُؤَادُهُ وَاقْتَصَّ الْحَدِيثَ بِمِثْلِ حَدِيثِ يُونُسَ وَمَعْمَرٍ وَلَمْ يَذْكُرْ أَوَّلَ حَدِيثِهِمَا مِنْ قَوْلِهِ أَوَّلُ مَا بُدِئَ بِهِ رَسُولُ اللَّهِ صلى الله عليه وسلم مِنَ الْوَحْىِ الرُّؤْيَا الصَّادِقَةُ ‏.‏ وَتَابَعَ يُونُسَ عَلَى قَوْلِهِ فَوَاللَّهِ لاَ يُخْزِيكَ اللَّهُ أَبَدًا ‏.‏ وَذَكَرَ قَوْلَ خَدِيجَةَ أَىِ ابْنَ عَمِّ اسْمَعْ مِنِ ابْنِ أَخِيكَ ‏.‏', NULL, 'This hadith has been reported from ''A''isha by another chain of transmitters and the words are:He (the Holy Prophet) came to Khadija an his heart was trembling. The rest of the hadith has been narrated like one transmitted by Yunus and Ma''mar, but the first part is not mentioned, i. e. the first thing with which was started the revelation to the Prophet was the true vision. And these words like those transmitted by Yunus are mentioned thus: By Allah, Allah would never humiliate you. And there is also a mention of the words of Khadija: O son of my uncle! Listen to the son of your brother.', NULL, NULL, 'https://sunnah.com/muslim:303', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 304, 'وَحَدَّثَنِي أَبُو الطَّاهِرِ، أَخْبَرَنَا ابْنُ وَهْبٍ، قَالَ حَدَّثَنِي يُونُسُ، قَالَ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ، أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ الأَنْصَارِيَّ، - وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صلى الله عليه وسلم كَانَ يُحَدِّثُ قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم وَهُوَ يُحَدِّثُ عَنْ فَتْرَةِ الْوَحْىِ - قَالَ فِي حَدِيثِهِ ‏"‏ فَبَيْنَا أَنَا أَمْشِي سَمِعْتُ صَوْتًا مِنَ السَّمَاءِ فَرَفَعْتُ رَأْسِي فَإِذَا الْمَلَكُ الَّذِي جَاءَنِي بِحِرَاءٍ جَالِسًا عَلَى كُرْسِيٍّ بَيْنَ السَّمَاءِ وَالأَرْضِ ‏"‏ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ فَجُئِثْتُ مِنْهُ فَرَقًا فَرَجَعْتُ فَقُلْتُ زَمِّلُونِي زَمِّلُونِي ‏.‏ فَدَثَّرُونِي فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى ‏{‏ يَا أَيُّهَا الْمُدَّثِّرُ * قُمْ فَأَنْذِرْ * وَرَبَّكَ فَكَبِّرْ * وَثِيَابَكَ فَطَهِّرْ * وَالرُّجْزَ فَاهْجُرْ‏}‏ وَهِيَ الأَوْثَانُ قَالَ ثُمَّ تَتَابَعَ الْوَحْىُ ‏.‏', NULL, 'Jabir b. ''Abdullah al-Ansari who was one of the Companions of the Messenger of Allah (ﷺ) reportedThe Messenger of Allah (ﷺ) told about the intermission of revelation and narrated While I was walking I heard a voice from the sky, and raising my head I saw the angel who had come to me in Hira'', sitting on a Throne between heaven and earth I was terror-stricken on that account and came back (to my family) and said:Wrap me up, wrap me up! So they wrapped me up, and the Blessed and Most Exalted Allah sent down:" You who are shrouded, arise and deliver warning, your Lord magnify, your clothes cleanse, and defilement shun," and" defilement" means idols; and then the revelation was followed continuously.', NULL, NULL, 'https://sunnah.com/muslim:304', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 305, 'وَحَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ، قَالَ حَدَّثَنِي أَبِي، عَنْ جَدِّي، قَالَ حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ، عَنِ ابْنِ شِهَابٍ، قَالَ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ، يَقُولُ أَخْبَرَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ، أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صلى الله عليه وسلم يَقُولُ ‏"‏ ثُمَّ فَتَرَ الْوَحْىُ عَنِّي فَتْرَةً فَبَيْنَا أَنَا أَمْشِي ‏"‏ ثُمَّ ذَكَرَ مِثْلَ حَدِيثِ يُونُسَ غَيْرَ أَنَّهُ قَالَ ‏"‏ فَجُثِثْتُ مِنْهُ فَرَقًا حَتَّى هَوَيْتُ إِلَى الأَرْضِ ‏"‏ ‏.‏ قَالَ وَقَالَ أَبُو سَلَمَةَ وَالرُّجْزُ الأَوْثَانُ قَالَ ثُمَّ حَمِيَ الْوَحْىُ بَعْدُ وَتَتَابَعَ', NULL, 'It is narrated on the authority of Jabir b. Abdullah that he heard the Messenger of Allah (ﷺ) says:The wahi was intermitted for me for a small span of time and while I was walking, and then the hadith like the one narrated by Yunus was transmitted but with the exception of these words: I was terror-stricken till I fell on the ground. Abu Salama said: Defilement means idols. After this the revelation was speeded up and followed rapidly.', NULL, NULL, 'https://sunnah.com/muslim:305', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 306, '"‏ فَجُثِثْتُ مِنْهُ ‏"', NULL, 'This hadith, the like of one narrated by Yunus has also been transmitted by Ma''mar on the authority of al-Zuhri who narrated:Allah the Most Glorious and Exalted revealed this:" You who are shrouded, arise and deliver warning, your Lord magnify, your clothes cleanse and defilement shun," before making the prayer obligatory. I felt terror-stricken as narrated by Uqail.', NULL, NULL, 'https://sunnah.com/muslim:306', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 307, 'وَحَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ، حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ، حَدَّثَنَا الأَوْزَاعِيُّ، قَالَ سَمِعْتُ يَحْيَى، يَقُولُ سَأَلْتُ أَبَا سَلَمَةَ أَىُّ الْقُرْآنِ أُنْزِلَ قَبْلُ قَالَ يَا أَيُّهَا الْمُدَّثِّرُ ‏.‏ فَقُلْتُ أَوِ اقْرَأْ ‏.‏ فَقَالَ سَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ أَىُّ الْقُرْآنِ أُنْزِلَ قَبْلُ قَالَ يَا أَيُّهَا الْمُدَّثِّرُ ‏.‏ فَقُلْتُ أَوِ اقْرَأْ قَالَ جَابِرٌ أُحَدِّثُكُمْ مَا حَدَّثَنَا رَسُولُ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ جَاوَرْتُ بِحِرَاءٍ شَهْرًا فَلَمَّا قَضَيْتُ جِوَارِي نَزَلْتُ فَاسْتَبْطَنْتُ بَطْنَ الْوَادِي فَنُودِيتُ فَنَظَرْتُ أَمَامِي وَخَلْفِي وَعَنْ يَمِينِي وَعَنْ شِمَالِي فَلَمْ أَرَ أَحَدًا ثُمَّ نُودِيتُ فَنَظَرْتُ فَلَمْ أَرَ أَحَدًا ثُمَّ نُودِيتُ فَرَفَعْتُ رَأْسِي فَإِذَا هُوَ عَلَى الْعَرْشِ فِي الْهَوَاءِ - يَعْنِي جِبْرِيلَ عَلَيْهِ السَّلاَمُ - فَأَخَذَتْنِي رَجْفَةٌ شَدِيدَةٌ فَأَتَيْتُ خَدِيجَةَ فَقُلْتُ دَثِّرُونِي ‏.‏ فَدَثَّرُونِي فَصَبُّوا عَلَىَّ مَاءً فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ ‏{‏ يَا أَيُّهَا الْمُدَّثِّرُ * قُمْ فَأَنْذِرْ * وَرَبَّكَ فَكَبِّرْ * وَثِيَابَكَ فَطَهِّرْ‏}‏ ‏"‏ ‏.‏', NULL, 'Yahya reported:I asked Abu Salama what was revealed first from the Qur''an. He said:" 0, the shrouded one." I said: Or" Recite." Jabir said: I am narrating to you what was narrated to us by the Messenger of Allah (ﷺ). He said: I stayed in Hira'' for one month and when my stay was completed, I come down and went into the heart of the valley. Somebody called me aloud. I looked in front of me, behind me, on the right of my side and on my left, but I did not see any body. I was again called and I looked about but saw nothing. I was called again and raised my head, and there on the Throne in the open atmosphere he, i. e. Gabriel (peace be upon him) was sitting. I began to tremble on account of fear. I came to Khadija and said: Wrap me up. They wrapped me up and threw water on me and Allah, the Exalted and Glorious, sent down this: you who are shrouded! arise and deliver warning, your Lord magnify, your clothes cleanse."', 'Yahya reported', NULL, 'https://sunnah.com/muslim:307', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 308, '"‏ فَإِذَا هُوَ جَالِسٌ عَلَى عَرْشٍ بَيْنَ السَّمَاءِ وَالأَرْضِ ‏"', NULL, 'Yahya b Abi Kathir has reported this hadith with the same chain of transmitters and narrated:And there he was sitting on the Throne between the heaven and the earth.', NULL, NULL, 'https://sunnah.com/muslim:308', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 309, 'حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ، حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ، حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ، عَنْ أَنَسِ بْنِ مَالِكٍ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ أُتِيتُ بِالْبُرَاقِ - وَهُوَ دَابَّةٌ أَبْيَضُ طَوِيلٌ فَوْقَ الْحِمَارِ وَدُونَ الْبَغْلِ يَضَعُ حَافِرَهُ عِنْدَ مُنْتَهَى طَرْفِهِ - قَالَ فَرَكِبْتُهُ حَتَّى أَتَيْتُ بَيْتَ الْمَقْدِسِ - قَالَ - فَرَبَطْتُهُ بِالْحَلْقَةِ الَّتِي يَرْبِطُ بِهِ الأَنْبِيَاءُ - قَالَ - ثُمَّ دَخَلْتُ الْمَسْجِدَ فَصَلَّيْتُ فِيهِ رَكْعَتَيْنِ ثُمَّ خَرَجْتُ فَجَاءَنِي جِبْرِيلُ - عَلَيْهِ السَّلاَمُ - بِإِنَاءٍ مِنْ خَمْرٍ وَإِنَاءٍ مِنْ لَبَنٍ فَاخْتَرْتُ اللَّبَنَ فَقَالَ جِبْرِيلُ صلى الله عليه وسلم اخْتَرْتَ الْفِطْرَةَ ‏.‏ ثُمَّ عَرَجَ بِنَا إِلَى السَّمَاءِ فَاسْتَفْتَحَ جِبْرِيلُ فَقِيلَ مَنْ أَنْتَ قَالَ جِبْرِيلُ ‏.‏ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ ‏.‏ قِيلَ وَقَدْ بُعِثَ إِلَيْهِ قَالَ قَدْ بُعِثَ إِلَيْهِ ‏.‏ فَفُتِحَ لَنَا فَإِذَا أَنَا بِآدَمَ فَرَحَّبَ بِي وَدَعَا لِي بِخَيْرٍ ‏.‏ ثُمَّ عَرَجَ بِنَا إِلَى السَّمَاءِ الثَّانِيَةِ فَاسْتَفْتَحَ جِبْرِيلُ عَلَيْهِ السَّلاَمُ ‏.‏ فَقِيلَ مَنْ أَنْتَ قَالَ جِبْرِيلُ ‏.‏ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ ‏.‏ قِيلَ وَقَدْ بُعِثَ إِلَيْهِ قَالَ قَدْ بُعِثَ إِلَيْهِ ‏.‏ فَفُتِحَ لَنَا فَإِذَا أَنَا بِابْنَىِ الْخَالَةِ عِيسَى ابْنِ مَرْيَمَ وَيَحْيَى بْنِ زَكَرِيَّاءَ صَلَوَاتُ اللَّهِ عَلَيْهِمَا فَرَحَّبَا وَدَعَوَا لِي بِخَيْرٍ ‏.‏ ثُمَّ عَرَجَ بِي إِلَى السَّمَاءِ الثَّالِثَةِ فَاسْتَفْتَحَ جِبْرِيلُ ‏.‏ فَقِيلَ مَنْ أَنْتَ قَالَ جِبْرِيلُ ‏.‏ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ صلى الله عليه وسلم ‏.‏ قِيلَ وَقَدْ بُعِثَ إِلَيْهِ قَالَ قَدْ بُعِثَ إِلَيْهِ ‏.‏ فَفُتِحَ لَنَا فَإِذَا أَنَا بِيُوسُفَ صلى الله عليه وسلم إِذَا هُوَ قَدْ أُعْطِيَ شَطْرَ الْحُسْنِ فَرَحَّبَ وَدَعَا لِي بِخَيْرٍ ‏.‏ ثُمَّ عَرَجَ بِنَا إِلَى السَّمَاءِ الرَّابِعَةِ فَاسْتَفْتَحَ جِبْرِيلُ - عَلَيْهِ السَّلاَمُ - قِيلَ مَنْ هَذَا قَالَ جِبْرِيلُ ‏.‏ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ ‏.‏ قَالَ وَقَدْ بُعِثَ إِلَيْهِ قَالَ قَدْ بُعِثَ إِلَيْهِ ‏.‏ فَفُتِحَ لَنَا فَإِذَا أَنَا بِإِدْرِيسَ فَرَحَّبَ وَدَعَا لِي بِخَيْرٍ قَالَ اللَّهُ عَزَّ وَجَلَّ ‏{‏ وَرَفَعْنَاهُ مَكَانًا عَلِيًّا‏}‏ ثُمَّ عَرَجَ بِنَا إِلَى السَّمَاءِ الْخَامِسَةِ فَاسْتَفْتَحَ جِبْرِيلُ ‏.‏ قِيلَ مَنْ هَذَا قَالَ جِبْرِيلُ ‏.‏ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ ‏.‏ قِيلَ وَقَدْ بُعِثَ إِلَيْهِ قَالَ قَدْ بُعِثَ إِلَيْهِ ‏.‏ فَفُتِحَ لَنَا فَإِذَا أَنَا بِهَارُونَ صلى الله عليه وسلم فَرَحَّبَ وَدَعَا لِي بِخَيْرٍ ‏.‏ ثُمَّ عَرَجَ بِنَا إِلَى السَّمَاءِ السَّادِسَةِ فَاسْتَفْتَحَ جِبْرِيلُ عَلَيْهِ السَّلاَمُ ‏.‏ قِيلَ مَنْ هَذَا قَالَ جِبْرِيلُ ‏.‏ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ ‏.‏ قِيلَ وَقَدْ بُعِثَ إِلَيْهِ قَالَ قَدْ بُعِثَ إِلَيْهِ ‏.‏ فَفُتِحَ لَنَا فَإِذَا أَنَا بِمُوسَى صلى الله عليه وسلم فَرَحَّبَ وَدَعَا لِي بِخَيْرٍ ‏.‏ ثُمَّ عَرَجَ بِنَا إِلَى السَّمَاءِ السَّابِعَةِ فَاسْتَفْتَحَ جِبْرِيلُ فَقِيلَ مَنْ هَذَا قَالَ جِبْرِيلُ ‏.‏ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ صلى الله عليه وسلم ‏.‏ قِيلَ وَقَدْ بُعِثَ إِلَيْهِ قَالَ قَدْ بُعِثَ إِلَيْهِ ‏.‏ فَفُتِحَ لَنَا فَإِذَا أَنَا بِإِبْرَاهِيمَ صلى الله عليه وسلم مُسْنِدًا ظَهْرَهُ إِلَى الْبَيْتِ الْمَعْمُورِ وَإِذَا هُوَ يَدْخُلُهُ كُلَّ يَوْمٍ سَبْعُونَ أَلْفَ مَلَكٍ لاَ يَعُودُونَ إِلَيْهِ ثُمَّ ذَهَبَ بِي إِلَى السِّدْرَةِ الْمُنْتَهَى وَإِذَا وَرَقُهَا كَآذَانِ الْفِيَلَةِ وَإِذَا ثَمَرُهَا كَالْقِلاَلِ - قَالَ - فَلَمَّا غَشِيَهَا مِنْ أَمْرِ اللَّهِ مَا غَشِيَ تَغَيَّرَتْ فَمَا أَحَدٌ مِنْ خَلْقِ اللَّهِ يَسْتَطِيعُ أَنْ يَنْعَتَهَا مِنْ حُسْنِهَا ‏.‏ فَأَوْحَى اللَّهُ إِلَىَّ مَا أَوْحَى فَفَرَضَ عَلَىَّ خَمْسِينَ صَلاَةً فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَنَزَلْتُ إِلَى مُوسَى صلى الله عليه وسلم فَقَالَ مَا فَرَضَ رَبُّكَ عَلَى أُمَّتِكَ قُلْتُ خَمْسِينَ صَلاَةً ‏.‏ قَالَ ارْجِعْ إِلَى رَبِّكَ فَاسْأَلْهُ التَّخْفِيفَ فَإِنَّ أُمَّتَكَ لاَ يُطِيقُونَ ذَلِكَ فَإِنِّي قَدْ بَلَوْتُ بَنِي إِسْرَائِيلَ وَخَبَرْتُهُمْ ‏.‏ قَالَ فَرَجَعْتُ إِلَى رَبِّي فَقُلْتُ يَا رَبِّ خَفِّفْ عَلَى أُمَّتِي ‏.‏ فَحَطَّ عَنِّي خَمْسًا فَرَجَعْتُ إِلَى مُوسَى فَقُلْتُ حَطَّ عَنِّي خَمْسًا ‏.‏ قَالَ إِنَّ أُمَّتَكَ لاَ يُطِيقُونَ ذَلِكَ فَارْجِعْ إِلَى رَبِّكَ فَاسْأَلْهُ التَّخْفِيفَ ‏.‏ - قَالَ - فَلَمْ أَزَلْ أَرْجِعُ بَيْنَ رَبِّي تَبَارَكَ وَتَعَالَى وَبَيْنَ مُوسَى - عَلَيْهِ السَّلاَمُ - حَتَّى قَالَ يَا مُحَمَّدُ إِنَّهُنَّ خَمْسُ صَلَوَاتٍ كُلَّ يَوْمٍ وَلَيْلَةٍ لِكُلِّ صَلاَةٍ عَشْرٌ فَذَلِكَ خَمْسُونَ صَلاَةً ‏.‏ وَمَنْ هَمَّ بِحَسَنَةٍ فَلَمْ يَعْمَلْهَا كُتِبَتْ لَهُ حَسَنَةً فَإِنْ عَمِلَهَا كُتِبَتْ لَهُ عَشْرًا وَمَنْ هَمَّ بِسَيِّئَةٍ فَلَمْ يَعْمَلْهَا لَمْ تُكْتَبْ شَيْئًا فَإِنْ عَمِلَهَا كُتِبَتْ سَيِّئَةً وَاحِدَةً - قَالَ - فَنَزَلْتُ حَتَّى انْتَهَيْتُ إِلَى مُوسَى صلى الله عليه وسلم فَأَخْبَرْتُهُ فَقَالَ ارْجِعْ إِلَى رَبِّكَ فَاسْأَلْهُ التَّخْفِيفَ ‏.‏ فَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم فَقُلْتُ قَدْ رَجَعْتُ إِلَى رَبِّي حَتَّى اسْتَحْيَيْتُ مِنْهُ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of Anas b. Malik that the Messenger of Allah (ﷺ) said:I was brought al-Buraq Who is an animal white and long, larger than a donkey but smaller than a mule, who would place his hoof a distance equal to the range of version. I mounted it and came to the Temple (Bait Maqdis in Jerusalem), then tethered it to the ring used by the prophets. I entered the mosque and prayed two rak''ahs in it, and then came out and Gabriel brought me a vessel of wine and a vessel of milk. I chose the milk, and Gabriel said: You have chosen the natural thing. Then he took me to heaven. Gabriel then asked the (gate of heaven) to be opened and he was asked who he was. He replied: Gabriel. He was again asked: Who is with you? He (Gabriel) said: Muhammad. It was said: Has he been sent for? Gabriel replied: He has indeed been sent for. And (the door of the heaven) was opened for us and lo! we saw Adam. He welcomed me and prayed for my good. Then we ascended to the second heaven. Gabriel (peace be upon him) (asked the door of heaven to be opened), and he was asked who he was. He answered: Gabriel; and was again asked: Who is with you? He replied: Muhammad. It was said: Has he been sent for? He replied: He has indeed been sent for. The gate was opened. When I entered ''Isa b. Maryam and Yahya b. Zakariya (peace be upon both of them), cousins from the maternal side. welcomed me and prayed for my good Then I was taken to the third heaven and Gabriel asked for the opening (of the door). He was asked: Who are you? He replied: Gabriel. He was (again) asked: Who is with you? He replied Muhammad (ﷺ). It was said: Has he been sent for? He replied He has indeed been sent for. (The gate) was opened for us and I saw Yusuf (peace of Allah be upon him) who had been given half of (world) beauty. He welcomed me prayed for my well-being. Then he ascended with us to the fourth heaven. Gabriel (peace be upon him) asked for the (gate) to be opened, and it was said: Who is he? He replied: Gabriel. It was (again) said: Who is with you? He said: Muhammad. It was said: Has he been sent for? He replied: He has indeed been sent for. The (gate) was opened for us, and lo! Idris was there. He welcomed me and prayed for my well-being (About him) Allah, the Exalted and the Glorious, has said:" We elevated him (Idris) to the exalted position" (Qur''an xix. 57). Then he ascended with us to the fifth heaven and Gabriel asked for the (gate) to be opened. It was said: Who is he? He replied Gabriel. It was (again) said: Who is with thee? He replied: Muhammad. It was said Has he been sent for? He replied: He has indeed been sent for. (The gate) was opened for us and then I was with Harun (Aaron-peace of Allah be upon him). He welcomed me prayed for my well-being. Then I was taken to the sixth heaven. Gabriel (peace be upon him) asked for the door to be opened. It was said: Who is he? He replied: Gabriel. It was said: Who is with thee? He replied: Muhammad. It was said: Has he been sent for? He replied: He has indeed been sent for. (The gate) was opened for us and there I was with Musa (Moses peace be upon him) He welcomed me and prayed for my well-being. Then I was taken up to the seventh heaven. Gabriel asked the (gate) to be opened. It was said: Who is he? He said: Gabriel It was said. Who is with thee? He replied: Muhammad (may peace be upon him.) It was said: Has he been sent for? He replied: He has indeed been sent for. (The gate) was opened for us and there I found Ibrahim (Abraham peace be upon him) reclining against the Bait-ul-Ma''mur and there enter into it seventy thousand angels every day, never to visit (this place) again. Then I was taken to Sidrat-ul-Muntaha whose leaves were like elephant ears and its fruit like big earthenware vessels. And when it was covered by the Command of Allah, it underwent such a change that none amongst the creation has the power to praise its beauty. Then Allah revealed to me a revelation and He made obligatory for me fifty prayers every day and night. Then I went down to Moses (peace be upon him) and he said: What has your Lord enjoined upon your Ummah? I said: Fifty prayers. He said: Return to thy Lord and beg for reduction (in the number of prayers), for your community shallnot be able to bear this burden. as I have put to test the children of Isra''il and tried them (and found them too weak to bear such a heavy burden). He (the Holy Prophet) said: I went back to my Lord and said: My Lord, make things lighter for my Ummah. (The Lord) reduced five prayers for me. I went down to Moses and said. (The Lord) reduced five (prayers) for me, He said: Verily thy Ummah shall not be able to bear this burden; return to thy Lord and ask Him to make things lighter. I then kept going back and forth between my Lord Blessed and Exalted and Moses, till He said: There are five prayers every day and night. O Muhammad, each being credited as ten, so that makes fifty prayers. He who intends to do a good deed and does not do it will have a good deed recorded for him; and if he does it, it will be recorded for him as ten; whereas he who intends to do an evil deed and does not do, it will not be recorded for him; and if he does it, only one evil deed will be recorded. I then came down and when I came to Moses and informed him, he said: Go back to thy Lord and ask Him to make things lighter. Upon this the Messenger of Allah remarked: I returned to my Lord until I felt ashamed before Him.', NULL, NULL, 'https://sunnah.com/muslim:309', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 310, '"‏ أُتِيتُ فَانْطَلَقُوا بِي إِلَى زَمْزَمَ فَشُرِحَ عَنْ صَدْرِي ثُمَّ غُسِلَ بِمَاءِ زَمْزَمَ ثُمَّ أُنْزِلْتُ ‏"', NULL, 'It is narrated on the the outhority of Anas b. Malik that the Messenger of Allah (ﷺ) said:(the angels) came to me and took me to the Zamzam and my heart was opened and washed with the water of Zamzam and then I was left (at my place).', NULL, NULL, 'https://sunnah.com/muslim:310', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 311, 'حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ، حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ، حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ، عَنْ أَنَسِ بْنِ مَالِكٍ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم أَتَاهُ جِبْرِيلُ صلى الله عليه وسلم وَهُوَ يَلْعَبُ مَعَ الْغِلْمَانِ فَأَخَذَهُ فَصَرَعَهُ فَشَقَّ عَنْ قَلْبِهِ فَاسْتَخْرَجَ الْقَلْبَ فَاسْتَخْرَجَ مِنْهُ عَلَقَةً فَقَالَ هَذَا حَظُّ الشَّيْطَانِ مِنْكَ ‏.‏ ثُمَّ غَسَلَهُ فِي طَسْتٍ مِنْ ذَهَبٍ بِمَاءِ زَمْزَمَ ثُمَّ لأَمَهُ ثُمَّ أَعَادَهُ فِي مَكَانِهِ وَجَاءَ الْغِلْمَانُ يَسْعَوْنَ إِلَى أُمِّهِ - يَعْنِي ظِئْرَهُ - فَقَالُوا إِنَّ مُحَمَّدًا قَدْ قُتِلَ ‏.‏ فَاسْتَقْبَلُوهُ وَهُوَ مُنْتَقَعُ اللَّوْنِ ‏.‏ قَالَ أَنَسٌ وَقَدْ كُنْتُ أَرَى أَثَرَ ذَلِكَ الْمِخْيَطِ فِي صَدْرِهِ ‏.‏', NULL, 'Anas b. Malik reported that Gabriel came to the Messenger of Allah (ﷺ) while he was playing with his playmates. He took hold of him and lay him prostrate on the ground and tore open his breast and took out the heart from it and then extracted a blood-clot out of it and said:That was the part of Satan in thee. And then he washed it with the water of Zamzam in a golden basin and then it was joined together and restored to it place. The boys came running to his mother, i. e. his nurse, and said: Verily Muhammad has been murdered. They all rushed toward him (and found him all right) His color was changed, Anas said. I myself saw the marks of needle on his breast.', NULL, NULL, 'https://sunnah.com/muslim:311', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 314, 'حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ، عَنْ سَعِيدٍ، عَنْ قَتَادَةَ، عَنْ أَنَسِ بْنِ مَالِكٍ، - لَعَلَّهُ قَالَ - عَنْ مَالِكِ بْنِ صَعْصَعَةَ، - رَجُلٌ مِنْ قَوْمِهِ - قَالَ قَالَ نَبِيُّ اللَّهِ صلى الله عليه وسلم ‏"‏ بَيْنَا أَنَا عِنْدَ الْبَيْتِ بَيْنَ النَّائِمِ وَالْيَقْظَانِ إِذْ سَمِعْتُ قَائِلاً يَقُولُ أَحَدُ الثَّلاَثَةِ بَيْنَ الرَّجُلَيْنِ ‏.‏ فَأُتِيتُ فَانْطُلِقَ بِي فَأُتِيتُ بِطَسْتٍ مِنْ ذَهَبٍ فِيهَا مِنْ مَاءِ زَمْزَمَ فَشُرِحَ صَدْرِي إِلَى كَذَا وَكَذَا ‏"‏ ‏.‏ قَالَ قَتَادَةُ فَقُلْتُ لِلَّذِي مَعِي مَا يَعْنِي قَالَ إِلَى أَسْفَلِ بَطْنِهِ ‏"‏ فَاسْتُخْرِجَ قَلْبِي فَغُسِلَ بِمَاءِ زَمْزَمَ ثُمَّ أُعِيدَ مَكَانَهُ ثُمَّ حُشِيَ إِيمَانًا وَحِكْمَةً ثُمَّ أُتِيتُ بِدَابَّةٍ أَبْيَضَ يُقَالُ لَهُ الْبُرَاقُ فَوْقَ الْحِمَارِ وَدُونَ الْبَغْلِ يَقَعُ خَطْوُهُ عِنْدَ أَقْصَى طَرْفِهِ فَحُمِلْتُ عَلَيْهِ ثُمَّ انْطَلَقْنَا حَتَّى أَتَيْنَا السَّمَاءَ الدُّنْيَا فَاسْتَفْتَحَ جِبْرِيلُ صلى الله عليه وسلم فَقِيلَ مَنْ هَذَا قَالَ جِبْرِيلُ ‏.‏ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ صلى الله عليه وسلم ‏.‏ قِيلَ وَقَدْ بُعِثَ إِلَيْهِ قَالَ نَعَمْ - قَالَ - فَفَتَحَ لَنَا وَقَالَ مَرْحَبًا بِهِ وَلَنِعْمَ الْمَجِيءُ جَاءَ - قَالَ - فَأَتَيْنَا عَلَى آدَمَ صلى الله عليه وسلم ‏"‏ ‏.‏ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ ‏.‏ وَذَكَرَ أَنَّهُ لَقِيَ فِي السَّمَاءِ الثَّانِيَةِ عِيسَى وَيَحْيَى - عَلَيْهِمَا السَّلاَمُ - وَفِي الثَّالِثَةِ يُوسُفَ وَفِي الرَّابِعَةِ إِدْرِيسَ وَفِي الْخَامِسَةِ هَارُونَ - صَلَّى اللَّهُ عَلَيْهِمْ وَسَلَّمَ - قَالَ ‏"‏ ثُمَّ انْطَلَقْنَا حَتَّى انْتَهَيْنَا إِلَى السَّمَاءِ السَّادِسَةِ فَأَتَيْتُ عَلَى مُوسَى عَلَيْهِ السَّلاَمُ فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَرْحَبًا بِالأَخِ الصَّالِحِ وَالنَّبِيِّ الصَّالِحِ ‏.‏ فَلَمَّا جَاوَزْتُهُ بَكَى فَنُودِيَ مَا يُبْكِيكَ قَالَ رَبِّ هَذَا غُلاَمٌ بَعَثْتَهُ بَعْدِي يَدْخُلُ مِنْ أُمَّتِهِ الْجَنَّةَ أَكْثَرُ مِمَّا يَدْخُلُ مِنْ أُمَّتِي ‏.‏ - قَالَ - ثُمَّ انْطَلَقْنَا حَتَّى انْتَهَيْنَا إِلَى السَّمَاءِ السَّابِعَةِ فَأَتَيْتُ عَلَى إِبْرَاهِيمَ ‏"‏ ‏.‏ وَقَالَ فِي الْحَدِيثِ وَحَدَّثَ نَبِيُّ اللَّهِ صلى الله عليه وسلم أَنَّهُ رَأَى أَرْبَعَةَ أَنْهَارٍ يَخْرُجُ مِنْ أَصْلِهَا نَهْرَانِ ظَاهِرَانِ وَنَهْرَانِ بَاطِنَانِ ‏"‏ فَقُلْتُ يَا جِبْرِيلُ مَا هَذِهِ الأَنْهَارُ قَالَ أَمَّا النَّهْرَانِ الْبَاطِنَانِ فَنَهْرَانِ فِي الْجَنَّةِ وَأَمَّا الظَّاهِرَانِ فَالنِّيلُ وَالْفُرَاتُ ‏.‏ ثُمَّ رُفِعَ لِيَ الْبَيْتُ الْمَعْمُورُ فَقُلْتُ يَا جِبْرِيلُ مَا هَذَا قَالَ هَذَا الْبَيْتُ الْمَعْمُورُ يَدْخُلُهُ كُلَّ يَوْمٍ سَبْعُونَ أَلْفَ مَلَكٍ إِذَا خَرَجُوا مِنْهُ لَمْ يَعُودُوا فِيهِ آخِرُ مَا عَلَيْهِمْ ‏.‏ ثُمَّ أُتِيتُ بِإِنَاءَيْنِ أَحَدُهُمَا خَمْرٌ وَالآخَرُ لَبَنٌ فَعُرِضَا عَلَىَّ فَاخْتَرْتُ اللَّبَنَ فَقِيلَ أَصَبْتَ أَصَابَ اللَّهُ بِكَ أُمَّتُكَ عَلَى الْفِطْرَةِ ‏.‏ ثُمَّ فُرِضَتْ عَلَىَّ كُلَّ يَوْمٍ خَمْسُونَ صَلاَةً ‏"‏ ‏.‏ ثُمَّ ذَكَرَ قِصَّتَهَا إِلَى آخِرِ الْحَدِيثِ ‏.‏', NULL, 'Anas b. Malik reported on the authority of Malik b. Sa sa'', perhaps a person of his tribe, that the Prophet of Allah (ﷺ) said:I was near the House (i. e. Ka''bah) in a state between sleep and wakefulness when I heard someone say: He is the third among the two persons. Then he came to me and took me with him. Then a golden basin containing the water of Zamzam was brought to me and my heart was opened up to such and such (part). Qatada said: I asked him who was with me (i e. the narrator) and what he meant by such and such (part). He replied: (It means that it was opened) up to the lower part of his abdomen (Then the hadith continues): My heart was extracted and it was washed with the water of Zamzam and then it was restored in its original position, after which it was filled with faith and wisdom. I was then brought a white beast which is called al-Buraq, bigger than a donkey and smaller than a mule. Its stride was as long as the eye could reach. I was mounted on it, and then we went forth till we reached the lowest heaven. Gabriel asked for the (gate) to be opened, and it was said: Who is he? He replied: Gabriel. It was again said: Who is with thee? He replied: Muhammad (ﷺ). It was said: Has he been sent for? He (Gabriel) said: Yes. He (the Prophet) said: Then (the gate) was opened for us (and it was said): Welcome unto him! His is a blessed arrival. Then we came to Adam (peace be upon him). And he (the narrator) narrated the whole account of the hadith. (The Holy Prophet) observed that he met Jesus in the second heaven, Yahya (peace be on both of them) in the third heaven, Yusuf in the third, Idris in the fourth, Harun in the fifth (peace and blessings of Allah be upon them). Then we travelled on till we reached the sixth heaven and came to Moses (peace be upon him) and I greeted him and he said: Welcome unto righteous brother and righteous prophet. And when I passed (by him) he wept, and a voice was heard saying: What makes thee weep? He said: My Lord, he is a young man whom Thou hast sent after me (as a prophet) and his followers will enter Paradise in greater numbers than my followers. Then we travelled on till we reached the seventh heaven and I came to Ibrahim. He (the narrator) narrat- ed in this hadith that the Prophet of Allah (ﷺ) told that he saw four rivers which flowed from (the root of the lote-tree of the farthest limits): two manifest rivers and two hidden rivers. I said: '' Gabriel! what are these rivers? He replied: The two hidden rivers are the rivers of Paradise, and as regards the two manifest ones, they are the Nile and the Euphrates. Then the Bait-ul-Ma''mur was raised up to me. I said: O Gabriel! what is this? He replied: It is the Bait-ul-Ma''mur. Seventy thousand angels enter into it daily and, after they come out, they never return again. Two vessels were then brought to me. The first one contained wine and the second one contained milk, and both of them were placed before me. I chose milk. It was said: You did right. Allah will guide rightly through you your Ummah on the natural course. Then fifty prayers daily were made obligatory for me. And then he narrated the rest of the hadith to the end.', NULL, NULL, 'https://sunnah.com/muslim:314', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 315, '"‏ فَأُتِيتُ بِطَسْتٍ مِنْ ذَهَبٍ مُمْتَلِئٍ حِكْمَةً وَإِيمَانًا فَشُقَّ مِنَ النَّحْرِ إِلَى مَرَاقِّ الْبَطْنِ فَغُسِلَ بِمَاءِ زَمْزَمَ ثُمَّ مُلِئَ حِكْمَةً وَإِيمَانًا ‏"', NULL, 'It is reported on the authority of Malik b. Sa''sa'' that the Messenger of Allah (ﷺ) narrated the hadith (mentioned above) and added to it:I was brought a gold basin full of wisdom and faith, and then the (part of the body) right from the upper end of the chest to the lower part of the abdomen was opened and it was washed with the water of Zamzam and then flled with wisdom and faith.', NULL, NULL, 'https://sunnah.com/muslim:315', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 316, 'حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى، وَابْنُ، بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ، حَدَّثَنَا شُعْبَةُ، عَنْ قَتَادَةَ، قَالَ سَمِعْتُ أَبَا الْعَالِيَةِ، يَقُولُ حَدَّثَنِي ابْنُ عَمِّ، نَبِيِّكُمْ صلى الله عليه وسلم - يَعْنِي ابْنَ عَبَّاسٍ - قَالَ ذَكَرَ رَسُولُ اللَّهِ صلى الله عليه وسلم حِينَ أُسْرِيَ بِهِ فَقَالَ ‏"‏ مُوسَى آدَمُ طُوَالٌ كَأَنَّهُ مِنْ رِجَالِ شَنُوءَةَ ‏"‏ ‏.‏ وَقَالَ ‏"‏ عِيسَى جَعْدٌ مَرْبُوعٌ ‏"‏ ‏.‏ وَذَكَرَ مَالِكًا خَازِنَ جَهَنَّمَ وَذَكَرَ الدَّجَّالَ ‏.‏', NULL, 'Qatada reported that he heard Abu al-''Aliya saying that the cousin of your Prophet (ﷺ), i. e. Ibn Abbas, told him:The Messenger of Allah (ﷺ), while narrating his night journey observed: Musa (peace be upon him) was a man of high stature as if he was of the people of the Shanu''a (tribe), and Jesus was a well-built person having curly hair. He also mentioned Malik, the guardian of Hell, and Dajjal.', NULL, NULL, 'https://sunnah.com/muslim:316', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 317, '"‏ مَرَرْتُ لَيْلَةَ أُسْرِيَ بِي عَلَى مُوسَى بْنِ عِمْرَانَ - عَلَيْهِ السَّلاَمُ - رَجُلٌ آدَمُ طُوَالٌ جَعْدٌ كَأَنَّهُ مِنْ رِجَالِ شَنُوءَةَ وَرَأَيْتُ عِيسَى ابْنَ مَرْيَمَ مَرْبُوعَ الْخَلْقِ إِلَى الْحُمْرَةِ وَالْبَيَاضِ سَبِطَ الرَّأْسِ ‏"', NULL, 'Abu al-''Aliya reported:Ibn Abbas, the son of your Prophet''s uncle, told us that the Messenger of Allah (ﷺ) had observed: On the night of my night journey I passed by Moses b. ''Imran (peace be upon him), a man light brown in complexion, tall. well-built as if he was one of the men of the Shanu''a, and saw Jesus son of Mary as a medium-statured man with white and red complexion and crisp hair, and I was shown Malik the guardian of Fire, and Dajjal amongst the signs which were shown to me by Allah. He (the narrator) observed: Then do not doubt his (i. e. of the Holy Prophet) meeting with him (Moses). Qatada elucidated it thus: Verily the Messenger of Allah (ﷺ), met Moses (peace be upon him).', 'Abu al-''Aliya reported', NULL, 'https://sunnah.com/muslim:317', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 318, 'حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ، وَسُرَيْجُ بْنُ يُونُسَ، قَالاَ حَدَّثَنَا هُشَيْمٌ، أَخْبَرَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ، عَنْ أَبِي الْعَالِيَةِ، عَنِ ابْنِ عَبَّاسٍ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم مَرَّ بِوَادِي الأَزْرَقِ فَقَالَ ‏"‏ أَىُّ وَادٍ هَذَا ‏"‏ ‏.‏ فَقَالُوا هَذَا وَادِي الأَزْرَقِ ‏.‏ قَالَ ‏"‏ كَأَنِّي أَنْظُرُ إِلَى مُوسَى - عَلَيْهِ السَّلاَمُ - هَابِطًا مِنَ الثَّنِيَّةِ وَلَهُ جُؤَارٌ إِلَى اللَّهِ بِالتَّلْبِيَةِ ‏"‏ ‏.‏ ثُمَّ أَتَى عَلَى ثَنِيَّةِ هَرْشَى ‏.‏ فَقَالَ ‏"‏ أَىُّ ثَنِيَّةٍ هَذِهِ ‏"‏ ‏.‏ قَالُوا ثَنِيَّةُ هَرْشَى قَالَ ‏"‏ كَأَنِّي أَنْظُرُ إِلَى يُونُسَ بْنِ مَتَّى - عَلَيْهِ السَّلاَمُ - عَلَى نَاقَةٍ حَمْرَاءَ جَعْدَةٍ عَلَيْهِ جُبَّةٌ مِنْ صُوفٍ خِطَامُ نَاقَتِهِ خُلْبَةٌ وَهُوَ يُلَبِّي ‏"‏ ‏.‏ قَالَ ابْنُ حَنْبَلٍ فِي حَدِيثِهِ قَالَ هُشَيْمٌ يَعْنِي لِيفًا ‏.‏', NULL, 'Abu al-''Aliya narrated it on the authority of Ibn ''Abbas that the Messenger of Allah (ﷺ) passed through the valley of Azraq, and he asked:Which valley is this? They said: This is the valley of Azraq, and he observed: (I perceive) as if I am seeing Moses (peace be upon him) coming down from the mountain track, and he is calling upon Allah loudly (saying: Here I am! at your service! ). Then he came to the mountain track of Harsha. He (the Holy Prophet) said: Which is this mountain track? They said: It is the mountain track of Harsha. He observed (I feel) as If I am seeing Yunus (Jonah-peace be upon him) son of Matta on a well- built red dromedary, with a cloak of wool around him and the rein of his dromedary is made of the fibres of date-palm, and he is calling upon Allah (saying: Here I am! at your service, my Lord! ). Ibn Hanbal said in the hadith narrated by him: Hushaim said that the meaning of khulba was fibre of date-palm.', NULL, NULL, 'https://sunnah.com/muslim:318', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 319, 'وَحَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى، حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ، عَنْ دَاوُدَ، عَنْ أَبِي الْعَالِيَةِ، عَنِ ابْنِ عَبَّاسٍ، قَالَ سِرْنَا مَعَ رَسُولِ اللَّهِ صلى الله عليه وسلم بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَمَرَرْنَا بِوَادٍ فَقَالَ ‏"‏ أَىُّ وَادٍ هَذَا ‏"‏ ‏.‏ فَقَالُوا وَادِي الأَزْرَقِ ‏.‏ فَقَالَ ‏"‏ كَأَنِّي أَنْظُرُ إِلَى مُوسَى صلى الله عليه وسلم فَذَكَرَ مِنْ لَوْنِهِ وَشَعْرِهِ شَيْئًا لَمْ يَحْفَظْهُ دَاوُدُ وَاضِعًا إِصْبَعَيْهِ فِي أُذُنَيْهِ لَهُ جُؤَارٌ إِلَى اللَّهِ بِالتَّلْبِيَةِ مَارًّا بِهَذَا الْوَادِي ‏"‏ ‏.‏ قَالَ ‏"‏ ثُمَّ سِرْنَا حَتَّى أَتَيْنَا عَلَى ثَنِيَّةٍ فَقَالَ ‏"‏ أَىُّ ثَنِيَّةٍ هَذِهِ ‏"‏ ‏.‏ قَالُوا هَرْشَى أَوْ لِفْتٌ ‏.‏ فَقَالَ ‏"‏ كَأَنِّي أَنْظُرُ إِلَى يُونُسَ عَلَى نَاقَةٍ حَمْرَاءَ عَلَيْهِ جُبَّةُ صُوفٍ خِطَامُ نَاقَتِهِ لِيفٌ خُلْبَةٌ مَارًّا بِهَذَا الْوَادِي مُلَبِّيًا ‏"‏ ‏.‏', NULL, 'Abu al-''Aliya narrated it on the authority of Ibn ''Abbas that he said:We travelled with the Messenger of Allah (ﷺ) between Mecca and Medina and we passed by a valley. He (the Holy Prophet) asked: Which valley is this? They said: This is the valley of Azraq Upon this he (the Holy Prophet) remarked: (I feel) as if I am seeing Moses (peace be upon him), and then he described something about his complexion and hair, which Diwud (the narrator) could not remember. He (Moses, as described by the Holy Prophet) was keeping his fingers in his ears and was responding loudly to Allah (saying: I am as Thy service, my Lord) while passing through that valley. We then travelled (further) till we came to the mountain trail. He (the Holy Prophet) said: Which mountain trail is this? They said: It is the Harsha or Lift. He (the Holy Prophet) said: (I perceive) as if I am seeing Yunus on a red camel, with a cloak of wool around him. The halter of his camel was that of the fibre of date-palm, and he was passing through the valley saying: I am at Thy service! my Lord.', 'Abu al-''Aliya narrated it on the authority of Ibn ''Abbas that he said', NULL, 'https://sunnah.com/muslim:319', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 320, '"‏ أَمَّا إِبْرَاهِيمُ فَانْظُرُوا إِلَى صَاحِبِكُمْ وَأَمَّا مُوسَى فَرَجُلٌ آدَمُ جَعْدٌ عَلَى جَمَلٍ أَحْمَرَ مَخْطُومٍ بِخُلْبَةٍ كَأَنِّي أَنْظُرُ إِلَيْهِ إِذَا انْحَدَرَ فِي الْوَادِي يُلَبِّي ‏"', NULL, 'It is narrated on the authority of Mujahid that he said:We were with Ibn ''Abbas and (the people) talked about al-Dajjal. (One of them remarked. There is written between his eyes (the word) Kafir (infidel). The narrator said: Ibn ''Abbas remarked: I did not hear him (the Holy Prophet) say it, but he said: So far as Ibrahim is concerned. you may see your companion and so far as Moses is concerned, he is a well-built man with wheat complexion (riding) on a red camel with its halter made of the fibre of date-palm (and I perceive) as if I am seeing towards him as he is going down in the valley saying: I am at Thy service! my Lord.', 'It is narrated on the authority of Mujahid that he said', NULL, 'https://sunnah.com/muslim:320', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 323, '"‏ أَرَانِي لَيْلَةً عِنْدَ الْكَعْبَةِ فَرَأَيْتُ رَجُلاً آدَمَ كَأَحْسَنِ مَا أَنْتَ رَاءٍ مِنْ أُدْمِ الرِّجَالِ لَهُ لِمَّةٌ كَأَحْسَنِ مَا أَنْتَ رَاءٍ مِنَ اللِّمَمِ قَدْ رَجَّلَهَا فَهِيَ تَقْطُرُ مَاءً مُتَّكِئًا عَلَى رَجُلَيْنِ - أَوْ عَلَى عَوَاتِقِ رَجُلَيْنِ - يَطُوفُ بِالْبَيْتِ فَسَأَلْتُ مَنْ هَذَا فَقِيلَ هَذَا الْمَسِيحُ ابْنُ مَرْيَمَ ‏.‏ ثُمَّ إِذَا أَنَا بِرَجُلٍ جَعْدٍ قَطَطٍ أَعْوَرِ الْعَيْنِ الْيُمْنَى كَأَنَّهَا عِنَبَةٌ طَافِيَةٌ فَسَأَلْتُ مَنْ هَذَا فَقِيلَ هَذَا الْمَسِيحُ الدَّجَّالُ ‏"', NULL, 'It is narrated on the authority of ''Abdullah b. Umar that the Messenger of Allah (ﷺ) said:I found myself one night near the Ka''bah, and I saw a man with wheat complexion amongst the fair-complexioned men that you ever saw. He had a lock of hair the most beautiful of the locks that you ever saw. He had combed it. Water was trickling out of them. He was leaning on two men, or on the shoulders of two men, and he was circumscribing the Ka''bah. I asked, What is he? It was said: He is al-Masih son of Mary. Then I saw another person, stout and having too much curly hair, and blind in his right eye as if it was a full swollen grape. I asked Who is he? It was said: He is al-Masih al-Dajjal.', NULL, NULL, 'https://sunnah.com/muslim:323', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 324, 'حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ الْمُسَيَّبِيُّ، حَدَّثَنَا أَنَسٌ، - يَعْنِي ابْنَ عِيَاضٍ - عَنْ مُوسَى، - وَهُوَ ابْنُ عُقْبَةَ - عَنْ نَافِعٍ، قَالَ قَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ ذَكَرَ رَسُولُ اللَّهِ صلى الله عليه وسلم يَوْمًا بَيْنَ ظَهْرَانَىِ النَّاسِ الْمَسِيحَ الدَّجَّالَ فَقَالَ ‏"‏ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى لَيْسَ بِأَعْوَرَ أَلاَ إِنَّ الْمَسِيحَ الدَّجَّالَ أَعْوَرُ عَيْنِ الْيُمْنَى كَأَنَّ عَيْنَهُ عِنَبَةٌ طَافِيَةٌ ‏"‏ ‏.‏ قَالَ وَقَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ أَرَانِي اللَّيْلَةَ فِي الْمَنَامِ عِنْدَ الْكَعْبَةِ فَإِذَا رَجُلٌ آدَمُ كَأَحْسَنِ مَا تَرَى مِنْ أُدْمِ الرِّجَالِ تَضْرِبُ لِمَّتُهُ بَيْنَ مَنْكِبَيْهِ رَجِلُ الشَّعَرِ يَقْطُرُ رَأْسُهُ مَاءً ‏.‏ وَاضِعًا يَدَيْهِ عَلَى مَنْكِبَىْ رَجُلَيْنِ وَهُوَ بَيْنَهُمَا يَطُوفُ بِالْبَيْتِ فَقُلْتُ مَنْ هَذَا فَقَالُوا الْمَسِيحُ ابْنُ مَرْيَمَ ‏.‏ وَرَأَيْتُ وَرَاءَهُ رَجُلاً جَعْدًا قَطَطًا أَعْوَرَ عَيْنِ الْيُمْنَى كَأَشْبَهِ مَنْ رَأَيْتُ مِنَ النَّاسِ بِابْنِ قَطَنٍ وَاضِعًا يَدَيْهِ عَلَى مَنْكِبَىْ رَجُلَيْنِ يَطُوفُ بِالْبَيْتِ فَقُلْتُ مَنْ هَذَا قَالُوا هَذَا الْمَسِيحُ الدَّجَّالُ ‏"‏ ‏.‏', NULL, 'It is narrated on the authority of ''Abdulldh b. Umar that one day the Messenger of Allah (ﷺ) mentioned in the presence of people about al-Masih al-Dajjal. He said:Verily Allah (hallowed be He and High) is not blind of one eye. Behold, but the Masih al-Dajjal is blind of right eye as if his eye is like a swollen grape, and the Messenger of Allah (ﷺ) said: I was shown in a dream in the night that near the Ka''bah there was a man fair-complexioned, fine amongst the white-complexioned men that you ever saw, his locks of hair were falling on his shoulders. He was a man whose hair were neither too curly nor too straight, and water trickled down from his head. He was placing his bands on the shoulders of two persons and amidst them was making a circuit around the Ka''bah. I said: Who is he? They replied: Al-Masih son of Mary. And I saw behind him a man with intensely curly hair, blind of right eye. Amongst the persons I have ever seen Ibn Qatan has the greatest resemblance with him. He was making a circuit around the Ka''bah by placing both his hands on the shoulders of two persons. I said: Who is he? They said; It is al-Masih al-Dajjal.', NULL, NULL, 'https://sunnah.com/muslim:324', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 325, '"‏ رَأَيْتُ عِنْدَ الْكَعْبَةِ رَجُلاً آدَمَ سَبِطَ الرَّأْسِ وَاضِعًا يَدَيْهِ عَلَى رَجُلَيْنِ ‏.‏ يَسْكُبُ رَأْسُهُ - أَوْ يَقْطُرُ رَأْسُهُ - فَسَأَلْتُ مَنْ هَذَا فَقَالُوا عِيسَى ابْنُ مَرْيَمَ أَوِ الْمَسِيحُ ابْنُ مَرْيَمَ - لاَ نَدْرِي أَىَّ ذَلِكَ قَالَ - وَرَأَيْتُ وَرَاءَهُ رَجُلاً أَحْمَرَ جَعْدَ الرَّأْسِ أَعْوَرَ الْعَيْنِ الْيُمْنَى أَشْبَهُ مَنْ رَأَيْتُ بِهِ ابْنُ قَطَنٍ فَسَأَلْتُ مَنْ هَذَا فَقَالُوا الْمَسِيحُ الدَّجَّالُ ‏"', NULL, 'It is narrated on the authority of Ibn ''Umar that the Messenger of Allah (ﷺ) said:I saw near the Ka''bah a man of fair complexion with straight hair, placing his hands on two persons. Water was flowing from his head or it was trickling from his head. I asked: Who is he? They said: He is Jesus son of Mary or al-Masih son of Mary. The narrator) says: I do not remember which word it was. He (the Holy Prophet) said: And I saw behind him a man with red complexion and thick curly hair, blind in the right eye. I saw in him the greatest resemblance with Ibn Qitan I asked: Who is he? They replied: It is al-Masih al-Dajjal.', NULL, NULL, 'https://sunnah.com/muslim:325', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 330, 'وَحَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ، حَدَّثَنَا عَبَّادٌ، - وَهُوَ ابْنُ الْعَوَّامِ - حَدَّثَنَا الشَّيْبَانِيُّ، قَالَ سَأَلْتُ زِرَّ بْنَ حُبَيْشٍ عَنْ قَوْلِ اللَّهِ، عَزَّ وَجَلَّ ‏{‏ فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى‏}‏ قَالَ أَخْبَرَنِي ابْنُ مَسْعُودٍ أَنَّ النَّبِيَّ صلى الله عليه وسلم رَأَى جِبْرِيلَ لَهُ سِتُّمِائَةِ جَنَاحٍ ‏.‏', NULL, 'Al-Shaibini reported to us:I asked Zirr b. Hubaish about the words of Allah (the Mighty and Great):" So he was (at a distance) of two bows or nearer" (al-Qur''an, Iiii 8). He said: Ibn Mas''ud informed me that, verily, the Messenger of Allah (ﷺ) saw Gabriel and he had six hundred wings.', 'Al-Shaibini reported to us', NULL, 'https://sunnah.com/muslim:330', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z'),
  ('muslim', 'The Book of Faith', 331, 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ، عَنِ الشَّيْبَانِيِّ، عَنْ زِرٍّ، عَنْ عَبْدِ اللَّهِ، قَالَ ‏{‏ مَا كَذَبَ الْفُؤَادُ مَا رَأَى‏}‏ قَالَ رَأَى جِبْرِيلَ - عَلَيْهِ السَّلاَمُ - لَهُ سِتُّمِائَةِ جَنَاحٍ ‏.‏', NULL, 'Al-Shaibani narrated on the authority of Zirr who narrated it on this authority of Abdullah that the (words of Allah):" The heart belied not what he saw" (al Qur''an, Iiii. 11) imply that he saw Gabriel (peace be upon him) and he had six hundred wings.', NULL, NULL, 'https://sunnah.com/muslim:331', 'Sunnah.com developers and open platform data access notice (https://sunnah.com/developers)', TIMESTAMPTZ '2026-04-23T17:38:25.677292Z')
